# --- HOTFIX: safe response JSON parsing (prevents JSONDecodeError / empty responses) ---
def safe_json_response(resp):
    """Return parsed JSON safely; invalid/empty/HTML bodies become {} quietly."""
    try:
        txt = str(getattr(resp, "text", "") or "")
    except Exception:
        txt = ""
    if not txt.strip():
        return {}
    try:
        ct = str((getattr(resp, "headers", {}) or {}).get("Content-Type", "") or "").lower()
    except Exception:
        ct = ""
    stripped = txt.lstrip()
    if stripped.startswith("<"):
        return {}
    if "json" not in ct and not stripped.startswith("{") and not stripped.startswith("["):
        return {}
    try:
        parsed = json.loads(txt)
        return parsed if isinstance(parsed, (dict, list)) else {}
    except Exception:
        return {}
# --- HOTFIX: safe parsing helpers ---
def safe_int(value, default=0):
    """Convert value to int safely. Handles '', '-', None, commas, floats."""
    try:
        if value is None:
            return default
        s = str(value).replace(",", "").strip()
        if s in ("", "-", "None", "null", "NULL"):
            return default
        return int(float(s))
    except Exception as e:
        _swallow_exception(e)  # v105 structured silent-exception log
        return default
def normalize_stock_code(value):
    """Return 6-digit numeric stock code or None."""
    if value is None:
        return None
    s = str(value).strip()
    if len(s) == 6 and s.isdigit():
        return s
    return None
_ver_match = _re.search(r"버전:\s*(v[0-9][0-9A-Za-z._-]*)", __doc__ or "")
BOT_VERSION = _ver_match.group(1) if _ver_match else "unknown"
_date_match = _re.search(r"날짜:\s*([\d-]+)", __doc__ or "")
BOT_DATE    = _date_match.group(1) if _date_match else "unknown"
_BOT_VER_FULLMATCH = _re.fullmatch(r"v(\d+)(?:\.(\d+))?", BOT_VERSION or "")
if _BOT_VER_FULLMATCH:
    _BOT_VER_MAJOR = int(_BOT_VER_FULLMATCH.group(1))
    _BOT_VER_MINOR = int(_BOT_VER_FULLMATCH.group(2) or 0)
    BOT_VERSION_SERIES = f"v{_BOT_VER_MAJOR}"
else:
    _BOT_VER_MAJOR = None
    _BOT_VER_MINOR = 0
    BOT_VERSION_SERIES = (BOT_VERSION.split(".", 1)[0] or BOT_VERSION or "legacy")
BOT_STATS_COHORT = BOT_VERSION_SERIES
BOT_VERSION_IS_MINOR = _BOT_VER_MINOR > 0

def _derive_stats_cohort(version: str | None) -> str:
    ver = str(version or "").strip()
    if not ver:
        return "legacy"
    m = _re.fullmatch(r"v(\d+)(?:\.(\d+))?", ver)
    if m:
        return f"v{int(m.group(1))}"
    return ver.split(".", 1)[0] or ver

