# 🔐 KIS API
# ============================================================
def _wait_for_kis_rest_slot(kind: str = "rest") -> None:
    """실전 KIS REST burst를 1초 윈도우 내부 상한으로 평탄화한다."""
    limit = KIS_TOKEN_LIMIT_PER_SEC if kind == "token" else KIS_REST_LIMIT_PER_SEC
    limit = max(1, int(limit or 1))
    window = 1.0
    min_sleep = 0.01
    dq = _kis_token_call_times if kind == "token" else _kis_rest_call_times
    stat_wait_key = "token_wait_sec" if kind == "token" else "rest_wait_sec"
    stat_evt_key = "token_wait_events" if kind == "token" else "rest_wait_events"
    while True:
        sleep_for = 0.0
        with _kis_rate_lock:
            now = time.monotonic()
            while dq and now - dq[0] >= window:
                dq.popleft()
            if len(dq) < limit:
                dq.append(now)
                return
            oldest = dq[0] if dq else now
            sleep_for = max(min_sleep, window - (now - oldest) + 0.005)
            _kis_rate_stats[stat_evt_key] = int(_kis_rate_stats.get(stat_evt_key, 0)) + 1
            _kis_rate_stats[stat_wait_key] = float(_kis_rate_stats.get(stat_wait_key, 0.0)) + float(sleep_for)
        time.sleep(sleep_for)
def _load_kis_token_state() -> dict:
    state = _read_json_locked(KIS_TOKEN_STATE_FILE, default={})
    return state if isinstance(state, dict) else {}
def _save_kis_token_state(token: str, expires_at: float, *, retry_block_until: float = 0.0, retry_block_reason: str = "") -> None:
    payload = {
        "access_token": str(token or "").strip(),
        "expires_at": int(float(expires_at or 0)),
        "base_url": KIS_BASE_URL,
        "saved_at": int(time.time()),
        "retry_block_until": int(float(retry_block_until or 0)),
        "retry_block_reason": str(retry_block_reason or "").strip(),
    }
    _write_json_atomic(KIS_TOKEN_STATE_FILE, payload, indent=2)
def _set_kis_token_retry_block_until(block_until: float, reason: str = "") -> None:
    global _kis_token_retry_block_until
    _kis_token_retry_block_until = max(_kis_token_retry_block_until, float(block_until or 0.0))
    state = _load_kis_token_state()
    payload = {
        "access_token": str(state.get("access_token") or "").strip(),
        "expires_at": int(float(state.get("expires_at") or 0)),
        "base_url": KIS_BASE_URL,
        "saved_at": int(time.time()),
        "retry_block_until": int(float(_kis_token_retry_block_until or 0)),
        "retry_block_reason": str(reason or state.get("retry_block_reason") or "").strip(),
    }
    _write_json_atomic(KIS_TOKEN_STATE_FILE, payload, indent=2)
def _get_kis_token_retry_block_until() -> float:
    global _kis_token_retry_block_until
    if _kis_token_retry_block_until > time.time():
        return _kis_token_retry_block_until
    state = _load_kis_token_state()
    block_until = float(state.get("retry_block_until") or 0.0)
    if block_until > time.time():
        _kis_token_retry_block_until = block_until
        return block_until
    return 0.0
def _clear_kis_token_state() -> None:
    global _kis_token_retry_block_until
    _kis_token_retry_block_until = 0.0
    _write_json_atomic(KIS_TOKEN_STATE_FILE, {}, indent=2)
def _restore_kis_token_from_state() -> str:
    global _access_token, _token_expires, _kis_token_retry_block_until
    state = _load_kis_token_state()
    _kis_token_retry_block_until = float(state.get("retry_block_until") or 0.0)
    token = str(state.get("access_token") or "").strip()
    expires_at = int(float(state.get("expires_at") or 0))
    base_url = str(state.get("base_url") or "").strip().rstrip("/")
    if not token or expires_at <= int(time.time()) + 300:
        return ""
    if base_url and base_url != KIS_BASE_URL:
        return ""
    _access_token = token
    _token_expires = expires_at
    _log_info_msg(f"♻️ KIS 토큰 캐시 복원 ({datetime.now().strftime('%H:%M:%S')})")
    return token
def _validate_kis_oauth_config() -> None:
    if not KIS_APP_KEY or not KIS_APP_SECRET:
        raise RuntimeError("KIS_APP_KEY 또는 KIS_APP_SECRET 누락")
    if not KIS_BASE_URL.startswith("https://"):
        raise RuntimeError(f"KIS_BASE_URL 형식 오류: {KIS_BASE_URL}")
def _kis_http_error_body_snippet(resp) -> str:
    try:
        raw = (getattr(resp, "text", "") or "").strip()
        return " ".join(raw.split())[:240]
    except Exception as e:
        _swallow_exception(e)
        return ""
def _is_kis_token_retry_block_error(err: Exception | str | None) -> bool:
    msg = str(err or "")
    return "EGW00133" in msg or "토큰 재발급 대기" in msg or "token retry cooldown" in msg
def get_token(retry: int = 3) -> str:
    global _access_token, _token_expires
    _validate_kis_oauth_config()
    if _access_token and time.time() < _token_expires:
        return _access_token
    cached = _restore_kis_token_from_state()
    if cached:
        return cached
    block_until = _get_kis_token_retry_block_until()
    if block_until > time.time():
        remain = max(1, int(block_until - time.time()))
        raise RuntimeError(f"KIS token retry cooldown active | wait={remain}s | cause=EGW00133")
    last_error: Exception | None = None
    for attempt in range(retry):
        resp = None
        try:
            _wait_for_kis_rest_slot("token")
            resp = _session.post(
                f"{KIS_BASE_URL}/oauth2/tokenP",
                json={"grant_type":"client_credentials","appkey":KIS_APP_KEY,"appsecret":KIS_APP_SECRET},
                timeout=15,
            )
            resp.raise_for_status()
            d = resp.json()
            _access_token = d["access_token"]
            _token_expires = time.time() + int(d.get("expires_in", 86400)) - 300
            _save_kis_token_state(_access_token, _token_expires)
            _log_info_msg(f"✅ KIS 토큰 발급 ({datetime.now().strftime('%H:%M:%S')})")
            return _access_token
        except requests.HTTPError as e:
            status = getattr(resp, "status_code", None)
            body_snip = _kis_http_error_body_snippet(resp)
            body_txt = str(body_snip or "")
            if status == 403:
                _access_token = None
                _token_expires = 0
                if "EGW00133" in body_txt or "1분당 1회" in body_txt:
                    block_until = time.time() + max(61, int(KIS_TOKEN_RETRY_BLOCK_SEC or 65))
                    _set_kis_token_retry_block_until(block_until, reason=body_txt)
                    remain = max(1, int(block_until - time.time()))
                    last_error = RuntimeError(f"KIS tokenP 403 Forbidden | EGW00133 | token retry cooldown {remain}s | body={body_txt or '없음'}")
                    # v165.18 [#5]: cooldown 오류는 정상 동작 — critical=False로 반복 알람 방지
                    _log_error(f"get_token(attempt={attempt+1})", last_error, critical=False)
                    break
                _clear_kis_token_state()
                hint = "실전/모의 URL-키 조합, API신청/권한 상태, 동일일 재발급 여부 점검 필요"
                last_error = RuntimeError(f"KIS tokenP 403 Forbidden | {hint} | body={body_txt or '없음'}")
            else:
                last_error = RuntimeError(f"KIS tokenP HTTP {status} | body={body_txt or '없음'}")
        except Exception as e:
            last_error = e
        _log_error(f"get_token(attempt={attempt+1})", last_error, critical=attempt==retry-1)
        if _is_kis_token_retry_block_error(last_error):
            break
        time.sleep(5 * (attempt + 1))
    raise RuntimeError(f"❌ KIS 토큰 최종 실패: {last_error}")
def _headers(tr_id: str) -> dict:
    return {"Content-Type":"application/json; charset=utf-8",
            "Authorization":f"Bearer {get_token()}",
            "appkey":KIS_APP_KEY,"appsecret":KIS_APP_SECRET,
            "tr_id":tr_id,"custtype":"P"}
def _safe_get(url: str, tr_id: str, params: dict, *, return_meta: bool = False):
    """v38.3-P1-8: KIS GET with retry/backoff. Never raises.
    return_meta=True → (data, status, ct, body_snippet) 4-tuple.
    return_meta=False(기본) → dict만 반환.
    """
    last_exc = None; last_status = None; last_ct = ""; last_body_snip = ""; last_url = url
    for attempt in range(3):
        try:
            _wait_for_kis_rest_slot("rest")
            resp = _session.get(url, headers=_headers(tr_id), params=params, timeout=15)
            last_status = getattr(resp, "status_code", None)
            last_ct = ((getattr(resp, "headers", {}) or {}).get("Content-Type", "") or "")
            last_url = getattr(resp, "url", url) or url
            if last_status == 403:
                global _access_token, _token_expires
                _access_token = None
                _token_expires = 0
                _clear_kis_token_state()
                _wait_for_kis_rest_slot("rest")
                resp = _session.get(url, headers=_headers(tr_id), params=params, timeout=15)
                last_status = getattr(resp, "status_code", None)
                last_ct = ((getattr(resp, "headers", {}) or {}).get("Content-Type", "") or "")
                last_url = getattr(resp, "url", url) or url
            if last_status == 500:
                try:
                    body_500 = (getattr(resp, "text", "") or "")
                    if "EGW00123" in body_500:
                        _access_token = None
                        _token_expires = 0
                        _clear_kis_token_state()
                        _log_warn_msg(f"⚠️ KIS 토큰만료(EGW00123) 감지 — 재발급 후 재시도")
                        _wait_for_kis_rest_slot("rest")
                        resp = _session.get(url, headers=_headers(tr_id), params=params, timeout=15)
                        last_status = getattr(resp, "status_code", None)
                        last_ct = ((getattr(resp, "headers", {}) or {}).get("Content-Type", "") or "")
                        last_url = getattr(resp, "url", url) or url
                except Exception as e:
                    _swallow_exception(e)
            if last_status == 200:
                data = safe_json_response(resp)
                return (data, last_status, last_ct, "") if return_meta else data
            try:
                raw = (getattr(resp, "text", "") or "").strip()
                last_body_snip = " ".join(raw.split())[:200]
            except Exception as e:
                _swallow_exception(e)  # v105 structured silent-exception log
                last_body_snip = ""
            if return_meta:
                break
            j = safe_json_response(resp)
            if isinstance(j, dict) and j:
                msg_cd = j.get("msg_cd") or j.get("error_code") or j.get("code")
                msg1 = j.get("msg1") or j.get("message") or j.get("error_description") or j.get("error")
                last_exc = f"rt_cd={j.get('rt_cd')} msg_cd={msg_cd} msg={msg1}"
            else:
                last_exc = None
        except Exception as e:
            last_exc = e
        if _is_kis_token_retry_block_error(last_exc):
            break
        try:
            time.sleep(0.8 * (2 ** attempt))
        except Exception as e:
            _swallow_exception(e)
    try:
        if last_status == 404 and isinstance(last_url, str):
            if "chgrate-pcls-100" in last_url: _disable_rank_api_for_today("404")
            if "inquire-daily-trade" in last_url: _disable_daily_trade_api_for_today("404")
    except Exception as e:
        _swallow_exception(e)
    try:
        _log_warn_msg(f"⚠️ API 오류 ({tr_id}): url={last_url} status={last_status} ct={last_ct} err={last_exc} body={last_body_snip}")
    except Exception as e:
        _swallow_exception(e)
    return ({}, last_status, last_ct, last_body_snip) if return_meta else {}
def _safe_get_meta(url: str, tr_id: str, params: dict):
    """v38.3: _safe_get 래퍼 (하위 호환)"""
    return _safe_get(url, tr_id, params, return_meta=True)
# ============================================================
# 📊 일봉 데이터 (공통 사용)
# ============================================================
_daily_cache = {}  # code → {items, ts}
_atr_cache   = {}  # code → {atr, date}  하루 1회 갱신
def get_daily_data(code: str, days: int = 60) -> list:
    """일봉 데이터 조회 (캐시 30분)"""
    cached = _daily_cache.get(code)
    if cached and time.time() - cached["ts"] < 1800:
        return cached["items"]
    try:
        end   = datetime.now().strftime("%Y%m%d")
        start = (datetime.now() - timedelta(days=days+10)).strftime("%Y%m%d")
        url   = f"{KIS_BASE_URL}/uapi/domestic-stock/v1/quotations/inquire-daily-itemchartprice"
        params = {"FID_COND_MRKT_DIV_CODE":"J","FID_INPUT_ISCD":code,
                  "FID_INPUT_DATE_1":start,"FID_INPUT_DATE_2":end,
                  "FID_PERIOD_DIV_CODE":"D","FID_ORG_ADJ_PRC":"0"}
        resp_json = _safe_get(url, "FHKST03010100", params)
        items = resp_json.get("output2", []) if isinstance(resp_json, dict) else []
        items = sorted([{
            "date":  i.get("stck_bsop_date",""),
            "open":  int(i.get("stck_oprc",0)),
            "high":  int(i.get("stck_hgpr",0)),
            "low":   int(i.get("stck_lwpr",0)),
            "close": int(i.get("stck_clpr",0)),
            "vol":   int(i.get("acml_vol",0)),
        } for i in items if i.get("stck_bsop_date")], key=lambda x: x["date"])
        _daily_cache[code] = {"items": items, "ts": time.time()}
        return items
    except Exception as e:
        _log_error(f"get_daily_data({code})", e); return []
# ============================================================
# ⑦-A 보조지표 계산 (RSI / 이동평균 / 볼린저밴드 / 유사패턴)
# ============================================================
def calc_rsi(items: list, period: int = None) -> float:
    """
    RSI 계산. period는 _dynamic["rsi_period"] 자동 적용.
    반환: 0~100 (70↑ 과매수, 30↓ 과매도)
    """
    period = period or int(_dynamic.get("rsi_period", 14))
    closes = [i["close"] for i in items if i.get("close")]
    if len(closes) < period + 1:
        return 50.0  # 데이터 부족 시 중립값
    gains, losses = [], []
    for i in range(1, period + 1):
        diff = closes[-(period + 1 - i)] - closes[-(period + 2 - i)]
        (gains if diff > 0 else losses).append(abs(diff))
    avg_gain = sum(gains) / period if gains else 0
    avg_loss = sum(losses) / period if losses else 0
    if avg_loss == 0:
        return 100.0
    rs = avg_gain / avg_loss
    return round(100 - (100 / (1 + rs)), 1)
def calc_ma_trend(items: list) -> dict:
    """
    이동평균선 정배열 여부 확인.
    _dynamic["ma_short"/"ma_mid"/"ma_long"] 자동 적용.
    반환: {"aligned": bool, "short": float, "mid": float, "long": float, "desc": str}
    """
    s = int(_dynamic.get("ma_short", 5))
    m = int(_dynamic.get("ma_mid",   20))
    l = int(_dynamic.get("ma_long",  60))
    closes = [i["close"] for i in items if i.get("close")]
    if len(closes) < l:
        return {"aligned": None, "short": 0, "mid": 0, "long": 0, "desc": "데이터부족"}
    ma_s = sum(closes[-s:]) / s
    ma_m = sum(closes[-m:]) / m
    ma_l = sum(closes[-l:]) / l
    aligned   = ma_s > ma_m               # v41.83: 정배열 기준 완화 (5일선 > 20일선)
    partially = (ma_s > ma_m) or (ma_m > ma_l)
    if aligned:
        desc = f"✅ 정배열 ({s}>{m}일)"
    elif partially:
        desc = f"🟡 부분정배열"
    else:
        desc = f"🔵 역배열"
    return {"aligned": aligned, "partial": partially,
            "short": round(ma_s), "mid": round(ma_m), "long": round(ma_l), "desc": desc}
def calc_bollinger(items: list, period: int = None, k: float = 2.0) -> dict:
    """
    볼린저밴드 계산.
    반환: {"upper": int, "mid": int, "lower": int,
           "pct_b": float,  # 현재가가 밴드 내 위치 (0=하단, 1=상단)
           "breakout": bool, "desc": str}
    """
    period = period or int(_dynamic.get("bb_period", 20))
    closes = [i["close"] for i in items if i.get("close")]
    if len(closes) < period:
        return {"upper": 0, "mid": 0, "lower": 0, "pct_b": 0.5, "breakout": False, "desc": "데이터부족"}
    window = closes[-period:]
    mid    = sum(window) / period
    std    = (sum((c - mid) ** 2 for c in window) / period) ** 0.5
    upper  = int(mid + k * std)
    lower  = int(mid - k * std)
    cur    = closes[-1]
    pct_b  = round((cur - lower) / (upper - lower), 2) if upper != lower else 0.5
    breakout = cur >= upper
    if breakout:
        desc = f"🚀 상단 돌파 (밴드폭 {(upper-lower)/mid*100:.1f}%)"
    elif pct_b >= 0.8:
        desc = f"🔥 상단 근접 ({pct_b*100:.0f}%)"
    elif pct_b <= 0.2:
        desc = f"🎯 하단 근접 ({pct_b*100:.0f}%) — 반등 가능"
    else:
        desc = f"밴드 중간 ({pct_b*100:.0f}%)"
    return {"upper": upper, "mid": int(mid), "lower": lower,
            "pct_b": pct_b, "breakout": breakout, "desc": desc}
def calc_indicators(code: str) -> dict:
    """
    RSI + MA + 볼린저밴드 한 번에 계산.
    get_daily_data 캐시 활용 → API 추가 호출 없음.
    반환: {"rsi": float, "ma": dict, "bb": dict, "filter_pass": bool, "score_adj": int, "summary": str}
    """
    try:
        items = get_daily_data(code, 70)
        if len(items) < 20:
            return {"rsi": 50, "ma": {}, "bb": {}, "filter_pass": True, "score_adj": 0, "summary": ""}
        rsi = calc_rsi(items)
        ma  = calc_ma_trend(items)
        bb  = calc_bollinger(items)
        score_adj   = 0
        filter_pass = True
        reasons     = []
        # ── 기능별 가중치 적용 ──
        w_rsi = _dynamic.get("feat_w_rsi", 1.0)
        w_ma  = _dynamic.get("feat_w_ma",  1.0)
        w_bb  = _dynamic.get("feat_w_bb",  1.0)
        # ── RSI 필터 → v38.6: 차단 제거, 감점만 (자금유입 종목을 RSI로 놓치지 않음) ──
        rsi_overbuy  = float(_dynamic.get("rsi_overbuy",  70))
        rsi_oversell = float(_dynamic.get("rsi_oversell", 30))
        if w_rsi > 0:
            if rsi >= rsi_overbuy:
                score_adj   -= int(15 * w_rsi)
                reasons.append(f"⚠️ RSI {rsi:.0f} 과매수 -{int(15*w_rsi)}점 (감점만, 차단X)")
            elif rsi <= rsi_oversell:
                score_adj += int(10 * w_rsi)
                reasons.append(f"🎯 RSI {rsi:.0f} 과매도 +{int(10*w_rsi)}점")
            elif rsi >= 60:
                score_adj += int(5 * w_rsi)
                reasons.append(f"📊 RSI {rsi:.0f} 강세 +{int(5*w_rsi)}점")
        # ── 이동평균 필터 → v38.6: 차단 제거, 감점만 ──
        if w_ma > 0:
            if ma.get("aligned") is False and not ma.get("partial"):
                score_adj -= int(10 * w_ma)
                reasons.append(f"⚠️ {ma.get('desc','역배열')} -{int(10*w_ma)}점 (감점만)")
            elif ma.get("aligned"):
                score_adj += int(10 * w_ma)
                reasons.append(f"✅ {ma.get('desc','정배열')} +{int(10*w_ma)}점")
            elif ma.get("partial"):
                score_adj += int(3 * w_ma)
                reasons.append(f"🟡 부분정배열 +{int(3*w_ma)}점")
        # ── 볼린저밴드 필터 ──
        if w_bb > 0:
            if bb.get("breakout"):
                score_adj += int(15 * w_bb)
                reasons.append(f"🚀 볼린저 상단 돌파 +{int(15*w_bb)}점")
            elif bb.get("pct_b", 0.5) <= 0.2:
                score_adj += int(8 * w_bb)
                reasons.append(f"🎯 볼린저 하단 근접 +{int(8*w_bb)}점")
        summary = "\n".join(reasons) if reasons else ""
        return {"rsi": rsi, "ma": ma, "bb": bb,
                "filter_pass": filter_pass, "score_adj": score_adj, "summary": summary}
    except Exception as e:
        _log_warn_msg(f"  ⚠️ 지표 계산 오류 ({code}): {e}")
        return {"rsi": 50, "ma": {}, "bb": {}, "filter_pass": True, "score_adj": 0, "summary": ""}
# ── 유사 패턴 매칭 (signal_log 기반) ──
def _get_similar_pattern_stats(code: str, signal_type: str, change_rate: float, vol_ratio: float) -> dict:
    """유사패턴 통계 공통 계산 (상세 표시 / 요약 표시 / 내부 점수화 공용)."""
    try:
        data = _load_signal_history()
        completed = _get_completed_signals(data, cohort=BOT_STATS_COHORT)
        if len(completed) < 3:
            return {}
        out = {"same_stock": {}, "similar": {}, "primary": {}}
        same_stock = [v for v in completed if v.get("code") == code]
        if len(same_stock) >= 2:
            s_wins = sum(1 for v in same_stock if v.get("pnl_pct", 0) > 0)
            s_wr = round(s_wins / len(same_stock) * 100)
            s_avg = round(sum(v.get("pnl_pct", 0) for v in same_stock) / len(same_stock), 1)
            s_best = max(same_stock, key=lambda x: x.get("pnl_pct", 0))
            s_worst = min(same_stock, key=lambda x: x.get("pnl_pct", 0))
            out["same_stock"] = {
                "label": "동일 종목",
                "count": len(same_stock),
                "win_rate": s_wr,
                "avg_pnl": s_avg,
                "best_pnl": round(float(s_best.get("pnl_pct", 0) or 0), 1),
                "worst_pnl": round(float(s_worst.get("pnl_pct", 0) or 0), 1),
                "name": same_stock[0].get("name", code),
            }
        same_type = [v for v in completed if v.get("signal_type") == signal_type]
        if len(same_type) >= 3:
            similar = [v for v in same_type
                       if abs(float(v.get("change_at_detect", 0) or 0) - float(change_rate or 0)) <= COMMON_THRESHOLD_3P0
                       and abs(float(v.get("volume_ratio", 0) or 0) - float(vol_ratio or 0)) <= COMMON_THRESHOLD_3P0]
            label = "유사 조건"
            if len(similar) < 2:
                similar = same_type
                label = "동일 신호"
            wins = sum(1 for v in similar if v.get("pnl_pct", 0) > 0)
            win_rate = round(wins / len(similar) * 100)
            avg_pnl = round(sum(v.get("pnl_pct", 0) for v in similar) / len(similar), 1)
            best = max(similar, key=lambda x: x.get("pnl_pct", 0))
            worst = min(similar, key=lambda x: x.get("pnl_pct", 0))
            out["similar"] = {
                "label": label,
                "count": len(similar),
                "win_rate": win_rate,
                "avg_pnl": avg_pnl,
                "best_pnl": round(float(best.get("pnl_pct", 0) or 0), 1),
                "worst_pnl": round(float(worst.get("pnl_pct", 0) or 0), 1),
            }
        out["primary"] = out.get("similar") or out.get("same_stock") or {}
        return out if out.get("primary") else {}
    except Exception as e:
        _swallow_exception(e)  # v105 structured silent-exception log
        return {}
def _build_similar_pattern_summary_block(stats: dict | None, top_exposed: bool = True) -> str:
    stats = dict(stats or {})
    primary = stats.get("primary") or {}
    if not primary:
        return ""
    prefix = "📚 <b>과거 유사패턴</b>" if top_exposed else "📚 유사패턴"
    return (
        f"{prefix}  {primary.get('label','유사 조건')} {int(primary.get('count',0) or 0)}건"
        f"  승률 {int(primary.get('win_rate',0) or 0)}%"
        f"  평균 {float(primary.get('avg_pnl',0.0) or 0.0):+.1f}%"
    )
def _build_similar_pattern_detail_block(stats: dict | None) -> str:
    stats = dict(stats or {})
    if not stats:
        return ""
    lines = []
    same_stock = stats.get("same_stock") or {}
    if same_stock:
        s_wr = int(same_stock.get("win_rate", 0) or 0)
        s_emoji = "🔴" if s_wr >= 60 else ("🟡" if s_wr >= 40 else "🔵")
        lines.append(
            f"  {s_emoji} <b>{same_stock.get('name','')} 전적</b>: {int(same_stock.get('count',0) or 0)}건 "
            f"승률 {s_wr}% 평균 {float(same_stock.get('avg_pnl',0.0) or 0.0):+.1f}%"
            f" (최고 {float(same_stock.get('best_pnl',0.0) or 0.0):+.1f}%)"
        )
    similar = stats.get("similar") or {}
    if similar:
        wr = int(similar.get("win_rate", 0) or 0)
        bar = "🔴" * max(1, wr // 20) if wr > 0 else ""
        lines.append(
            f"  {bar} {similar.get('label','유사 조건')} {int(similar.get('count',0) or 0)}건  승률 {wr}%  평균 {float(similar.get('avg_pnl',0.0) or 0.0):+.1f}%"
            f"\n  최고 {float(similar.get('best_pnl',0.0) or 0.0):+.1f}%  최저 {float(similar.get('worst_pnl',0.0) or 0.0):+.1f}%"
        )
    if not lines:
        return ""
    return "🔍 <b>과거 유사 패턴</b>\n" + "\n".join(lines)
def _apply_similar_pattern_score(score: int, reasons: list, code: str, signal_type: str,
                                 change_rate: float, vol_ratio: float,
                                 weight_mode: str = "strong") -> tuple[int, list, dict]:
    stats = _get_similar_pattern_stats(code, signal_type, change_rate, vol_ratio)
    primary = (stats or {}).get("primary") or {}
    if not primary:
        return score, reasons, {}
    sample = int(primary.get("count", 0) or 0)
    win_rate = float(primary.get("win_rate", 0) or 0)
    avg_pnl = float(primary.get("avg_pnl", 0) or 0)
    adj = 0
    if sample >= 10 and win_rate >= 70 and avg_pnl >= 2.0:
        adj = 6 if weight_mode == "strong" else 4 if weight_mode == "confirm" else 2
    elif sample >= 5 and win_rate >= 60 and avg_pnl >= 0.5:
        adj = 4 if weight_mode == "strong" else 3 if weight_mode == "confirm" else 2
    elif sample >= 5 and (win_rate <= 35 or avg_pnl <= -1.5):
        adj = -6 if weight_mode == "strong" else -4 if weight_mode == "confirm" else -2
    elif sample >= 3 and (win_rate < 45 and avg_pnl < 0):
        adj = -3 if weight_mode == "strong" else -2 if weight_mode == "confirm" else -1
    if adj != 0:
        score += adj
        reasons.append(
            f"📚 유사패턴 학습 보정 {adj:+d}점 "
            f"({primary.get('label','유사 조건')} {sample}건 / 승률 {int(win_rate)}% / 평균 {avg_pnl:+.1f}%)"
        )
    return score, reasons, stats
# ============================================================
# v37.0 — 📊 중앙 이력 조회 시스템 (signal_log 기반)
# 모든 알림/브리핑에서 과거 유사 상황 참조
# ============================================================
_history_cache: dict = {"data": {}, "ts": 0}
def _load_signal_history() -> dict:
    """signal_log.json 캐시 로드 (5분 TTL)"""
    if time.time() - _history_cache["ts"] < 300 and _history_cache["data"]:
        return _history_cache["data"]
    try:
        data = _read_json_locked(SIGNAL_LOG_FILE)
        if isinstance(data, dict):
            _normalize_signal_log_pnl_fields(data)
        _history_cache["data"] = data
        _history_cache["ts"] = time.time()
    except Exception as e:
        _swallow_exception(e)  # v105 structured silent-exception log
        _history_cache["data"] = {}
    return _history_cache["data"]
def _get_completed_signals(data: dict = None, cohort: str | None = BOT_STATS_COHORT) -> list:
    """완료된 신호만 추출 (현재 구조 cohort 기준, net_pnl_pct 우선)"""
    if data is None:
        data = _load_signal_history()
    completed = []
    for v in data.values():
        if not isinstance(v, dict):
            continue
        if cohort is not None and not _record_matches_stats_scope(v, cohort=cohort):
            continue
        if v.get("status") not in ("수익", "손실", "본전"):
            continue
        _sync_record_pnl_fields(v)
        if _effective_pnl_pct(v, 0.0) == 0:
            continue
        completed.append(v)
    return completed
def _format_history_stats(records: list, label: str = "과거 이력") -> str:
    """공통 통계 포맷 (최소 2건 이상)"""
    if len(records) < 2:
        return ""
    total  = len(records)
    wins   = sum(1 for r in records if r["pnl_pct"] > 0)
    avg    = round(sum(r["pnl_pct"] for r in records) / total, 1)
    wr     = round(wins / total * 100)
    emoji  = "🔴" if wr >= 60 else ("🟡" if wr >= 40 else "🔵")
    return f"{emoji} {label}: {total}건 중 {wins}건↑ ({wr}%) 평균{avg:+.1f}%"
def _format_recent_examples(records: list, max_n: int = 3) -> str:
    """최근 사례 포맷"""
    recent = sorted(records, key=lambda x: x.get("detect_date",""), reverse=True)[:max_n]
    parts = []
    for r in recent:
        d = r.get("detect_date", "")
        d_str = f"({d[4:6]}/{d[6:8]})" if d and len(d) == 8 else ""
        parts.append(f"{r.get('name','?')} {r['pnl_pct']:+.1f}%{d_str}")
    return " | ".join(parts) if parts else ""
def _format_capture_datetime_label(detected_at=None, detect_date: str = "", detect_time: str = "") -> str:
    """포착 시각을 사용자 표시용 문자열로 정리한다."""
    try:
        if isinstance(detected_at, datetime):
            return detected_at.strftime("%Y-%m-%d %H:%M:%S")
    except Exception as e:
        _swallow_exception(e)
    d = str(detect_date or "").strip()
    t = str(detect_time or "").strip()
    date_label = ""
    time_label = t
    if d:
        try:
            if len(d) == 8 and d.isdigit():
                date_label = datetime.strptime(d, "%Y%m%d").strftime("%Y-%m-%d")
            else:
                date_label = d
        except Exception as e:
            _swallow_exception(e)  # v105 structured silent-exception log
            date_label = d
    if t:
        try:
            if len(t) >= 8:
                time_label = t[:8]
            elif len(t) >= 5:
                time_label = t[:5]
        except Exception as e:
            _swallow_exception(e)  # v105 structured silent-exception log
            time_label = t
    if date_label and time_label:
        return f"{date_label} {time_label}"
    return date_label or time_label or "-"
def get_stock_track_record(code: str, name: str = "") -> str:
    """
    ① 동일 종목의 과거 신호 전적.
    send_alert / DART / 브리핑에서 사용.
    """
    completed = _get_completed_signals()
    same_stock = [r for r in completed if r.get("code") == code]
    if len(same_stock) < 2:
        return ""
    stats = _format_history_stats(same_stock, f"{name or code} 전적")
    recent = _format_recent_examples(same_stock, 2)
    result = f"  {stats}"
    if recent:
        result += f"\n     {recent}"
    return result
def get_dart_keyword_history(code: str, name: str, keywords: list) -> str:
    """
    ② 같은 종목의 유사 공시 후 결과.
    DART run_dart_intraday에서 사용.
    키워드 매칭 or 동일 종목 전적.
    """
    data = _load_signal_history()
    completed = _get_completed_signals(data)
    if not completed:
        return ""
    # 1순위: 같은 종목의 완료 신호
    same_stock = [r for r in completed if r.get("code") == code]
    # 2순위: 같은 종목 없으면 같은 섹터 + DART 연관 신호
    if len(same_stock) < 2:
        # sector_theme에서 같은 테마 찾기
        dart_kw_set = set(kw for kw in keywords if len(kw) >= 2)
        related = []
        for r in completed:
            theme = r.get("sector_theme", "")
            # 공시 키워드가 feature_flags에 반영됐거나 같은 테마면 매칭
            if dart_kw_set and theme:
                for kw in dart_kw_set:
                    if kw in theme or theme in kw:
                        related.append(r)
                        break
        if len(related) >= 2:
            stats = _format_history_stats(related, "유사 공시 섹터")
            return f"━━━━━━━━━━━━━━━\n📊 {stats}"
    if len(same_stock) < 2:
        return ""
    stats = _format_history_stats(same_stock, f"{name} 과거 공시 반응")
    recent = _format_recent_examples(same_stock, 2)
    result = f"━━━━━━━━━━━━━━━\n📊 {stats}"
    if recent:
        result += f"\n     {recent}"
    return result
def get_regime_history(regime: str) -> str:
    """
    ③ 동일 시장 국면에서의 과거 전체 신호 승률.
    오버나이트 위험 알림 / 장전 브리핑에서 사용.
    """
    completed = _get_completed_signals()
    if len(completed) < 5:
        return ""
    same_regime = [r for r in completed
                   if r.get("feature_flags", {}).get("regime") == regime
                   or r.get("regime") == regime]
    if len(same_regime) < 3:
        return ""
    # v40.0: crash/bear/normal/bull 4단계 통일 (구 명칭 호환 유지)
    regime_label = {
        "crash": "급락장", "bear": "약세장", "normal": "보통장", "bull": "강세장",
        # 하위 호환 (기존 로그)
        "crisis": "급락장", "risk_off": "약세장", "euphoria": "강세장", "panic": "급락장",
    }
    label = regime_label.get(regime, regime)
    return _format_history_stats(same_regime, f"{label} 국면 과거")
def get_weekly_comparison(week_records: list) -> str:
    """
    ④ 이번 주 실적 vs 역대 평균 비교.
    주간 리포트에서 사용.
    """
    completed = _get_completed_signals()
    if len(completed) < 10 or not week_records:
        return ""
    all_wr   = round(sum(1 for r in completed if r["pnl_pct"] > 0) / len(completed) * 100)
    all_avg  = round(sum(r["pnl_pct"] for r in completed) / len(completed), 1)
    w_pnls   = [r["pnl_pct"] for r in week_records]
    w_wr     = round(sum(1 for p in w_pnls if p > 0) / len(w_pnls) * 100)
    w_avg    = round(sum(w_pnls) / len(w_pnls), 1)
    wr_diff  = w_wr - all_wr
    avg_diff = round(w_avg - all_avg, 1)
    wr_icon  = "📈" if wr_diff > 0 else ("📉" if wr_diff < 0 else "➡️")
    avg_icon = "📈" if avg_diff > 0 else ("📉" if avg_diff < 0 else "➡️")
    return (f"\n📊 <b>역대 대비</b>  (전체 {len(completed)}건)\n"
            f"  {wr_icon} 승률: 이번주 {w_wr}% vs 역대 {all_wr}%  ({wr_diff:+d}%p)\n"
            f"  {avg_icon} 수익: 이번주 {w_avg:+.1f}% vs 역대 {all_avg:+.1f}%  ({avg_diff:+.1f}%p)")
def get_overnight_history() -> str:
    """
    ⑤ 오버나이트 보유 후 다음날 결과 통계.
    오버나이트 위험 알림에서 사용.
    """
    completed = _get_completed_signals()
    if len(completed) < 5:
        return ""
    # 장 마감 후 감지된 신호 (14시 이후) 또는 추적 2일 이상
    overnight = []
    for r in completed:
        t = r.get("detect_time", "09:00")
        try:
            if t >= "14:00" or (r.get("exit_date","") > r.get("detect_date","")):
                overnight.append(r)
        except Exception as e:
            _swallow_exception(e)
    if len(overnight) < 3:
        return ""
    return _format_history_stats(overnight, "오버나이트 보유")
# ============================================================
# ⑦ 거래량 5일 평균 대비 정확 계산
# ============================================================
_avg_volume_cache = {}
def get_avg_volume(code: str) -> int:
    cached = _avg_volume_cache.get(code)
    if cached and time.time() - cached["ts"] < 3600:
        return cached["avg_vol"]
    items = get_daily_data(code, 20)
    vols  = [i["vol"] for i in items if i["vol"]]
    avg   = int(sum(vols[-5:]) / len(vols[-5:])) if len(vols) >= 3 else 0
    _avg_volume_cache[code] = {"avg_vol": avg, "ts": time.time()}
    return avg
def get_real_volume_ratio(code: str, today_vol: int) -> float:
    avg = get_avg_volume(code)
    return round(today_vol / avg, 1) if avg and today_vol else 0.0
# ============================================================
# ⑧ ATR 기반 동적 손절·목표가
# ============================================================
def get_atr(code: str) -> float:
    today = datetime.now().strftime("%Y%m%d")
    cached = _atr_cache.get(code)
    if cached and cached.get("date") == today:
        return cached["atr"]
    items = get_daily_data(code, 20)
    trs   = [i["high"] - i["low"] for i in items[-ATR_PERIOD:] if i["high"] and i["low"]]
    atr   = sum(trs) / len(trs) if trs else 0
    _atr_cache[code] = {"atr": atr, "date": today}
    return atr
def get_atr_regime_mult() -> float:
    """
    현재 시장 국면에 따른 ATR 배수 반환.
    트레일링 스탑 / 진입 허용범위 / 재진입 기준 등에 공통 사용.
      bull  → 0.8  (타이트하게 — 수익 빨리 확보)
      normal→ 1.2
      bear  → 1.8  (여유있게 — 노이즈에 안 털림)
      crash → 2.5
    NXT 단독 시간대면 추가 × 1.3 (변동성 높음)
    """
    regime_info = get_market_regime()
    regime      = regime_info.get("mode", "normal")
    nxt_only    = regime_info.get("nxt_only", False)
    base = {"bull": 0.8, "normal": 1.2, "bear": 1.8, "crash": 2.5}.get(regime, 1.2)
    return round(base * (1.3 if nxt_only else 1.0), 2)
def calc_atr_pct(code: str, price: int, fallback_pct: float = 2.0) -> float:
    """
    종목 ATR을 현재가 대비 %로 반환.
    ATR 조회 실패 시 fallback_pct 사용.
    """
    try:
        atr = get_atr(code)
        if atr > 0 and price > 0:
            return round(atr / price * 100, 2)
    except Exception as e:
        _swallow_exception(e)
    return fallback_pct
def calc_trailing_stop(code: str, high_price: int) -> int:
    """
    트레일링 스탑 가격 계산.
    고점 - ATR × 국면배수 (최소 -1.5%, 최대 -8%)
    v41.61 #9: 종목별 ATR 변동성 구간 보정 추가.
      저변동(ATR<1.5%) → 트레일링 타이트 (빠른 익절 보호)
      고변동(ATR>4.0%) → 트레일링 여유 (노이즈 방지)
    """
    try:
        atr  = get_atr(code)
        mult = get_atr_regime_mult()
        if atr > 0:
            # v41.61: 변동성 구간 보정
            atr_pct = atr / high_price * 100 if high_price else COMMON_THRESHOLD_3P0
            if atr_pct < 1.5:
                mult = max(mult * 0.8, 0.6)    # 저변동: 더 타이트
            elif atr_pct > 4.0:
                mult = min(mult * 1.3, 3.5)    # 고변동: 더 여유
            trail_gap = int(atr * mult)
            trail_pct = trail_gap / high_price * 100 if high_price else COMMON_THRESHOLD_3P0
            # 최소 1.5%, 최대 8% 범위 제한
            trail_pct = max(1.5, min(trail_pct, 8.0))
            trail_gap = int(high_price * trail_pct / 100)
            return int((high_price - trail_gap) / 10) * 10
    except Exception as e:
        _swallow_exception(e)
    # fallback: 고점 × 0.97
    return int(high_price * 0.97 / 10) * 10
def calc_reentry_bounce(code: str, price: int) -> float:
    """
    손절 후 재진입 반등 기준 (%) 계산.
    ATR × 0.5 배수 (최소 1.5%, 최대 6.0%)
    """
    atr_pct = calc_atr_pct(code, price, fallback_pct=COMMON_THRESHOLD_3P0)
    mult    = get_atr_regime_mult()
    bounce  = round(atr_pct * mult * 0.5, 1)
    return max(1.5, min(bounce, 6.0))
def calc_surge_escape_pct(code: str, price: int) -> float:
    """
    진입가 상승이탈 판단 기준 (%) — 진입가보다 이 % 이상 오르면 포기.
    ATR × 3배 (최소 8%, 최대 25%)
    v66: 최소 5→8%, 최대 15→25%로 상향. 급등장에서 너무 일찍 상승이탈 판정되어
    기회를 놓치는 현상(와이어블 +20.4%, SK이터닉스 +17.6%) 방지.
    """
    atr_pct = calc_atr_pct(code, price, fallback_pct=COMMON_THRESHOLD_3P0)
    mult    = get_atr_regime_mult()
    escape  = round(atr_pct * mult * COMMON_THRESHOLD_3P0, 1)
    return max(8.0, min(escape, 25.0))
def calc_partial_exit_min_pct(code: str, price: int) -> float:
    """
    분할 청산 트리거 최소 수익률 (%) — 이 이상 수익일 때만 분할 청산 알림.
    ATR × 1배 (최소 1.5%, 최대 5.0%)
    v41.61: 레짐별 배수 적용 — bull이면 일찍 익절, bear/crash면 여유.
    """
    atr_pct = calc_atr_pct(code, price, fallback_pct=2.0)
    base = max(1.5, min(round(atr_pct, 1), 5.0))
    regime_mult = get_regime_partial_exit_mult()
    return max(1.0, min(round(base * regime_mult, 1), 7.0))
def calc_stop_target(code: str, entry: int, signal_type: str | None = None) -> tuple:
    """
    손절/목표가 계산 — v41.61: calc_dynamic_stop_target으로 위임.
    기존 호출부 호환: signal_type 미지정 시 표준 배수 적용.
    반환: (stop, target, stop_pct, target_pct, atr_used)
    """
