def get_stock_price(code: str) -> dict:
    url    = f"{KIS_BASE_URL}/uapi/domestic-stock/v1/quotations/inquire-price"
    params = {"FID_COND_MRKT_DIV_CODE":"J","FID_INPUT_ISCD":code}
    data   = _safe_get(url, "FHKST01010100", params)
    o      = data.get("output", {})
    price  = int(o.get("stck_prpr", 0))
    if not price: return {}
    today_vol = int(o.get("acml_vol", 0))
    mktcap_raw = int(o.get("hts_avls", 0) or 0)  # 시가총액 (억원)
    payload = {
        "code": code, "name": o.get("hts_kor_isnm",""),
        "price": price, "change_rate": float(o.get("prdy_ctrt",0)),
        "volume_ratio": get_real_volume_ratio(code, today_vol),
        "today_vol": today_vol,
        "high": int(o.get("stck_hgpr",0)),
        "low":  int(o.get("stck_lwpr",0)),   # v161.29: 당일 저가 추가
        "open": int(o.get("stck_oprc",0)),
        "upper_price": int(o.get("stck_mxpr",0)),   # v161.29: 상한가 가격 추가
        "lower_price": int(o.get("stck_llam",0)),   # v161.29: 하한가 가격 추가
        "acml_tr_pbmn": int(o.get("acml_tr_pbmn",0)),  # v161.29: 누적 거래대금(원) 추가
        "prdy_vrss_sign": str(o.get("prdy_vrss_sign","3")),  # v161.29: 전일대비부호(1=상한) 추가
        "ask_qty": int(o.get("askp_rsqn1",0)),
        "bid_qty": int(o.get("bidp_rsqn1",0)),
        "ask_price": int(o.get("askp1",0) or 0),
        "bid_price": int(o.get("bidp1",0) or 0),
        "prev_close": int(o.get("stck_sdpr",0)),
        "bstp_code": o.get("bstp_cls_code",""),
        "bstp_name": o.get("bstp_kor_isnm","") or "동일업종",
        "vi_cls_code":  str(o.get("vi_cls_code","") or o.get("vi_yn","") or ""),  # v165.6 [#1]: trht_yn/halt_yn 분리 — VI발동 전용
        "raw_status_code": str(o.get("iscd_stat_cls_code","") or ""),  # v165.1: temp_stop_yn 분리
        "raw_temp_stop":   str(o.get("temp_stop_yn","") or ""),        # v165.1: VI임시정지 별도 필드
        "raw_trht_yn":     str(o.get("trht_yn","") or ""),             # v165.6 [#1]: 거래정지여부 별도 필드
        "raw_halt_yn":     str(o.get("halt_yn","") or ""),             # v165.6 [#1]: halt여부 별도 필드
        "mrkt_alrm_cls_code": str(o.get("mrkt_alrm_cls_code","") or ""),  # v163.2: 투자주의(01)/경고(02)/위험(03)
        "cap_size":  ("large" if mktcap_raw >= 10000   # 1조 이상
                      else "mid" if mktcap_raw >= 1000  # 1000억 이상
                      else "small"),
    }
    try:
        _record_execution_snapshot(code, payload, market="KRX")
    except Exception as e:
        _swallow_exception(e)
    try:
        _remember_public_stock_meta(code, payload.get("name", ""), payload.get("bstp_name", ""))
    except Exception as e:
        _swallow_exception(e)
    return payload
