_nxt_confirmed_codes: set = set()  # v165.27: NXT 실거래 확인 종목 화이트리스트 (volume-rank 누적)
def get_nxt_info(code: str) -> dict:
    """
    NXT 종합 정보 (캐시 5분)
    NXT 비상장 종목은 _nxt_unavailable에 기록 → 당일 재조회 없음
    반환: {price, change_rate, volume_ratio, foreign_net, institution_net,
            vs_krx_pct, vol_surge, inv_bullish, inv_bearish}
    """
    if code in _nxt_unavailable: return {}   # 비상장 종목 빠르게 스킵
    cached = _nxt_cache.get(code)
    if cached and time.time() - cached["ts"] < 300:
        return cached["data"]
    if not is_nxt_open():
        return {}
    try:
        p = get_nxt_stock_price(code)
        if not p:
            _nxt_unavailable.add(code)       # 조회 실패 → 비상장으로 간주
            return {}
        inv = {}
        try: inv = get_nxt_investor_trend(code)
        except Exception as e:
            _swallow_exception(e)
        krx = get_stock_price(code)
        krx_price = krx.get("price", 0)
        vs_krx = round((p["price"] - krx_price) / krx_price * 100, 2) if krx_price else 0
        f_net = inv.get("foreign_net", 0)
        i_net = inv.get("institution_net", 0)
        result = {
            "price":           p["price"],
            "change_rate":     p["change_rate"],
            "volume_ratio":    p["volume_ratio"],
            "foreign_net":     f_net,
            "institution_net": i_net,
            "vs_krx_pct":      vs_krx,
            "vol_surge":       p["volume_ratio"] >= COMMON_THRESHOLD_3P0,
            "inv_bullish":     f_net > 0 and i_net > 0,
            "inv_bearish":     f_net < 0 and i_net < 0,
            "nxt_listed":      True,          # NXT 상장 확인됨
        }
        _nxt_cache[code] = {"data": result, "ts": time.time()}
        return result
    except Exception as e:
        _log_warn_msg(f"⚠️ NXT 정보 오류 ({code}): {e}")
        _nxt_unavailable.add(code)
        return {}
def nxt_score_bonus(code: str) -> tuple:
    """
    NXT 데이터 기반 신호 보정값 반환
    returns: (score_delta, reason_str)
    score_delta > 0 → 강화 / < 0 → 감점
    """
    if not is_nxt_open(): return 0, ""
    nxt = get_nxt_info(code)
    if not nxt: return 0, ""
    delta, reasons = 0, []
    if nxt["inv_bullish"]:
        delta += 15
        reasons.append(_build_nxt_investor_label(nxt))
    elif nxt["foreign_net"] > 0:
        delta += 7
        reasons.append(_build_nxt_investor_label(nxt))
    elif nxt["institution_net"] > 0:
        delta += 5
        reasons.append(_build_nxt_investor_label(nxt))
    if nxt["inv_bearish"]:
        delta -= 15
        reasons.append(_build_nxt_investor_label(nxt))
    elif nxt["foreign_net"] < -3000:
        delta -= 10
        reasons.append("🔵 NXT 수급 약화 (외국인 이탈 확대)")
    if nxt["vol_surge"] and delta > 0:
        delta += 5
        reasons.append(f"🔴 NXT 거래량 급증 ({nxt['volume_ratio']:.1f}배)")
    if nxt["vs_krx_pct"] > 1.0:
        delta += 5
        reasons.append(f"🔴 NXT 프리미엄 +{nxt['vs_krx_pct']:.1f}% (내일 갭상 주목)")
    elif nxt["vs_krx_pct"] < -1.0:
        delta -= 5
        reasons.append(f"🔵 NXT 디스카운트 {nxt['vs_krx_pct']:.1f}%")
    return delta, "\n".join(reasons)
def get_investor_trend(code: str) -> dict:
    data   = _safe_get(f"{KIS_BASE_URL}/uapi/domestic-stock/v1/quotations/inquire-investor",
                       "FHKST01010900", {"FID_COND_MRKT_DIV_CODE":"J","FID_INPUT_ISCD":code})
    output = data.get("output",[])
    if not output: return {}
    return {
        "foreign_net":     safe_int(output[0].get('frgn_ntby_qty', 0)),
        "institution_net": safe_int(output[0].get('orgn_ntby_qty', 0)),
        "retail_net":      safe_int(output[0].get('prsn_ntby_qty', 0)),  # 개인 순매수
    }
def get_investor_provisional_trend(code: str, market: str = "KRX") -> dict:
    """v161.30 ⑤: KIS 기관·외국인 당일 가집계 조회 신규 함수.
    get_investor_trend()가 일별 누계를 반환하는 것과 달리,
    이 함수는 당일 장 중 실시간 잠정 집계(가집계)를 반환한다.
    - KRX: FHKST01010900 (FID_COND_MRKT_DIV_CODE=J), 당일 포함
    - NXT: FHKST01010900 (FID_COND_MRKT_DIV_CODE=NX)
    반환: {
        "foreign_net": 외국인 순매수(주),
        "institution_net": 기관 순매수(주),
        "retail_net": 개인 순매수(주),
        "foreign_net_amount": 외국인 순매수(원),
        "institution_net_amount": 기관 순매수(원),
        "is_provisional": True,   ← 가집계 플래그
        "market": "KRX" or "NXT",
    }
    """
    try:
        _mkt_div = "NX" if str(market or "").upper() == "NXT" else "J"
        data = _safe_get(
            f"{KIS_BASE_URL}/uapi/domestic-stock/v1/quotations/inquire-investor",
            "FHKST01010900",
            {"FID_COND_MRKT_DIV_CODE": _mkt_div, "FID_INPUT_ISCD": code},
        )
        output = data.get("output", [])
        if not output:
            return {"foreign_net": 0, "institution_net": 0, "retail_net": 0,
                    "foreign_net_amount": 0, "institution_net_amount": 0,
                    "is_provisional": True, "market": market}
        row = output[0] if isinstance(output, list) else output
        f_qty  = safe_int(row.get("frgn_ntby_qty",  0))
        i_qty  = safe_int(row.get("orgn_ntby_qty",  0))
        r_qty  = safe_int(row.get("prsn_ntby_qty",  0))
        f_amt  = safe_int(row.get("frgn_ntby_tr_pbmn", 0))  # 외국인 순매수 거래대금(원)
        i_amt  = safe_int(row.get("orgn_ntby_tr_pbmn", 0))  # 기관 순매수 거래대금(원)
        return {
            "foreign_net":             f_qty,
            "institution_net":         i_qty,
            "retail_net":              r_qty,
            "foreign_net_amount":      f_amt,
            "institution_net_amount":  i_amt,
            "is_provisional":          True,
            "market":                  market,
        }
    except Exception as e:
        _swallow_exception(e)
        return {"foreign_net": 0, "institution_net": 0, "retail_net": 0,
                "foreign_net_amount": 0, "institution_net_amount": 0,
                "is_provisional": True, "market": market}


def get_investor_trend_estimate(code: str) -> dict:
    """v166.0: KIS 종목별 외인기관 추정가집계 (investor-trend-estimate).
    tr_id: HHPTJ04160200 (실전 전용, 모의투자 미지원) — v1_국내주식-046
    파라미터: MKSC_SHRN_ISCD (종목코드)
    응답: output2[] — bsop_hour_gb(1~5), frgn_fake_ntby_qty, orgn_fake_ntby_qty, sum_fake_ntby_qty
    시간구분: 1=09:30 / 2=10:00 / 3=11:20 / 4=13:20 / 5=14:30
    최신(가장 큰 bsop_hour_gb) 집계값을 사용.
    실패 시: get_investor_provisional_trend() 폴백
    """
    try:
        data = _safe_get(
            f"{KIS_BASE_URL}/uapi/domestic-stock/v1/quotations/investor-trend-estimate",
            "HHPTJ04160200",
            {"MKSC_SHRN_ISCD": code},
        )
        rows = data.get("output2") or []
        if not rows:
            raise ValueError("empty output2")
        # 가장 최신 집계(bsop_hour_gb 최대값) 사용
        latest = max(rows, key=lambda r: safe_int(r.get("bsop_hour_gb", 0)))
        f_qty = safe_int(latest.get("frgn_fake_ntby_qty", 0))
        i_qty = safe_int(latest.get("orgn_fake_ntby_qty", 0))
        s_qty = safe_int(latest.get("sum_fake_ntby_qty",  0))   # 외인+기관 합산
        return {
            "foreign_net": f_qty,
            "institution_net": i_qty,
            "retail_net": 0,                  # 추정가집계에 개인 항목 없음
            "foreign_net_amount": 0,
            "institution_net_amount": 0,
            "sum_net": s_qty,
            "is_estimate": True,
            "hour_gb": safe_int(latest.get("bsop_hour_gb", 0)),
        }
    except Exception:
        # 폴백: 기존 inquire-investor (일별 누계)
        return get_investor_provisional_trend(code, market="KRX")


def get_program_trade_by_stock(code: str) -> dict:
    """v166.0: KIS 종목별 프로그램매매추이(체결) (program-trade-by-stock).
    tr_id: FHPPG04650101 (실전 전용, 모의투자 미지원) — v1_국내주식-044
           구TR FHPPG04650100은 사전고지 없이 막힐 수 있으므로 신TR 사용
    파라미터: FID_COND_MRKT_DIV_CODE(J/NX/UN), FID_INPUT_ISCD(종목코드)
    응답: output[] — whol_smtn_ntby_qty(전체순매수수량), whol_smtn_ntby_tr_pbmn(거래대금)
    반환: {
        "total_net_buy": 전체 합계 순매수 수량(주),
        "total_net_amount": 전체 합계 순매수 거래대금(원),
        "ok": bool,
    }
    실패 시: all 0 반환
    """
    _empty = {"total_net_buy": 0, "total_net_amount": 0, "ok": False}
    try:
        data = _safe_get(
            f"{KIS_BASE_URL}/uapi/domestic-stock/v1/quotations/program-trade-by-stock",
            "FHPPG04650101",
            {
                "FID_COND_MRKT_DIV_CODE": "J",
                "FID_INPUT_ISCD": code,
            },
        )
        rows = data.get("output") or []
        if not rows:
            return _empty
        # 최신(첫 번째) 행 사용
        row = rows[0] if isinstance(rows, list) else rows
        tot_qty = safe_int(row.get("whol_smtn_ntby_qty",      0))
        tot_amt = safe_int(row.get("whol_smtn_ntby_tr_pbmn",  0))
        return {
            "total_net_buy": tot_qty,
            "total_net_amount": tot_amt,
            "ok": True,
        }
    except Exception as e:
        _swallow_exception(e)
        return _empty


