def _load_sector_stock_base_context(code: str) -> dict:
    data = _safe_get(
        f"{KIS_BASE_URL}/uapi/domestic-stock/v1/quotations/inquire-price",
        "FHKST01010100",
        {"FID_COND_MRKT_DIV_CODE": "J", "FID_INPUT_ISCD": code},
    )
    output = data.get("output", {})
    return {
        "bstp_code": output.get("bstp_cls_code", ""),
        "bstp_name": output.get("bstp_kor_isnm", "") or "동일업종",
    }
def _collect_sector_stock_candidates(code: str) -> dict:
    candidates = {}
    try:
        for item in get_volume_surge_stocks() + get_upper_limit_stocks():
            peer_code = item.get("code")
            if peer_code and peer_code != code:
                candidates[peer_code] = item.get("name", "")
    except Exception as e:
        _swallow_exception(e)
    return candidates
def _collect_same_sector_peers_from_candidates(candidates: dict, bstp_code: str, limit: int = 8) -> list:
    stocks = []
    for peer_code, peer_name in list(candidates.items())[:30]:
        if len(stocks) >= limit:
            break
        try:
            peer_data = _safe_get(
                f"{KIS_BASE_URL}/uapi/domestic-stock/v1/quotations/inquire-price",
                "FHKST01010100",
                {"FID_COND_MRKT_DIV_CODE": "J", "FID_INPUT_ISCD": peer_code},
            )
            peer_bstp = peer_data.get("output", {}).get("bstp_cls_code", "")
            if peer_bstp == bstp_code:
                stocks.append((peer_code, peer_name))
            time.sleep(0.1)
        except Exception as e:
            _swallow_exception(e)
    return stocks
def _collect_same_sector_rank_fallback(code: str, bstp_code: str, stocks: list) -> list:
    if _rank_api_disabled_today():
        return stocks
    try:
        url = f"{KIS_BASE_URL}/uapi/domestic-stock/v1/quotations/chgrate-pcls-100"
        data, status, ct, body = _safe_get_meta(
            url,
            "FHPST01700000",
            {
                "FID_COND_MRKT_DIV_CODE": "J",
                "FID_COND_SCR_DIV_CODE": "20170",
                "FID_INPUT_ISCD": "0000",
                "FID_RANK_SORT_CLS_CODE": "0",
                "FID_INPUT_CNT_1": "50",
                "FID_PRC_CLS_CODE": "0",
                "FID_INPUT_PRICE_1": "500",
                "FID_INPUT_PRICE_2": "",
                "FID_VOL_CNT": "1000",
                "FID_TRGT_CLS_CODE": "0",
                "FID_TRGT_EXLS_CLS_CODE": "0",
                "FID_DIV_CLS_CODE": "0",
                "FID_RSFL_RATE1": "-30",
                "FID_RSFL_RATE2": "30",
            },
        )
        if status == 404:
            _rank_api_fallback("404", status=status, ct=ct, body=body, market="KRX")
            return stocks
        if status not in (None, 200):
            _log_warn_msg(f"⚠️ [KIS] 테마/업종 보강용 chgrate-pcls-100 실패 status={status} ct={ct or '-'} body={str(body)[:120]}")
            return stocks
        for item in data.get("output", []):
            peer_code = item.get("mksc_shrn_iscd", "")
            if not peer_code or peer_code == code:
                continue
            try:
                peer_data = _safe_get(
                    f"{KIS_BASE_URL}/uapi/domestic-stock/v1/quotations/inquire-price",
                    "FHKST01010100",
                    {"FID_COND_MRKT_DIV_CODE": "J", "FID_INPUT_ISCD": peer_code},
                )
                if peer_data.get("output", {}).get("bstp_cls_code", "") == bstp_code:
                    stocks.append((peer_code, item.get("hts_kor_isnm", "")))
                time.sleep(0.1)
            except Exception as e:
                _swallow_exception(e)
            if len(stocks) >= 6:
                break
    except Exception as e:
        _swallow_exception(e)
    return stocks
def get_sector_stocks_from_kis(code: str) -> list:
    """
    동일 업종 종목 조회 (3단계 폴백)
    1순위: 거래량 급증 + 상한가 근접 종목 중 업종코드 직접 매칭
           → 실제 장 중 움직이는 동업종 종목만 추출 (가장 실용적)
    2순위: 등락률 상위 조회 전체에서 업종코드 필터
    3순위: 그래도 없으면 빈 결과 (업종 조회 실패 표시)
    """
    cached = _sector_cache.get(code)
    if cached and time.time() - cached["ts"] < 3600:
        return cached["stocks"]
    try:
        base_ctx = _load_sector_stock_base_context(code)
        bstp_code = base_ctx.get("bstp_code", "")
        bstp_name = base_ctx.get("bstp_name", "동일업종")
        if not bstp_code:
            _sector_cache[code] = {"sector": "업종미상", "stocks": [], "ts": time.time()}
            return []
        candidates = _collect_sector_stock_candidates(code)
        stocks = _collect_same_sector_peers_from_candidates(candidates, bstp_code, limit=8)
        if not stocks:
            stocks = _collect_same_sector_rank_fallback(code, bstp_code, stocks)
        _sector_cache[code] = {"sector": bstp_name, "stocks": stocks, "ts": time.time()}
        _log_info_msg(f"  🏭 [{bstp_name}] 동업종 {len(stocks)}개 조회됨 (업종코드: {bstp_code})")
        return stocks
    except Exception as e:
        _log_warn_msg(f"⚠️ 섹터 조회 오류 ({code}): {e}")
        return []
# ============================================================
# ① 가격 상관관계 기반 동적 테마 탐지
# ============================================================
def calc_price_correlation(code_a: str, code_b: str) -> float:
    """두 종목의 최근 N일 수익률 피어슨 상관계수 계산"""
    try:
        items_a = get_daily_data(code_a, CORR_LOOKBACK + 5)
        items_b = get_daily_data(code_b, CORR_LOOKBACK + 5)
        closes_a = [i["close"] for i in items_a[-CORR_LOOKBACK:] if i["close"]]
        closes_b = [i["close"] for i in items_b[-CORR_LOOKBACK:] if i["close"]]
        n = min(len(closes_a), len(closes_b))
        if n < 10:
            return 0.0
        # 일간 수익률로 변환
        rets_a = [(closes_a[i] - closes_a[i-1]) / closes_a[i-1] for i in range(1, n)]
        rets_b = [(closes_b[i] - closes_b[i-1]) / closes_b[i-1] for i in range(1, n)]
        n2 = len(rets_a)
        mean_a = sum(rets_a) / n2
        mean_b = sum(rets_b) / n2
        cov  = sum((rets_a[i]-mean_a)*(rets_b[i]-mean_b) for i in range(n2)) / n2
        std_a = math.sqrt(sum((r-mean_a)**2 for r in rets_a) / n2)
        std_b = math.sqrt(sum((r-mean_b)**2 for r in rets_b) / n2)
        if std_a == 0 or std_b == 0:
            return 0.0
        return round(cov / (std_a * std_b), 3)
    except Exception as e:
        _swallow_exception(e)  # v105 structured silent-exception log
        return 0.0
def build_correlation_theme(code: str, name: str) -> list:
    """
    급등 종목과 상관관계 높은 종목들을 탐색 → 동적 테마 구성
    거래량 상위 + 상한가 상위에서 후보 선정 → 상관계수 0.7 이상만 채택
    캐시 1시간
    """
    cache_key = f"corr_{code}"
    cached = _sector_cache.get(cache_key)
    if cached and time.time() - cached["ts"] < 3600:
        return cached["peers"]
    try:
        candidates = {}
        for s in (get_volume_surge_stocks() + get_upper_limit_stocks()):
            c = s.get("code","")
            if c and c != code:
                candidates[c] = s.get("name", c)
        # 최대 20개 후보만 계산 (API 부하 방지)
        peers = []
        for peer_code, peer_name in list(candidates.items())[:20]:
            corr = calc_price_correlation(code, peer_code)
            if corr >= CORR_MIN:
                peers.append((peer_code, peer_name, corr))
            time.sleep(0.05)
        peers.sort(key=lambda x: x[2], reverse=True)
        result = [(c, n) for c, n, _ in peers[:6]]
        _sector_cache[cache_key] = {"peers": result, "ts": time.time()}
        if result:
            _log_info_msg(f"  🔗 [{name}] 가격 상관관계 종목 {len(result)}개: {[n for _,n in result]}")
        return result
    except Exception as e:
        _log_warn_msg(f"⚠️ 상관관계 계산 오류 ({code}): {e}")
        return []
# ============================================================
# ② 뉴스 공동언급 기반 테마 자동 확장
# ============================================================
_news_cooccur = {}   # code → {peers: {code: count}, last_headline: str, ts}
def extract_stock_mentions(headlines: list, known_stocks: dict) -> dict:
    """
    뉴스 헤드라인에서 종목명 추출 → 같은 기사에 함께 언급된 종목 쌍 기록
    known_stocks: {code: name}
    """
    cooccur = {}   # code → {peer_code: count}
    for headline in headlines:
        mentioned = [code for code, name in known_stocks.items() if name in headline]
        if len(mentioned) < 2:
            continue
        for i, c1 in enumerate(mentioned):
            for c2 in mentioned[i+1:]:
                cooccur.setdefault(c1, {}).setdefault(c2, 0)
                cooccur[c1][c2] += 1
                cooccur.setdefault(c2, {}).setdefault(c1, 0)
                cooccur[c2][c1] += 1
    return cooccur
def update_news_cooccur(headlines: list):
    """뉴스 공동언급 DB 업데이트 (뉴스 스캔 시마다 호출)"""
    global _news_cooccur
    # 알려진 종목 풀 구성 (THEME_MAP + 동적 후보군)
    known = {}
    for ti in THEME_MAP.values():
        for c, n in ti["stocks"]:
            known[c] = n
    for c, info in dict(_dynamic_candidates).items():
        known[c] = info["name"]
    new_pairs = extract_stock_mentions(headlines, known)
    for code, peers in new_pairs.items():
        if code not in _news_cooccur:
            _news_cooccur[code] = {"peers": {}, "ts": time.time()}
        for peer_code, cnt in peers.items():
            prev = _news_cooccur[code]["peers"].get(peer_code, 0)
            _news_cooccur[code]["peers"][peer_code] = prev + cnt
        _news_cooccur[code]["ts"] = time.time()
    # 파일 저장 (장 마감 후 분석용)
    try:
        _write_json_atomic(NEWS_COOCCUR_FILE, _news_cooccur, indent=2)
    except Exception as e:
        _swallow_exception(e)
def get_news_cooccur_peers(code: str) -> list:
    """뉴스에서 함께 언급된 횟수 상위 종목 반환 [(code, name, count)]"""
    if code not in _news_cooccur:
        return []
    peers_raw = _news_cooccur[code]["peers"]
    # 알려진 종목 이름 역매핑
    name_map = {}
    for ti in THEME_MAP.values():
        for c, n in ti["stocks"]: name_map[c] = n
    for c, info in dict(_dynamic_candidates).items():
        name_map[c] = info["name"]
    result = sorted(
        [(c, name_map.get(c, c), cnt) for c, cnt in peers_raw.items() if cnt >= 2],
        key=lambda x: x[2], reverse=True
    )
    return result[:6]
# ============================================================
# ③ THEME_MAP 자동 업데이트 (급등 감지 시 호출)
# ============================================================
def auto_update_theme(code: str, name: str, trigger: str = "급등"):
    """
    급등/상한가/눌림목 포착 시 해당 종목의 상관관계 종목을 동적 테마로 등록
    trigger: 왜 이 테마가 만들어졌는지 (알림에 표시됨)
    """
    global _dynamic_theme_map
    # 이미 등록된 테마면 스킵
    for tk, ti in _dynamic_theme_map.items():
        if code in [c for c, _ in ti["stocks"]]:
            return
    # 가격 상관관계 + 뉴스 공동언급 통합
    corr_peers  = build_correlation_theme(code, name)        # [(code, name)]
    news_peers_raw = get_news_cooccur_peers(code)            # [(code, name, count)]
    news_peers  = [(c, n) for c, n, _ in news_peers_raw]
    # 합산 (중복 제거)
    seen = set()
    all_peers = []
    for c, n in (corr_peers + news_peers):
        if c not in seen and c != code:
            seen.add(c); all_peers.append((c, n))
    if not all_peers:
        return
    # 이유 설명 생성
    reasons = []
    if corr_peers:
        reasons.append(f"가격 상관관계 {len(corr_peers)}종목")
    if news_peers:
        reasons.append(f"뉴스 공동언급 {len(news_peers)}종목")
    reason_str = " + ".join(reasons)
    theme_key = f"auto_{code}_{datetime.now().strftime('%m%d')}"
    _dynamic_theme_map[theme_key] = {
        "desc":   f"{name} 연관 테마 ({trigger})",
        "reason": reason_str,
        "stocks": [(code, name)] + all_peers,
        "ts":     time.time(),
    }
    _log_info_msg(f"  🆕 동적 테마 생성: [{theme_key}] {name} + {[n for _,n in all_peers]} ({reason_str})")
    # 파일 저장
    try:
        _write_json_atomic(DYNAMIC_THEME_FILE, {k: {**v, "stocks": v["stocks"]} for k,v in _dynamic_theme_map.items()}, indent=2)
    except Exception as e:
        _swallow_exception(e)
def load_dynamic_themes():
    """장 시작 시 동적 테마 파일 복원 — v163.19: 성과 기반 수명 관리"""
    global _dynamic_theme_map, _stock_theme_profile
    try:
        data = _read_json_safe(DYNAMIC_THEME_FILE, {})
        if not isinstance(data, dict):
            data = {}
        now_ts = time.time()
        def _theme_ttl(v: dict) -> float:
            """성과 기반 TTL 계산 (초)"""
            win  = int(v.get("win_count", 0) or 0)
            loss = int(v.get("loss_count", 0) or 0)
            if win >= 1:
                return 86400 * 30   # 수익 발생 → 30일
            if loss > win:
                return 86400 * 7    # 손실 누적 → 7일
            return 86400 * 3        # 미포착 → 3일
        _dynamic_theme_map = {
            k: v for k, v in data.items()
            if now_ts - float(v.get("ts", 0) or 0) < _theme_ttl(v)
        }
        if _dynamic_theme_map:
            _log_info_msg(f"  📂 동적 테마 {len(_dynamic_theme_map)}개 복원")
    except Exception as e:
        _swallow_exception(e)
    # 종목 프로파일 로드 — 영구 보존 (TTL 없음)
    try:
        prof_data = _read_json_safe(STOCK_THEME_PROFILE_FILE, {})
        if isinstance(prof_data, dict):
            _stock_theme_profile = prof_data
            if _stock_theme_profile:
                _log_info_msg(f"  📂 종목 테마 프로파일 {len(_stock_theme_profile)}종목 복원")
    except Exception as e:
        _swallow_exception(e)
# v165.30 [#2]: 섹터 시드 → KIS 동업종 자동 등록

def _auto_register_sector_from_signal(code: str, name: str, change_rate: float = 0.0) -> None:
    """v169.0: 포착 즉시 bstp_code 기반 동업종 자동 섹터 등록.
    SECTOR_SEED_STOCKS 하드코딩 없이 어떤 종목이든 포착 시 자동으로 섹터 시드가 됨.
    이유: 급등 종목이 SECTOR_SEED_STOCKS에 없으면 섹터 시나리오 후보가 대형주로 고정됨.
    동작: bstp_code 조회 → 동업종 중소형주 수집 → _dynamic_theme_map 등록.
    """
    global _dynamic_theme_map
    try:
        if not code:
            return
        today = _now_kst().strftime("%m%d")
        existing_key = f"auto_sector_{code}_{today}"
        if existing_key in _dynamic_theme_map:
            return
        base_ctx = _load_sector_stock_base_context(code)
        bstp_code = base_ctx.get("bstp_code", "")
        bstp_name = base_ctx.get("bstp_name", "")
        if not bstp_code or not bstp_name:
            return
        # 동일 업종코드 오늘 이미 등록됐으면 스킵
        bstp_key = f"auto_sector_bstp_{bstp_code}_{today}"
        if bstp_key in _dynamic_theme_map:
            _dynamic_theme_map[existing_key] = {"ref": bstp_key, "ts": time.time()}
            return
        candidates = _collect_sector_stock_candidates(code)
        peers = _collect_same_sector_peers_from_candidates(candidates, bstp_code, limit=8)
        seed_name = _resolve_stock_name(code, name)
        all_stocks = [(code, seed_name)] + [(c, n) for c, n in peers if c != code]
        if not all_stocks:
            return
        normalized_sector = _normalize_geo_sector_name(bstp_name)
        _dynamic_theme_map[bstp_key] = {
            "desc":        f"[자동감지] {normalized_sector} ({bstp_name})",
            "sectors":     [normalized_sector, bstp_name],
            "events":      [normalized_sector],
            "stocks":      all_stocks[:8],
            "ts":          time.time(),
            "direction":   "up",
            "source":      "auto_capture",
            "bstp_code":   bstp_code,
            "seed_code":   code,
            "seed_name":   seed_name,
            "trigger_chg": round(float(change_rate or 0), 1),
            "win_count":   0,
            "loss_count":  0,
        }
        _dynamic_theme_map[existing_key] = {"ref": bstp_key, "ts": time.time()}
        _log_info_msg(
            f"  🌱 [자동섹터] {normalized_sector}({bstp_code}) 등록: "
            f"{seed_name} +{change_rate:.1f}% → 동업종 {len(all_stocks)}종목"
        )
        try:
            _write_json_atomic(
                DYNAMIC_THEME_FILE,
                {k: {**v, "stocks": v.get("stocks", [])} for k, v in _dynamic_theme_map.items()
                 if isinstance(v, dict) and "ref" not in v},
                indent=2,
            )
        except Exception as _e:
            _swallow_exception(_e)
    except Exception as e:
        _swallow_exception(e)

def _register_sector_seed_stocks() -> None:
    """
    SECTOR_SEED_STOCKS 시드 종목코드 → KIS 동업종 조회 → _dynamic_theme_map 자동 등록.
    09:05 장 시작 직후 실행 — volume surge 풀이 활성화된 시점 활용.
    sectors 필드 포함 등록 → _iter_theme_stock_candidates_by_sector()가 섹터명으로 정확히 매칭.
    파일 저장 → 다음날 07:30 load_dynamic_themes()로 복원.
    """
    global _dynamic_theme_map
    if not SECTOR_SEED_STOCKS:
        return
    today = _now_kst().strftime("%m%d")
    updated = False
    for sector_name, seed_code in SECTOR_SEED_STOCKS.items():
        theme_key = f"sector_seed_{sector_name}_{today}"
        try:
            peers = get_sector_stocks_from_kis(seed_code)
            seed_name = _resolve_stock_name(seed_code, seed_code)
            all_stocks = [(seed_code, seed_name)] + [(c, n) for c, n in peers if c != seed_code]
            if not all_stocks:
                continue
            _dynamic_theme_map[theme_key] = {
                "desc":       f"[섹터시드] {sector_name}",
                "sectors":    [sector_name],
                "events":     [sector_name],
                "stocks":     all_stocks[:8],
                "ts":         time.time(),
                "direction":  "up",
                "source":     "sector_seed",
                "win_count":  0,
                "loss_count": 0,
            }
            _log_info_msg(f"  🌱 섹터시드 등록: [{sector_name}] {len(all_stocks[:8])}종목 (시드: {seed_name})")
            updated = True
        except Exception as e:
            _swallow_exception(e)
    if updated:
        try:
            _write_json_atomic(
                DYNAMIC_THEME_FILE,
                {k: {**v, "stocks": v["stocks"]} for k, v in _dynamic_theme_map.items()},
                indent=2,
            )
        except Exception as e:
            _swallow_exception(e)

# ============================================================
# v41.77 #1: 테마 자동 발굴 엔진
# ============================================================
def _discover_new_theme_from_surge(code: str, name: str, news_titles: list, change_rate: float = 0.0):
    """
    급등 종목 발생 시 뉴스 키워드 추출 → 동일 키워드 종목 동반상승 여부 확인
    → dynamic_themes.json 자동 저장·적용.
    news_titles: 해당 종목 관련 뉴스 헤드라인 리스트
    """
    global _dynamic_theme_map
    try:
        # 1) 뉴스 키워드에서 이벤트 유형 감지
        all_text = " ".join(news_titles).lower()
        detected_events = []
        for event_name, keywords in OVERNIGHT_EVENT_KEYWORDS.items():
            if any(kw.lower() in all_text for kw in keywords):
                detected_events.append(event_name)
        if not detected_events:
            return
        # 2) 이벤트 수혜 섹터 → THEME_MAP 종목에서 동반상승 후보 추출
        sector_candidates = []
        for ev in detected_events:
            for sec in OVERNIGHT_EVENT_SECTOR_MAP.get(ev, []):
                for tk, ti in THEME_MAP.items():
                    if sec in ti.get("sectors", []) or sec.lower() in ti.get("desc", "").lower():
                        for c, n in ti.get("stocks", []):
                            if c != code and (c, n) not in sector_candidates:
                                sector_candidates.append((c, n))
        # 3) 동적 후보군에서도 추가
        for tk, ti in _dynamic_theme_map.items():
            for c, n in ti.get("stocks", []):
                if c != code and (c, n) not in sector_candidates:
                    sector_candidates.append((c, n))
        if not sector_candidates:
            return
        # 4) 이미 오늘 이 종목의 테마가 있으면 강도만 업데이트
        today = datetime.now().strftime("%m%d")
        theme_key = f"auto_{code}_{today}"
        existing = _dynamic_theme_map.get(theme_key)
        if existing:
            # 기존 테마에 이번 이벤트 추가
            existing["events"] = list(set(existing.get("events", []) + detected_events))
            existing["ts"] = time.time()
            existing["change_rate"] = max(existing.get("change_rate", 0), change_rate)
        else:
            _dynamic_theme_map[theme_key] = {
                "desc":        f"{name} 연관 자동발굴 테마",
                "events":      detected_events,
                "reason":      f"뉴스 키워드({', '.join(detected_events)}) 자동 감지",
                "stocks":      [(code, name)] + sector_candidates[:8],
                "ts":          time.time(),
                "change_rate": change_rate,
                "source":      "auto_discover",
            }
            _log_info_msg(f"  🔍 테마 자동발굴: [{theme_key}] {name} | 이벤트={detected_events} | 연관{len(sector_candidates)}종목")
        # 5) 파일 저장
        try:
            _write_json_atomic(DYNAMIC_THEME_FILE, {k: {**v, "stocks": v["stocks"]} for k, v in _dynamic_theme_map.items()}, indent=2)
        except Exception as e:
            _swallow_exception(e)
    except Exception as e:
        _log_warn_msg(f"⚠️ _discover_new_theme_from_surge: {e}")
def _auto_reinforce_dynamic_theme(code: str, pnl_pct: float):
    """
    signal_log 결과 반영 → 동적 테마 강도 자동 조정.
    v163.19: _stock_theme_profile win/loss_count 동시 갱신.
    """
    global _dynamic_theme_map, _stock_theme_profile
    now_ts = time.time()
    try:
        today = datetime.now().strftime("%m%d")
        for tk, ti in _dynamic_theme_map.items():
            if today not in tk:
                continue
            if any(c == code for c, _ in ti.get("stocks", [])):
                prev_adj = ti.get("score_adj", 0)
                if pnl_pct > 0:
                    ti["score_adj"] = min(prev_adj + 3, 15)
                    ti["win_count"] = ti.get("win_count", 0) + 1
                else:
                    ti["score_adj"] = max(prev_adj - 2, -10)
                    ti["loss_count"] = ti.get("loss_count", 0) + 1
                _log_info_msg(f"  📊 테마 강도 조정: [{tk}] score_adj {prev_adj}→{ti['score_adj']} (pnl={pnl_pct:+.1f}%)")
                break
    except Exception as e:
        _log_warn_msg(f"⚠️ _auto_reinforce_dynamic_theme: {e}")
    # v163.19: 종목 프로파일 win/loss 연동
    try:
        prof = _stock_theme_profile.get(code)
        if prof is not None:
            if pnl_pct > 0:
                prof["win_count"] = prof.get("win_count", 0) + 1
            elif pnl_pct < 0:
                prof["loss_count"] = prof.get("loss_count", 0) + 1
            prof["last_active"] = now_ts
            try:
                _write_json_atomic(STOCK_THEME_PROFILE_FILE, _stock_theme_profile, indent=2)
            except Exception as e:
                _swallow_exception(e)
    except Exception as e:
        _swallow_exception(e)
