def _build_overnight_risk_alert_message(limit_items: int | None = None, include_stats: bool = True) -> str:
    try:
        data = _read_json_locked(SIGNAL_LOG_FILE)
    except Exception as e:
        _swallow_exception(e)  # v105 structured silent-exception log
        return ""
    tracking = _get_valid_tracking(data)
    if not tracking:
        return ""
    high_risk = []
    for rec in tracking:
        code = rec.get("code", "")
        name = rec.get("name", "")
        entry = rec.get("entry_price", 0)
        pnl = rec.get("pnl_pct", 0.0)
        risk = calc_overnight_risk(code, name, entry, pnl)
        if risk["level"] in ("high", "mid"):
            high_risk.append((rec, risk))
    if not high_risk:
        return ""
    if limit_items is not None:
        try:
            limit_items = max(1, int(limit_items))
        except Exception as e:
            _swallow_exception(e)  # v105 structured silent-exception log
            limit_items = None
    rows = high_risk if limit_items is None else high_risk[:limit_items]
    msg = "🌙 <b>오버나이트 위험 알림</b>\n━━━━━━━━━━━━━━━\n"
    for rec, risk in rows:
        pnl_str = f"{rec.get('pnl_pct', 0):+.1f}%"
        msg += (f"{'🔵' if risk['level']=='high' else '🟡'} "
                f"<b>{rec['name']}</b>  현재 {pnl_str}\n"
                f"  {risk['reason']}\n")
        for c in risk.get("causes", [])[:2]:
            c_emoji = {"liquidity": "💧", "energy_geo": "🌍", "domestic_trend": "📉"}.get(c["type"], "⚠️")
            msg += f"  {c_emoji} {c['label']}: {c['detail']}\n"
    if include_stats:
        try:
            _on_hist = get_overnight_history()
            if _on_hist:
                msg += f"\n📊 {_on_hist}\n"
            _regime = get_market_regime()
            _r_hist = get_regime_history(_regime)
            if _r_hist:
                msg += f"📊 {_r_hist}\n"
        except Exception as e:
            _swallow_exception(e)
    return msg.rstrip()
def send_overnight_risk_alerts():
    """장 마감 후 추적 중 종목 오버나이트 위험도 알림"""
    try:
        msg = _build_overnight_risk_alert_message()
        if not msg:
            return
        # Save latest overnight risk message (for diagnostics / same-night recall)
        try:
            _write_json_atomic(OVERNIGHT_RISK_LAST_FILE, {
                "ts": _now_kst().isoformat(timespec="seconds"),
                "msg": msg,
            })
        except Exception as e:
            _swallow_exception(e)
        # Quiet night: do not push; only store
        if _is_quiet_night():
            _log_info_msg("💤 야간(20:00~07:30): 오버나이트 위험 알림 저장만 수행")
            return
        send(msg)
    except Exception as e:
        _log_error("send_overnight_risk_alerts", e)
# ============================================================
# 🌙/🌍 장전 버퍼 파일 저장 helpers
# ============================================================
def _default_overnight_active_state(now_dt: datetime | None = None) -> dict:
    now_dt = now_dt or _now_kst()
    return {
        "day_key": now_dt.strftime("%Y-%m-%d"),
        "last_us_regime": "neutral",
        "last_vix": 20.0,
        "alerted_regime": "",
        "summary_lines": [],
        "updated_at": now_dt.strftime("%Y-%m-%d %H:%M:%S"),
    }
def _load_overnight_active_state(now_dt: datetime | None = None) -> dict:
    now_dt = now_dt or _now_kst()
    base = _default_overnight_active_state(now_dt)
    raw = _read_json_safe(OVERNIGHT_ACTIVE_FILE, {})
    if isinstance(raw, dict):
        base.update(raw)
    if str(base.get("day_key") or "") != now_dt.strftime("%Y-%m-%d"):
        base = _default_overnight_active_state(now_dt)
    return base
def _save_overnight_active_state(state: dict):
    payload = _default_overnight_active_state()
    if isinstance(state, dict):
        payload.update(state)
    payload["updated_at"] = _now_kst().strftime("%Y-%m-%d %H:%M:%S")
    _write_json_atomic(OVERNIGHT_ACTIVE_FILE, payload, indent=2)
def _default_geo_active_state(now_dt: datetime | None = None) -> dict:
    now_dt = now_dt or _now_kst()
    return {
        "day_key": now_dt.strftime("%Y-%m-%d"),
        "active": False,
        "uncertainty": "low",
        "sectors": [],
        "sector_directions": [],
        "score_adj": 0,
        "summary": "",
        "entities": [],
        "kws": [],
        "history_lines": [],
        "sector_evidence": {},
        "ts": 0,
        "last_sent_ts": 0,
        "last_sent_msg": "",
        "updated_at": now_dt.strftime("%Y-%m-%d %H:%M:%S"),
    }
def _load_geo_active_state(now_dt: datetime | None = None) -> dict:
    now_dt = now_dt or _now_kst()
    base = _default_geo_active_state(now_dt)
    raw = _read_json_safe(GEO_ACTIVE_FILE, {})
    if isinstance(raw, dict):
        base.update(raw)
    if str(base.get("day_key") or "") != now_dt.strftime("%Y-%m-%d"):
        base = _default_geo_active_state(now_dt)
    return base
def _save_geo_active_state(state: dict):
    payload = _default_geo_active_state()
    if isinstance(state, dict):
        payload.update(state)
    payload["updated_at"] = _now_kst().strftime("%Y-%m-%d %H:%M:%S")
    _write_json_atomic(GEO_ACTIVE_FILE, payload, indent=2)
def _write_preopen_snapshot(prefix: str, payload: dict, now_dt: datetime | None = None):
    now_dt = now_dt or _now_kst()
    _ensure_dir(PREOPEN_SNAPSHOT_DIR)
    day_key = now_dt.strftime("%Y-%m-%d")
    last_path = OVERNIGHT_SNAPSHOT_LAST_FILE if prefix == "overnight" else GEO_SNAPSHOT_LAST_FILE
    dated_path = os.path.join(PREOPEN_SNAPSHOT_DIR, f"{prefix}_{day_key}.json")
    _write_json_atomic(last_path, payload, indent=2)
    _write_json_atomic(dated_path, payload, indent=2)
def _get_effective_geo_state(now_dt: datetime | None = None) -> dict:
    now_dt = now_dt or _now_kst()
    day_key = now_dt.strftime("%Y-%m-%d")
    active = _load_geo_active_state(now_dt)
    if active.get("active") and int(active.get("ts", 0) or 0) > 0:
        return active
    snap = _read_json_safe(GEO_SNAPSHOT_LAST_FILE, {})
    if isinstance(snap, dict) and str(snap.get("day_key") or "") == day_key and snap.get("summary"):
        return snap
    return active if isinstance(active, dict) else {}
def _get_effective_overnight_lines(now_dt: datetime | None = None) -> list:
    now_dt = now_dt or _now_kst()
    day_key = now_dt.strftime("%Y-%m-%d")
    active = _load_overnight_active_state(now_dt)
    lines = active.get("summary_lines") if isinstance(active, dict) else None
    if lines:
        return list(lines)[-10:]
    snap = _read_json_safe(OVERNIGHT_SNAPSHOT_LAST_FILE, {})
    if isinstance(snap, dict) and str(snap.get("day_key") or "") == day_key:
        return list(snap.get("summary_lines") or [])[-10:]
    return []
def _consume_preopen_buffers(now_dt: datetime | None = None):
    now_dt = now_dt or _now_kst()
    ov = _load_overnight_active_state(now_dt)
    geo = _load_geo_active_state(now_dt)
    if (ov.get("summary_lines") or geo.get("active") or geo.get("history_lines")):
        _write_preopen_snapshot("overnight", ov, now_dt)
        _write_preopen_snapshot("geo", geo, now_dt)
    cleared_ov = _default_overnight_active_state(now_dt)
    cleared_geo = _default_geo_active_state(now_dt)
    _save_overnight_active_state(cleared_ov)
    _save_geo_active_state(cleared_geo)
    _overnight_state.update({
        "last_us_regime": cleared_ov["last_us_regime"],
        "last_vix": cleared_ov["last_vix"],
        "alerted_regime": cleared_ov["alerted_regime"],
        "summary_lines": [],
    })
    _geo_event_state.update({
        "active": False,
        "uncertainty": "low",
        "sectors": [],
        "sector_directions": [],
        "score_adj": 0,
        "summary": "",
        "entities": [],
        "kws": [],
        "ts": 0,
    })
# ============================================================
# 🌙 오버나이트 모니터링 (장 마감 후 ~ 장 시작 전)
# ============================================================
_overnight_state: dict = {
    "last_us_regime": "neutral",  # 직전 미국 국면
    "last_vix":        20.0,      # 직전 VIX
    "alerted_regime":  "",        # 이미 알림 보낸 국면
    "summary_lines":   [],        # 오버나이트 요약 (브리핑용)
}
try:
    _ov_boot = _load_overnight_active_state()
    _overnight_state.update({
        "last_us_regime": _ov_boot.get("last_us_regime", "neutral"),
        "last_vix": float(_ov_boot.get("last_vix", 20.0) or 20.0),
        "alerted_regime": _ov_boot.get("alerted_regime", ""),
        "summary_lines": list(_ov_boot.get("summary_lines") or [])[-10:],
    })
except Exception as e:
    _swallow_exception(e)
def _is_overnight_monitor_window(now_dt: datetime) -> bool:
    return (now_dt.time() >= dtime(20, 10)) or (now_dt.time() < dtime(7, 30))
def _sync_overnight_state_from_persisted(persisted: dict) -> None:
    _overnight_state["last_us_regime"] = str(persisted.get("last_us_regime") or _overnight_state.get("last_us_regime", "neutral"))
    _overnight_state["last_vix"] = float(persisted.get("last_vix", _overnight_state.get("last_vix", 20.0)) or 20.0)
    _overnight_state["alerted_regime"] = str(persisted.get("alerted_regime") or _overnight_state.get("alerted_regime", ""))
    _overnight_state["summary_lines"] = list(persisted.get("summary_lines") or _overnight_state.get("summary_lines") or [])[-10:]
def _collect_overnight_market_alerts(us: dict) -> list:
    cur_regime = us.get("us_regime", "neutral")
    cur_vix = us.get("vix", 20.0)
    nasdaq_chg = us.get("nasdaq_chg", 0.0)
    prev_regime = _overnight_state["last_us_regime"]
    prev_vix = _overnight_state["last_vix"]
    regime_rank = {"risk_on": 0, "neutral": 1, "risk_off": 2, "panic": 3}
    cur_rank = regime_rank.get(cur_regime, 1)
    prev_rank = regime_rank.get(prev_regime, 1)
    alerts = []
    if cur_rank > prev_rank and cur_regime != _overnight_state["alerted_regime"]:
        _overnight_state["alerted_regime"] = cur_regime
        regime_label = {"risk_off": "🔵 약세장", "panic": "🔵 급락장"}
        alerts.append(f"⚠️ 미국 시장 국면 악화: {regime_label.get(cur_regime, cur_regime)}\n  나스닥 {nasdaq_chg:+.1f}%  VIX {cur_vix:.0f}")
    elif cur_rank < prev_rank and cur_regime != _overnight_state["alerted_regime"]:
        _overnight_state["alerted_regime"] = cur_regime
        alerts.append(f"✅ 미국 시장 국면 개선: 🔴 강세장 전환\n  나스닥 {nasdaq_chg:+.1f}%  VIX {cur_vix:.0f}")
    if cur_vix >= 30 and prev_vix < 30:
        alerts.append(f"🔵 VIX 공포 구간 진입: {cur_vix:.0f} (이전 {prev_vix:.0f})")
    elif cur_vix >= 25 and prev_vix < 25:
        alerts.append(f"🟡 VIX 불안 구간 진입: {cur_vix:.0f}")
    if nasdaq_chg <= -COMMON_THRESHOLD_3P0 and prev_rank < 3:
        alerts.append(f"🔵 나스닥 급락 {nasdaq_chg:+.1f}% — 내일 갭하락 주의")
    elif nasdaq_chg >= 2.0 and prev_rank > 0:
        alerts.append(f"🔴 나스닥 강세 {nasdaq_chg:+.1f}% — 내일 갭상승 기대")
    _overnight_state["last_us_regime"] = cur_regime
    _overnight_state["last_vix"] = cur_vix
    return alerts
def _append_overnight_summary_lines(now_dt: datetime, alerts: list) -> None:
    ts_str = now_dt.strftime("%H:%M")
    for alert in alerts:
        _overnight_state["summary_lines"].append(f"[{ts_str}] {alert}")
        _overnight_state["summary_lines"] = _overnight_state["summary_lines"][-10:]
def _persist_overnight_monitor_state() -> None:
    _save_overnight_active_state({
        "last_us_regime": _overnight_state.get("last_us_regime", "neutral"),
        "last_vix": _overnight_state.get("last_vix", 20.0),
        "alerted_regime": _overnight_state.get("alerted_regime", ""),
        "summary_lines": list(_overnight_state.get("summary_lines") or [])[-10:],
    })
def _run_overnight_geo_watch(alerts: list) -> None:
    try:
        headlines_by_src = _fetch_multi_source_headlines()
        if not headlines_by_src:
            return
        geo = analyze_geopolitical_event(headlines_by_src)
        if geo.get("detected") and geo.get("uncertainty") in ("high", "mid"):
            alerts.append(f"🌍 지정학 이벤트: {geo.get('summary','')}\n  관련 섹터: {', '.join(geo.get('sectors', []))}")
        all_headlines = [h for hl in headlines_by_src.values() for h in hl]
        if all_headlines:
            detected_events = _extract_overnight_event_keywords(all_headlines)
            if detected_events:
                _build_overnight_watchlist(detected_events)
                _log_info_msg(f"  🌙 overnight→야간 이벤트 {len(detected_events)}건 → 워치리스트 갱신")
    except Exception as e:
        _swallow_exception(e)
def _build_overnight_monitor_message(ts_str: str, alerts: list, gap_signal: str, us: dict) -> str:
    gap_emoji = {"gap_up": "⬆️ 갭상승", "flat": "➡️ 갭 없음", "gap_down": "⬇️ 갭하락"}
    msg = f"🌙 <b>오버나이트 알림</b>  {ts_str}\n━━━━━━━━━━━━━━━\n" + "\n".join(alerts) + f"\n\n내일 갭 예측: {gap_emoji.get(gap_signal, '➡️')}"
    extra = []
    if us.get("gold_chg", 0):
        extra.append(f"금{us.get('gold_chg', 0):+.1f}%")
    if us.get("oil_chg", 0):
        extra.append(f"유가{us.get('oil_chg', 0):+.1f}%")
    if us.get("tnx", 0):
        extra.append(f"10Y{us.get('tnx', 0):.2f}%")
    if us.get("sp500_chg", 0):
        extra.append(f"S&P{us.get('sp500_chg', 0):+.1f}%")
    if extra:
        msg += f"\n📊 {' '.join(extra)}"
    return msg
def _emit_overnight_monitor_logs(now_dt: datetime, alerts: list, us: dict) -> None:
    if not alerts:
        return
    ts_str = now_dt.strftime("%H:%M")
    if not is_holiday():
        _build_overnight_monitor_message(ts_str, alerts, us.get("gap_signal", "flat"), us)
        _log_info_msg("🌙 오버나이트 알림 감지 — 텔레그램 발송 비활성화")
    else:
        _log_info_msg(f"  🌙 오버나이트(대기모드): {len(alerts)}건 — 내부 저장만")
def run_overnight_monitor():
    """
    오버나이트(20:10~07:30) 주기적 실행.
    미국 시장 국면 변화 감지 → 즉시 알림.
    변화 없으면 조용히 넘어감 (스팸 방지).
    """
    try:
        now_dt = _now_kst()
        if not _is_overnight_monitor_window(now_dt):
            return
        _sync_overnight_state_from_persisted(_load_overnight_active_state())
        us = get_us_market_signals()
        collect_market_scenarios_24h(force=False, us=us)
        alerts = _collect_overnight_market_alerts(us)
        _append_overnight_summary_lines(now_dt, alerts)
        _persist_overnight_monitor_state()
        _run_overnight_geo_watch(alerts)
        _emit_overnight_monitor_logs(now_dt, alerts, us)
    except Exception as e:
        _log_error("run_overnight_monitor", e)
def _send_pending_result_reminder():
    """
    장 마감 시 추적 중인 종목 중 오늘 신호이면서 아직 결과 미입력인 것들을
    텔레그램으로 알려줌.
    ※ 입력하지 않으면?
      - 목표가/손절가 도달 시 자동 확정 (계속 감시)
      - TRACK_MAX_DAYS(5일) 경과 시 그날 종가 기준으로 자동 기록
      - NXT 상장 종목은 20:00까지 자동 감시 후 기록
    """
    try:
        data = {}
        try:
            data = _read_json_locked(SIGNAL_LOG_FILE)
        except Exception as e:
            _swallow_exception(e)  # v105 structured silent-exception log
            return
        today   = datetime.now().strftime("%Y%m%d")
        pending = [
            v for v in data.values()
            if v.get("status") == "추적중"
            and not _is_orphan_tracking(v)
            and v.get("detect_date") == today
        ]
        if not pending:
            return
        # NXT 운영 중이면 NXT 마감 후 발송 (20:05), KRX만이면 15:30 후 발송
        # 이 함수는 두 시점 모두에서 호출되므로 중복 방지 플래그 사용
        reminder_key = f"reminder_{today}"
        if reminder_key in _tracking_notified:
            return
        _tracking_notified.add(reminder_key)
        nxt_running = is_nxt_open()
        timing_note = ("📡 NXT 마감(20:00) 후에도 NXT 상장 종목은 자동 감시됩니다."
                       if nxt_running else
                       "💡 내일도 자동 추적됩니다. (최대 5일)")
        msg = (f"✍️ <b>오늘 결과 미입력 종목</b>  ({len(pending)}건)\n"
               f"━━━━━━━━━━━━━━━\n"
               f"실제 매도하셨다면 /result 로 입력해주세요.\n"
               f"입력 안 하셔도 봇이 자동 추적합니다.\n\n")
        sig_labels = {
            "UPPER_LIMIT":"상한가","NEAR_UPPER":"상한가근접","SURGE":"급등",
            "EARLY_DETECT":"조기포착","MID_PULLBACK":"눌림목",
            "ENTRY_POINT":"눌림목","STRONG_BUY":"강력매수",
        }
        for v in pending:
            entry = v.get("entry_price", 0)
            code  = v.get("code", "")
            # NXT 먼저, 없으면 KRX 현재가
            try:
                if is_nxt_open() and is_nxt_listed(code):
                    cur_p = get_nxt_stock_price(code).get("price", 0) or get_stock_price(code).get("price", 0)
                else:
                    cur_p = get_stock_price(code).get("price", 0)
                cur_pnl = round((cur_p - entry) / entry * 100, 1) if entry and cur_p else 0
                pnl_emoji = "🔴" if cur_pnl >= 0 else "🔵"
                cur_str = f"  현재 {cur_p:,}원  {pnl_emoji}{cur_pnl:+.1f}%"
            except Exception as e:
                _swallow_exception(e)  # v105 structured silent-exception log
                cur_str = ""
            sig = sig_labels.get(v.get("signal_type",""), "")
            msg += (f"• <b>{v['name']}</b>  {sig}\n"
                    f"  진입 {entry:,}원  손절 {v.get('stop_price',0):,}  목표 {v.get('target_price',0):,}\n"
                    f"{cur_str}\n"
                    f"  → <code>/result {v['name']} +수익률</code>\n\n")
        msg += f"━━━━━━━━━━━━━━━\n{timing_note}"
        send(msg)
    except Exception as e:
        _log_warn_msg(f"⚠️ 결과 입력 알림 오류: {e}")
def _load_tracking_results_runtime():
    try:
        data = _read_json_locked(SIGNAL_LOG_FILE)
    except Exception as e:
        _swallow_exception(e)  # v105 structured silent-exception log
        return None
    return {
        "data": data if isinstance(data, dict) else {},
        "updated": False,
        "today": datetime.now().strftime("%Y%m%d"),
    }
def _merge_tracking_result_representatives(runtime):
    data = runtime["data"]
    updated = bool(runtime.get("updated"))
    active_codes = []
    for _k, _rec in data.items():
        if not isinstance(_rec, dict):
            continue
        if _rec.get("status") not in TRACK_ACTIVE_STATUSES:
            continue
        _code = normalize_stock_code(_rec.get("code"))
        if _code and _code not in active_codes:
            active_codes.append(_code)
    for _code in active_codes:
        rep_key = _find_representative_tracking_log_key(data, _code)
        if rep_key and _merge_tracking_episode_records(data, _code, rep_key, reason="추적중_대표레코드통합"):
            updated = True
    runtime["updated"] = updated
def _calc_tracking_elapsed_days(detect_date, today):
    try:
        return (datetime.strptime(today, "%Y%m%d") - datetime.strptime(detect_date, "%Y%m%d")).days
    except Exception as e:
        _swallow_exception(e)
        return 0
def _handle_tracking_orphan_record(rec, log_key, today, code):
    entry = rec.get("entry_price", 0)
    stop = rec.get("stop_price", 0)
    target = rec.get("target_price", 0)
    if entry and stop and target:
        return False, False
    detect_date = rec.get("detect_date", today)
    elapsed_orphan = _calc_tracking_elapsed_days(detect_date, today)
    if elapsed_orphan < TRACK_MAX_DAYS:
        return True, False
    rec["status"] = TRACK_TIMEOUT_RESULT
    rec["exit_date"] = today
    rec["exit_reason"] = "고아추적_자동만료"
    rec["pnl_pct"] = 0.0
    _tracking_notified.add(log_key)
    _log_info_msg(
        f"  🗑 고아 추적 자동 만료: {rec.get('name', code)} "
        f"(entry/stop/target 미설정, {elapsed_orphan}일 경과)"
    )
    return True, True
def _get_tracking_runtime_price(code):
    try:
        if is_market_open():
            cur = get_stock_price(code)
            price = cur.get("price", 0)
        elif is_nxt_open():
            nxt_cur = get_nxt_stock_price(code)
            price = nxt_cur.get("price", 0)
            if not price:
                cur = get_stock_price(code)
                price = cur.get("price", 0)
        else:
            return 0
        return price or 0
    except Exception as e:
        _swallow_exception(e)
        return 0
def _refresh_tracking_record_extremes(rec, price):
    rec["max_price"] = max(rec.get("max_price", price), price)
    rec["min_price"] = min(rec.get("min_price", price), price)
def _run_tracking_record_watchdogs(log_key, rec, code, rec_name, price, entry, pnl_now):
    _now_ts = time.time()
    _last_check = _carry_news_watch.get(code, 0)
    if _now_ts - _last_check < TRACK_NEWS_WATCH_INTERVAL_SEC:
        return
    _carry_news_watch[code] = _now_ts
    try:
        _d = check_dart_risk(code)
        if _d["is_risk"]:
            _title = _d['title']
            _allow_external = _should_send_tracking_dart_alert(rec)
            if not _allow_external:
                _log_info_msg(f"  ℹ️ 추적종목 DART위험 내부기록만: {rec_name} — {_title} (actual_entry 미확정)")
            else:
                _dk = f"{log_key}_dart_exit"
                if _dk not in _tracking_notified:
                    _tracking_notified.add(_dk)
                    _HALT_POSITIVE_KEYWORDS = ["계약", "수주", "공급", "납품", "MOU", "협약", "투자", "인수"]
                    _is_halt = "거래정지" in _title or "매매정지" in _title
                    _is_positive_reason = _is_halt and any(kw in _title for kw in _HALT_POSITIVE_KEYWORDS)
                    if _is_positive_reason:
                        _alert_title = "⚠️ <b>[거래정지 — 호재성 공시 사유]</b>"
                        _action_line = "⏸ <b>거래정지 중 — 재개 후 진입 판단</b>\n💡 사유는 호재성이나 재개 전까지 매매 불가"
                    elif _is_halt:
                        _alert_title = "🚨 <b>[거래정지 공시 감지]</b>"
                        _action_line = "⚡ <b>거래정지 — 재개일 확인 필요</b>"
                    else:
                        _alert_title = "🚨 <b>[보유 종목 악재 공시 감지]</b>"
                        _action_line = "⚡ <b>즉시 매도 검토 권장</b>"
                    _msg = (
                        f"{_alert_title}\n"
                        "━━━━━━━━━━━━━━━\n"
                        f"🔵 <b>{rec_name}</b>  <code>{code}</code>\n"
                        "━━━━━━━━━━━━━━━\n"
                        f"📋 공시: {_title}\n"
                        "━━━━━━━━━━━━━━━\n"
                        f"💰 현재가: <b>{price:,}원</b>  ({pnl_now:+.1f}%)\n"
                        "━━━━━━━━━━━━━━━\n"
                        f"{_action_line}\n"
                        f"💡 /result {code} 로 결과 기록"
                    )
                    send_with_chart_buttons(_msg, code, rec_name)
                    _log_warn_msg(f"  🚨 보유종목 공시악재: {rec_name} — {_title}")
    except Exception as _e:
        _log_warn_msg(f"  ⚠️ 보유종목 DART체크오류: {_e}")
    try:
        _articles = fetch_news_for_stock(code, rec_name)
        if _articles:
            _deep = analyze_news_deep(_articles, rec_name, code)
            _nadj = int(_deep.get("score_adj", 0) or 0)
            _verd = _deep.get("verdict", "중립")
            if _nadj <= -40:
                _nk = f"{log_key}_news_exit"
                if _nk not in _tracking_notified:
                    _tracking_notified.add(_nk)
                    _rps = "\n".join(f"  ⚠️ {rp}" for rp in _deep.get("risk_points", [])[:3])
                    _msg2 = (
                        "⚠️ <b>[보유 종목 부정 뉴스 감지]</b>\n"
                        "━━━━━━━━━━━━━━━\n"
                        f"🟡 <b>{rec_name}</b>  <code>{code}</code>\n"
                        "━━━━━━━━━━━━━━━\n"
                        f"📰 뉴스 판단: {_verd}  ({_nadj:+d}점)\n"
                        f"{_rps}\n"
                        "━━━━━━━━━━━━━━━\n"
                        f"💰 현재가: <b>{price:,}원</b>  ({pnl_now:+.1f}%)\n"
                        "━━━━━━━━━━━━━━━\n"
                        "💡 손절가 재확인 후 매도 판단 권장\n"
                        f"/result {code} 로 결과 기록"
                    )
                    send_with_chart_buttons(_msg2, code, rec_name)
                    _log_warn_msg(f"  ⚠️ 보유종목 부정뉴스: {rec_name} 감성점수={_nadj}")
    except Exception as _e:
        _log_warn_msg(f"  ⚠️ 보유종목 뉴스체크오류: {_e}")
def _score_tracking_weakness(rec: dict, code: str, price: int, entry: int) -> dict:
    rec = rec if isinstance(rec, dict) else {}
    score = 0
    reasons: list[str] = []
    max_price = max(safe_int(rec.get("max_price", 0), 0), safe_int(price, 0))
    pullback_pct = round(((max_price - price) / max(max_price, 1)) * 100, 2) if max_price else 0.0
    if pullback_pct >= 3.5:
        score += 25
        reasons.append(f"고점 대비 되밀림 {pullback_pct:.1f}%")
    elif pullback_pct >= 2.2:
        score += 15
        reasons.append(f"고점 대비 되밀림 {pullback_pct:.1f}%")
    exec_m = get_execution_speed_metrics(code, current_price=price) or {}
    exec_score = safe_int(exec_m.get("execution_speed_score", 0), 0)
    detect_exec = safe_int((rec.get("feature_snapshot") or {}).get("execution_speed_score", rec.get("execution_speed_at_detect", 0)), 0)
    if exec_score and exec_score < 42:
        score += 15
        reasons.append(f"체결속도 약화 {exec_score}점")
    if detect_exec and exec_score and (detect_exec - exec_score) >= 15:
        score += 15
        reasons.append(f"체결속도 둔화 {detect_exec}->{exec_score}점")
    try:
        inv = get_investor_trend(code) or {}
        f_net = safe_int(inv.get("foreign_net", 0), 0)
        i_net = safe_int(inv.get("institution_net", 0), 0)
        if f_net < 0 and i_net < 0:
            score += 20
            reasons.append("수급 보조 동반 약화")
        elif f_net < 0 or i_net < 0:
            score += 10
            reasons.append("수급 보조 약화")
    except Exception as e:
        _swallow_exception(e)
    try:
        theme_key = str((rec.get("sector_info") or {}).get("theme", "") or (rec.get("sector_info") or {}).get("theme_key", "")).strip()
        rot = detect_theme_rotation()
        weak_now = {str(k) for k, _v in (rot.get("weak") or [])}
        if theme_key and theme_key in weak_now:
            score += 15
            reasons.append(f"테마 약화 [{theme_key}]")
    except Exception as e:
        _swallow_exception(e)
    try:
        fp = detect_force_pattern(code, rec.get("name", code))
        if fp.get("risk_flag"):
            score += 20
            reasons.append("세력 이탈 패턴 경고")
    except Exception as e:
        _swallow_exception(e)
    timeslot = _get_timeslot(datetime.now().strftime("%H:%M:%S"))
    if timeslot in ("late", "nxt_post_late"):
        score += 10
        reasons.append("후반 시간대 보수 관리")
    return {
        "score": int(score),
        "reasons": reasons[:4],
        "pullback_pct": pullback_pct,
        "exec_score": exec_score,
        "detect_exec": detect_exec,
    }
def _build_tracking_weakness_reason_lines(weakness: dict, max_lines: int = 3) -> str:
    reasons = list((weakness or {}).get("reasons") or [])[:max_lines]
    if not reasons:
        return ""
    return "\n".join(f"  ⚠️ {reason}" for reason in reasons)
def _calc_tightened_trailing_stop(base_stop: int, max_price: int, weakness_score: int) -> int:
    if safe_int(base_stop, 0) <= 0 or safe_int(max_price, 0) <= 0 or weakness_score < TRACKING_WEAKNESS_WARN_SCORE:
        return int(base_stop or 0)
    if weakness_score >= TRACKING_WEAKNESS_HARD_EXIT_SCORE:
        gap_pct = 1.8
    elif weakness_score >= TRACKING_WEAKNESS_PARTIAL_EXIT_SCORE:
        gap_pct = 2.2
    else:
        gap_pct = 2.6
    tightened = int((max_price * (1 - gap_pct / 100)) / 10) * 10
    return max(int(base_stop or 0), tightened)
def _maybe_send_tracking_partial_exit_guide(log_key, rec, code, price, entry, target):
    if not (entry and target and _should_send_partial_exit_guide(rec)):
        return
    pnl_now = (price - entry) / entry * 100
    half_pct = (target - entry) / entry * 100 / 2
    partial_key = f"{log_key}_partial"
    _partial_min = calc_partial_exit_min_pct(code, price)
    weakness = _score_tracking_weakness(rec, code, price, entry)
    weakness_score = int(weakness.get("score", 0) or 0)
    weakness_trigger = weakness_score >= TRACKING_WEAKNESS_PARTIAL_EXIT_SCORE and pnl_now >= max(_partial_min, 1.8)
    half_trigger = pnl_now >= half_pct and half_pct > _partial_min
    if not (
        (half_trigger or weakness_trigger)
        and partial_key not in _tracking_notified
        and (time.time() - _partial_exit_last_ts.get(code, 0) >= PARTIAL_EXIT_GUIDE_COOLDOWN_MIN * 60)
    ):
        return
    _tracking_notified.add(partial_key)
    _partial_exit_last_ts[code] = time.time()
    target_pct = ((target - entry) / entry * 100) if entry else 0
    target_progress_pct = (pnl_now / target_pct * 100) if target_pct else 0
    display_rec = dict(rec)
    display_rec['log_key'] = log_key
    entry_hit_line = _build_entry_hit_line(entry, display_rec, include_hit_price=False, include_hit_time=True)
    weakness_lines = _build_tracking_weakness_reason_lines(weakness)
    if weakness_trigger and not half_trigger:
        title = "💡 <b>[약화 기반 분할 청산]</b>"
        guide_line = f"📌 약화 점수: <b>{weakness_score}점</b> — 목표 절반 전이라도 1차 익절 검토"
        status_line = f"✅ 현재 수익: <b>+{pnl_now:.1f}%</b>  (목표의 {target_progress_pct:.0f}%)"
        tail_line = "💡 힘 약화 구간 — 일부 이익 확보 후 잔량만 보수 추적"
    else:
        title = "💡 <b>[분할 청산 타이밍]</b>"
        guide_line = f"📌 분할 기준: <b>+{half_pct:.1f}% 이상</b> 달성 시 1차 익절 검토"
        status_line = f"✅ 현재 상태: 기준 대비 <b>{pnl_now-half_pct:+.1f}%p</b>"
        tail_line = "💡 절반 익절 후 나머지 홀딩 전략 고려"
    send_with_chart_buttons(
        f"{title}\n"
        f"━━━━━━━━━━━━━━━\n"
        f"🔴 <b>{rec['name']}</b>  <code>{code}</code>\n"
        f"━━━━━━━━━━━━━━━\n"
        f"현재 <b>+{pnl_now:.1f}%</b>  (목표의 {target_progress_pct:.0f}%)\n"
        f"{guide_line}\n"
        f"{status_line}\n"
        f"📍 현재가: <b>{price:,}원</b>\n"
        f"{entry_hit_line}\n"
        f"🏆 목표가: <b>{target:,}원</b>  (+{target_pct:.1f}%)\n"
        f"{weakness_lines}\n"
        f"━━━━━━━━━━━━━━━\n"
        f"{tail_line}",
        code, rec["name"]
    )
    _log_info_msg(f"  💡 분할 청산 가이드: {rec['name']} +{pnl_now:.1f}% / 약화 {weakness_score}점")

def _maybe_warn_force_pattern_exit(code: str, rec_name: str, price: int, pnl_now: float) -> None:
    try:
        fp_key = f"force_warn_{code}"
        if fp_key in _tracking_notified:
            return
        fp = detect_force_pattern(code, rec_name)
        if not fp.get("risk_flag"):
            return
        _tracking_notified.add(fp_key)
        out_patterns = [p for p in fp.get("patterns", []) if p.get("score_adj", 0) < 0]
        out_lines = ""
        for op in out_patterns[:3]:
            ce = {"high": "🔵", "mid": "🟡", "low": ""}.get(op.get("confidence", "low"), "")
            ck = {"high": "신뢰높음", "mid": "참고용"}.get(op.get("confidence", ""), "참고용")
            out_lines += f"  {ce} {op['label']} [{ck}]\n  └ {op['detail']}\n"
        send(
            f"🔵 <b>[수급 이탈 경고]  {rec_name}</b>\n"
            f"━━━━━━━━━━━━━━━\n"
            f"{out_lines}현재가: {price:,}원  ({pnl_now:+.1f}%)\n"
            f"━━━━━━━━━━━━━━━\n"
            f"⚠️ 통계적 패턴 감지 — 확증 아님, 익절/손절 직접 판단 필요"
        )
    except Exception as e:
        _swallow_exception(e)
def _maybe_warn_theme_rotation_exit(rec: dict, code: str, rec_name: str, pnl_now: float) -> None:
    try:
        rot = detect_theme_rotation()
        tkey = (rec.get("sector_info") or {}).get("theme", "") or (rec.get("sector_info") or {}).get("theme_key", "")
        weak_now = [k for k, _v in rot.get("weak", [])]
        warn_key = f"theme_warn_{code}"
        if not tkey or tkey not in weak_now or warn_key in _tracking_notified or pnl_now <= 0:
            return
        _tracking_notified.add(warn_key)
        t_chg = rot.get("themes", {}).get(tkey, 0)
        send_with_chart_buttons(
            f"🔄 <b>[{rec_name}] 테마 약세 전환 경고</b>\n"
            f"  [{tkey}] 현재 {t_chg:+.1f}% — 테마 식는 중\n"
            f"  현재 수익 {pnl_now:+.1f}% — 익절 고려 권장",
            code, rec_name
        )
    except Exception as e:
        _swallow_exception(e)
def _maybe_warn_overnight_risk_exit(code: str, rec_name: str, entry: int, pnl_now: float) -> None:
    try:
        risk_key = f"overnight_risk_{code}"
        if risk_key in _tracking_notified:
            return
        risk = calc_overnight_risk(code, rec_name, entry, pnl_now)
        if risk["level"] != "high":
            return
        _tracking_notified.add(risk_key)
        send_with_chart_buttons(
            f"🔵 <b>[{rec_name}] 오버나이트 위험 긴급 알림</b>\n"
            f"  {risk['reason']}\n"
            f"  현재 {pnl_now:+.1f}% — 마감 전 매도 고려",
            code, rec_name
        )
    except Exception as e:
        _swallow_exception(e)
def _process_tracking_trailing_mode(data, log_key, rec, code, rec_name, price, entry, target, today, pnl_now):
    trailing_key = f"{log_key}_trailing"
    if not rec.get("trailing_active"):
        return False, False
    updated = False
    max_price = max(safe_int(rec.get("max_price", 0), 0), safe_int(price, 0))
    trail_stop = safe_int(rec.get("trailing_stop", target), target)
    weakness = _score_tracking_weakness(rec, code, price, entry)
    weakness_score = int(weakness.get("score", 0) or 0)
    rec["tracking_weakness_score_latest"] = weakness_score
    rec["tracking_weakness_reasons_latest"] = list(weakness.get("reasons") or [])[:4]
    if price > rec.get("max_price", price):
        new_trail = calc_trailing_stop(code, price)
        trail_stop = _calc_tightened_trailing_stop(new_trail, max(price, max_price), weakness_score)
        if trail_stop > safe_int(rec.get("trailing_stop", 0), 0):
            rec["trailing_stop"] = trail_stop
            updated = True
    else:
        tightened = _calc_tightened_trailing_stop(trail_stop, max_price, weakness_score)
        if tightened > trail_stop:
            rec["trailing_stop"] = tightened
            trail_stop = tightened
            updated = True
    _maybe_warn_force_pattern_exit(code, rec_name, price, pnl_now)
    _maybe_warn_theme_rotation_exit(rec, code, rec_name, pnl_now)
    _maybe_warn_overnight_risk_exit(code, rec_name, entry, pnl_now)
    if price > rec.get("trailing_stop", trail_stop):
        return False, updated
    gross_pnl_pct = round((price - entry) / entry * 100, 2) if entry else 0
    net_pnl_pct = _calc_net_pnl_pct(gross_pnl_pct, rec.get("round_trip_cost_pct"))
    rec.update({
        "status": "수익" if net_pnl_pct > 0 else ("손실" if net_pnl_pct < 0 else "본전"),
        "exit_price": price,
        "current_price": price,
        "exit_date": today,
        "exit_time": datetime.now().strftime("%H:%M:%S"),
        "gross_pnl_pct": gross_pnl_pct,
        "net_pnl_pct": net_pnl_pct,
        "round_trip_cost_pct": round(ROUND_TRIP_COST_PCT, 4),
        "pnl_pct": net_pnl_pct,
        "exit_reason": "트레일링스탑",
    })
    _apply_result_labels(rec)
    _tracking_notified.add(log_key)
    _send_tracking_result(rec, log_key=log_key)
    _log_info_msg(f"  📊 트레일링 청산: {rec['name']} {net_pnl_pct:+.1f}%")
    return True, True
def _handle_tracking_target_reached(data, log_key, rec, code, price, entry, target):
    trailing_key = f"{log_key}_trailing"
    if price < target:
        # v165.46 [3]: 2차 목표가 도달 체크 (1차 이미 도달한 경우)
        target2 = safe_int(rec.get("target_price_phase2", 0), 0)
        if rec.get("phase2_confirmed") and target2 > 0 and price >= target2:
            t2_key = f"{log_key}_target2"
            if t2_key not in _tracking_notified:
                _tracking_notified.add(t2_key)
                entry_hit_line = _build_entry_hit_line(entry, rec, include_hit_price=True, include_hit_time=False)
                send_with_chart_buttons(
                    f"🎯🎯 <b>[2차 목표가 도달 → 전량 익절 실행]</b>\n"
                    f"━━━━━━━━━━━━━━━\n"
                    f"🔴 <b>{rec.get('name', code)}</b>  <code>{code}</code>\n"
                    f"{entry_hit_line}\n"
                    f"현재가 <b>{price:,}원</b>  2차목표 {target2:,}원\n"
                    f"━━━━━━━━━━━━━━━\n"
                    f"📤 분할매수 전량 익절 실행\n"
                    f"📐 평균단가: {entry:,}원  |  수익률: <b>{round((price-entry)/entry*100,1):+.1f}%</b>",
                    code, rec.get("name", code)
                )
                _record_partial_exit_in_signal_log(rec, "target2", price, 100.0)
                _log_info_msg(f"  🎯🎯 2차 목표 익절 실행: {rec.get('name', code)} {price:,} / 2차목표 {target2:,}")
            return True, True
        return False, False
    if rec.get("trailing_active"):
        return True, False
    weakness = _score_tracking_weakness(rec, code, price, entry)
    weakness_score = int(weakness.get("score", 0) or 0)
    rec["tracking_weakness_score_latest"] = weakness_score
    rec["tracking_weakness_reasons_latest"] = list(weakness.get("reasons") or [])[:4]
    rec["trailing_active"] = True
    rec["target_hit_price"] = int(price or 0)
    rec["target_hit_time"] = datetime.now().strftime('%Y-%m-%d %H:%M:%S')
    base_trail = calc_trailing_stop(code, price)
    max_price = max(safe_int(rec.get("max_price", 0), 0), safe_int(price, 0))
    rec["trailing_stop"] = _calc_tightened_trailing_stop(base_trail, max_price, weakness_score)
    if not _should_send_trailing_mode_message(dict(rec, log_key=log_key)):
        _tracking_notified.add(f"{trailing_key}_suppressed_no_entry_hit")
        _log_info_msg(f"  🔇 트레일링모드 메시지 억제(도달메타 없음): {rec.get('name', code)} {log_key}")
        return True, True
    display_rec = dict(rec)
    display_rec['log_key'] = log_key
    if not _is_representative_tracking_record(data, log_key, display_rec):
        _tracking_notified.add(f"{trailing_key}_suppressed_non_repr")
        _log_info_msg(f"  🔇 트레일링모드 메시지 억제(대표레코드 아님): {rec.get('name', code)} {log_key}")
        return True, True
    _tracking_notified.add(trailing_key)
    entry_hit_line = _build_entry_hit_line(entry, display_rec, include_hit_price=True, include_hit_time=True)
    weakness_lines = _build_tracking_weakness_reason_lines(weakness)
    # v165.46 [3]: 분할매수 종목은 "1차 목표가 도달 → 일부 매도 고려"로 표시
    is_phase2_confirmed = bool(rec.get("phase2_confirmed"))
    target2 = safe_int(rec.get("target_price_phase2", 0), 0)
    if is_phase2_confirmed and target2 > 0:
        if weakness_score >= TRACKING_WEAKNESS_PARTIAL_EXIT_SCORE:
            title = "🎯 <b>[1차 목표가 도달 → 50% 익절 실행·타이트 트레일링]</b>"
            body = "⚠️ 힘 약화 징후 — 1차 물량 50% 익절 실행, 잔량은 보수적으로 관리"
        else:
            title = "🎯 <b>[1차 목표가 도달 → 50% 익절 실행]</b>"
            body = f"📤 분할매수 1차 익절 실행 (50%)\n🎯 2차 목표: <b>{target2:,}원</b> ({round((target2-entry)/entry*100,1):+.1f}%) 잔량 50% 보유"
        _record_partial_exit_in_signal_log(rec, "target1", price, 50.0)
    elif weakness_score >= TRACKING_WEAKNESS_PARTIAL_EXIT_SCORE:
        title = "🎯 <b>[목표가 도달 → 분할익절 실행·타이트 트레일링]</b>"
        body = "⚠️ 힘 약화 징후 — 분할 익절 실행 후 잔량 보수적 관리"
    else:
        title = "🎯 <b>[목표가 도달 → 보유 유지·트레일링]</b>"
        body = "✅ 지금은 <b>매도 지시가 아니라 보유 유지 구간</b>입니다"
    send_with_chart_buttons(
        f"{title}\n"
        f"━━━━━━━━━━━━━━━\n"
        f"🔴 <b>{rec['name']}</b>  <code>{code}</code>\n"
        f"{entry_hit_line}\n"
        f"현재가 <b>{price:,}원</b>  목표가 {target:,}원\n"
        f"━━━━━━━━━━━━━━━\n"
        f"{body}\n"
        f"📉 현재 트레일링 스탑 <b>{int(rec['trailing_stop']):,}원</b>\n"
        f"{weakness_lines}",
        code, rec["name"]
    )
    return True, True

def _record_partial_exit_in_signal_log(rec: dict, exit_type: str, price: int, pct: float) -> None:
    """v165.47: 분할 매도/손절 이벤트를 signal_log record에 기록.
    exit_type: "target1" | "target2" | "stop_warn"
    pct: 실행된 비중 (50.0 = 50%)
    학습 목적: partial_exit_events가 쌓이면 _finalize_tracking_exit_record()에서 가중 P&L 계산
    """
    if not isinstance(rec, dict):
        return
    events = rec.setdefault("partial_exit_events", [])
    events.append({
        "type": exit_type,
        "price": int(price),
        "pct": float(pct),
        "time": _now_kst().strftime('%Y-%m-%d %H:%M:%S'),
    })
    rec["partial_exit_events"] = events

def _finalize_tracking_exit_record(rec, code, price, entry, exit_reason, today, log_key):
    # v165.47 [3]: 분할매수 종목은 partial_exit_events 기반 가중 P&L 계산
    partial_events = list(rec.get("partial_exit_events") or [])
    if partial_events and rec.get("phase2_confirmed") and entry:
        total_partial_pct = sum(e["pct"] for e in partial_events)
        remaining_pct = max(0.0, 100.0 - total_partial_pct)
        weighted_gross = sum(
            e["pct"] * (e["price"] - entry) / entry * 100
            for e in partial_events if entry
        )
        weighted_gross += remaining_pct * (price - entry) / entry * 100
        gross_pnl_pct = round(weighted_gross / 100, 2)
    else:
        gross_pnl_pct = round((price - entry) / entry * 100, 2) if entry else 0
    net_pnl_pct = _calc_net_pnl_pct(gross_pnl_pct, rec.get("round_trip_cost_pct"))
    status = "수익" if net_pnl_pct > 0 else ("손실" if net_pnl_pct < 0 else "본전")
    rec["status"] = status
    rec["exit_price"] = price
    rec["current_price"] = price
    rec["exit_date"] = today
    rec["exit_time"] = datetime.now().strftime("%H:%M:%S")
    rec["gross_pnl_pct"] = gross_pnl_pct
    rec["net_pnl_pct"] = net_pnl_pct
    rec["round_trip_cost_pct"] = round(ROUND_TRIP_COST_PCT, 4)
    rec["pnl_pct"] = net_pnl_pct
    rec["exit_reason"] = exit_reason
    if ACTUAL_ENTRY_CONFIRM_ENABLED and rec.get("actual_entry") is None and exit_reason != TRACK_TIMEOUT_RESULT:
        _request_actual_entry_confirm(rec)
    _tracking_notified.add(log_key)
    if not is_trade_candidate_name(rec.get("name", "")):
        _log_info_msg(f"  📊 추적 완료(내부): {rec['name']} {net_pnl_pct:+.1f}% ({exit_reason}) [상품→알림생략]")
    else:
        _dup_key = f"result_{code}_{rec.get('detect_date','')}"
        if _dup_key not in _tracking_notified:
            _tracking_notified.add(_dup_key)
            _send_tracking_result(rec, log_key=log_key)
            if os.getenv("STOCK_ALERT_DEBUG_TRACKING"):
                _log_info_msg(f"  📊 추적 완료: {rec['name']} {net_pnl_pct:+.1f}% ({exit_reason}) [이론]")
        else:
            _log_info_msg(f"  📊 추적 완료(중복생략): {rec['name']} {net_pnl_pct:+.1f}%")
    global _consecutive_loss_count, _consecutive_win_count
    if net_pnl_pct <= 0:
        _consecutive_loss_count += 1
        _consecutive_win_count = 0
        if _consecutive_loss_count >= EMERGENCY_TUNE_THRESHOLD:
            _log_warn_msg(f"  🚨 연속 손절 {_consecutive_loss_count}회 → 긴급 튜닝 평가")
            auto_tune(notify=False)
        # v163.13 [#4]: 10연속 손절 → auto_tune "변경없음" 루프 돌파용 강제 min_score 상향
        if _consecutive_loss_count >= 10:
            _old_n = int(_dynamic.get("min_score_normal", 56))
            _old_s = int(_dynamic.get("min_score_strict", 66))
            _new_n = min(_old_n + 5, 80)
            _new_s = min(_old_s + 5, 88)
            if _new_n > _old_n or _new_s > _old_s:
                _dynamic["min_score_normal"] = _new_n
                _dynamic["min_score_strict"] = _new_s
                _log_warn_msg(
                    f"  🛑 연속 손절 {_consecutive_loss_count}회 → 진입 기준 강제 강화: "
                    f"min_score {_old_n}/{_old_s} → {_new_n}/{_new_s} (3시간 후 자동복원)"
                )
                # 3시간 후 복원 예약 (동적 복원 타임스탬프 기록)
                _dynamic["_emergency_score_boost_ts"] = time.time()
                _dynamic["_emergency_score_boost_n"] = _old_n
                _dynamic["_emergency_score_boost_s"] = _old_s
                _save_dynamic_params()  # v165.12: 재시작 후에도 boost_ts 유지되도록 즉시 저장
    else:
        if _consecutive_loss_count >= EMERGENCY_TUNE_THRESHOLD:
            _clear_emergency_tune_state("win_recovered")
        _consecutive_loss_count = 0
        _consecutive_win_count += 1
        if _consecutive_win_count >= WIN_STREAK_THRESHOLD:
            old_n = _dynamic["min_score_normal"]
            old_s = _dynamic["min_score_strict"]
            if old_n > 50:
                _dynamic["min_score_normal"] = max(old_n - 3, 50)
                _dynamic["min_score_strict"] = max(old_s - 3, 60)
                _log_info_msg(
                    f"  🔥 연속 수익 {_consecutive_win_count}회 → 공격 모드: "
                    f"최소점수 {old_n}→{_dynamic['min_score_normal']}"
                )
                try:
                    send(
                        f"🔥 <b>연속 수익 {_consecutive_win_count}회!</b>\n"
                        f"신호 기준 완화: {old_n}→{_dynamic['min_score_normal']}점\n"
                        f"더 많은 신호를 포착합니다"
                    )
                except Exception as e:
                    _swallow_exception(e)
def _process_tracking_result_record(data, today, log_key, rec):
    if rec.get("status") != "추적중" or log_key in _tracking_notified:
        return False
    rec["episode_representative"] = True
    code = rec["code"]
    entry = rec.get("entry_price", 0)
    stop = rec.get("stop_price", 0)
    target = rec.get("target_price", 0)
    rec_name = rec.get("name", code)
    handled_orphan, orphan_updated = _handle_tracking_orphan_record(rec, log_key, today, code)
    if handled_orphan:
        return orphan_updated
    detect_date = rec.get("detect_date", today)
    elapsed_days = _calc_tracking_elapsed_days(detect_date, today)
    price = _get_tracking_runtime_price(code)
    if not price:
        return False
    _refresh_tracking_record_extremes(rec, price)
    pnl_now = round((price - entry) / entry * 100, 2) if entry else 0
    _run_tracking_record_watchdogs(log_key, rec, code, rec_name, price, entry, pnl_now)
    _maybe_send_tracking_partial_exit_guide(log_key, rec, code, price, entry, target)
    handled_trailing, trailing_updated = _process_tracking_trailing_mode(
        data, log_key, rec, code, rec_name, price, entry, target, today, pnl_now
    )
    if handled_trailing:
        return trailing_updated or True
    handled_target, target_updated = _handle_tracking_target_reached(data, log_key, rec, code, price, entry, target)
    if handled_target:
        return target_updated or True
    exit_reason = None
    if price <= stop:
        # v165.46 [4]: 분할매수 종목은 손절도 분할 처리
        # 1차 경고 손절: 손절가 접근 시 "50% 축소 고려" 알람 (전량 손절 전 경고)
        if rec.get("phase2_confirmed"):
            warn_key = f"{log_key}_stop_warn"
            warn_level = int(stop + (entry - stop) * 0.3) if entry > stop else stop
            if price <= warn_level and warn_key not in _tracking_notified:
                _tracking_notified.add(warn_key)
                entry_hit_line = _build_entry_hit_line(entry, rec, include_hit_price=True, include_hit_time=False)
                send_with_chart_buttons(
                    f"⚠️ <b>[손절 경고 — 50% 손절 실행]</b>\n"
                    f"━━━━━━━━━━━━━━━\n"
                    f"🔵 <b>{rec.get('name', code)}</b>  <code>{code}</code>\n"
                    f"{entry_hit_line}\n"
                    f"현재가 <b>{price:,}원</b>  손절가 {stop:,}원\n"
                    f"━━━━━━━━━━━━━━━\n"
                    f"⚠️ 손절가 근접 — <b>50% 손절 실행</b>\n"
                    f"📐 평균단가: {entry:,}원  |  손실률: <b>{round((price-entry)/entry*100,1):+.1f}%</b>\n"
                    f"🔵 손절가({stop:,}) 도달 시 잔량 전량 청산 실행",
                    code, rec.get("name", code)
                )
                _record_partial_exit_in_signal_log(rec, "stop_warn", price, 50.0)
                _log_info_msg(f"  ⚠️ 분할손절 50% 실행: {rec.get('name', code)} {price:,} / 손절 {stop:,}")
                return True  # 경고만 발송, 아직 종료 아님
        exit_reason = "손절가"
    elif elapsed_days >= TRACK_MAX_DAYS and not rec.get("trailing_active"):
        # v165.18 [#4]: 5일 경과 결과는 NXT 마감(20:00) 이후에만 발송
        # 이유: 장중 발송 시 타이밍 부적절 — 종가 기준 결과가 더 정확함
        _now_t = _now_kst().time()
        _after_nxt_close = _now_t >= dtime(20, 0) or _now_t < dtime(7, 0)
        if _after_nxt_close or is_holiday():
            exit_reason = TRACK_TIMEOUT_RESULT
    if not exit_reason:
        return True
    _finalize_tracking_exit_record(rec, code, price, entry, exit_reason, today, log_key)
    return True
def _run_tracking_results_batch(runtime):
    data = runtime["data"]
    updated = bool(runtime.get("updated"))
    today = runtime["today"]
    for log_key, rec in data.items():
        updated = _process_tracking_result_record(data, today, log_key, rec) or updated
    runtime["updated"] = updated
def _persist_tracking_results_runtime(runtime):
    if not runtime or not runtime.get("updated"):
        return
    data = _prune_signal_log(runtime["data"])
    _write_json_atomic(SIGNAL_LOG_FILE, data, indent=2)
    load_tracker_feedback()
def _run_tracking_results_cycle():
    runtime = _load_tracking_results_runtime()
    if not runtime:
        return
    try:
        _merge_tracking_result_representatives(runtime)
        _run_tracking_results_batch(runtime)
        _persist_tracking_results_runtime(runtime)
    except Exception as e:
        _log_error("track_signal_results", e, critical=True)
def track_signal_results():
    """
    추적 중인 모든 신호의 현재가를 조회해서
    ① 목표가 도달 → 수익 확정
    ② 손절가 도달 → 손실 확정
    ③ N일 경과   → 현재가 기준 결과 기록
    결과 확정 시 텔레그램 알림 발송
    """
    _run_tracking_results_cycle()
def _build_tracking_result_header_context(rec: dict) -> dict:
    pnl = rec["pnl_pct"]
    reason = rec["exit_reason"]
    if reason == "목표가":
        emoji, title = "🎯✅", "목표가 달성!"
    elif reason == "손절가":
        emoji, title = "🛡🔵", "손절가 도달"
    elif reason == TRACK_TIMEOUT_RESULT:
        emoji, title = "⏱", f"{TRACK_MAX_DAYS}일 경과 결과"
    else:
        emoji, title = "📊", "결과 확정"
    pnl_emoji = "✅" if pnl > 0 else ("🔵" if pnl < 0 else "➖")
    sig_label = {
        "UPPER_LIMIT": "상한가",
        "NEAR_UPPER": "상한가근접",
        "SURGE": "급등",
        "EARLY_DETECT": "조기포착",
        "MID_PULLBACK": "눌림목",
        "ENTRY_POINT": "눌림목",
        "STRONG_BUY": "강력매수",
    }.get(rec.get("signal_type", ""), rec.get("signal_type", ""))
    entry = rec.get("entry_price", 0)
    min_price = rec.get("min_price", rec["exit_price"])
    mdd = round((min_price - entry) / entry * 100, 1) if entry else 0
    theme_tag = (f"\n🏭 테마: {rec.get('sector_theme', '')} (+{rec.get('sector_bonus', 0)}점)"
                 if rec.get("sector_bonus", 0) > 0 else "\n🔍 단독 상승")
    return {
        "pnl": pnl,
        "reason": reason,
        "emoji": emoji,
        "title": title,
        "pnl_emoji": pnl_emoji,
        "sig_label": sig_label,
        "theme_tag": theme_tag,
        "entry": entry,
        "mdd": mdd,
    }
def _build_tracking_result_cause_block(code: str, reason: str) -> str:
    if reason != "손절가":
        return ""
    causes = []
    try:
        cur = get_stock_price(code)
        price = cur.get("price", 0)
        if price:
            inv = get_investor_trend(code)
            f_net = inv.get("foreign_net", 0)
            i_net = inv.get("institution_net", 0)
            vr = cur.get("volume_ratio", 0)
            if f_net < -5000:
                causes.append("🔵 외국인 대량 이탈")
            elif f_net < 0:
                causes.append("🔵 외국인 이탈")
            if i_net < -3000:
                causes.append("🔵 기관 대량 이탈")
            elif i_net < 0:
                causes.append("🔵 기관 이탈")
            if vr and vr < 0.5:
                causes.append(f"📉 거래량 급감 ({vr:.1f}배 — 매수세 소멸)")
            if vr and vr > 5:
                causes.append(f"🌊 거래량 급증 속 하락 (세력 매도 가능성)")
            if not causes:
                causes.append("⚠️ 특이 원인 미감지 (기술적 손절)")
    except Exception as e:
        _swallow_exception(e)
        causes = ["조회 실패"]
    return (
        "\n━━━━━━━━━━━━━━━\n🔍 <b>손절 원인 분석</b>\n"
        + "\n".join(f"  {c}" for c in causes)
        + "\n\n🚨 <b>포지션 정리 신호</b>\n"
        + "  → 신규 진입 판단이 아닌 보유분 감축/청산 단계\n"
        + "  → 추가매수 금지, 잔여 보유분 즉시 정리 검토\n"
        + "  → 반등 시 재진입은 새로운 포착 신호 기준으로만\n"
    )
def _build_tracking_result_profit_guide(rec: dict, pnl: float, reason: str, entry: int, exit_price: int) -> str:
    target = int(rec.get("target_price", exit_price) or exit_price)
    if not (pnl > 0 and reason == "목표가" and entry and target):
        return ""
    r2 = int(entry + (target - entry) * 1.5)
    return (
        f"\n━━━━━━━━━━━━━━━\n"
        f"💡 <b>추가 보유 고려</b>\n"
        f"  현재 +{pnl:.1f}% 달성\n"
        f"  R2 목표: {r2:,}원  (+{(r2-entry)/entry*100:.1f}%)\n"
        f"  → 절반 익절 후 나머지 홀딩 전략\n"
    )
def _build_tracking_result_message(rec: dict, display_rec: dict, header: dict, cause_block: str, profit_guide: str) -> str:
    entry_hit_line = _build_entry_hit_line(header["entry"], display_rec, include_hit_price=False, include_hit_time=True)
    exit_p = rec["exit_price"]
    max_p = rec.get("max_price", exit_p)
    min_p = rec.get("min_price", exit_p)
    mdd_text = "낙폭 없음 🟢" if header["mdd"] > 0 else f"{header['mdd']:+.1f}%"
    mfe = safe_float(rec.get("mfe_pct", 0.0), 0.0)
    return (
        f"{header['emoji']} <b>[자동 추적 결과]</b>  {header['title']}\n"
        f"━━━━━━━━━━━━━━━\n"
        f"{header['pnl_emoji']} <b>{rec['name']}</b>  <b><code>{rec['code']}</code></b>\n"
        f"━━━━━━━━━━━━━━━\n"
        f"신호: {header['sig_label']}  |  감지: {_format_capture_datetime_label(detect_date=rec.get('detect_date',''), detect_time=rec.get('detect_time',''))}\n"
        f"{header['theme_tag']}\n"
        f"━━━━━━━━━━━━━━━\n"
        f"{entry_hit_line}\n"
        f"청산가:  <b>{exit_p:,}원</b>  ({header['reason']})\n"
        f"현재가:  <b>{rec.get('current_price', exit_p):,}원</b>\n"
        f"최고가:  {max_p:,}원  |  최저가: {min_p:,}원\n"
        f"최대수익: {mfe:+.1f}%\n"
        f"최대낙폭: {mdd_text}\n"
        f"━━━━━━━━━━━━━━━\n"
        f"{header['pnl_emoji']} <b>수익률: {header['pnl']:+.1f}%</b>{cause_block}{profit_guide}"
    )
def _register_tracking_reentry_watch_from_result(rec: dict) -> None:
    if rec.get("exit_reason") != "손절가" or not is_any_market_open():
        return
    code = rec["code"]
    name = rec["name"]
    try:
        if is_market_open():
            cur_price = get_stock_price(code).get("price", 0)
        elif is_nxt_open():
            cur_price = get_nxt_stock_price(code).get("price", 0) or get_stock_price(code).get("price", 0)
        else:
            cur_price = 0
        if not cur_price:
            return
        _reentry_watch[code] = {
            "name": name,
            "stop_price": cur_price,
            "entry": rec.get("entry_price", 0),
            "stop": rec.get("stop_price", 0),
            "target": rec.get("target_price", 0),
            "signal_type": rec.get("signal_type", ""),
            "ts": time.time(),
            "nxt_listed": bool(is_nxt_listed(code)),
            "market_basis": "NXT" if is_nxt_listed(code) else "KRX",
        }
        _save_reentry_watch()
        _log_info_msg(f"  🔄 재진입 감시 등록: {name} ({code}) 손절가 {cur_price:,}")
        # v163.13 [#5]: 손절 완료 종목을 MID_PULLBACK 우선 스캔 풀에 추가
        try:
            _stopped_priority_pool[code] = {
                "name": name,
                "stop_ts": time.time(),
                "orig_entry": rec.get("entry_price", 0),
                "orig_signal_type": rec.get("signal_type", ""),
            }
        except Exception as _spp_e:
            _swallow_exception(_spp_e)
        # v161.11: 손절 완료 종목은 TOP 리스트에서 즉시 제거
        if code in _today_top_signals:
            _today_top_signals.pop(code, None)
            _log_info_msg(f"  ⏭ TOP 리스트 제거: {name} (손절 완료)")
    except Exception as e:
        _swallow_exception(e)
def _send_tracking_result(rec: dict, log_key: str | None = None):
    """결과 확정 텔레그램 알림 + 손절 원인 분석"""
    header = _build_tracking_result_header_context(rec)
    cause_block = _build_tracking_result_cause_block(rec["code"], header["reason"])
    profit_guide = _build_tracking_result_profit_guide(rec, header["pnl"], header["reason"], header["entry"], rec["exit_price"])
    display_rec = dict(rec or {})
    if log_key:
        display_rec["log_key"] = log_key
    send_with_chart_buttons(
        _build_tracking_result_message(rec, display_rec, header, cause_block, profit_guide),
        rec["code"],
        rec["name"],
    )
    _register_tracking_reentry_watch_from_result(rec)
def check_reentry_watch():
    """
    손절 종목 재진입 감시 — 20초마다 run_scan에서 호출
    만료: 장 완전 마감(KRX only→15:30, NXT 상장→20:00) 또는 on_market_close
    조건: 손절가 대비 +3% 반등 + 거래량 1.5배 이상
    """
    if not _reentry_watch: return
    expired = []
    changed = False
    for code, w in list(_reentry_watch.items()):
        # 종목별 실질 마감 판단
        nxt_ok  = is_nxt_open() and is_nxt_listed(code)
        krx_ok  = is_market_open()
        if not krx_ok and not nxt_ok:
            expired.append(code); continue   # 모든 시장 마감 → 만료
        try:
            # KRX 장중이면 KRX 가격, 마감 후면 NXT 가격
            if krx_ok:
                cur   = get_stock_price(code)
                price = cur.get("price", 0)
                vr    = cur.get("volume_ratio", 0)
            else:
                cur   = get_nxt_stock_price(code)
                price = cur.get("price", 0)
                vr    = cur.get("volume_ratio", 0)
                if not price:   # NXT 거래 없으면 스킵 (마감 아님)
                    continue
            if not price: continue
            bounce = (price - w["stop_price"]) / w["stop_price"] * 100
            mkt_tag = " 🟡NXT" if not krx_ok and nxt_ok else ""
            _reentry_min = calc_reentry_bounce(code, price)
            if bounce >= _reentry_min and vr >= REENTRY_VOL_MIN:
                sig_labels = {"UPPER_LIMIT":"상한가","NEAR_UPPER":"상한가근접",
                              "SURGE":"급등","EARLY_DETECT":"조기포착",
                              "MID_PULLBACK":"눌림목","ENTRY_POINT":"눌림목"}
                sig = sig_labels.get(w["signal_type"], w["signal_type"])
                send_with_chart_buttons(
                    f"🔄 <b>[손절 후 재진입 후보{mkt_tag}]</b>\n"
                    f"━━━━━━━━━━━━━━━\n"
                    f"🟡 <b>{w['name']}</b>  <code>{code}</code>\n"
                    f"원신호: {sig}\n"
                    f"━━━━━━━━━━━━━━━\n"
                    f"📍 손절가:  {w['stop_price']:,}원\n"
                    f"📈 현재가:  <b>{price:,}원</b>  (+{bounce:.1f}% 반등)\n"
                    f"🔊 거래량:  {vr:.1f}배 (회복)\n"
                    f"━━━━━━━━━━━━━━━\n"
                    f"ℹ️ 실제 재진입가는 재진입 확정 알림에서만 제공합니다.\n"
                    f"⚠️ 손절 후 재진입 — 물타기 아님, 새 포지션으로 판단",
                    code, w["name"]
                )
                expired.append(code)
                _log_info_msg(f"  🔄 재진입 신호: {w['name']} {price:,} (+{bounce:.1f}%){mkt_tag}")
        except Exception as e:
            _swallow_exception(e)  # v105 structured silent-exception log
            continue
    for code in expired:
        _reentry_watch.pop(code, None)
        changed = True
    if changed:
        _save_reentry_watch()
def save_carry_stocks():
    with _file_lock:  # v38.3-P0-5
        try:
            payload = {}
            for raw_code, info in _detected_stocks.items():
                if not isinstance(info, dict):
                    continue
                code = normalize_stock_code(raw_code or info.get("code"))
                if not code:
                    continue
                snap = {
                    "code": code,
                    "name": info.get("name", code),
                    "high_price": safe_int(info.get("high_price", 0), 0),
                    "entry_price": safe_int(info.get("entry_price", 0), 0),
                    "stop_loss": safe_int(info.get("stop_loss", 0), 0),
                    "target_price": safe_int(info.get("target_price", 0), 0),
                    "detected_at": info.get("detected_at").strftime("%Y%m%d%H%M%S") if isinstance(info.get("detected_at"), datetime) else str(info.get("detected_at", "") or ""),
                    "carry_day": safe_int(info.get("carry_day", 0), 0),
                }
                if not _is_active_carry_snapshot(snap):
                    continue
                payload[code] = snap
            with open(CARRY_FILE, "w", encoding="utf-8", newline="\n") as f:
                json.dump(payload, f, ensure_ascii=False)
        except Exception as e:
            _log_warn_msg(f"⚠️ 이월 저장 실패: {e}")
def _purge_orphan_tracking_bootstrap() -> None:
    try:
        orphan_count = purge_orphan_tracking(notify=True)
        if orphan_count:
            _log_info_msg(f"🗑 봇 시작 시 고아 추적 {orphan_count}건 자동 만료")
    except Exception as exc:
        _log_warn_msg(f"⚠️ 고아 추적 정리 오류: {exc}")
def _restore_carry_snapshot(sig_data: dict) -> None:
    try:
        raw_carry = _read_json_locked(CARRY_FILE)
        data, dropped_codes = _sanitize_carry_snapshot_map(raw_carry, siglog_data=sig_data)
        if dropped_codes or not isinstance(raw_carry, dict) or len(data) != len(raw_carry):
            _write_json_atomic(CARRY_FILE, data)
        if dropped_codes:
            _log_info_msg(f"  🧹 stale carry 정리: {len(dropped_codes)}개 제거")
        for code, info in data.items():
            detected_at = _coerce_kst_datetime(_parse_compact_datetime(info.get("detected_at"))) or _now_kst()
            _detected_stocks[code] = {
                "name": info.get("name", code),
                "high_price": safe_int(info.get("high_price", 0), 0),
                "entry_price": safe_int(info.get("entry_price", 0), 0),
                "stop_loss": safe_int(info.get("stop_loss", 0), 0),
                "target_price": safe_int(info.get("target_price", 0), 0),
                "detected_at": detected_at,
                "carry_day": safe_int(info.get("carry_day", 0), 0),
            }
        if _detected_stocks:
            _log_info_msg(f"📂 이월 종목 {len(_detected_stocks)}개 복원")
    except Exception as e:
        _swallow_exception(e)
def _restore_tracking_from_signal_log(sig_data: dict) -> None:
    try:
        today = datetime.now().strftime("%Y%m%d")
        restored = 0
        for rec in _get_valid_tracking(sig_data):
            code = normalize_stock_code(rec.get("code", ""))
            if rec.get("detect_date") != today or not code or code in _detected_stocks:
                continue
            _detected_stocks[code] = {
                "name": rec["name"],
                "high_price": rec.get("detect_price", 0),
                "entry_price": rec.get("entry_price", 0),
                "stop_loss": rec.get("stop_price", 0),
                "target_price": rec.get("target_price", 0),
                "detected_at": datetime.now(),
                "carry_day": 0,
            }
            restored += 1
        if restored:
            _log_info_msg(f"  📋 signal_log에서 추적 중 종목 {restored}개 추가 복원")
    except Exception as e:
        _swallow_exception(e)
def _notify_carry_restore() -> None:
    if not _detected_stocks:
        return
    send(
        f"🔄 <b>봇 재시작 — 추적 상태 복원</b>\n"
        f"📂 감시 중 종목 {len(_detected_stocks)}개\n"
        + "\n".join([f"• {v['name']} ({k})" for k, v in list(_detected_stocks.items())[:6]])
        + ("\n  ..." if len(_detected_stocks) > 6 else "")
        + "\n\n📡 스캔 재개"
    )
def load_carry_stocks():
    """Railway 재시작 시 추적 상태 전체 복원"""
    _purge_orphan_tracking_bootstrap()
    try:
        sig_data = _read_json_locked(SIGNAL_LOG_FILE)
    except Exception as e:
        _swallow_exception(e)
        sig_data = {}
    _restore_carry_snapshot(sig_data)
    _restore_tracking_from_signal_log(sig_data)
    save_carry_stocks()
    _notify_carry_restore()
    _load_compact_mode()
    _load_runtime_state_bundle()
    _load_entry_watch_active()
    _purge_stale_entry_watch_hits(notify=True)
