def _sector_info_has_meaningful_payload(si: dict | None) -> bool:
    si = si or {}
    summary = str(si.get("summary", "") or "").strip()
    rising = si.get("rising", []) or []
    return bool(summary or rising)
def _clone_alert_snapshot_for_sector_retry(s: dict | None) -> dict:
    if not isinstance(s, dict):
        return {}
    cloned = dict(s)
    if isinstance(cloned.get("reasons"), list):
        cloned["reasons"] = list(cloned["reasons"])
    if isinstance(cloned.get("sector_info"), dict):
        cloned["sector_info"] = dict(cloned["sector_info"])
    if isinstance(cloned.get("position"), dict):
        cloned["position"] = dict(cloned["position"])
    if isinstance(cloned.get("indic"), dict):
        cloned["indic"] = dict(cloned["indic"])
    if isinstance(cloned.get("news_analysis"), dict):
        cloned["news_analysis"] = dict(cloned["news_analysis"])
    if isinstance(cloned.get("news_articles"), list):
        cloned["news_articles"] = [dict(x) if isinstance(x, dict) else x for x in cloned["news_articles"]]
    return cloned
def _needs_sector_resend_for_alert(s: dict | None) -> bool:
    if not isinstance(s, dict):
        return False
    return not _sector_info_has_meaningful_payload(s.get("sector_info") or {})
def _get_live_quote_for_signal(s: dict | None) -> dict:
    if not isinstance(s, dict):
        return {}
    code = str(s.get("code", "") or "").strip()
    if not code:
        return {}
    market = str(s.get("market", "") or "").strip().upper()
    try:
        if market == "NXT" and is_nxt_open():
            return get_nxt_stock_price(code) or get_stock_price(code) or {}
        return get_stock_price(code) or (get_nxt_stock_price(code) if market == "NXT" and is_any_market_open() else {}) or {}
    except Exception as e:
        _swallow_exception(e)  # v105 structured silent-exception log
        return {}
def _get_countertrend_surge_context(code: str) -> dict:
    """장기 하락 추세 속 급등인지 보수적으로 판정."""
    out = {"is_countertrend": False, "ret60": 0.0, "drawdown120": 0.0, "cond_ma": False}
    try:
        items = get_daily_data(code, 130) or []
        if len(items) < 60:
            return out
        closes = [float((it or {}).get("close", 0) or 0) for it in items if float((it or {}).get("close", 0) or 0) > 0]
        if len(closes) < 60:
            return out
        last_close = closes[-1]
        ref60 = closes[-60]
        ret60 = ((last_close / ref60) - 1.0) * 100.0 if ref60 > 0 else 0.0
        last120 = items[-120:] if len(items) >= 120 else items[:]
        highs = [float((it or {}).get("high", 0) or 0) for it in last120 if float((it or {}).get("high", 0) or 0) > 0]
        if not highs:
            highs = [float((it or {}).get("close", 0) or 0) for it in last120 if float((it or {}).get("close", 0) or 0) > 0]
        high120 = max(highs) if highs else last_close
        drawdown120 = ((last_close / high120) - 1.0) * 100.0 if high120 > 0 else 0.0
        ma20 = sum(closes[-20:]) / min(20, len(closes))
        ma60 = sum(closes[-60:]) / min(60, len(closes))
        cond_ma = ma20 < ma60
        flags = 0
        if ret60 <= -15.0:
            flags += 1
        if drawdown120 <= -30.0:
            flags += 1
        if cond_ma:
            flags += 1
        out.update({
            "is_countertrend": flags >= 2,
            "ret60": round(ret60, 1),
            "drawdown120": round(drawdown120, 1),
            "cond_ma": bool(cond_ma),
        })
        return out
    except Exception as e:
        _swallow_exception(e)  # v105 structured silent-exception log
        return out
def _empty_multi_tf_downtrend_context() -> dict:
    return {
        "is_multi_tf_downtrend": False,
        "daily_ret20": 0.0,
        "weekly_ret8": 0.0,
        "daily_ma_down": False,
        "weekly_ma_down": False,
        "daily_lower_high": False,
        "weekly_lower_high": False,
        "daily_flags": 0,
        "weekly_flags": 0,
        "daily_uptrend": False,
        "weekly_uptrend": False,
        "insufficient_daily_data": False,
        "insufficient_weekly_data": False,
    }
def _calc_multi_tf_daily_context(items: list[dict]) -> dict:
    closes = [float((it or {}).get("close", 0) or 0) for it in items]
    highs = [float((it or {}).get("high", 0) or 0) for it in items]
    last_close = closes[-1]
    ref20 = closes[-20] if len(closes) >= 20 else closes[0]
    daily_ret20 = ((last_close / ref20) - 1.0) * 100.0 if ref20 > 0 else 0.0
    ma20 = sum(closes[-20:]) / min(20, len(closes))
    ma60 = sum(closes[-60:]) / min(60, len(closes))
    daily_ma_down = ma20 < ma60
    recent_high10 = max(highs[-10:]) if len(highs) >= 10 else max(highs)
    prev_high10 = max(highs[-20:-10]) if len(highs) >= 20 else recent_high10
    daily_lower_high = bool(prev_high10 > 0 and recent_high10 <= prev_high10 * 0.985)
    daily_flags = int(daily_ret20 <= -10.0) + int(daily_ma_down) + int(daily_lower_high)
    return {
        "daily_ret20": daily_ret20,
        "daily_ma_down": daily_ma_down,
        "daily_lower_high": daily_lower_high,
        "daily_flags": daily_flags,
        "daily_uptrend": bool(daily_ret20 > 0 and not daily_ma_down and not daily_lower_high),
    }
def _calc_multi_tf_weekly_context(items: list[dict]) -> dict:
    out = {
        "weekly_ret8": 0.0,
        "weekly_ma_down": False,
        "weekly_lower_high": False,
        "weekly_flags": 0,
        "weekly_uptrend": False,
        "insufficient_weekly_data": False,
    }
    if len(items) < 40:
        out["insufficient_weekly_data"] = True
        return out
    last40 = items[-40:]
    weekly_chunks = [last40[i:i+5] for i in range(0, len(last40), 5) if len(last40[i:i+5]) >= 5]
    if len(weekly_chunks) < 8:
        out["insufficient_weekly_data"] = True
        return out
    week_closes = [float(chunk[-1].get("close", 0) or 0) for chunk in weekly_chunks]
    week_highs = [max(float((row or {}).get("high", 0) or 0) for row in chunk) for chunk in weekly_chunks]
    week_last = week_closes[-1]
    week_ref = week_closes[0]
    weekly_ret8 = ((week_last / week_ref) - 1.0) * 100.0 if week_ref > 0 else 0.0
    ma4w = sum(week_closes[-4:]) / 4.0
    ma8w = sum(week_closes[-8:]) / 8.0
    weekly_ma_down = ma4w < ma8w
    recent_high4 = max(week_highs[-4:])
    prev_high4 = max(week_highs[-8:-4])
    weekly_lower_high = bool(prev_high4 > 0 and recent_high4 <= prev_high4 * 0.985)
    weekly_flags = int(weekly_ret8 <= -15.0) + int(weekly_ma_down) + int(weekly_lower_high)
    out.update({
        "weekly_ret8": weekly_ret8,
        "weekly_ma_down": weekly_ma_down,
        "weekly_lower_high": weekly_lower_high,
        "weekly_flags": weekly_flags,
        "weekly_uptrend": bool(weekly_ret8 > 0 and not weekly_ma_down and not weekly_lower_high),
    })
    return out
def _judge_multi_tf_downtrend(daily: dict, weekly: dict) -> bool:
    severe_daily_down = bool(daily["daily_ret20"] <= -15.0 and daily["daily_ma_down"] and daily["daily_lower_high"])
    severe_weekly_down = bool(weekly["weekly_ret8"] <= -18.0 and weekly["weekly_ma_down"] and weekly["weekly_lower_high"])
    if weekly.get("insufficient_weekly_data"):
        return bool(
            severe_daily_down
            or (daily["daily_flags"] >= 2 and daily["daily_ret20"] <= -4.0)
            or (daily["daily_ma_down"] and daily["daily_lower_high"] and daily["daily_ret20"] <= -2.0)
        )
    clear_daily_down = bool(daily["daily_flags"] >= 2 and daily["daily_ret20"] <= -COMMON_THRESHOLD_3P0)
    clear_weekly_down = bool(weekly["weekly_flags"] >= 2 and weekly["weekly_ret8"] <= -COMMON_THRESHOLD_3P0)
    aligned_ma_down = bool(daily["daily_ma_down"] and weekly["weekly_ma_down"] and (daily["daily_ret20"] <= -COMMON_THRESHOLD_3P0 or weekly["weekly_ret8"] <= -6.0))
    aligned_lower_high = bool(daily["daily_lower_high"] and weekly["weekly_lower_high"] and (daily["daily_ret20"] <= -COMMON_THRESHOLD_3P0 or weekly["weekly_ret8"] <= -6.0))
    non_uptrend_cascade = bool(
        not daily.get("daily_uptrend")
        and not weekly.get("weekly_uptrend")
        and (daily["daily_flags"] + weekly["weekly_flags"] >= 4)
        and (daily["daily_ret20"] <= -4.0 or weekly["weekly_ret8"] <= -6.0)
    )
    return bool(
        (clear_daily_down and clear_weekly_down)
        or severe_daily_down
        or severe_weekly_down
        or aligned_ma_down
        or aligned_lower_high
        or non_uptrend_cascade
    )
def _get_multi_tf_downtrend_context(code: str) -> dict:
    """일·주봉 하향/비상승 구조는 기본 차단하고, 추세전환 토큰이 강할 때만 예외를 허용하도록 다중 추세를 판정."""
    out = _empty_multi_tf_downtrend_context()
    try:
        items = get_daily_data(code, 90) or []
        items = [it for it in items if float((it or {}).get("close", 0) or 0) > 0]
        if len(items) < 20:
            out.update({"insufficient_daily_data": True, "insufficient_weekly_data": True})
            return out
        daily = _calc_multi_tf_daily_context(items)
        weekly = _calc_multi_tf_weekly_context(items)
        out.update(daily)
        out.update(weekly)
        out["insufficient_daily_data"] = False
        out["is_multi_tf_downtrend"] = bool(_judge_multi_tf_downtrend(daily, weekly))
        out["daily_ret20"] = round(float(out.get("daily_ret20", 0.0) or 0.0), 1)
        out["weekly_ret8"] = round(float(out.get("weekly_ret8", 0.0) or 0.0), 1)
    except Exception as e:
        _swallow_exception(e)
        return out
    return out
def _count_intraday_leader_follow_confirmations(signal_meta: dict | None = None) -> int:
    meta = signal_meta if isinstance(signal_meta, dict) else {}
    hits = 0
    if bool(meta.get("direct_news_hit")):
        hits += 1
    if bool(meta.get("resurge_mode")):
        hits += 1
    if bool(meta.get("is_intraday")):
        hits += 1
    if safe_float(meta.get("vol_ratio", 0.0), 0.0) >= 2.0:
        hits += 1
    if safe_float(meta.get("rs", 0.0), 0.0) >= RS_MIN:
        hits += 1
    if safe_float(meta.get("vol_zscore", 0.0), 0.0) >= VOL_ZSCORE_MIN:
        hits += 1
    if bool(meta.get("vol_recovered")):
        hits += 1
    if bool(meta.get("is_bullish")):
        hits += 1
    if bool(meta.get("turnaround_confirmed")):
        hits += 1
    sector_info = meta.get("sector_info") if isinstance(meta.get("sector_info"), dict) else {}
    if int(sector_info.get("bonus", 0) or 0) >= 3:
        hits += 1
    return hits
def _count_multi_tf_reversal_tokens(signal_meta: dict | None = None) -> int:
    meta = signal_meta if isinstance(signal_meta, dict) else {}
    reasons = " ".join(str(x) for x in list(meta.get("reasons") or []))
    sector_info = meta.get("sector_info") if isinstance(meta.get("sector_info"), dict) else {}
    theme = str(sector_info.get("theme", "") or "")
    sector_bonus = int(sector_info.get("bonus", 0) or 0)
    hits = 0
    if bool(meta.get("direct_news_hit")):
        hits += 2
    if bool(meta.get("quiet_absorption")) or "조용한 선매집" in reasons:
        hits += 1
    if bool(meta.get("resurge_mode")) or bool(meta.get("crossday_episode_active")) or bool(meta.get("crossday_episode_confirmed")):
        hits += 1
    if bool(meta.get("turnaround_confirmed")):
        hits += 1
    if bool(meta.get("recent_high_breakout")) or bool(meta.get("orb_breakout")) or bool(meta.get("breakout_to_surge")):
        hits += 1
    if sector_bonus >= 8 and theme not in ("", "기타업종"):
        hits += 1
    if safe_float(meta.get("vol_ratio", 0.0), 0.0) >= 2.2 and safe_float(meta.get("change_rate", 0.0), 0.0) >= 4.0:
        hits += 1
    return hits

def _has_early_non_news_reversal_support(signal_meta: dict | None = None) -> bool:
    meta = signal_meta if isinstance(signal_meta, dict) else {}
    reasons = " ".join(str(x) for x in list(meta.get("reasons") or []))
    crossday_reclaim = safe_float(meta.get("crossday_episode_reclaim_ratio", 0.0), 0.0)
    return bool(
        meta.get("quiet_absorption")
        or "조용한 선매집" in reasons
        or meta.get("turnaround_confirmed")
        or meta.get("resurge_mode")
        or meta.get("crossday_episode_confirmed")
        or (meta.get("crossday_episode_active") and crossday_reclaim >= 0.35)
    )

def _calc_sector_breadth_strength(sector_info: dict | None = None, leader_change_hint: float = 0.0) -> dict:
    sector_info = sector_info if isinstance(sector_info, dict) else {}
    theme = str(sector_info.get("theme", "") or sector_info.get("theme_key", "") or "")
    bonus = int(sector_info.get("bonus", 0) or 0)
    rising = [r for r in list(sector_info.get("rising") or []) if isinstance(r, dict)]
    leader = sector_info.get("leader") if isinstance(sector_info.get("leader"), dict) else {}
    leader_change = max(
        safe_float(leader.get("cr", 0.0), 0.0),
        safe_float(leader.get("change_rate", 0.0), 0.0),
        safe_float(leader_change_hint, 0.0),
    )
    react_cnt = len(rising)
    has_theme = theme not in ("", "기타업종", "unknown", "미분류")
    return {"theme": theme, "bonus": bonus, "react_cnt": react_cnt, "leader_change": round(leader_change, 2), "has_theme": has_theme}

def _evaluate_early_sector_breadth_gate(signal_meta: dict | None = None) -> dict:
    meta = signal_meta if isinstance(signal_meta, dict) else {}
    market = str(meta.get("market", "") or "").upper()
    direct_like = bool(meta.get("direct_news_hit"))
    score = safe_int(meta.get("score", 0), 0)
    breadth = _calc_sector_breadth_strength(meta.get("sector_info"), leader_change_hint=safe_float(meta.get("leader_change", 0.0), 0.0))
    out = {"allow": True, "hard_block": False, "external_delay": False, "reason": "", "breadth": breadth}
    if not breadth.get("has_theme") or (breadth.get("bonus", 0) <= 0 and not direct_like):
        return out
    if _has_early_non_news_reversal_support(meta):
        return out
    min_leader = EARLY_NXT_SECTOR_LEADER_MIN_CHANGE if market == "NXT" else EARLY_SECTOR_LEADER_MIN_CHANGE
    breadth_ok = bool(breadth.get("react_cnt", 0) >= EARLY_SECTOR_REACT_MIN_COUNT and safe_float(breadth.get("leader_change", 0.0), 0.0) >= min_leader)
    if breadth_ok:
        return out
    react_cnt = int(breadth.get("react_cnt", 0) or 0)
    leader_change = safe_float(breadth.get("leader_change", 0.0), 0.0)
    label = f"섹터 breadth 미확인 ({react_cnt}/{EARLY_SECTOR_REACT_MIN_COUNT}, 대장 {leader_change:+.1f}%)"
    if market == "NXT" and (direct_like or breadth.get("bonus", 0) >= 5 or react_cnt == 0):
        return {**out, "allow": False, "hard_block": True, "reason": label, "breadth": breadth}
    if direct_like and score < EARLY_NXT_NO_BREADTH_SCORE_MIN:
        return {**out, "allow": False, "hard_block": True, "reason": label, "breadth": breadth}
    return {**out, "external_delay": True, "reason": label, "breadth": breadth}

def _should_override_multi_tf_downtrend_block(signal_type: str, signal_meta: dict | None = None, ctx: dict | None = None) -> tuple[bool, str]:
    sig = str(signal_type or "").upper()
    meta = signal_meta if isinstance(signal_meta, dict) else {}
    ctx = ctx if isinstance(ctx, dict) else {}
    if sig in {"MID_PULLBACK", "ENTRY_POINT"}:
        if _should_bypass_mid_pullback_downtrend_block(sig, signal_meta=meta, ctx=ctx):
            return True, "leader_followup"
        return False, ""
    if sig not in {"EARLY_DETECT", "SURGE", "NEAR_UPPER", "STRONG_BUY", "DART_EVENT", "DART_BUYBACK_CANCEL"}:
        return False, ""
    total_flags = safe_int(ctx.get("daily_flags", 0), 0) + safe_int(ctx.get("weekly_flags", 0), 0)
    daily_ret20 = safe_float(ctx.get("daily_ret20", 0.0), 0.0)
    weekly_ret8 = safe_float(ctx.get("weekly_ret8", 0.0), 0.0)
    if daily_ret20 <= -20.0 or weekly_ret8 <= -26.0 or total_flags >= 6:
        return False, ""
    reversal_hits = _count_multi_tf_reversal_tokens(meta)
    direct_like = bool(meta.get("direct_news_hit"))
    quiet_like = bool(meta.get("quiet_absorption")) or "조용한 선매집" in " ".join(str(x) for x in list(meta.get("reasons") or []))
    breakout_like = bool(meta.get("recent_high_breakout")) or bool(meta.get("orb_breakout")) or bool(meta.get("breakout_to_surge"))
    if reversal_hits < 3:
        return False, ""
    if not (direct_like or quiet_like or breakout_like or bool(meta.get("resurge_mode")) or bool(meta.get("crossday_episode_confirmed"))):
        return False, ""
    if safe_int(meta.get("score", 0), 0) < max(74, INTRADAY_CAPTURE_RELAX_SCORE):
        return False, ""
    if safe_float(meta.get("change_rate", 0.0), 0.0) < 3.5 and not (direct_like or quiet_like):
        return False, ""
    if safe_float(meta.get("vol_ratio", 0.0), 0.0) < 1.8 and not (direct_like or quiet_like):
        return False, ""
    return True, "trend_reclaim"

def _should_bypass_mid_pullback_downtrend_block(signal_type: str, signal_meta: dict | None = None, ctx: dict | None = None) -> bool:
    sig = str(signal_type or "").upper()
    if sig not in {"MID_PULLBACK", "ENTRY_POINT"}:
        return False
    st = _get_intraday_capture_mode()
    if not _intraday_capture_mode_active(st):
        return False
    meta = signal_meta if isinstance(signal_meta, dict) else {}
    ctx = ctx if isinstance(ctx, dict) else {}
    score = safe_int(meta.get("score", 0), 0)
    change_rate = safe_float(meta.get("change_rate", 0.0), 0.0)
    daily_ret20 = safe_float(ctx.get("daily_ret20", 0.0), 0.0)
    weekly_ret8 = safe_float(ctx.get("weekly_ret8", 0.0), 0.0)
    total_flags = safe_int(ctx.get("daily_flags", 0), 0) + safe_int(ctx.get("weekly_flags", 0), 0)
    confirms = _count_intraday_leader_follow_confirmations(meta)
    if score < INTRADAY_CAPTURE_RELAX_SCORE:
        return False
    if change_rate < COMMON_THRESHOLD_3P0:
        return False
    if confirms < 2:
        return False
    if daily_ret20 <= -28.0 or weekly_ret8 <= -35.0:
        return False
    if total_flags >= 6:
        return False
    return True
def _should_block_multi_tf_downtrend_capture(code: str, signal_type: str, signal_meta: dict | None = None) -> dict:
    block_types = {"UPPER_LIMIT", "NEAR_UPPER", "SURGE", "EARLY_DETECT", "STRONG_BUY", "MID_PULLBACK", "ENTRY_POINT", "DART_EVENT", "DART_BUYBACK_CANCEL"}
    ctx = _get_multi_tf_downtrend_context(code)
    if signal_type not in block_types:
        return {"block": False, "context": ctx, "reason": ""}
    if not ctx.get("is_multi_tf_downtrend"):
        return {"block": False, "context": ctx, "reason": ""}
    override_ok, override_label = _should_override_multi_tf_downtrend_block(signal_type, signal_meta=signal_meta, ctx=ctx)
    if override_ok:
        return {"block": False, "context": ctx, "reason": "", "override": override_label}
    reason = (
        f"주봉·일봉 하향 추세 차단 "
        f"(20일 {ctx.get('daily_ret20', 0):+.1f}% / 8주 {ctx.get('weekly_ret8', 0):+.1f}% / "
        f"일봉UP {int(bool(ctx.get('daily_uptrend')))} / 주봉UP {int(bool(ctx.get('weekly_uptrend')))} / "
        f"일봉{'↓' if ctx.get('daily_ma_down') else '-'}·주봉{'↓' if ctx.get('weekly_ma_down') else '-'} / "
        f"일LH {int(bool(ctx.get('daily_lower_high')))} / 주LH {int(bool(ctx.get('weekly_lower_high')))} )"
    )
    return {"block": True, "context": ctx, "reason": reason}
def _signal_age_minutes_for_retry(s: dict | None) -> int:
    if not isinstance(s, dict):
        return 10**9
    detected_at = s.get("detected_at")
    if isinstance(detected_at, datetime):
        secs = _kst_seconds_since(detected_at)
        return max(0, int((secs or 0) // 60)) if secs is not None else 10**9
    if isinstance(detected_at, str):
        detected_at = detected_at.strip()
        if not detected_at:
            return 10**9
        parsed = _parse_compact_datetime(detected_at)
        if parsed is None and len(detected_at) == 8 and detected_at.count(":") == 2:
            now_dt = _now_kst()
            try:
                hh, mm, ss = [int(x) for x in detected_at.split(":")[:3]]
                parsed = now_dt.replace(hour=hh, minute=mm, second=ss, microsecond=0)
            except Exception as e:
                _swallow_exception(e)
                parsed = None
        secs = _kst_seconds_since(parsed)
        return max(0, int((secs or 0) // 60)) if secs is not None else 10**9
    return 10**9
def _latest_entry_watch_by_code(code: str) -> dict | None:
    if not code or not _entry_watch:
        return None
    cand = [w for w in _entry_watch.values() if isinstance(w, dict) and w.get("code") == code]
    if not cand:
        return None
    return max(cand, key=lambda x: x.get("registered_ts", 0))
def _sector_resend_relevance_ok(alert_snapshot: dict, si_retry: dict) -> bool:
    if not _sector_info_has_meaningful_payload(si_retry):
        return False
    if _signal_age_minutes_for_retry(alert_snapshot) > SECTOR_RESEND_MAX_MINUTES:
        return False
    code = str(alert_snapshot.get("code", "") or "").strip()
    # v161.42: 상한가 도달 종목 재안내 차단 — _upper_limit_alerted_today 체크
    today = _now_kst().strftime("%Y%m%d")
    if code and _upper_limit_alerted_today.get(code) == today:
        return False
    quote = _get_live_quote_for_signal(alert_snapshot)
    # v161.42: 실시간 상한가 상태 이중 체크 (prdy_vrss_sign=="1" 또는 현재가>=상한가)
    if quote:
        _sign = str(quote.get("prdy_vrss_sign", "") or "")
        _upper_price = safe_int(quote.get("upper_price", 0), 0)
        _cur_price = safe_int(quote.get("price", 0), 0)
        if _sign == "1" or (_upper_price > 0 and _cur_price >= _upper_price):
            return False
    price = safe_int((quote or {}).get("price", 0) or alert_snapshot.get("price", 0))
    entry = safe_int(alert_snapshot.get("entry_price", 0))
    stop = safe_int(alert_snapshot.get("stop_loss", 0))
    base_vr = float(alert_snapshot.get("volume_ratio", 0) or 0)
    live_vr = float((quote or {}).get("volume_ratio", 0) or 0)
    if entry and price:
        upper = entry * (1.0 + SECTOR_RESEND_ENTRY_DEVIATION_PCT / 100.0)
        if price > upper:
            return False
    if stop and price and price <= stop:
        return False
    if base_vr >= 2.0 and live_vr and live_vr < max(1.0, base_vr * 0.35):
        return False
    watch = _latest_entry_watch_by_code(str(alert_snapshot.get("code", "") or ""))
    if watch and watch.get("entry_hit"):
        hit_time = str(watch.get("entry_hit_time") or "").strip()
        if hit_time:
            try:
                parsed = _parse_compact_datetime(hit_time)
                secs = _kst_seconds_since(parsed)
                if secs is not None and secs / 60.0 > SECTOR_RESEND_ENTRY_HIT_GRACE_MINUTES:
                    return False
            except Exception as e:
                _swallow_exception(e)
    return True
def _dispatch_sector_resend_alert(alert_snapshot: dict, si_retry: dict) -> None:
    snap = _clone_alert_snapshot_for_sector_retry(alert_snapshot)
    if not snap:
        return
    quote = _get_live_quote_for_signal(snap)
    if quote:
        for key in ("price", "change_rate", "volume_ratio", "today_vol", "market"):
            if key in quote and quote.get(key) not in (None, ""):
                snap[key] = quote.get(key)
        if quote.get("name"):
            snap["name"] = _resolve_stock_name(str(snap.get("code", "") or ""), str(quote.get("name", "") or ""))
    snap["sector_info"] = si_retry or {}
    snap["_skip_repeat_throttle"] = True
    snap["_header_override"] = "🔁 <b>[섹터 미반영 종목 재안내]</b>"
    sender_kind = str(snap.get("_alert_sender", "send_alert") or "send_alert")
    if sender_kind == "mid_pullback":
        send_mid_pullback_alert(snap)
    else:
        send_alert(snap)
def _build_sector_monitor_meta(name: str, origin_signal: str, detect_time: str, from_alert: bool, alert_snapshot: dict | None) -> dict:
    return {
        "name": name,
        "known_codes": set(),
        "last_update": time.time(),
        "alert_count": 0,
        "start_ts": time.time(),
        "origin_signal": origin_signal or "",
        "detect_time": detect_time or "",
        "from_alert": bool(from_alert),
        "alert_snapshot": _clone_alert_snapshot_for_sector_retry(alert_snapshot) if from_alert else None,
    }
def _refresh_sector_monitor_info(info: dict, name: str, origin_signal: str, detect_time: str, from_alert: bool, alert_snapshot: dict | None) -> None:
    info.setdefault("known_codes", set())
    info.update({
        "name": name or info.get("name", ""),
        "last_update": time.time(),
        "origin_signal": origin_signal or info.get("origin_signal", ""),
        "detect_time": detect_time or info.get("detect_time", ""),
        "from_alert": bool(from_alert or info.get("from_alert", False)),
        "alert_snapshot": _clone_alert_snapshot_for_sector_retry(alert_snapshot) if (from_alert and alert_snapshot) else info.get("alert_snapshot"),
    })
def _should_stop_sector_monitor(info: dict) -> bool:
    if not is_any_market_open():
        return True
    elapsed_h = (time.time() - info["start_ts"]) / 3600
    alert_cnt = info.get("alert_count", 0)
    max_hours = min(SECTOR_MONITOR_MAX_HOURS + alert_cnt * 2, 24)
    if elapsed_h > max_hours:
        _log_info_msg(f"  📡 섹터 감시 종료: {info.get('name','?')} ({elapsed_h:.1f}h, 알림 {alert_cnt}회)")
        return True
    return False
def _build_sector_monitor_message(code: str, name: str, info: dict, si: dict, new_rising: list[dict]) -> str:
    theme = si.get("theme", "")
    rising = si.get("rising", [])
    flat = si.get("flat", [])
    bonus = si.get("bonus", 0)
    summary = si.get("summary", "")
    new_set = {x["code"] for x in new_rising}
    tag = f"🆕 {len(new_rising)}종목 추가" if new_rising and info["alert_count"] > 1 else f"#{info['alert_count']}회 업데이트"
    lines = f"🏭 <b>섹터 모멘텀</b> [{theme}]  {tag}\n"
    lines += _sector_origin_line(code, info)
    lines += f"  {summary}\n" if summary else ""
    leader = si.get("leader")
    leader_code = leader["code"] if isinstance(leader, dict) else None
    if leader and isinstance(leader, dict):
        lines += (f"  ━━━━━━━━━━━━━\n"
                  f"  👑 <b>대장: {leader['name']}</b>  "
                  f"<b>{leader.get('cr',0):+.1f}%</b>  "
                  f"거래량 {leader.get('vr',0):.1f}배  "
                  f"점수 {leader.get('score',0):.2f}\n"
                  f"  ━━━━━━━━━━━━━\n")
    for r in rising[:5]:
        if r["code"] == leader_code:
            continue
        vt = f" 🔊{r['volume_ratio']:.0f}x" if r.get("volume_ratio", 0) >= 2 else ""
        new_t = " 🆕" if r["code"] in new_set else ""
        wsuf = _watch_suffix(r["code"], safe_int(r.get("price", 0)))
        marker = '🟩' if r['change_rate'] > 0 else ('🟥' if r['change_rate'] < 0 else '')
        lines += f"  {marker} {_resolve_stock_name(r['code'], r.get('name',''))} <b>{r['change_rate']:+.1f}%</b>{vt}{new_t}{wsuf}\n"
    for r in flat[:2]:
        marker = '🟩' if r['change_rate'] > 0 else ('🟥' if r['change_rate'] < 0 else '')
        lines += f"  {marker} {_resolve_stock_name(r['code'], r.get('name',''))} {r['change_rate']:+.1f}%\n"
    if bonus > 0:
        lines += f"  💡 섹터 가산점: +{bonus}점\n"
    return lines
def _handle_sector_monitor_snapshot_resend(code: str, info: dict, si: dict) -> bool:
    snap = info.get("alert_snapshot") or {}
    if _signal_age_minutes_for_retry(snap) > SECTOR_RESEND_MAX_MINUTES:
        return True
    if not _sector_info_has_meaningful_payload(si):
        return False
    if _sector_resend_relevance_ok(snap, si):
        _dispatch_sector_resend_alert(snap, si)
    return True
def _process_sector_monitor_iteration(code: str, name: str, info: dict) -> bool:
    if _should_stop_sector_monitor(info):
        return True
    try:
        _sector_cache.pop(code, None)
        si = calc_sector_momentum(code, name)
        if info.get("from_alert"):
            return _handle_sector_monitor_snapshot_resend(code, info, si)
        if not si.get("detail"):
            return False
        new_rising = [r for r in si.get("rising", []) if r["code"] not in info["known_codes"]]
        info["known_codes"].update({r["code"] for r in si.get("detail", [])})
        if new_rising or info.get("alert_count", 0) == 0:
            info["alert_count"] = info.get("alert_count", 0) + 1
            lines = _build_sector_monitor_message(code, name, info, si, new_rising)
            send_with_chart_buttons(f"🏭 <b>[{name} 섹터 모니터링]</b>\n━━━━━━━━━━━━━━━\n{lines}", code, name)
    except Exception as e:
        _log_error(f"start_sector_monitor({code})", e)
    return False
def _run_sector_monitor_loop(code: str, name: str) -> None:
    while True:
        time.sleep(SECTOR_MONITOR_INTERVAL)
        info = _sector_monitor.get(code)
        if not info:
            break
        if _process_sector_monitor_iteration(code, name, info):
            _sector_monitor.pop(code, None)
            break
def start_sector_monitor(code: str, name: str, origin_signal: str = "", detect_time: str = "", from_alert: bool = False, alert_snapshot: dict | None = None):
    if is_scoring_only_instrument(code, name):
        return
    if code in _sector_monitor:
        _refresh_sector_monitor_info(_sector_monitor.get(code, {}), name, origin_signal, detect_time, from_alert, alert_snapshot)
        _sector_monitor[code] = _sector_monitor.get(code, {})
        return
    _sector_monitor[code] = _build_sector_monitor_meta(name, origin_signal, detect_time, from_alert, alert_snapshot)
    threading.Thread(target=_run_sector_monitor_loop, args=(code, name), daemon=True).start()
    _log_info_msg(f"  📡 섹터 모니터링 시작: {name}")
# ============================================================
# 🎯 진입가 감지
# ============================================================
SCORING_ONLY_NAME_MARKERS = ("KODEX", "TIGER", "KOSEF", "KBSTAR", "ARIRANG", "HANARO", "ACE", "SOL", "ETF", "ETN")
def is_scoring_only_instrument(code: str, name: str = "") -> bool:
    """ETF/ETN/지수형 종목은 점수 참고용으로만 사용하고 실제 포착/감시 대상에서는 제외."""
    try:
        nm = str(name or "").upper()
        return any(m in nm for m in SCORING_ONLY_NAME_MARKERS)
    except Exception as e:
        _swallow_exception(e)  # v105 structured silent-exception log
        return False
def _sector_origin_line(code: str, info: dict | None = None) -> str:
    """섹터 모니터링 기준 종목의 출처/원신호/포착시각/현재상태를 한 줄로 요약."""
    try:
        info = info or {}
        from_alert = bool(info.get("from_alert", False))
        origin_signal = str(info.get("origin_signal", "") or "").strip()
        detect_time = str(info.get("detect_time", "") or "").strip()
        if is_scoring_only_instrument(code, info.get("name", "")):
            origin_label = "참고·점수 종목"
            status_label = "점수만 반영"
        else:
            origin_label = "포착 종목" if from_alert else "참고·점수 종목"
            status_label = "점수만 반영"
            if _entry_watch:
                cand = [w for w in _entry_watch.values() if w.get("code") == code]
                if cand:
                    w = max(cand, key=lambda x: x.get("registered_ts", 0))
                    status_label = "진입가 도달" if w.get("entry_hit") else "진입 감시중"
                elif from_alert:
                    status_label = "포착 후 감시 대기"
        parts = [f"  🎯 기준 종목: {origin_label}"]
        if origin_signal:
            parts.append(f"원신호 {origin_signal}")
        if detect_time:
            parts.append(f"포착 {detect_time[:5]}")
        if status_label:
            parts.append(f"상태 {status_label}")
        return "  |  ".join(parts) + "\n"
    except Exception as e:
        _swallow_exception(e)  # v105 structured silent-exception log
        return ""
def _watch_suffix(peer_code: str, peer_price: int) -> str:
    """감시 상태/수익률 표기 (진입가 대비 현재가 기준)."""
    try:
        if not _entry_watch:
            return ""
        cand = [w for w in _entry_watch.values() if w.get('code') == peer_code]
        if not cand:
            return ""
        w = max(cand, key=lambda x: x.get('registered_ts', 0))
        entry = safe_int(w.get('entry_price', 0))
        if not entry:
            return ""
        if w.get('entry_hit'):
            if peer_price:
                pnl = (peer_price / entry - 1.0) * 100.0
                return f" ✅ <b>({pnl:+.1f}%)</b>"
            return " ✅"
        return " ⏳ <b>(미도달)</b>"
    except Exception as e:
        _swallow_exception(e)  # v105 structured silent-exception log
        return ""
def _format_watch_list_entry_vs_current(entry_price: int, current_price: int) -> str:
    """`/list`에서 현재가 기준 진입가 괴리율 표기."""
    try:
        entry = safe_int(entry_price, 0)
        current = safe_int(current_price, 0)
        if entry <= 0 or current <= 0:
            return ""
        gap_pct = (entry / current - 1.0) * 100.0
        return f" (현재가 대비 {gap_pct:+.1f}%)"
    except Exception as e:
        _swallow_exception(e)  # v105 structured silent-exception log
        return ""
def _get_watch_list_current_price(code: str, rec: dict | None = None, quote_cache: dict | None = None) -> dict:
    """`/list` 감시 종목 현황용 현재가 조회."""
    try:
        code = normalize_stock_code(code)
        if not code:
            return {}
        cache = quote_cache if isinstance(quote_cache, dict) else None
        if cache is not None and code in cache:
            return cache.get(code) or {}
        rec = rec if isinstance(rec, dict) else {}
        fallback_price = safe_int(rec.get("last_price", 0) or rec.get("current_price", 0) or rec.get("price", 0), 0)
        fallback_market = str(rec.get("market") or "").strip()
        out = {}
        try:
            if is_market_open():
                cur = get_stock_price(code) or {}
            elif is_nxt_open():
                cur = get_nxt_stock_price(code) if is_nxt_listed(code) else {}
                if not safe_int(cur.get("price", 0), 0):
                    cur = get_stock_price(code) or {}
            else:
                cur = get_stock_price(code) or {}
            price = safe_int(cur.get("price", 0), 0)
            market = str(cur.get("market") or fallback_market or "").strip()
            if price > 0:
                out = {"price": price, "market": market}
        except Exception as e:
            _swallow_exception(e)  # v105 structured silent-exception log
            out = {}
        if not out and fallback_price > 0:
            out = {"price": fallback_price, "market": fallback_market}
        if cache is not None:
            cache[code] = out
        return out
    except Exception as e:
        _swallow_exception(e)  # v105 structured silent-exception log
        return {}
def register_top_signal(s: dict):
    """신호 발생마다 오늘의 최우선 종목 풀에 추가 (점수 높은 종목 유지)"""
    code  = s.get("code","")
    score = s.get("score", 0)
    if not code: return
    if is_scoring_only_instrument(code, s.get("name", "")):
        return
    existing = _today_top_signals.get(code, {})
    new_entry = s.get("entry_price", 0)
    if score > existing.get("score", 0):
        # v161.46: score 갱신 시 진입가 3종 + signal_type + detected_at 함께 갱신
        _today_top_signals[code] = {
            "score":       score,
            "name":        s.get("name", code),
            "signal_type": s.get("signal_type",""),
            "entry_price": new_entry,
            "stop_loss":   s.get("stop_loss", 0),
            "target_price":s.get("target_price", 0),
            "reasons":     s.get("reasons", []),
            "detected_at": datetime.now().strftime("%H:%M"),
            "nxt_delta":   s.get("nxt_delta", 0),
        }
    elif new_entry > 0 and code in _today_top_signals:
        # v161.46: score가 낮아도 진입가가 바뀌었으면 진입가 3종 갱신
        prev_entry = int(_today_top_signals[code].get("entry_price", 0) or 0)
        if new_entry != prev_entry:
            _today_top_signals[code]["entry_price"] = new_entry
            _today_top_signals[code]["stop_loss"]   = s.get("stop_loss", _today_top_signals[code].get("stop_loss", 0))
            _today_top_signals[code]["target_price"] = s.get("target_price", _today_top_signals[code].get("target_price", 0))
def send_top_signals():
    """10:00~장마감까지 1시간마다 — 최우선 종목 TOP 5 발송"""
    if not _today_top_signals: return
    sig_labels = {
        "UPPER_LIMIT":"상한가","NEAR_UPPER":"상한가근접","SURGE":"급등",
        "EARLY_DETECT":"조기포착","MID_PULLBACK":"눌림목",
        "ENTRY_POINT":"눌림목","STRONG_BUY":"강력매수",
    }
    # v161.11: 손절 완료 후 재진입 감시 중인 종목 제외
    reentry_codes = set(str(c) for c in (_reentry_watch or {}).keys())
    candidates = {
        code: val for code, val in _today_top_signals.items()
        if str(code) not in reentry_codes
    }
    if not candidates: return
    # v161.46: 발송 시점에 _entry_watch 최신 진입가로 동기화
    # _entry_watch key = signal_log_key, value에 code + entry_price/stop_loss/target_price
    _watch_by_code: dict[str, dict] = {}
    try:
        for _w in list((_entry_watch or {}).values()):
            if not isinstance(_w, dict): continue
            _wc = normalize_stock_code(_w.get("code", ""))
            if _wc and _wc not in _watch_by_code:
                _watch_by_code[_wc] = _w
    except Exception:
        pass
    top5  = sorted(candidates.values(), key=lambda x: x["score"], reverse=True)[:5]
    medals = ["🥇","🥈","🥉","4️⃣","5️⃣"]
    msg   = f"🏆 <b>최우선 종목 TOP 5</b>  {datetime.now().strftime('%m/%d %H:%M')}\n━━━━━━━━━━━━━━━\n"
    for i, t in enumerate(top5, 1):
        medal   = medals[i-1]
        sig     = sig_labels.get(t["signal_type"], t["signal_type"])
        nxt_tag = f"  🟡NXT +{t['nxt_delta']}pt" if t.get("nxt_delta",0) > 0 else ""
        # v161.46: _entry_watch 최신값 우선 사용
        _code = next((c for c, v in candidates.items() if v is t), "")
        _live_w = _watch_by_code.get(normalize_stock_code(_code), {})
        entry   = int(_live_w.get("entry_price", 0) or 0) or t.get("entry_price", 0)
        stop    = int(_live_w.get("stop_loss",   0) or 0) or t.get("stop_loss",   0)
        target  = int(_live_w.get("target_price",0) or 0) or t.get("target_price",0)
        rr      = round((target - entry) / (entry - stop), 1) if entry and stop and entry > stop else 0
        # v165.14: 종목명 옆 종목코드 <b><code> 태그 — 탭 1회로 복사 가능
        _code_tag = f"  <b><code>{_code}</code></b>" if _code else ""
        msg += (
            f"\n{medal} <b>{t['name']}</b>{_code_tag}  {sig}  {t['score']}점{nxt_tag}\n"
            f"   포착: {t['detected_at']}\n"
            f"   🎯 진입 {entry:,}  🛡 손절 {stop:,}  🏆 목표 {target:,}\n"
            f"   손익비: {rr:.1f}:1\n"
        )
    msg += "\n━━━━━━━━━━━━━━━\n💡 점수·NXT·손익비 종합 순위"
    send(msg)
def reset_top_signals_daily():
    """장 시작 시 최우선 종목 풀 초기화"""
    _today_top_signals.clear()
    _nxt_eligible_cache.clear()  # v165.14: NXT 거래가능 캐시 당일 초기화
def _get_expire_days_by_regime(signal_type: str = "") -> tuple:
    """
    v84: 레짐 + 신호유형별 만료 일수 반환.
    반환: (expire_days, upward_escape_pct)
      - expire_days: 감시 만료 일수
      - upward_escape_pct: 현재가가 진입가 대비 이 % 이상 올라가면 즉시만료
    레짐별 기준:
      bull  — 안 빠지고 올라가는 장 → 빠른 정리
      normal— 현재 기본값
      bear  — 잘 빠지는 장 → 기다릴 가치 있음
      crash — 반등 빠름 → 짧게 대응
    """
    try:
        regime = get_market_regime()
        mode = regime.get("mode", "normal")
    except Exception as e:
        _swallow_exception(e)  # v105 structured silent-exception log
        mode = "normal"
    is_surge = str(signal_type or "").upper() in ("SURGE", "NEAR_UPPER", "UPPER_LIMIT", "STRONG_BUY")
    # v162.4: FZONE_VWAP_BOUNCE는 당일 만료 고정 (레짐 무관)
    if str(signal_type or "").upper() == "FZONE_VWAP_BOUNCE":
        return (0, 0.0)  # expire_days=0 → _build_entry_watch_active_record에서 당일 만료 처리
    # (expire_days, upward_escape_pct)
    if mode == "bull":
        return (1, 6.0) if is_surge else (2, 6.0)
    elif mode == "bear":
        return (3, 10.0) if is_surge else (4, 10.0)
    elif mode == "crash":
        return (1, 5.0) if is_surge else (2, 5.0)
    else:  # normal
        return (2, 8.0) if is_surge else (3, 8.0)
def _find_locked_entry_watch(code: str):
    for watch_key, watch in list(_entry_watch.items()):
        if normalize_stock_code((watch or {}).get("code")) != code:
            continue
        if watch.get("entry_hit") or watch.get("entry_hit_locked"):
            return watch_key, watch
    return None
def _resolve_entry_watch_detect_meta(s: dict, code: str, now_dt: datetime) -> tuple[str, str, str, str]:
    log_key = f"{code}_{now_dt.strftime('%Y%m%d%H%M')}"
    signal_log_key = str(s.get("signal_log_key") or "").strip()
    detect_date = str(s.get("detect_date") or "").strip()
    detect_time = str(s.get("detect_time") or "").strip()
    try:
        detected_at = s.get("detected_at")
        if isinstance(detected_at, datetime):
            signal_log_key = signal_log_key or f"{code}_{detected_at.strftime('%Y%m%d%H%M')}"
            detect_date = detect_date or detected_at.strftime('%Y%m%d')
            detect_time = detect_time or detected_at.strftime('%H:%M:%S')
    except Exception as e:
        _swallow_exception(e)
        signal_log_key = signal_log_key or ""
    detect_date = detect_date or now_dt.strftime('%Y%m%d')
    detect_time = detect_time or now_dt.strftime('%H:%M:%S')
    return log_key, signal_log_key, detect_date, detect_time
def _prepare_entry_watch_registration_context(s: dict, code: str, stock_name: str) -> dict:
    now_dt = datetime.now()
    log_key, signal_log_key, detect_date, detect_time = _resolve_entry_watch_detect_meta(s, code, now_dt)
    old_items = [(k, w) for k, w in _entry_watch.items() if normalize_stock_code((w or {}).get("code")) == code]
    latest_old_watch = max((w for _, w in old_items), key=lambda x: x.get("registered_ts", 0), default=None)
    previous_entry = safe_int((latest_old_watch or {}).get("entry_price", 0), 0)
    previous_miss_count = safe_int((latest_old_watch or {}).get("miss_count", 0), 0)
    previous_first_detect_date = str((latest_old_watch or {}).get("first_detect_date", (latest_old_watch or {}).get("detect_date", "")) or "")
    # v161.31: 대표갱신 시 notify 이력 승계용 — 중복 도달 알람 방지
    prior_last_notified_ts = max((safe_int((w or {}).get("last_notified_ts", 0), 0) for _, w in old_items), default=0)
    prior_notify_count = max((safe_int((w or {}).get("notify_count", 0), 0) for _, w in old_items), default=0)
    # v169.5: entry_hit 승계 — 대표갱신 시 기존 entry_hit=True가 소실되어 재알람 발생하는 버그 수정
    prior_entry_hit = any((w or {}).get("entry_hit") for _, w in old_items)
    prior_entry_hit_time = next((str((w or {}).get("entry_hit_time", "") or "") for _, w in old_items if (w or {}).get("entry_hit")), "")
    entry, entry_guard_mode = _apply_entry_price_guard(
        s,
        previous_entry,
        detect_date=previous_first_detect_date,
        miss_count=previous_miss_count,
    )
    s["entry_price"] = int(entry or 0)
    # v169.5: 진입가 동일 + 기존 entry_hit=True → 대표갱신 스킵 (재알람 방지)
    # 이유: 진입가 3,510→3,510 동일 갱신 시에도 새 watch가 등록되어 entry_hit 소실
    #       entry_hit=False 상태로 재감시 → 현재가 이미 진입가 돌파 시 즉시 재알람
    if prior_entry_hit and old_items and entry == previous_entry:
        _log_info_msg(
            f"  ⏭ 대표갱신 스킵: {s.get('name','')}"
            f" 진입가={entry:,}원 동일 + entry_hit 유지 — 재알람 방지"
        )
        return None  # 호출부에서 None 체크 필요
    expire_days, escape_pct = _get_expire_days_by_regime(s.get("signal_type", ""))
    current_price = safe_int(s.get("price", 0), 0)
    return {
        "now_dt": now_dt,
        "log_key": log_key,
        "signal_log_key": signal_log_key,
        "detect_date": detect_date,
        "detect_time": detect_time,
        "old_items": old_items,
        "previous_entry": previous_entry,
        "previous_miss_count": previous_miss_count,
        "previous_first_detect_date": previous_first_detect_date,
        "entry": int(entry or 0),
        "entry_guard_mode": entry_guard_mode,
        "expire_days": expire_days,
        "escape_pct": escape_pct,
        "current_price": current_price,
        "stock_name": stock_name,
        "code": code,
        "prior_last_notified_ts": prior_last_notified_ts,  # v161.31
        "prior_notify_count": prior_notify_count,          # v161.31
        "prior_entry_hit": prior_entry_hit,                # v169.5: entry_hit 승계
        "prior_entry_hit_time": prior_entry_hit_time,      # v169.5
    }
def _should_skip_entry_watch_registration(ctx: dict, regime_mode: str) -> bool:
    current_price = ctx["current_price"]
    entry = ctx["entry"]
    if not (current_price and entry and current_price > entry):
        return False
    gap_pct = (current_price - entry) / entry * 100
    if gap_pct < ctx["escape_pct"]:
        return False
    _log_info_msg(
        f"  ⏭ 상방이탈 즉시만료: {ctx['stock_name']} 현재가 {current_price:,}원 / 진입가 {entry:,}원 "
        f"(+{gap_pct:.1f}% ≥ {ctx['escape_pct']:.0f}%, {regime_mode}장)"
    )
    return True
def _sync_entry_watch_representative_log(s: dict, ctx: dict) -> None:
    try:
        sig_data = {}
        try:
            sig_data = _read_json_locked(SIGNAL_LOG_FILE)
        except Exception as e:
            _swallow_exception(e)
        representative_key = _find_representative_tracking_log_key(sig_data, ctx["code"], preferred_key=ctx["signal_log_key"])
        if not representative_key:
            return
        ctx["signal_log_key"] = representative_key
        rec = sig_data.get(representative_key) or {}
        candidate = _build_tracking_episode_candidate(s, reason="진입감시재등록")
        _append_tracking_episode_candidate(rec, candidate)
        if ctx["previous_entry"] and ctx["entry"] and ctx["previous_entry"] != ctx["entry"]:
            _append_tracking_entry_update(
                rec,
                ctx["previous_entry"],
                ctx["entry"],
                reason="재포착대표진입갱신" if ctx["entry_guard_mode"] != "고점추격방지유지" else "재포착고점추격방지",
            )
        rec["last_entry_guard_mode"] = ctx["entry_guard_mode"]
        rec["episode_representative"] = True
        rec["signal_type"] = s.get("signal_type", rec.get("signal_type", ""))
        rec["name"] = ctx["stock_name"]
        rec["entry_price"] = ctx["entry"]
        rec["stop_price"] = s.get("stop_loss", rec.get("stop_price", 0))
        rec["target_price"] = s.get("target_price", rec.get("target_price", 0))
        rec["execution_setup_required"] = False
        rec["planned_entry_price"] = safe_int(s.get("planned_entry_price", ctx["entry"]), ctx["entry"])
        rec["status"] = "추적중"
        rec["last_detect_date"] = ctx["detect_date"]
        rec["last_detect_time"] = ctx["detect_time"]
        rec["entry_blocked"] = False
        rec["entry_blocked_reason"] = ""
        rec["entry_blocked_time"] = ""
        rec["entry_blocked_price"] = 0
        rec["entry_reference_only"] = False
        rec["entry_reference_market"] = ""
        rec["entry_reference_reason"] = ""
        rec["entry_reference_time"] = ""
        rec["entry_reference_date"] = ""
        rec["entry_reference_clock"] = ""
        rec["entry_reference_price"] = 0
        _merge_tracking_episode_records(sig_data, ctx["code"], representative_key, reason="재포착_대표레코드통합")
        _write_json_atomic(SIGNAL_LOG_FILE, sig_data, indent=2)
    except Exception as e:
        _log_warn_msg(f"⚠️ 대표 진입가 동기화 오류: {e}")
def _archive_prior_entry_watches(old_items: list[tuple[str, dict]], ctx: dict) -> None:
    for watch_key, watch in old_items:
        old_entry = safe_int((watch or {}).get("entry_price", 0), 0)
        miss_count = safe_int((watch or {}).get("miss_count", 0), 0)
        if old_entry and ctx["entry_guard_mode"] == "고점추격방지유지" and ctx["entry"] == old_entry:
            _log_info_msg(
                f"  🛡 대표 진입가 유지: {ctx['stock_name']} {old_entry:,}원 (고점 추격 방지, 미도달 {miss_count}회)"
            )
        else:
            _log_info_msg(
                f"  🔄 대표 진입가 갱신: {ctx['stock_name']} {old_entry:,}→{ctx['entry']:,}원 (미도달 {miss_count}회)"
            )
        archived_watch = _entry_watch.pop(watch_key, None)
        if archived_watch:
            _archive_entry_watch_record(
                watch_key,
                archived_watch,
                consume_reason="재포착_대표진입승계",
                final_status="대표진입승계",
            )
def _build_entry_watch_active_record(s: dict, ctx: dict) -> dict:
    signal_log_key = ctx["signal_log_key"] or ctx["log_key"]
    entry = ctx["entry"]
    # v161.31: 대표갱신 재등록 시 기존 notify 이력 승계 — last_notified_ts=0 초기화로 중복 도달 알람 방지
    _prior_last_notified_ts = ctx.get("prior_last_notified_ts", 0)
    _prior_notify_count = ctx.get("prior_notify_count", 0)
    # v169.5: 대표갱신 시 entry_hit 승계 — 기존 entry_hit=True 소실 → 재알람 방지
    _prior_entry_hit = bool(ctx.get("prior_entry_hit", False))
    _prior_entry_hit_time = str(ctx.get("prior_entry_hit_time", "") or "")
    return {
        "code": ctx["code"],
        "name": ctx["stock_name"],
        "entry_price": entry,
        "stop_loss": s.get("stop_loss", 0),
        "target_price": s.get("target_price", 0),
        "signal_type": s.get("signal_type", ""),
        "signal_log_key": signal_log_key,
        "detect_date": ctx["detect_date"],
        "detect_time": ctx["detect_time"],
        "first_detect_date": ctx["previous_first_detect_date"] or ctx["detect_date"],
        "last_notified_ts": _prior_last_notified_ts,  # v161.31: 기존 notify 시각 승계
        "notify_count": _prior_notify_count,           # v161.31: 기존 notify 횟수 승계
        "entry_hit": _prior_entry_hit,                 # v169.5: entry_hit 승계 (True이면 재알람 방지)
        "entry_hit_time": _prior_entry_hit_time,       # v169.5
        "miss_count": ctx["previous_miss_count"] + len(ctx["old_items"]),
        "registered_ts": time.time(),
        "expire_ts": s.get("expire_ts") or (time.time() + 86400 * ctx["expire_days"]) if ctx["expire_days"] > 0 else (s.get("expire_ts") or time.time() + 3600),
        "peak_price": s.get("price", 0),
        "low_price": safe_int(s.get("price", entry), entry),
        "low_price_time": datetime.now().strftime('%Y-%m-%d %H:%M:%S'),
        "volume_at_low": safe_int(s.get("today_vol", 0), 0),
        "reasons": (s.get("reasons") or [])[:5],
        "sector_theme": s.get("sector_info", {}).get("theme", ""),
        "change_at_detect": float(s.get("change_rate", 0) or 0),
        "volume_ratio": float(s.get("volume_ratio", 0) or 0),
        "volume_ratio_at_detect": float(s.get("volume_ratio", 0) or 0),
        "execution_metrics": dict(s.get("execution_metrics") or {}),
        "execution_speed_at_detect": int((s.get("execution_metrics") or {}).get("execution_speed_score", 0) or 0),
        "signal_strength_at_detect": str(s.get("signal_strength") or (s.get("position") or {}).get("strength") or _classify_signal_strength(s, dict(s.get("execution_metrics") or {}))),
        "resurge_mode": bool(s.get("resurge_mode")),
        "entry_soft_block_allowed": bool(s.get("entry_soft_block_allowed")),
        "pullback_reclaim_ratio": float(s.get("pullback_reclaim_ratio", 0.0) or 0.0),
        "pullback_ratio_at_register": float(s.get("pullback_reclaim_ratio", 0.0) or 0.0),
        "pattern_grade": str(s.get("pattern_grade", s.get("grade", "B"))),
        "execution_grade": str(s.get("grade", "B")),
        "entry_price_at_detect": int(entry or 0),
        "pattern_grade_at_detect": str(s.get("pattern_grade", s.get("grade", "B"))),
        "execution_grade_at_detect": str(s.get("grade", "B")),
        "grade_at_detect": str(s.get("grade", "B")),
        "mid_pullback_bucket": str(s.get("mid_pullback_bucket", "") or ""),
        "mid_pullback_bucket_label": str(s.get("mid_pullback_bucket_label", "") or ""),
        "grade": str(s.get("grade", "B")),
        "score": int(s.get("score", 0) or 0),
        "source": str(s.get("source", "") or ""),
        "dart_reliability_score": int(s.get("dart_reliability_score", 0) or 0),
        "shareholder_confirmation_date": str(s.get("shareholder_confirmation_date", "") or ""),
        "entry_reference_only": False,
        "entry_reference_market": "",
        "entry_reference_reason": "",
        "entry_reference_time": "",
        "entry_reference_price": 0,
        "crossday_episode_active": bool(s.get("crossday_episode_active")),
        "crossday_episode_prep": bool(s.get("crossday_episode_prep")),
        "crossday_episode_confirmed": bool(s.get("crossday_episode_confirmed")),
        "crossday_episode_reason": str(s.get("crossday_episode_reason", "") or ""),
        "crossday_episode_reclaim_ratio": float(s.get("crossday_episode_reclaim_ratio", 0.0) or 0.0),
        "entry_execution_focus": bool(s.get("entry_execution_focus")),
        "entry_watch_state": "active",
    }
def _load_entry_termination_state() -> dict:
    state = _read_json_safe(ENTRY_TERMINATION_STATE_FILE, {}) or {}
    return state if isinstance(state, dict) else {}

def _save_entry_termination_state(state: dict) -> None:
    _write_json_atomic(ENTRY_TERMINATION_STATE_FILE, state if isinstance(state, dict) else {}, indent=2)

def _entry_signal_rank(signal_type: str) -> int:
    sig = str(signal_type or "").upper()
    ranks = {"MID_PULLBACK": 1, "ENTRY_POINT": 1, "EARLY_DETECT": 2, "SURGE": 3, "NEAR_UPPER": 4, "UPPER_LIMIT": 5, "STRONG_BUY": 5}
    return int(ranks.get(sig, 0))

def _entry_grade_rank(grade: str) -> int:
    return {"C": 1, "B": 2, "A": 3}.get(str(grade or "").upper(), 0)

def _mark_entry_termination_state(code: str, reason: str, signal_type: str = "", grade: str = "", score: int = 0) -> None:
    code = normalize_stock_code(code)
    if not code:
        return
    state = _load_entry_termination_state()
    state[code] = {
        "ts": time.time(),
        "reason": str(reason or ""),
        "signal_type": str(signal_type or ""),
        "grade": str(grade or ""),
        "score": int(score or 0),
    }
    _entry_termination_state_runtime[code] = dict(state[code])
    _save_entry_termination_state(state)

def _get_entry_termination_state(code: str) -> dict:
    code = normalize_stock_code(code)
    if not code:
        return {}
    row = dict((_entry_termination_state_runtime or {}).get(code) or {})
    if row:
        return row
    state = _load_entry_termination_state()
    row = dict((state or {}).get(code) or {})
    if row:
        _entry_termination_state_runtime[code] = dict(row)
    return row

def _should_skip_entry_termination_notice(watch: dict, reason: str) -> bool:
    code = normalize_stock_code((watch or {}).get("code", ""))
    if not code:
        return False
    row = _get_entry_termination_state(code)
    last_ts = float(row.get("notice_ts", 0.0) or 0.0)
    if time.time() - last_ts < ENTRY_TERMINATION_ALERT_COOLDOWN_SEC and str(row.get("notice_reason", "")) == str(reason or ""):
        return True
    return False

def _mark_entry_termination_notice(code: str, reason: str) -> None:
    code = normalize_stock_code(code)
    if not code:
        return
    state = _load_entry_termination_state()
    row = dict((state or {}).get(code) or {})
    row["notice_ts"] = time.time()
    row["notice_reason"] = str(reason or "")
    state[code] = row
    _entry_termination_state_runtime[code] = dict(row)
    _save_entry_termination_state(state)

def _should_skip_terminated_rearm(signal: dict) -> bool:
    sig = dict(signal or {})
    code = normalize_stock_code(sig.get("code", ""))
    if not code:
        return False
    row = _get_entry_termination_state(code)
    if not row:
        return False
    if time.time() - float(row.get("ts", 0.0) or 0.0) >= ENTRY_TERMINATION_REARM_COOLDOWN_SEC:
        return False
    prev_sig_rank = _entry_signal_rank(row.get("signal_type", ""))
    new_sig_rank = _entry_signal_rank(sig.get("signal_type", ""))
    prev_grade_rank = _entry_grade_rank(row.get("grade", ""))
    new_grade_rank = _entry_grade_rank(sig.get("execution_grade") or sig.get("grade") or "")
    prev_score = int(row.get("score", 0) or 0)
    new_score = safe_int(sig.get("score", 0), 0)
    meaningful_upgrade = new_sig_rank > prev_sig_rank or new_grade_rank > prev_grade_rank or new_score >= prev_score + 8
    return not meaningful_upgrade

def _refresh_nxt_preopen_entry_to_krx(s: dict) -> None:
    """v165.32 [#3]: NXT 선포착 종목 KRX 개장 직후(09:00~09:15) 진입가를 KRX 실시간 가격으로 재설정.
    이유: NXT 08:xx 선포착 종목 진입가가 NXT 기준가로 저장 → KRX 개장 후 실거래가 괴리
    2026-04-27: 동국제강 13,700원(NXT)→KRX 13,570원 / 서울반도체 13,630원 등 오차 반복
    """
    try:
        if not is_market_open():
            return
        _now_t = datetime.now().time()
        if not (dtime(9, 0) <= _now_t < dtime(9, 15)):
            return
        _market = str(s.get("market") or "").upper()
        _detect_t = str(s.get("detect_time") or s.get("detected_at") or "")
        _is_nxt_preopen = (_market == "NXT") or ("08:" in _detect_t)
        if not _is_nxt_preopen:
            return
        _code = normalize_stock_code(s.get("code", ""))
        if not _code:
            return
        _krx_cur = get_stock_price(_code)
        _krx_price = safe_int((_krx_cur or {}).get("price", 0), 0)
        if _krx_price <= 0:
            return
        _old_entry = safe_int(s.get("entry_price", 0), 0)
        if _old_entry <= 0:
            return
        _new_entry = int(_krx_price * 0.975)  # 2.5% 눌림 예상가
        if abs(_new_entry - _old_entry) > _old_entry * 0.02:  # 2% 이상 차이 시에만 갱신
            s["entry_price"] = _new_entry
            s["_nxt_entry_refreshed"] = True
            s["_nxt_entry_orig"] = _old_entry
            _log_info_msg(
                f"  🔄 NXT→KRX 진입가 재설정: {s.get('name','')}"
                f" {_old_entry:,}→{_new_entry:,}원 (KRX현재가 {_krx_price:,})"
            )
    except Exception as _e:
        _swallow_exception(_e)

def register_entry_watch(s: dict):
    entry = s.get("entry_price", 0)
    if not entry:
        return
    # v165.32 [#3]: NXT 선포착 종목 KRX 개장 직후 진입가 재설정
    _refresh_nxt_preopen_entry_to_krx(s)
    entry = s.get("entry_price", entry)  # 재설정 후 재조회
    # v163.14 [#1]: 대표진입가=현재가 즉시도달 알람 루프 방지
    # 현재가 >= 신규 진입가이면서 직전 등록과 동일한 경우 60초 쿨다운
    _cur_price_chk = safe_int(s.get("price", 0), 0)
    _code_chk = normalize_stock_code(s.get("code", ""))
    if _cur_price_chk and entry and _cur_price_chk >= entry and not s.get("_force_entry_watch"):
        _cd_key = f"{_code_chk}:{entry}"
        _last_reg = float(_entry_watch_register_cooldown.get(_cd_key, 0) or 0)
        if time.time() - _last_reg < 60:
            _log_info_msg(
                f"  ⏭ 진입가 즉시도달 쿨다운: {_resolve_stock_name(_code_chk, s.get('name',''))} "
                f"진입가{entry:,}=현재가{_cur_price_chk:,} (60초 쿨다운)"
            )
            return
        _entry_watch_register_cooldown[_cd_key] = time.time()
    if s.get("execution_setup_required") and not s.get("force_register_entry_watch"):
        _register_execution_setup_watch(s)
        return
    code = normalize_stock_code(s["code"])
    if _should_skip_terminated_rearm(s):
        _log_info_msg(f"  ⏭ 감시종료 재등록 쿨다운: {_resolve_stock_name(code, s.get('name',''))}")
        return
    stock_name = _resolve_stock_name(code, s.get("name", ""))
    if is_scoring_only_instrument(code, stock_name):
        return
    s["name"] = stock_name
    if _find_locked_entry_watch(code):
        _log_info_msg(f"  🔒 재포착 진입가 갱신 생략: {stock_name} (이미 대표 진입 확정)")
        return
    ctx = _prepare_entry_watch_registration_context(s, code, stock_name)
    if ctx is None:  # v169.5: 진입가 동일+entry_hit 상태 → 대표갱신 스킵
        return None
    if _should_skip_entry_watch_registration(ctx, _dynamic.get("regime_mode", "normal")):
        return None
    _sync_entry_watch_representative_log(s, ctx)
    _archive_prior_entry_watches(ctx["old_items"], ctx)
    _entry_watch[ctx["log_key"]] = _build_entry_watch_active_record(s, ctx)
    _save_entry_watch_active()
    _record_capture_funnel_event("watch", s, {"entry_price": ctx["entry"], "guard_mode": ctx["entry_guard_mode"]})
    _exec_speed_prewarm[code] = time.time()
    _log_info_msg(
        f"  🎯 진입가 감시 등록: {stock_name} {ctx['entry']:,}원 "
        f"(만료: {ctx['expire_days']}일 후, {_dynamic.get('regime_mode', 'normal')}장)"
    )
    return ctx["log_key"]
def _record_entry_blocked(watch: dict, reason: str, blocked_price: int):
    """가격은 도달했지만 실제 진입이 곤란한 상태를 signal_log에 기록."""
    try:
        data = {}
        try:
            data = _read_json_locked(SIGNAL_LOG_FILE)
        except Exception as e:
            _swallow_exception(e)
        target_log_key = str(watch.get("signal_log_key") or "").strip()
        now_s = datetime.now().strftime('%Y-%m-%d %H:%M:%S')
        blocked_date, blocked_clock = (now_s.split(' ', 1) + [""])[:2]
        updated = False
        for log_key, rec in data.items():
            if target_log_key and log_key != target_log_key:
                continue
            if (rec.get("code") == watch.get("code")
                    and rec.get("status") in ("추적중", "진입준비")
                    and rec.get("signal_type") == watch.get("signal_type")):
                rec["entry_blocked"] = True
                rec["entry_blocked_reason"] = str(reason or "")
                rec["entry_blocked_time"] = now_s
                rec["entry_blocked_date"] = blocked_date
                rec["entry_blocked_clock"] = blocked_clock
                rec["entry_blocked_price"] = int(blocked_price or 0)
                rec["entry_reachable_but_untradable"] = True
                updated = True
                break
        if updated:
            _write_json_atomic(SIGNAL_LOG_FILE, data, indent=2)
        # v161.3 #9: 종목별 30초 쿨다운으로 중복 경고 억제
        blocked_code = str(watch.get("code") or "")
        _cooldown_key = f"{blocked_code}_{reason}"
        _now_ts = time.time()
        if _now_ts - _entry_blocked_log_cooldown.get(_cooldown_key, 0) >= 30:
            _entry_blocked_log_cooldown[_cooldown_key] = _now_ts
            _log_warn_msg(f"  🚫 진입불가 기록: {watch.get('name','')} {reason} @ {int(blocked_price or 0):,}")
    except Exception as e:
        _log_warn_msg(f"⚠️ 진입불가 기록 오류: {e}")
def _record_entry_policy_filtered(watch: dict, reason: str, filtered_price: int):
    try:
        data = {}
        try:
            data = _read_json_locked(SIGNAL_LOG_FILE)
        except Exception as e:
            _swallow_exception(e)
        target_log_key = str(watch.get("signal_log_key") or "").strip()
        now_s = datetime.now().strftime('%Y-%m-%d %H:%M:%S')
        updated = False
        for log_key, rec in data.items():
            if target_log_key and log_key != target_log_key:
                continue
            if str(rec.get("code") or "") != str(watch.get("code") or ""):
                continue
            if rec.get("status") not in ("추적중", "진입준비"):
                continue
            rec["status"] = "정책제외"
            rec["policy_filtered"] = True
            rec["policy_filtered_reason"] = str(reason or "")
            rec["policy_filtered_time"] = now_s
            rec["policy_filtered_price"] = int(filtered_price or 0)
            updated = True
            break
        if updated:
            _write_json_atomic(SIGNAL_LOG_FILE, data, indent=2)
        _log_info_msg(f"  📴 정책제외 기록: {watch.get('name','')} {reason} @ {int(filtered_price or 0):,}")
    except Exception as e:
        _log_warn_msg(f"⚠️ 정책제외 기록 오류: {e}")
def _record_entry_dropped(watch: dict, reason: str, current_price: int):
    try:
        data = {}
        try:
            data = _read_json_locked(SIGNAL_LOG_FILE)
        except Exception as e:
            _swallow_exception(e)
        target_log_key = str(watch.get("signal_log_key") or "").strip()
        now_s = datetime.now().strftime('%Y-%m-%d %H:%M:%S')
        updated = False
        for log_key, rec in data.items():
            if target_log_key and log_key != target_log_key:
                continue
            if str(rec.get("code") or "") != str(watch.get("code") or ""):
                continue
            if rec.get("status") not in ("추적중", "진입준비"):
                continue
            rec["status"] = "근거탈락"
            rec["entry_drop_reason"] = str(reason or "")
            rec["entry_drop_time"] = now_s
            rec["entry_drop_price"] = int(current_price or 0)
            rec["signal_strength_at_detect"] = watch.get("signal_strength_at_detect", rec.get("signal_strength_at_detect", ""))
            rec["volume_ratio_at_detect"] = float(watch.get("volume_ratio_at_detect", rec.get("volume_ratio_at_detect", 0)) or 0)
            updated = True
            break
        if updated:
            _write_json_atomic(SIGNAL_LOG_FILE, data, indent=2)
        _mark_entry_termination_state(watch.get("code", ""), reason, watch.get("signal_type", ""), watch.get("execution_grade") or watch.get("grade") or "", watch.get("score", 0))
        _log_info_msg(f"  🗑 근거약화 탈락 기록: {watch.get('name','')} {reason} @ {int(current_price or 0):,}")
    except Exception as e:
        _log_warn_msg(f"⚠️ 근거약화 탈락 기록 오류: {e}")
def _record_entry_guard_followup(watch: dict, reason: str, current_price: int):
    """entry_hit 이후 취소/보류 사유를 signal_log에 기록하되 추적상태는 유지."""
    try:
        data = {}
        try:
            data = _read_json_locked(SIGNAL_LOG_FILE)
        except Exception as e:
            _swallow_exception(e)
        target_log_key = str(watch.get("signal_log_key") or "").strip()
        now_s = datetime.now().strftime('%Y-%m-%d %H:%M:%S')
        updated = False
        for log_key, rec in data.items():
            if target_log_key and log_key != target_log_key:
                continue
            if str(rec.get("code") or "") != str(watch.get("code") or ""):
                continue
            if rec.get("status") not in ("추적중", "진입준비", "진입가도달", "진입불가", "근거탈락"):
                continue
            rec["entry_guard_reason_latest"] = str(reason or "")
            rec["entry_guard_time_latest"] = now_s
            rec["entry_guard_price_latest"] = int(current_price or 0)
            rec["entry_guard_monitoring_continues"] = True
            updated = True
            break
        if updated:
            _write_json_atomic(SIGNAL_LOG_FILE, data, indent=2)
        _log_warn_msg(f"  ⚠️ 진입 보류/취소 기록: {watch.get('name','')} {reason} @ {int(current_price or 0):,}")
    except Exception as e:
        _log_warn_msg(f"⚠️ 진입 보류/취소 기록 오류: {e}")
def _entry_guard_reason_label(reason: str) -> str:
    mapping = {
        "근거약화_신호강도약함": "신호강도 약화",
        "근거약화_거래량폭락": "거래량 급감",
        "섹터약세": "섹터 평균 약세",
        "limit_up_locked": "상한가 잠김",
        "upper_limit_reached": "상한가 도달",
        "no_ask_liquidity": "매도호가 부족",
        "fake_breakout_risk": "가짜 돌파 위험",
    }
    return mapping.get(str(reason or ""), str(reason or "사유 미상"))
def _entry_watch_termination_summary(reason: str) -> tuple[str, str]:
    reason_key = str(reason or "").strip()
    mapping = {
        "근거약화_신호강도약함": ("신호강도 약화", "포착 당시 근거가 약해져 재포착 전까지 신규 진입을 보류합니다."),
        "근거약화_거래량폭락": ("거래량 급감", "포착 직후 후속 거래량이 급감해 현재 흐름은 더 보지 않는 편이 낫습니다."),
        "기간만료": ("감시 기간 만료", "정해진 감시 기간 안에 진입 근거가 다시 살아나지 않아 감시를 종료합니다."),
        "알림횟수만료": ("감시 횟수 만료", "반복 재확인에도 실행 근거가 이어지지 않아 감시를 종료합니다."),
        "정책제외": ("정책 제외", "현재 정책 기준상 실행 후보에서 제외되어 감시를 종료합니다."),
        "하방재료차단": ("하방 재료 차단", "급락/상장폐지 위험 재료가 감지되어 재포착 전까지 신규 진입을 보류합니다."),
    }
    return mapping.get(reason_key, (_entry_guard_reason_label(reason_key), "현재 포착 근거가 유지되지 않아 감시를 종료합니다."))


def _notify_entry_watch_terminated(watch: dict, reason: str, current_price: int = 0, *, detail: str = "") -> bool:
    try:
        if not isinstance(watch, dict):
            return False
        if watch.get("entry_hit") or watch.get("entry_hit_locked"):
            return False
        notice_key = f"{str(watch.get('signal_log_key') or '')}|{str(reason or '')}"
        if watch.get("termination_notice_key") == notice_key:
            return False
        if _should_skip_entry_termination_notice(watch, reason):
            return False
        label, default_detail = _entry_watch_termination_summary(reason)
        code = normalize_stock_code(watch.get("code"))
        if not code:
            return False
        name = watch.get("name") or _resolve_stock_name(code) or code
        entry = safe_int(watch.get("entry_price", 0), 0)
        price = safe_int(current_price or watch.get("last_price", 0) or watch.get("price", 0), 0)
        detect_label = _format_capture_datetime_label(
            detect_date=watch.get("detect_date", ""),
            detect_time=watch.get("detect_time", ""),
        )
        parts = [
            "🚫 <b>[감시 종료 — 재포착 전 신규 진입 보류]</b>",
            "━━━━━━━━━━━━━━━",
            f"<b>{name}</b>  <code>{code}</code>",
        ]
        signal_type = str(watch.get("signal_type") or "").strip()
        if signal_type:
            parts.append(f"원신호: {signal_type}")
        if detect_label:
            parts.append(f"포착시각: {detect_label}")
        detail_bits = []
        if price > 0:
            detail_bits.append(f"현재가 {price:,}원")
        if entry > 0:
            detail_bits.append(f"진입가 {entry:,}원")
        if detail_bits:
            parts.append("  |  ".join(detail_bits))
        parts.extend([
            "━━━━━━━━━━━━━━━",
            f"📋 사유: {label}",
            f"• {detail or default_detail}",
            "• 현재 감시에서는 제외합니다.",
            "• 다시 살아나면 새 포착 알림으로 재안내합니다.",
        ])
        send_with_chart_buttons("\n".join([part for part in parts if part]), code, name)
        watch["termination_notice_key"] = notice_key
        watch["termination_notice_reason"] = str(reason or "")
        watch["termination_notice_time"] = datetime.now().strftime('%Y-%m-%d %H:%M:%S')
        _mark_entry_termination_notice(code, reason)
        return True
    except Exception as e:
        _swallow_exception(e)
        return False


def _calc_upper_wick_ratio(cur: dict | None = None, price: int = 0) -> float:
    cur = cur if isinstance(cur, dict) else {}
    last_price = safe_int(price or cur.get("price", cur.get("stck_prpr", 0)), 0)
    open_price = safe_int(cur.get("open", cur.get("stck_oprc", last_price)), last_price)
    high_price = safe_int(cur.get("high", cur.get("stck_hgpr", cur.get("today_high", 0))), 0)
    low_price = safe_int(cur.get("low", cur.get("stck_lwpr", cur.get("today_low", 0))), 0)
    if high_price <= 0 or low_price <= 0 or high_price <= low_price:
        return 0.0
    body_top = max(open_price, last_price)
    upper = max(high_price - body_top, 0)
    ratio = upper / max(high_price - low_price, 1)
    return round(max(0.0, min(ratio, 1.0)), 3)
def _score_fake_breakout_risk(cur: dict, watch: dict, price: int, entry: int) -> dict:
    cur = cur if isinstance(cur, dict) else {}
    watch = watch if isinstance(watch, dict) else {}
    sig_type = str(watch.get("signal_type") or "").upper()
    breakout_types = {"SURGE", "EARLY_DETECT", "NEAR_UPPER", "STRONG_BUY"}
    out = {"block": False, "score": 0, "reasons": [], "required_vol": 0.0, "vol_ratio": 0.0, "upper_wick_ratio": 0.0}
    if sig_type not in breakout_types or safe_int(entry, 0) <= 0 or safe_int(price, 0) < safe_int(entry, 0):
        return out
    current_time = datetime.now().strftime("%H:%M:%S")
    change_rate = safe_float(watch.get("change_rate", _get_effective_change_rate(cur, price)), 0.0)
    vol_ratio = safe_float(watch.get("volume_ratio", 0.0), 0.0)
    if vol_ratio <= 0:
        return out
    ref_sig_type = sig_type if sig_type in ("EARLY_DETECT", "SURGE", "NEAR_UPPER", "UPPER_LIMIT") else "SURGE"
    required_vol = get_effective_volume_ratio(ref_sig_type, current_time)
    required_vol, _ = _relax_opening_general_required_volume(required_vol, ref_sig_type, change_rate, current_time, market=str(watch.get("market", cur.get("market", "")) or ""))
    upper_wick_ratio = _calc_upper_wick_ratio(cur, price)
    high_price = safe_int(cur.get("high", cur.get("stck_hgpr", cur.get("today_high", 0))), 0)
    hold_failure = bool(high_price > 0 and price <= int(high_price * 0.988))
    exec_m = watch.get("execution_metrics") or {}
    exec_score = safe_int(exec_m.get("execution_speed_score", 0), 0)
    bid_ask_ratio = _signal_bid_ask_ratio_hint(watch)
    reasons = []
    score = 0
    hard_volume_fail = vol_ratio < required_vol * FAKE_BREAKOUT_VOLUME_HARD_MULT
    soft_volume_fail = vol_ratio < required_vol * FAKE_BREAKOUT_VOLUME_SOFT_MULT
    hard_wick = upper_wick_ratio >= FAKE_BREAKOUT_UPPER_WICK_HARD
    soft_wick = upper_wick_ratio >= FAKE_BREAKOUT_UPPER_WICK_SOFT
    if hard_volume_fail:
        score += 25
        reasons.append(f"돌파 거래량 약함 ({vol_ratio:.1f}/{required_vol:.1f}배)")
    elif soft_volume_fail:
        score += 15
        reasons.append(f"돌파 거래량 기준 미달 ({vol_ratio:.1f}/{required_vol:.1f}배)")
    if hard_wick:
        score += 25
        reasons.append(f"윗꼬리 부담 큼 ({upper_wick_ratio*100:.0f}%)")
    elif soft_wick:
        score += 15
        reasons.append(f"윗꼬리 부담 ({upper_wick_ratio*100:.0f}%)")
    if hold_failure:
        score += 10
        reasons.append("돌파 유지 실패")
    if exec_score and exec_score < 48:
        score += 10
        reasons.append(f"체결 둔화 {exec_score}점")
    if 0 < bid_ask_ratio < 1.0:
        score += 10
        reasons.append(f"호가 우위 약함 {bid_ask_ratio:.1f}배")
    block = soft_volume_fail and soft_wick and (hold_failure or exec_score < 48 or (0 < bid_ask_ratio < 1.0)) and score >= 40
    out.update({"block": bool(block), "score": int(score), "reasons": reasons, "required_vol": round(required_vol, 2), "vol_ratio": round(vol_ratio, 2), "upper_wick_ratio": round(upper_wick_ratio, 3)})
    return out

def _get_trading_halt_reason_label(code: str) -> str:
    """거래정지 취소 알림에 노출할 사용자용 사유 라벨을 정리한다."""
    _fallback = "주권매매거래정지"
    try:
        persisted = _get_persisted_trading_halt(code)
        persisted_title = str((persisted or {}).get("title") or "").strip()
        if persisted_title and ("거래정지" in persisted_title or "매매정지" in persisted_title):
            return persisted_title
        cached = _dart_risk_cache.get(code)
        if not isinstance(cached, dict) or not str(cached.get("title") or "").strip():
            cached = check_dart_risk(code)
        title = str((cached or {}).get("title") or "").strip()
        if title and ("거래정지" in title or "매매정지" in title):
            return title
    except Exception as e:
        _swallow_exception(e)
    return _fallback
def _notify_trading_halt_cancel(watch: dict, use_nxt: bool = False, cur: dict | None = None) -> None:
    """v76/v87/v88: 거래정지 감지 시 entry_watch 즉시 만료 + 사용자 취소 알림.
    v162.6: 전날 등록 halt가 오늘 정상 거래 시 무음 해제 — 사용자 알람 없음."""
    code = watch.get("code", "")
    name = _resolve_stock_name(code, watch.get("name", code), cur if isinstance(cur, dict) else None)
    halt_reason = _get_trading_halt_reason_label(code)
    # v162.6: 전날 등록 halt → 오늘 정상 거래 확인 시 무음 해제 (사용자 알람 없음)
    _persisted_for_ts = _get_persisted_trading_halt(code)
    if isinstance(_persisted_for_ts, dict):
        _halt_ts = float(_persisted_for_ts.get("ts", 0) or 0)
        if _halt_ts > 0:
            _today_start = time.mktime(
                datetime.now().replace(hour=0, minute=0, second=0, microsecond=0).timetuple()
            )
            if _halt_ts < _today_start:
                # 전날 등록된 halt — 오늘 정상 거래 중이면 무음 해제만
                _clear_trading_halt_state(code, resume_title="전날 halt 오늘 정상 거래 확인 — 무음 해제", source="LIVE_MARKET")
                _clear_dart_halt_cache(code, "전날 halt 오늘 정상 거래 무음 해제")
                _log_info_msg(f"  ℹ️ {name}({code}) 전날 거래정지 기록 무음 해제 (ts={_halt_ts:.0f})")
                return
    _mark_trading_halt_state(code, title=halt_reason, name=name, source="entry_watch_cancel")
    # v165.6 [#3]: 발송 직전 현재가 재조회 — KRX 개장 직후 순간 플래그 오판 방어
    try:
        _re_cur = get_stock_price(code) if not use_nxt else get_nxt_stock_price(code)
        if _re_cur and _is_live_trading_normal(_re_cur):
            _clear_trading_halt_state(code, resume_title="발송 직전 재확인 — 정상 거래 확인", source="LIVE_MARKET")
            _clear_dart_halt_cache(code, "발송 직전 재확인 — 정상 거래")
            _log_info_msg(f"  ✅ {name}({code}) 거래정지 오판 — 발송 직전 재확인 후 무음 해제")
            return
    except Exception as _re_e:
        _swallow_exception(_re_e)
    if watch.get("halt_cancel_notified"):
        return
    watch["halt_cancel_notified"] = True
    entry = safe_int(watch.get("entry_price", 0), 0)
    ref_price = safe_int((cur or {}).get("price", 0), 0) if isinstance(cur, dict) else 0
    capture_label = _format_capture_datetime_label(
        detected_at=watch.get("detected_at"),
        detect_date=watch.get("detect_date", ""),
        detect_time=watch.get("detect_time", ""),
    )
    halt_checked_label = datetime.now().strftime('%Y-%m-%d %H:%M:%S')
    sig_labels = {
        "UPPER_LIMIT": "상한가", "NEAR_UPPER": "상한가근접", "SURGE": "급등",
        "EARLY_DETECT": "조기포착", "MID_PULLBACK": "눌림목", "ENTRY_POINT": "눌림목",
        "PRECLOSE_GAP_ENTRY": "종가선진입",
        "OPENING_GAP_ENTRY":  "시초가진입",
    }
    sig = sig_labels.get(watch.get("signal_type", ""), watch.get("signal_type", ""))
    basis_suffix = f"  <b>{ref_price:,}원</b>" if use_nxt and ref_price > 0 else ""
    nxt_notice = f"\n📡 <b>NXT 기준 가격</b>{basis_suffix}" if use_nxt else ""
    price_line = f"\n💰 {'NXT 현재가' if use_nxt else '현재가'} <b>{ref_price:,}원</b>" if ref_price > 0 else ""
    msg = (
        f"🚫 <b>[포착 취소 — 거래정지]</b>{nxt_notice}\n"
        f"━━━━━━━━━━━━━━━\n"
        f"🔵 <b>{name}</b>  <code>{code}</code>\n"
        f"원신호: {sig}  |  포착: {capture_label}\n"
        f"거래정지 확인: {halt_checked_label}\n\n"
        f"📋 사유: <b>{halt_reason}</b>"
        f"{price_line}\n"
        f"💵 기준 진입가 <b>{entry:,}원</b>\n"
        f"━━━━━━━━━━━━━━━\n"
        f"• 거래정지 해제/매매재개 확인 전까지 진입 불가\n"
        f"• 감시 종료 — 거래재개 시 재포착 대기"
    )
    try:
        send_with_chart_buttons(msg, code, name)
        _log_info_msg(f"  🚫 거래정지 취소 알림: {name} ({code})")
    except Exception as _e:
        _log_warn_msg(f"  ⚠️ 거래정지 취소 알림 오류: {_e}")
def _notify_entry_guard_followup(watch: dict, reason: str, price: int, entry: int, use_nxt: bool = False, detail: str = "") -> bool:
    reason = str(reason or "").strip()
    if not reason:
        return False
    # v74: notify_count=0이면 사용자가 진입가 도달 알림을 아직 못 받은 상태
    # → 보류/취소 알림을 먼저 보내는 것은 맥락 없는 알림이므로 차단
    if safe_int(watch.get("notify_count", 0), 0) < 1:
        return False
    now_ts = time.time()
    last_reason = str(watch.get("entry_guard_alert_reason") or "").strip()
    last_ts = float(watch.get("entry_guard_alert_ts") or 0.0)
    if last_reason == reason and (now_ts - last_ts) < ENTRY_GUARD_SAME_REASON_COOLDOWN_SEC:
        return False
    if bool(watch.get("entry_guard_alert_sent_once")):
        _log_info_msg(f"  ⏭ guard 1회성 유지: {watch.get('name','')} — 내부기록만")
        return False
    if not _should_send_entry_followup_alert(watch, "guard", reason):
        _log_warn_msg(f"  ⏭ 후속알림 통합억제(guard/{reason}): {watch.get('name','')} — 외부알림 생략")
        return False
    diff_pct = round(((price - entry) / entry) * 100, 1) if entry else 0.0
    diff_str = f"+{diff_pct:.1f}%" if diff_pct >= 0 else f"{diff_pct:.1f}%"
    sig_labels = {
        "UPPER_LIMIT": "상한가", "NEAR_UPPER": "상한가근접", "SURGE": "급등",
        "EARLY_DETECT": "조기포착", "MID_PULLBACK": "눌림목", "ENTRY_POINT": "눌림목",
        "PRECLOSE_GAP_ENTRY": "종가선진입",
        "OPENING_GAP_ENTRY":  "시초가진입",
    }
    sig = sig_labels.get(watch.get("signal_type", ""), watch.get("signal_type", ""))
    nxt_notice = "\n📡 <b>NXT 기준 가격</b>" if use_nxt else ""
    hit_time = str(watch.get("entry_hit_time") or "") or _format_capture_datetime_label(
        detect_date=watch.get('detect_date', ''), detect_time=watch.get('detect_time', '')
    )
    detail_line = f"\n📌 {detail}" if detail else ""
    send_with_chart_buttons(
        f"⚠️ <b>[진입 보류/취소 사유]</b>{nxt_notice}\n"
        f"━━━━━━━━━━━━━━━\n"
        f"🔴 <b>{watch.get('name','')}</b>  <b><code>{watch.get('code','')}</code></b>\n"
        f"원신호: {sig}  |  1차도달: {hit_time}  |  감지: {datetime.now().strftime('%Y-%m-%d %H:%M:%S')}\n\n"
        f"사유: <b>{_entry_guard_reason_label(reason)}</b>{detail_line}\n"
        f"현재가 <b>{int(price or 0):,}원</b>  ({diff_str})\n"
        f"기준 진입가 <b>{int(entry or 0):,}원</b>\n"
        f"━━━━━━━━━━━━━━━\n"
        f"• 아직 미진입이면 <b>신규 진입 보류</b>\n"
        f"• 이미 1차 진입했다면 <b>내부 모니터링은 계속 유지</b>",
        watch.get("code", ""), watch.get("name", "")
    )
    watch["entry_guard_alert_reason"] = reason
    watch["entry_guard_alert_time"] = datetime.now().strftime('%Y-%m-%d %H:%M:%S')
    watch["entry_guard_alert_ts"] = now_ts
    watch["entry_guard_alert_price"] = int(price or 0)
    watch["entry_guard_alert_sent_once"] = True
    _mark_entry_followup_alert_sent(watch, "guard", reason, price)
    _record_entry_guard_followup(watch, reason, price)
    return True
def _build_entry_phase_reasons_block(watch: dict) -> str:
    reasons = list(watch.get("reasons") or [])
    if not reasons:
        return ""
    reasons_lines = "\n".join([f"  {r}" for r in reasons[:3]])
    return f"\n📋 <b>포착 이유</b>\n{reasons_lines}\n"
def _build_entry_phase_sector_block(watch: dict) -> str:
    sector_block = ""
    try:
        sector_info = calc_sector_momentum(watch["code"], watch["name"])
        theme = str(sector_info.get("theme", "") or "").strip()
        summary = str(sector_info.get("summary", "") or "").strip()
        rising = sector_info.get("rising", []) or []
        sector_lines = []
        if theme:
            sector_lines.append(f"🏭 <b>섹터 모멘텀</b> [{theme}]")
        elif summary or rising:
            sector_lines.append("🏭 <b>섹터 모멘텀</b>")
        if summary:
            sector_lines.append(f"  {summary}")
        if rising:
            co_rise = ", ".join([
                f"{_resolve_stock_name(r['code'], r.get('name',''))} {r['change_rate']:+.1f}%"
                for r in rising[:4]
            ])
            sector_lines.append(f"  📌 동반 상승: {co_rise}")
        if sector_lines:
            sector_block = "\n" + "\n".join(sector_lines) + "\n"
    except Exception as e:
        _swallow_exception(e)
        sector_block = ""
    return sector_block
def _build_entry_phase_similar_block(similar_stats: dict) -> str:
    try:
        similar_line = _build_similar_pattern_summary_block(similar_stats, top_exposed=True)
        if similar_line:
            return f"{similar_line}\n\n"
    except Exception as e:
        _swallow_exception(e)
    return ""
def _prepare_entry_phase_alert_context(watch: dict, cur: dict, price: int, entry: int, use_nxt: bool = False, hit_ts: str | None = None) -> dict:
    diff_pct = ((price - entry) / entry * 100) if entry else 0.0
    diff_str = f"+{diff_pct:.1f}%" if diff_pct >= 0 else f"{diff_pct:.1f}%"
    stop_pct = round((watch["stop_loss"] - entry) / entry * 100, 1) if entry else 0
    tgt_pct = round((watch["target_price"] - entry) / entry * 100, 1) if entry else 0
    nxt_notice = "\n📡 <b>NXT 기준 가격</b>" if use_nxt else ""
    sig_labels = {
        "UPPER_LIMIT": "상한가", "NEAR_UPPER": "상한가근접", "SURGE": "급등",
        "EARLY_DETECT": "조기포착", "MID_PULLBACK": "눌림목", "ENTRY_POINT": "눌림목",
        "PRECLOSE_GAP_ENTRY": "종가선진입",
        "OPENING_GAP_ENTRY":  "시초가진입",
    }
    similar_stats = _get_similar_pattern_stats(
        watch["code"],
        watch.get("signal_type", ""),
        float(watch.get("change_at_detect", cur.get("change_rate", 0)) or 0),
        float(watch.get("volume_ratio", cur.get("volume_ratio", 0)) or 0),
    )
    entry_exec_metrics = get_execution_speed_metrics(watch["code"], current_price=price)
    entry_exec_block = _entry_execution_status_block(
        watch["code"],
        price=price,
        metrics=entry_exec_metrics,
        fallback_metrics=dict(watch.get("execution_metrics") or {}),
    )
    strength = _classify_signal_strength(watch, entry_exec_metrics)
    return {
        "diff_pct": diff_pct,
        "diff_str": diff_str,
        "stop_pct": stop_pct,
        "tgt_pct": tgt_pct,
        "nxt_notice": nxt_notice,
        "sig": sig_labels.get(watch.get("signal_type", ""), watch.get("signal_type", "")),
        "reasons_block": _build_entry_phase_reasons_block(watch),
        "sector_block": _build_entry_phase_sector_block(watch),
        "entry_hit_ts": str(hit_ts or datetime.now().strftime('%Y-%m-%d %H:%M:%S')),
        "similar_block": _build_entry_phase_similar_block(similar_stats),
        "entry_exec_metrics": entry_exec_metrics,
        "entry_exec_block": entry_exec_block,
        "strength": strength,
        "split_rule": _get_entry_split_rule(strength),
    }
def _send_phase1_entry_alert_message(watch: dict, cur: dict, price: int, entry: int, reach_via_recovery: bool, merge_capture_phase1: bool, ctx: dict) -> None:
    p1_pct = ctx["split_rule"]["phase1_pct"]
    strength = ctx["strength"]
    strength_emoji = {"강한": "🔥", "보통": "📊", "약한": "⚠️"}.get(strength, "📊")
    nxt_delta_block = _format_nxt_transition_delta_block(watch)
    reach_note_block = f"│ 🛠 회복모드 근접도달 허용  (+{_get_dynamic_entry_reach_slack_pct(watch)*100:.1f}%)\n" if reach_via_recovery else ""
    if merge_capture_phase1 and str(watch.get("signal_type") or "").upper() in ("MID_PULLBACK", "ENTRY_POINT"):
        merged_message = _build_integrated_pullback_phase1_message(
            cur, watch, price, entry, ctx["diff_str"], strength, p1_pct, ctx["stop_pct"], ctx["tgt_pct"], ctx["entry_hit_ts"], nxt_notice=ctx["nxt_notice"]
        )
        send_with_chart_buttons(merged_message, watch["code"], watch["name"])
    else:
        send_with_chart_buttons(
            f"🔔 <b>[1차 진입가 도달]</b>{ctx['nxt_notice']}\n"
            f"━━━━━━━━━━━━━━━\n"
            f"🔴 <b>{watch['name']}</b>  <b><code>{watch['code']}</code></b>\n"
            f"원신호: {ctx['sig']}  |  포착: {_format_capture_datetime_label(detect_date=watch.get('detect_date',''), detect_time=watch.get('detect_time',''))}  |  도달: {ctx['entry_hit_ts']}\n\n"
            f"{nxt_delta_block}{ctx['similar_block']}"
            f"{ctx['reasons_block']}"
            f"{ctx['sector_block']}"
            f"{ctx['entry_exec_block']}"
            f"━━━━━━━━━━━━━━━\n"
            f"┌─────────────────────\n"
            f"│ {strength_emoji} <b>1차 진입 구간</b>  (신호: {strength})\n"
            f"│ 📍 현재가  <b>{price:,}원</b>  ({ctx['diff_str']})\n"
            f"│ 🎯 진입가  <b>{entry:,}원</b>  ◀ 목표!\n"
            f"{reach_note_block}"
            f"│ 💰 <b>권장 진입: {p1_pct}%</b>\n"
            f"│ 🛡 손절가  <b>{watch['stop_loss']:,}원</b>  ({ctx['stop_pct']:+.1f}%)\n"
            f"│ 🏆 목표가  <b>{watch['target_price']:,}원</b>  ({ctx['tgt_pct']:+.1f}%)\n"
            f"└─────────────────────",
            watch["code"], watch["name"]
        )
    watch["phase1_price"] = price
    watch["phase1_pct"] = p1_pct
    watch["signal_strength"] = strength
    bottom_check = confirm_bottom_and_signal(
        watch,
        price,
        {"volume_ratio": cur.get("volume_ratio", 0), "execution_metrics": ctx["entry_exec_metrics"], **dict(cur or {})},
    )
    if bottom_check.get("is_bottom_confirmed") and bottom_check.get("should_send_signal"):
        bottom_title = "✅ 바닥 확인 + 재상승 신호" if bottom_check.get("signal_type") == "entry_signal" else "👀 바닥 형성 확인"
        send_with_chart_buttons(
            f"{bottom_title}{ctx['nxt_notice']}\n"
            f"━━━━━━━━━━━━━━━\n"
            f"🔴 <b>{watch['name']}</b>  <b><code>{watch['code']}</code></b>\n"
            f"{bottom_check.get('reason','')}",
            watch["code"], watch["name"]
        )
def _send_phase2_entry_alert_message(watch: dict, cur: dict, price: int, entry: int, ctx: dict) -> None:
    p1_price = watch.get("phase1_price", entry)
    p1_pct = watch.get("phase1_pct", ctx["split_rule"]["phase1_pct"])
    if not ctx["split_rule"]["phase2_allowed"]:
        p2_pct = 0
        total_pct = p1_pct
        avg_price = p1_price
        decision_emoji = "🔵"
        decision_label = "추가진입: 금지"
        p2_reasons = ["🔵 약한 신호 — 2차 추가매수 금지 대상"]
        p2_detail = "신호 강도 부족 — 1차 진입분만 유지, 추가매수 불가"
        stop_adj = "유지"
    else:
        p2_judgement = _judge_phase2_entry(watch, cur, price, ctx["entry_exec_metrics"])
        p2_decision = p2_judgement["decision"]
        p2_reasons = p2_judgement["reasons"]
        p2_detail = p2_judgement["detail"]
        if p2_decision == "가능":
            p2_pct = ctx["split_rule"]["phase2_pct"]
            total_pct = p1_pct + p2_pct
            avg_price = _calc_avg_entry_price(p1_price, price, p1_pct, p2_pct)
            decision_emoji = "✅"
            decision_label = "추가진입: 가능"
        elif p2_decision == "보류":
            p2_pct = 0
            total_pct = p1_pct
            avg_price = p1_price
            decision_emoji = "🟡"
            decision_label = "추가진입: 보류"
        else:
            p2_pct = 0
            total_pct = p1_pct
            avg_price = p1_price
            decision_emoji = "🔵"
            decision_label = "추가진입: 금지"
        stop_adj = "유지"
        if p2_decision == "가능" and p2_pct > 0:
            new_stop = int(avg_price * (1 - abs(ctx["stop_pct"]) / 100)) if ctx["stop_pct"] else watch["stop_loss"]
            if new_stop != watch["stop_loss"]:
                stop_adj = f"조정 ({watch['stop_loss']:,}→{new_stop:,}원)"
    reasons_str = "\n".join([f"  {r}" for r in p2_reasons])
    send_with_chart_buttons(
        f"🔔🔔 <b>[2차 진입 판단]</b>{ctx['nxt_notice']}\n"
        f"━━━━━━━━━━━━━━━\n"
        f"🔴 <b>{watch['name']}</b>  <b><code>{watch['code']}</code></b>\n"
        f"원신호: {ctx['sig']}  |  도달: {ctx['entry_hit_ts']}\n\n"
        f"{ctx['entry_exec_block']}"
        f"━━━━━━━━━━━━━━━\n"
        f"┌─────────────────────\n"
        f"│ {decision_emoji} <b>{decision_label}</b>\n"
        f"│ 📍 현재가  <b>{price:,}원</b>  ({ctx['diff_str']})\n"
        f"│ 💰 권장 추가비중: <b>{p2_pct}%</b>\n"
        f"│ 📊 총 누적 권장비중: <b>{total_pct}%</b>\n"
        f"│ 📐 평균단가: <b>{avg_price:,}원</b>\n"
        f"│ 🛡 손절가: <b>{stop_adj}</b>\n"
        f"├─────────────────────\n"
        f"│ <b>판단 근거</b>\n"
        f"{reasons_str}\n"
        f"│ → {p2_detail}\n"
        f"└─────────────────────",
        watch["code"], watch["name"]
    )
    # v165.45: 2차 진입 "가능" 확정 시 watch 실제 업데이트
    if p2_decision == "가능" and avg_price > 0:
        orig_stop_pct = abs(ctx["stop_pct"]) / 100 if ctx.get("stop_pct") else 0.07
        new_stop_final = int(avg_price * (1 - orig_stop_pct) / 10) * 10
        # v165.46 [1]: target_price 재계산 — avg가 높아진 경우 목표도 올려야 원래 수익률 유지
        # avg가 낮아진 경우(눌림): max(원래목표, avg기준목표) → 원래 목표 유지 (실수익률 더 개선)
        # avg가 높아진 경우(모멘텀 추가매수): avg × (1 + 원래target%) → 목표 상향
        orig_target_price = watch.get("target_price", 0)
        orig_entry_p1 = watch.get("entry_price", 0)  # 아직 갱신 전
        if orig_target_price > 0 and orig_entry_p1 > 0:
            orig_target_pct = (orig_target_price - orig_entry_p1) / orig_entry_p1
            new_target_from_avg = int(avg_price * (1 + orig_target_pct) / 10) * 10
            final_target = max(orig_target_price, new_target_from_avg)  # 낮아지는 일 없음
        else:
            final_target = orig_target_price
        # v165.46 [2]: 분할 목표가 — 1차 목표(기존) + 2차 목표(추가 상승 여지)
        # 2차 목표 = 1차 목표 + (1차 목표 - avg) × 0.5 (절반 추가 상승)
        target_phase1 = final_target
        target_phase2 = int((final_target + (final_target - avg_price) * 0.5) / 10) * 10 if final_target > avg_price else final_target
        watch["phase2_confirmed"] = True
        watch["phase2_entry_price"] = price
        watch["phase2_pct"] = p2_pct
        watch["phase2_ts"] = datetime.now().strftime('%Y-%m-%d %H:%M:%S')
        watch["entry_price_phase1"] = watch.get("entry_price", 0)  # 1차 보존
        watch["entry_price"] = avg_price   # 평균단가로 업데이트
        watch["stop_loss"] = new_stop_final  # avg 기준 손절 재계산
        watch["target_price_phase1"] = target_phase1  # 1차 목표 보존
        watch["target_price"] = target_phase1          # 현재 모니터링 기준
        watch["target_price_phase2"] = target_phase2   # 2차 목표 (추가 상승)
        try:
            _mark_entry_hit_in_signal_log(
                watch.get("code", ""),
                watch.get("signal_type", ""),
                hit_price=avg_price,
                hit_time=datetime.now().strftime('%Y-%m-%d %H:%M:%S'),
                log_key=watch.get("signal_log_key"),
                extra={
                    "phase2_confirmed": True, "phase2_avg_entry": avg_price,
                    "phase2_stop": new_stop_final, "target_price_phase1": target_phase1,
                    "target_price_phase2": target_phase2,
                },
            )
        except Exception as _ep2:
            _swallow_exception(_ep2)
        _log_info_msg(f"  ✅ 2차진입 확정 — {watch.get('name','')} avg={avg_price:,} stop={new_stop_final:,} target1={target_phase1:,} target2={target_phase2:,}")
def _finalize_entry_phase_alert(watch: dict, price: int, entry: int, reach_via_recovery: bool, ctx: dict, is_phase1: bool) -> None:
    watch['entry_hit'] = True
    watch['entry_hit_time'] = ctx["entry_hit_ts"]
    watch['entry_hit_price'] = price
    if ' ' in ctx["entry_hit_ts"]:
        watch['entry_hit_date'], watch['entry_hit_clock'] = ctx["entry_hit_ts"].split(' ', 1)
    try:
        _mark_entry_hit_in_signal_log(watch['code'], watch.get('signal_type', ''), hit_price=price, hit_time=ctx["entry_hit_ts"], log_key=watch.get('signal_log_key'))
        _record_capture_funnel_event("reached", watch, {"hit_price": int(price or 0), "recovery_reach": bool(reach_via_recovery)})
    except Exception as e:
        _swallow_exception(e)
    phase_label = "1차" if is_phase1 else "2차"
    _log_info_msg(f"  🎯 {phase_label} 진입가 도달: {watch['name']} {price:,} / 진입 {entry:,}")
def _send_entry_phase_alert(watch: dict, cur: dict, price: int, entry: int, use_nxt: bool = False, reach_via_recovery: bool = False, hit_ts: str | None = None, merge_capture_phase1: bool = False) -> bool:
    now_ts = time.time()
    last_ts = watch.get("last_notified_ts", 0)
    notify_count = safe_int(watch.get("notify_count", 0), 0)
    cooldown_sec = ENTRY_REWATCH_MINS * 60
    if notify_count >= 2:
        return False
    if now_ts - last_ts < cooldown_sec:
        return False
    watch["last_notified_ts"] = now_ts
    watch["notify_count"] = notify_count + 1
    watch["entry_reference_only"] = False
    watch["entry_reference_market"] = ""
    watch["entry_reference_reason"] = ""
    watch["entry_reference_time"] = ""
    watch["entry_reference_price"] = 0
    ctx = _prepare_entry_phase_alert_context(watch, cur, price, entry, use_nxt=use_nxt, hit_ts=hit_ts)
    if notify_count == 0 and ctx["strength"] == "약한":
        _log_suppressed_alert(
            watch["code"], watch["name"],
            "1차 정책제외 (약한 신호 관찰 전용)",
            watch.get("signal_type", ""),
            {"entry_price": entry, "filtered_price": int(price or 0), "strength": ctx["strength"]}
        )
        _record_entry_policy_filtered(watch, "약한신호_관찰전용", price)
        return False
    is_phase1 = (notify_count == 0)
    if is_phase1:
        _send_phase1_entry_alert_message(watch, cur, price, entry, reach_via_recovery, merge_capture_phase1, ctx)
    else:
        _send_phase2_entry_alert_message(watch, cur, price, entry, ctx)
    _finalize_entry_phase_alert(watch, price, entry, reach_via_recovery, ctx, is_phase1)
    return True
def _should_immediate_first_entry_hit_from_signal(signal: dict | None = None, watch: dict | None = None) -> bool:
    signal = signal if isinstance(signal, dict) else {}
    watch = watch if isinstance(watch, dict) else {}
    price = safe_int(signal.get("price", 0), 0)
    entry = safe_int(watch.get("entry_price", signal.get("entry_price", 0)), 0)
    return bool(price > 0 and entry > 0 and price <= entry)

def _sync_watch_entry_hit_from_price(watch: dict | None, price: int) -> bool:
    watch = watch if isinstance(watch, dict) else {}
    entry = safe_int(watch.get("entry_price", 0), 0)
    if price > 0 and entry > 0 and price <= entry and not (watch.get("entry_hit") or watch.get("entry_hit_locked")):
        watch["entry_hit"] = True
        watch.setdefault("entry_hit_time", datetime.now().strftime("%Y-%m-%d %H:%M:%S"))
        watch.setdefault("entry_hit_price", int(price))
        try:
            _save_entry_watch_active()
        except Exception as e:
            _swallow_exception(e)
        return True
    return False

def _is_watch_effectively_entry_hit(watch: dict | None, current_price: int = 0) -> bool:
    watch = watch if isinstance(watch, dict) else {}
    if watch.get("entry_hit") or watch.get("entry_hit_locked"):
        return True
    entry = safe_int(watch.get("entry_price", 0), 0)
    return bool(entry > 0 and safe_int(current_price, 0) > 0 and safe_int(current_price, 0) <= entry)

def _maybe_send_immediate_entry_hit_from_signal(signal: dict, watch_key: str | None = None, merge_capture_phase1: bool = False) -> bool:
    if not isinstance(signal, dict):
        return False
    if not watch_key or watch_key not in _entry_watch:
        return False
    watch = _entry_watch.get(watch_key) or {}
    if not isinstance(watch, dict) or watch.get("entry_hit_locked"):
        return False
    # v161.13: 포착 시점 저장 가격 대신 실시간 현재가 재조회
    code = str(signal.get("code", "") or "").strip()
    live_cur = {}
    live_price = 0
    try:
        if str(signal.get("market", "") or "").upper() == "NXT" and is_nxt_open():
            live_cur = get_nxt_stock_price(code) or {}
        else:
            live_cur = get_stock_price(code) or {}
        live_price = safe_int(live_cur.get("price", 0), 0)
    except Exception as e:
        _swallow_exception(e)
    price = live_price if live_price > 0 else safe_int(signal.get("price", 0), 0)
    # 실시간 현재가로 signal 업데이트
    merged_signal = dict(signal)
    if live_price > 0:
        merged_signal["price"] = live_price
        merged_signal.update({k: v for k, v in live_cur.items() if k not in ("code", "name")})
    entry = safe_int(watch.get("entry_price", 0), 0)
    if not _should_immediate_first_entry_hit_from_signal(merged_signal, watch):
        return False
    blocked_reason = _detect_entry_block_reason(merged_signal, watch, price, entry)
    if blocked_reason:
        return False
    watch["entry_hit"] = True
    watch["entry_hit_time"] = datetime.now().strftime('%Y-%m-%d %H:%M:%S')
    watch["entry_hit_price"] = int(price)
    # v169.0 [#1]: 즉시 entry_hit 기록 시 signal_log도 동기화
    # 이유: watch에만 entry_hit=True 기록 → 10분 후 _purge_stale_entry_watch_hits가
    #       signal_log 기준으로 체크 시 entry_hit=False 판단 → watch 삭제 → 재등록 → 재트리거
    try:
        _mark_entry_hit_in_signal_log(
            code,
            str(signal.get("signal_type") or ""),
            hit_price=int(price),
            hit_time=watch["entry_hit_time"],
        )
    except Exception as _eh_e:
        _swallow_exception(_eh_e)
    return _send_entry_phase_alert(watch, merged_signal, price, entry, use_nxt=bool(merged_signal.get("use_nxt") or str(merged_signal.get("market") or "").upper()=="NXT"), reach_via_recovery=False, merge_capture_phase1=merge_capture_phase1)
def _get_effective_change_rate(cur: dict, price: int = 0) -> float:
    """KIS change_rate와 전일종가 대비 실계산 등락률 중 절대값이 큰 값을 사용."""
    try:
        api_rate = float(cur.get("change_rate", 0.0) or 0.0)
    except Exception as e:
        _swallow_exception(e)  # v105 structured silent-exception log
        api_rate = 0.0
    prev_close = safe_int(cur.get("prev_close", 0), 0)
    current_price = safe_int(price or cur.get("price", 0), 0)
    calc_rate = 0.0
    if prev_close > 0 and current_price > 0:
        try:
            calc_rate = ((current_price - prev_close) / prev_close) * 100.0
        except Exception as e:
            _swallow_exception(e)  # v105 structured silent-exception log
            calc_rate = 0.0
    return calc_rate if abs(calc_rate) > abs(api_rate) else api_rate
def _detect_entry_block_reason(cur: dict, watch: dict, price: int, entry: int) -> str:
    """가격은 왔지만 실제 체결이 어렵다고 볼 수 있는 상태를 판별."""
    change_rate = _get_effective_change_rate(cur, price)
    ask_qty = safe_int(cur.get("ask_qty", 0), 0)
    bid_qty = safe_int(cur.get("bid_qty", 0), 0)
    sig_type = str(watch.get("signal_type") or "").upper()
    # v161.29: upper_price(상한가 가격) 직접 비교 — change_rate>=29% 보다 정확
    upper_price = safe_int(cur.get("upper_price", 0), 0)
    prdy_vrss_sign = str(cur.get("prdy_vrss_sign", "") or "")
    # v163.9 [#1]: upper_price 실제 도달 여부로 1차 검증
    # upper_price가 수신된 경우 — price >= upper_price일 때만 진짜 상한가로 판정
    # ask_qty=0 + change_rate 높음만으로는 upper_limit_reached 판정 금지 → no_ask_liquidity로 downgrade
    if upper_price > 0:
        is_upper_price_hit = price >= upper_price
    else:
        # upper_price 미수신(0) — 기존 로직 유지 (보수적)
        is_upper_price_hit = (prdy_vrss_sign == "1") or change_rate >= 29.0
    upper_like = is_upper_price_hit or sig_type in ("UPPER_LIMIT", "NEAR_UPPER")
    if upper_like and ask_qty <= 0 and bid_qty > 0:
        return "limit_up_locked"
    if upper_like and ask_qty <= 0:
        # v163.9 [#1]: 실제 upper_price 미도달이면 no_ask_liquidity로 downgrade
        # 대한전선 사례: change_rate 높고 ask_qty 일시 0 → 오판 방지
        if upper_price > 0 and price < upper_price and sig_type not in ("UPPER_LIMIT", "NEAR_UPPER"):
            return "no_ask_liquidity"
        return "upper_limit_reached"
    if upper_like and sig_type in ("MID_PULLBACK", "ENTRY_POINT"):
        return "upper_limit_reached"
    fake_breakout = _score_fake_breakout_risk(cur, watch, price, entry)
    if fake_breakout.get("block"):
        return "fake_breakout_risk"
    if ask_qty <= 0:
        return "no_ask_liquidity"
    return ""
def _find_existing_entry_hit_watch(code: str):
    norm_code = normalize_stock_code(code)
    if not norm_code:
        return None, None
    for _ek, _ew in list(_entry_watch.items()):
        if not isinstance(_ew, dict):
            continue
        if normalize_stock_code((_ew or {}).get("code")) != norm_code:
            continue
        if _ew.get("entry_hit") or _ew.get("entry_hit_locked"):
            return _ek, _ew
    return None, None
def _is_general_capture_first_entry_reached(signal: dict | None = None, live_price: int = 0) -> bool:
    signal = signal if isinstance(signal, dict) else {}
    if signal.get("first_entry_reached") is True:
        return True
    entry_price = safe_int(signal.get("entry_price", 0), 0)
    # v161.43: live_price 우선, 없으면 signal price 사용. 0이면 판단 포기하지 않고 entry_price만으로 체크
    price_now = safe_int(live_price, 0) or safe_int(signal.get("price", 0), 0)
    if entry_price > 0 and price_now > 0 and price_now <= entry_price:
        return True
    # v161.43: signal에 저장된 change_rate가 음수(-) 또는 0에 가까우면 진입가 도달 가능성 — 추가 체크
    # analyze()에서 first_entry_reached 미세팅 케이스 보완: price가 entry 이하면 True
    if entry_price > 0 and price_now <= 0:
        # price 정보 없을 때는 False 유지 (잘못된 헤더 방지)
        return False
    code = normalize_stock_code(signal.get("code", ""))
    if code and signal.get("_allow_existing_entry_hit_header"):
        try:
            _, watch = _find_existing_entry_hit_watch(code)
            if isinstance(watch, dict) and (watch.get("entry_hit") or watch.get("entry_hit_locked")):
                return True
        except Exception as e:
            _swallow_exception(e)
    return False
def _apply_first_entry_reached_header_line(header_line: str, signal: dict | None = None, live_price: int = 0) -> str:
    line = str(header_line or "").strip()
    if not line or "1차 진입가 도달" in line:
        return line
    if not _is_general_capture_first_entry_reached(signal, live_price=live_price):
        return line
    if ']</b>' in line:
        return line.replace(']</b>', ' + 1차 진입가 도달]</b>', 1)
    return line + ' + 1차 진입가 도달'
def _should_send_phase2_upgrade_alert(watch: dict, new_sig_type: str, decision: str) -> bool:
    if not isinstance(watch, dict):
        return True
    last_sig = str(watch.get("phase2_upgrade_alert_signal_type") or "").upper()
    last_decision = str(watch.get("phase2_upgrade_alert_decision") or "").strip()
    last_ts = float(watch.get("phase2_upgrade_alert_ts") or 0.0)
    if last_sig != str(new_sig_type or "").upper() or last_decision != str(decision or "").strip():
        return True
    return (time.time() - last_ts) >= PHASE2_UPGRADE_ALERT_COOLDOWN_SEC
def _mark_phase2_upgrade_alert_sent(watch: dict, new_sig_type: str, decision: str, price: int = 0) -> None:
    if not isinstance(watch, dict):
        return
    watch["phase2_upgrade_alert_signal_type"] = str(new_sig_type or "").upper()
    watch["phase2_upgrade_alert_decision"] = str(decision or "").strip()
    watch["phase2_upgrade_alert_time"] = datetime.now().strftime('%Y-%m-%d %H:%M:%S')
    watch["phase2_upgrade_alert_ts"] = time.time()
    watch["phase2_upgrade_alert_price"] = int(price or 0)
def _is_entry_followup_actionable_transition(last_kind: str, last_value: str, new_kind: str, new_value: str) -> bool:
    last_kind = str(last_kind or "").strip().lower()
    last_value = str(last_value or "").strip()
    new_kind = str(new_kind or "").strip().lower()
    new_value = str(new_value or "").strip()
    if new_kind == "phase2" and new_value == "가능":
        return not (last_kind == "phase2" and last_value == "가능")
    return False
def _should_send_entry_followup_alert(watch: dict, kind: str, value: str) -> bool:
    if not isinstance(watch, dict):
        return True
    last_ts = float(watch.get("entry_followup_alert_ts") or 0.0)
    if last_ts <= 0:
        return True
    now_ts = time.time()
    if (now_ts - last_ts) >= ENTRY_FOLLOWUP_ALERT_COOLDOWN_SEC:
        return True
    last_kind = str(watch.get("entry_followup_alert_kind") or "").strip().lower()
    last_value = str(watch.get("entry_followup_alert_value") or "").strip()
    if _is_entry_followup_actionable_transition(last_kind, last_value, kind, value):
        return True
    return False
def _mark_entry_followup_alert_sent(watch: dict, kind: str, value: str, price: int = 0) -> None:
    if not isinstance(watch, dict):
        return
    watch["entry_followup_alert_kind"] = str(kind or "").strip().lower()
    watch["entry_followup_alert_value"] = str(value or "").strip()
    watch["entry_followup_alert_time"] = datetime.now().strftime('%Y-%m-%d %H:%M:%S')
    watch["entry_followup_alert_ts"] = time.time()
    watch["entry_followup_alert_price"] = int(price or 0)
def _is_truthy_market_flag(v) -> bool:
    s = str(v or "").strip().upper()
    return s in ("Y", "1", "TRUE", "T", "VI", "HALT", "STOP")
def _is_trade_resume_title(title: str) -> bool:
    title = str(title or "").strip()
    if not title:
        return False
    resume_kws = ("거래재개", "매매재개", "거래정지해제", "매매정지해제", "정지해제")
    if any(kw in title for kw in resume_kws):
        return True
    if ("거래정지" in title or "매매정지" in title) and "해제" in title:
        return True
    return False
def _is_trade_halt_title(title: str) -> bool:
    title = str(title or "").strip()
    if not title:
        return False
    if _is_trade_resume_title(title):
        return False
    if not ("거래정지" in title or "매매정지" in title):
        return False
    ambiguous_kws = ("기간변경", "정지및정지해제", "및정지해제")
    if any(kw in title for kw in ambiguous_kws):
        return False
    return True
def _should_persist_trade_halt_title(title: str, rcept_dt: str = "") -> bool:
    if not _is_trade_halt_title(title):
        return False
    today_str = datetime.now().strftime("%Y%m%d")
    return str(rcept_dt or "") == today_str
def _has_explicit_halt_market_flag(cur: dict | None) -> bool:
    if not isinstance(cur, dict):
        return False
    # v165.1: VI발동 코드(55/56/"V"/"4") = 임시 거래정지이지만 2분 후 자동해제 — 실제 거래정지 아님
    # temp_stop_yn="Y"는 VI발동 포함이므로 raw_status_code에서 분리해 raw_temp_stop으로 별도 처리
    _VI_CODES = {"55", "56", "V", "4", "VI"}
    for _k in ("vi_cls_code", "vi_yn", "trht_yn", "halt_yn", "is_vi", "raw_status_code"):
        _raw = cur.get(_k)
        _v = str(_raw or "").strip().upper()
        if not _v:
            continue
        if _k in ("vi_cls_code", "raw_status_code") and _v in _VI_CODES:
            continue  # VI발동 코드 (거래정지 아님)
        if _is_truthy_market_flag(_raw):
            return True
        if _v in ("Y", "1", "T", "TRUE", "H", "2"):
            return True
    # raw_temp_stop(temp_stop_yn) — VI발동 시 "Y"이므로 vi_cls_code와 교차 확인
    _temp = str(cur.get("raw_temp_stop", "") or "").strip().upper()
    if _temp in ("Y", "1"):
        _vi = str(cur.get("vi_cls_code", "") or "").strip().upper()
        if _vi in _VI_CODES:
            return False  # VI에 의한 임시정지 — 거래정지 아님
        return True
    # v165.6 [#2] / v165.8 보강: raw_trht_yn/raw_halt_yn — 정상 거래 교차 검증
    # no_ask_liquidity 상태(ask=0)여도 today_vol > 0이면 정상 거래 중 — 무시
    # 실제 거래정지는 price=0 AND vol=0 AND ask=0 AND bid=0 이 모두 성립
    for _rk in ("raw_trht_yn", "raw_halt_yn"):
        _rv = str(cur.get(_rk, "") or "").strip().upper()
        if _rv not in ("Y", "1"):
            continue
        _price = safe_int(cur.get("price", 0), 0)
        _ask   = safe_int(cur.get("ask_qty", cur.get("ask_vol", cur.get("askp1", 0))), 0)
        _bid   = safe_int(cur.get("bid_qty", cur.get("bid_vol", cur.get("bidp1", 0))), 0)
        _vol   = safe_int(cur.get("today_vol", cur.get("volume", 0)), 0)
        # price > 0 OR vol > 0 → 거래 이력 있음 → 오판 무시 (ask=0은 순간적으로 발생 가능)
        if _price > 0 or _vol > 0:
            continue
        # ask 또는 bid만 있어도 호가 형성 중 → 정상
        if _ask > 0 or _bid > 0:
            continue
        return True  # price=0, vol=0, ask=0, bid=0 → 실제 거래정지
    return False
def _is_live_trading_normal(cur: dict | None) -> bool:
    if not isinstance(cur, dict):
        return False
    if _has_explicit_halt_market_flag(cur):
        return False
    price = safe_int(cur.get("price", 0), 0)
    ask_qty = safe_int(cur.get("ask_qty", cur.get("ask_vol", 0)), 0)
    bid_qty = safe_int(cur.get("bid_qty", cur.get("bid_vol", 0)), 0)
    ask_price = safe_int(cur.get("ask_price", cur.get("askp1", 0)), 0)
    bid_price = safe_int(cur.get("bid_price", cur.get("bidp1", 0)), 0)
    today_vol = safe_int(cur.get("today_vol", cur.get("volume", 0)), 0)
    if price <= 0:
        return False
    if ask_qty > 0 or bid_qty > 0 or ask_price > 0 or bid_price > 0:
        return True
    if is_market_open() and today_vol > 0:
        return True
    return False
def _clear_dart_halt_cache(code: str, reason: str = "") -> None:
    code = normalize_stock_code(code)
    if not code:
        return
    cached = _dart_risk_cache.get(code)
    if isinstance(cached, dict):
        title = str(cached.get("title") or "")
        if _is_trade_halt_title(title) or _is_trade_resume_title(title):
            _dart_risk_cache[code] = {"is_risk": False, "title": "", "ts": time.time()}
    if reason:
        _log_info_msg(f"  ✅ DART halt 캐시 해제: {code} ({reason})")
def _maybe_clear_false_trading_halt(code: str, persisted: dict | None = None, cur: dict | None = None, reason: str = "") -> bool:
    code = normalize_stock_code(code)
    if not code or not isinstance(cur, dict) or not _is_live_trading_normal(cur):
        return False
    rec = persisted if isinstance(persisted, dict) else _get_persisted_trading_halt(code)
    if not isinstance(rec, dict) or not rec:
        return False
    source = str(rec.get("source") or "")
    if source == "KIS_FLAG":
        return False
    # v162.6: source/title 필터 제거 — 실시간 정상 거래 확인 시 KIS_FLAG 제외 전 소스 해제
    # 기존: DART/DART_CACHE/run_dart_intraday 소스만 해제 → dispatch_block·entry_watch_cancel 소스는
    #       정상 거래 중에도 해제 안 돼 [포착 취소—거래정지] 오발송 발생
    _clear_trading_halt_state(code, resume_title=reason or "실시간 정상 거래 확인", source="LIVE_MARKET")
    _clear_dart_halt_cache(code, reason or "실시간 정상 거래 확인")
    return True
def _is_krx_vi_reference_mode(cur: dict, code: str) -> bool:
    """KRX 장중이지만 NXT 참고만 허용할 만한 VI/거래정지 유사 상태인지 보수적으로 판별.
    v163.5: 호가 소멸(ask_qty=0, bid_qty=0) 단독 조건 제거
    - 정규장 개장 직후 호가가 아직 안 붙은 정상 상태도 차단하는 오판 발생
    - 실제 VI/거래정지는 API 플래그(vi_cls_code 등)로만 판별
    """
    if not is_market_open():
        return False
    if not (is_nxt_open() and is_nxt_listed(code)):
        return False
    for _k in ("vi_cls_code", "vi_yn", "trht_yn", "halt_yn", "raw_temp_stop", "is_vi", "raw_status_code"):
        if _is_truthy_market_flag(cur.get(_k)):
            return True
    return False
def _is_trading_halt(code: str, cur: dict | None = None) -> bool:
    """v76/v88/v92: 종목 거래정지 여부 통합 판별.
    영속 halt 상태, KIS API 플래그, DART 거래정지 공시 중 하나라도 감지되면 True.
    v92: DART halt는 same-day 직접 거래정지 제목만 영속 저장하며, 장중 실시간 정상 거래가 확인되면 DART 기반 오판을 자동 해제.
    cur: get_stock_price/get_nxt_stock_price 반환값 (없으면 API 플래그 체크 생략)
    주의: 장마감 후 호가 소멸은 정상이므로 호가 기반 판별은 사용하지 않음.
    """
    code = normalize_stock_code(code)
    if not code:
        return False
    # 0) 영속 거래정지 상태 체크 (재시작 후 재포착 방지)
    persisted = _get_persisted_trading_halt(code)
    if persisted:
        if _maybe_clear_false_trading_halt(code, persisted=persisted, cur=cur, reason="실시간 정상 거래 확인"):
            persisted = {}
        else:
            return True
    # 1) KIS API 응답 플래그 체크 (명시적 정지 플래그만)
    if _has_explicit_halt_market_flag(cur):
        _mark_trading_halt_state(code, title="주권매매거래정지", name=_resolve_stock_name(code, (cur or {}).get("name", code), cur or {}), source="KIS_FLAG")
        return True
    # 장중 실시간 정상 거래가 확인되면 DART halt보다 실제 거래 상태를 우선
    if _is_live_trading_normal(cur):
        _clear_dart_halt_cache(code)
        return False
    # 2) DART 캐시 체크 (same-day 직접 거래정지 제목만 인정)
    cached = _dart_risk_cache.get(code)
    if isinstance(cached, dict) and cached.get("is_risk"):
        title = str(cached.get("title") or "")
        if _is_trade_resume_title(title):
            _clear_dart_halt_cache(code, "거래재개/정지해제 제목")
            return False
        if _is_trade_halt_title(title):
            _ts = cached.get("ts", 0)
            if _ts == 0:
                _mark_trading_halt_state(code, title=title, source="DART_CACHE")
                return True
            _today_start = time.mktime(datetime.now().replace(
                hour=0, minute=0, second=0, microsecond=0).timetuple())
            if _ts >= _today_start:
                return True
    return False
def _record_entry_reference_reach(watch: dict, ref_price: int, market: str = "NXT", reason: str = "krx_vi_reference"):
    """KRX VI/거래정지 유사 상태에서 NXT 참고 도달만 기록."""
    try:
        data = {}
        try:
            data = _read_json_locked(SIGNAL_LOG_FILE)
        except Exception as e:
            _swallow_exception(e)
        target_log_key = str(watch.get("signal_log_key") or "").strip()
        now_s = datetime.now().strftime('%Y-%m-%d %H:%M:%S')
        ref_date, ref_clock = (now_s.split(' ', 1) + [""])[:2]
        updated = False
        for log_key, rec in data.items():
            if target_log_key and log_key != target_log_key:
                continue
            if (rec.get("code") == watch.get("code")
                    and rec.get("status") in ("추적중", "진입준비")
                    and rec.get("signal_type") == watch.get("signal_type")):
                rec["entry_reference_only"] = True
                rec["entry_reference_market"] = str(market or "")
                rec["entry_reference_reason"] = str(reason or "")
                rec["entry_reference_time"] = now_s
                rec["entry_reference_date"] = ref_date
                rec["entry_reference_clock"] = ref_clock
                rec["entry_reference_price"] = int(ref_price or 0)
                updated = True
                break
        if updated:
            _write_json_atomic(SIGNAL_LOG_FILE, data, indent=2)
        _log_info_msg(f"  🟦 참고도달 기록: {watch.get('name','')} {market} @ {int(ref_price or 0):,}")
    except Exception as e:
        _log_warn_msg(f"⚠️ 참고도달 기록 오류: {e}")
def _record_entry_miss(watch: dict, reason: str, final_price: int):
    """진입가 미도달 만료 시 signal_log에 기록 → auto_tune 학습"""
    try:
        data = {}
        try:
            data = _read_json_locked(SIGNAL_LOG_FILE)
        except Exception as e:
            _swallow_exception(e)
        entry     = watch.get("entry_price", 0)
        miss_away = round((final_price - entry) / entry * 100, 1) if entry else 0
        peak      = watch.get("peak_price", final_price)
        peak_away = round((peak - entry) / entry * 100, 1) if entry else 0
        target_log_key = str(watch.get("signal_log_key") or "").strip()
        for log_key, rec in data.items():
            if target_log_key and log_key != target_log_key:
                continue
            if (rec.get("code") == watch["code"]
                    and rec.get("status") in ("추적중", "진입준비")
                    and rec.get("signal_type") == watch.get("signal_type")):
                rec["entry_miss"]      = reason
                rec["entry_miss_away"] = miss_away
                rec["entry_peak_away"] = peak_away
                rec["miss_count"]      = watch.get("miss_count", 0)
                if watch.get("entry_reference_market") or rec.get("entry_reference_market"):
                    rec["status"]      = "NXT참고도달"
                    rec["pnl_pct"]     = 0.0
                    _ref_market = watch.get("entry_reference_market") or rec.get("entry_reference_market") or "NXT"
                    _ref_reason = watch.get("entry_reference_reason") or rec.get("entry_reference_reason") or reason
                    rec["exit_reason"] = f"{_ref_market}참고도달_{_ref_reason}"
                elif watch.get("entry_blocked") or rec.get("entry_blocked"):
                    rec["status"]      = "진입불가"
                    rec["pnl_pct"]     = 0.0
                    _blk_reason = watch.get("entry_blocked_reason") or rec.get("entry_blocked_reason") or reason
                    rec["exit_reason"] = f"진입불가_{_blk_reason}"
                else:
                    rec["status"]      = "진입미달"
                    rec["pnl_pct"]     = 0.0
                    rec["exit_reason"] = f"진입미달_{reason}"
                break
        _write_json_atomic(SIGNAL_LOG_FILE, data, indent=2)
        _log_info_msg(f"  📝 진입미달 기록: {watch['name']} {reason} (진입가 대비 {miss_away:+.1f}%)")
    except Exception as e:
        _log_warn_msg(f"⚠️ 진입미달 기록 오류: {e}")
# [v58] 상승이탈 후속 추적 — 이탈 종목이 이후 얼마나 더 올랐는지 기록
def _track_escape_aftermath() -> list:
    """
    당일 상승이탈된 종목의 현재가를 조회해 '이탈 후 추가 상승률'을 signal_log에 기록.
    run_daily_self_audit 시점에 호출 → entry_pullback_ratio 정밀 조정 데이터로 활용.
    반환: 변경 요약 리스트
    """
    changes = []
    try:
        data = _read_json_locked(SIGNAL_LOG_FILE) if os.path.exists(SIGNAL_LOG_FILE) else {}
        if not isinstance(data, dict):
            return changes
        today = _now_kst().strftime("%Y%m%d")
        updated = False
        for log_key, rec in data.items():
            if not isinstance(rec, dict):
                continue
            # 오늘 상승이탈된 종목만
            if str(rec.get("status") or "") != "진입미달":
                continue
            if "상승이탈" not in str(rec.get("exit_reason") or ""):
                continue
            if str(rec.get("detect_date") or "")[:8] != today and str(rec.get("exit_date") or "")[:8] != today:
                continue
            # 이미 후속 추적 완료된 건은 건너뛰기
            if rec.get("escape_aftermath_pct") is not None:
                continue
            code = normalize_stock_code(rec.get("code"))
            if not code:
                continue
            entry = safe_int(rec.get("entry_price", 0), 0)
            if not entry:
                continue
            # 현재가 조회
            try:
                cur = get_stock_price(code)
                price = cur.get("price", 0)
                if not price:
                    nxt_cur = get_nxt_stock_price(code)
                    price = nxt_cur.get("price", 0)
                if not price:
                    continue
            except Exception as e:
                _swallow_exception(e)  # v105 structured silent-exception log
                continue
            # 진입가 대비 현재가 상승률 = "진입했더라면 얼마나 벌었을까"
            aftermath_pct = round((price - entry) / entry * 100, 2)
            # 이탈 시점 가격 대비 추가 상승률
            escape_price = safe_int(rec.get("entry_peak_away", 0), 0)
            miss_away = float(rec.get("entry_miss_away", 0) or 0)
            rec["escape_aftermath_pct"] = aftermath_pct
            rec["escape_aftermath_price"] = price
            rec["escape_aftermath_ts"] = _now_kst().strftime("%Y-%m-%d %H:%M:%S")
            updated = True
            name = rec.get("name", code)
            changes.append(
                f"📊 상승이탈 후속: {name} 진입가 {entry:,}원 → 현재 {price:,}원 ({aftermath_pct:+.1f}%)"
            )
        if updated:
            _write_json_atomic(SIGNAL_LOG_FILE, data, indent=2)
        # entry_pullback_ratio 정밀 조정 데이터로 활용
        if changes:
            _refine_pullback_ratio_from_escape(data)
    except Exception as e:
        _log_warn_msg(f"⚠️ 상승이탈 후속 추적 오류: {e}")
    return changes
def _refine_pullback_ratio_from_escape(data: dict):
    """
    상승이탈 후속 추적 데이터 기반 entry_pullback_ratio 미세 조정.
    이탈 후에도 계속 오른 종목이 많으면 → 진입가를 좀 더 현재가에 가깝게 (완화)
    이탈 후 하락한 종목이 많으면 → 현재 진입가 설정이 적절 (유지)
    """
    try:
        # 최근 20건의 상승이탈 후속 데이터
        escape_recs = [
            rec for rec in data.values()
            if isinstance(rec, dict)
            and rec.get("escape_aftermath_pct") is not None
            and "상승이탈" in str(rec.get("exit_reason") or "")
        ]
        escape_recs.sort(key=lambda r: str(r.get("escape_aftermath_ts") or ""))
        recent = escape_recs[-20:]
        if len(recent) < 5:
            return
        # 이탈 후 +10% 이상 더 오른 종목 비율
        still_rising = [r for r in recent if float(r.get("escape_aftermath_pct", 0) or 0) >= 10.0]
        still_rising_pct = len(still_rising) / len(recent)
        # 이탈 후 0% 이하(진입가 아래)로 내려간 종목 비율
        came_back = [r for r in recent if float(r.get("escape_aftermath_pct", 0) or 0) <= 0]
        came_back_pct = len(came_back) / len(recent)
        avg_aftermath = sum(float(r.get("escape_aftermath_pct", 0) or 0) for r in recent) / len(recent)
        cur_ratio = round(float(_dynamic.get('entry_pullback_ratio', ENTRY_PULLBACK_RATIO) or ENTRY_PULLBACK_RATIO), 2)
        # 이탈 후 계속 오르는 비율이 60% 이상 + 평균 +15% 이상 → 완화 압력
        if still_rising_pct >= 0.60 and avg_aftermath >= 15.0 and cur_ratio > ENTRY_PULLBACK_RATIO_MIN:
            new_ratio = round(max(ENTRY_PULLBACK_RATIO_MIN, cur_ratio - 0.3), 2)
            if new_ratio != cur_ratio:
                _dynamic['entry_pullback_ratio'] = new_ratio
                _save_dynamic_params()
                _log_info_msg(
                    f"  📊 이탈 후속 기반 진입가 완화: {cur_ratio:.2f}→{new_ratio:.2f} "
                    f"(이탈 후 +10%↑ {len(still_rising)}/{len(recent)}, 평균 {avg_aftermath:+.1f}%)"
                )
        # 이탈 후 되돌아온 비율이 40% 이상 → 현재 설정 적절, 보수화 필요 없음
        elif came_back_pct >= 0.40:
            _log_info_msg(f"  📊 이탈 후속 분석: 이탈 후 되돌림 {len(came_back)}/{len(recent)} — 현재 비율 {cur_ratio:.2f} 유지")
    except Exception as e:
        _log_warn_msg(f"⚠️ 이탈 후속 비율 조정 오류: {e}")
def _mark_entry_hit_in_signal_log(code: str, signal_type: str, hit_price: int | None = None, hit_time: str | None = None, log_key: str | None = None, extra: dict | None = None) -> None:
    """진입가 도달(HIT) 이벤트를 signal_log에 기록. (가상진입/학습용)
    extra: 2차 진입 확정 시 추가 필드 저장 (phase2_confirmed, phase2_avg_entry, phase2_stop 등)
    """
    try:
        data = {}
        try:
            data = _read_json_locked(SIGNAL_LOG_FILE)
        except Exception as e:
            _swallow_exception(e)  # v105 structured silent-exception log
            return
        now_s = str(hit_time or datetime.now().strftime('%Y-%m-%d %H:%M:%S'))
        hit_date, hit_clock = "", ""
        if " " in now_s:
            hit_date, hit_clock = now_s.split(" ", 1)
        elif len(now_s) >= 10:
            hit_date = now_s[:10]
        target_key = ""
        if log_key and log_key in data:
            _rec = data.get(log_key) or {}
            if _rec.get('code') == code and _rec.get('status') in ('추적중', '진입준비'):
                target_key = log_key
        if not target_key:
            candidates = []
            for _k, rec in data.items():
                if rec.get('code') == code and rec.get('status') in ('추적중', '진입준비') and rec.get('signal_type') == signal_type:
                    detect_key = f"{rec.get('detect_date','')}{rec.get('detect_time','')}".replace(":", "")
                    candidates.append((detect_key, _k))
            if candidates:
                candidates.sort()
                target_key = candidates[-1][1]
        if target_key:
            rec = data.get(target_key) or {}
            rec['entry_hit'] = True
            rec['entry_hit_time'] = now_s
            rec['entry_blocked'] = False
            rec['entry_blocked_reason'] = ''
            rec['entry_reachable_but_untradable'] = False
            rec['entry_reference_only'] = False
            rec['entry_reference_market'] = ''
            rec['entry_reference_reason'] = ''
            rec['entry_reference_time'] = ''
            rec['entry_reference_date'] = ''
            rec['entry_reference_clock'] = ''
            rec['entry_reference_price'] = 0
            if hit_price:
                rec['entry_hit_price'] = int(hit_price)
            if hit_date:
                rec['entry_hit_date'] = hit_date
            if hit_clock:
                rec['entry_hit_clock'] = hit_clock
            # v165.45: 2차 진입 확정 시 extra 필드 저장 (학습 데이터 분할매수 완성)
            if extra and isinstance(extra, dict):
                for _ek, _ev in extra.items():
                    rec[_ek] = _ev
                # 2차 확정이면 entry_price도 avg로 갱신 (track_signal_results 기준 변경)
                if extra.get("phase2_confirmed") and extra.get("phase2_avg_entry"):
                    rec["entry_price_phase1"] = rec.get("entry_price", 0)
                    rec["entry_price"] = int(extra["phase2_avg_entry"])
                if extra.get("phase2_stop"):
                    rec["stop_loss"] = int(extra["phase2_stop"])
            data[target_key] = rec
            _write_json_atomic(SIGNAL_LOG_FILE, data, indent=2)
    except Exception as e:
        _log_warn_msg(f"⚠️ entry_hit 기록 오류: {e}")
def _lookup_entry_hit_fallback(rec: dict | None) -> dict:
    """rec에 도달 메타가 비어 있을 때 signal_log/_entry_watch에서 보강용 entry_hit 정보를 조회."""
    rec = rec or {}
    out = {}
    code = str(rec.get('code') or '').strip()
    signal_type = str(rec.get('signal_type') or '').strip()
    log_key = str(rec.get('log_key') or '').strip()
    try:
        data = _read_json_locked(SIGNAL_LOG_FILE)
        if isinstance(data, dict):
            target = None
            if log_key and isinstance(data.get(log_key), dict):
                _exact = data.get(log_key) or {}
                if not code or _exact.get('code') == code:
                    target = _exact
            if not target and code:
                candidates = []
                for _k, _rec in data.items():
                    if not isinstance(_rec, dict):
                        continue
                    if _rec.get('code') != code:
                        continue
                    if signal_type and _rec.get('signal_type') != signal_type:
                        continue
                    has_hit_meta = any(_rec.get(_k) not in (None, '', False) for _k in (
                        'entry_hit_time', 'entry_hit_price', 'legacy_entry_hit_time', 'legacy_entry_hit_price'
                    ))
                    if not has_hit_meta and _rec.get('status') not in ('추적중', '진입준비'):
                        continue
                    detect_key = f"{_rec.get('detect_date','')}{_rec.get('detect_time','')}".replace(":", "")
                    candidates.append((detect_key, _rec))
                if candidates:
                    candidates.sort(key=lambda x: x[0])
                    target = candidates[-1][1]
            if isinstance(target, dict):
                for _k in ('entry_hit', 'entry_hit_price', 'entry_hit_time', 'entry_hit_date', 'entry_hit_clock'):
                    if target.get(_k) not in (None, '', False):
                        out[_k] = target.get(_k)
                legacy_map = {
                    'legacy_entry_hit_price': 'entry_hit_price',
                    'legacy_entry_hit_time': 'entry_hit_time',
                    'legacy_entry_hit_date': 'entry_hit_date',
                    'legacy_entry_hit_clock': 'entry_hit_clock',
                }
                for _src, _dst in legacy_map.items():
                    if out.get(_dst) in (None, '', False) and target.get(_src) not in (None, '', False):
                        out[_dst] = target.get(_src)
    except Exception as e:
        _swallow_exception(e)
    if code and (not out.get('entry_hit_time') or not out.get('entry_hit_price')):
        try:
            watch = _latest_entry_watch_by_code(code)
            if isinstance(watch, dict) and watch.get('entry_hit'):
                for _k in ('entry_hit', 'entry_hit_price', 'entry_hit_time', 'entry_hit_date', 'entry_hit_clock'):
                    if watch.get(_k) not in (None, '', False):
                        out[_k] = watch.get(_k)
        except Exception as e:
            _swallow_exception(e)
    return out
def _get_entry_hit_display(rec: dict | None) -> tuple[int | None, str]:
    """진입가 도달 관련 표시용 데이터(도달가, 도달시각 문자열) 반환."""
    rec = dict(rec or {})
    if rec.get('entry_hit_price') in (None, '', False) and rec.get('legacy_entry_hit_price') not in (None, '', False):
        rec['entry_hit_price'] = rec.get('legacy_entry_hit_price')
    if rec.get('entry_hit_time') in (None, '', False) and rec.get('legacy_entry_hit_time') not in (None, '', False):
        rec['entry_hit_time'] = rec.get('legacy_entry_hit_time')
    if rec.get('entry_hit_date') in (None, '', False) and rec.get('legacy_entry_hit_date') not in (None, '', False):
        rec['entry_hit_date'] = rec.get('legacy_entry_hit_date')
    if rec.get('entry_hit_clock') in (None, '', False) and rec.get('legacy_entry_hit_clock') not in (None, '', False):
        rec['entry_hit_clock'] = rec.get('legacy_entry_hit_clock')
    if not rec.get('entry_hit_time') or not rec.get('entry_hit_price'):
        try:
            rec.update(_lookup_entry_hit_fallback(rec))
        except Exception as e:
            _swallow_exception(e)
    hit_price = None
    try:
        _hp = rec.get('entry_hit_price')
        if _hp:
            hit_price = int(_hp)
    except Exception as e:
        _swallow_exception(e)  # v105 structured silent-exception log
        hit_price = None
    hit_time = str(rec.get('entry_hit_time') or '').strip()
    if not hit_time:
        hit_date = str(rec.get('entry_hit_date') or '').strip()
        hit_clock = str(rec.get('entry_hit_clock') or '').strip()
        if hit_date and hit_clock:
            hit_time = f"{hit_date} {hit_clock}"
        else:
            hit_time = hit_date or hit_clock
    return hit_price, hit_time
def _build_entry_hit_line(entry: int, rec: dict | None = None, include_hit_price: bool = False, include_hit_time: bool = True) -> str:
    parts = [f"🎯 진입가: <b>{int(entry):,}원</b>"]
    hit_price, hit_time = _get_entry_hit_display(rec)
    if include_hit_price and hit_price:
        parts.append(f"도달가 <b>{hit_price:,}원</b>")
    if include_hit_time and hit_time:
        parts.append(f"도달시각 {hit_time}")
    return "  |  ".join(parts)
def _has_entry_hit_metadata(rec: dict | None = None) -> bool:
    try:
        hit_price, hit_time = _get_entry_hit_display(dict(rec or {}))
        return hit_price not in (None, '', False) and bool(str(hit_time or '').strip())
    except Exception as e:
        _swallow_exception(e)  # v105 structured silent-exception log
        return False
def _should_send_trailing_mode_message(rec: dict | None = None) -> bool:
    return _has_entry_hit_metadata(rec)
def _tracking_record_sort_key(rec: dict | None = None):
    rec = dict(rec or {})
    detect_ts = f"{rec.get('detect_date','')} {rec.get('detect_time','')}".strip()
    hit_ts = str(rec.get('entry_hit_time') or '').strip()
    target = float(rec.get('target_price', 0) or 0)
    entry = float(rec.get('entry_price', 0) or 0)
    return (bool(rec.get('entry_hit')), hit_ts, detect_ts, target, entry)
def _is_representative_tracking_record(data: dict | None, log_key: str, rec: dict | None = None) -> bool:
    data = data or {}
    rec = dict(rec or {})
    code = str(rec.get('code') or '').strip()
    if not code:
        return True
    same = []
    for k, v in data.items():
        if not isinstance(v, dict):
            continue
        if str(v.get('code') or '').strip() != code:
            continue
        if v.get('status') != '추적중':
            continue
        same.append((k, v))
    if not same:
        return True
    best_key, _ = max(same, key=lambda kv: _tracking_record_sort_key(kv[1]))
    return best_key == log_key
def _format_nxt_transition_delta_block(watch: dict) -> str:
    lines = []
    base_grade = str(watch.get("execution_grade_at_detect") or watch.get("grade_at_detect") or watch.get("grade") or "").upper()
    cur_grade = str(watch.get("execution_grade") or watch.get("grade") or "").upper()
    if base_grade and cur_grade and base_grade != cur_grade:
        lines.append(f"- 등급 변화: {base_grade} → {cur_grade}")
    base_entry = safe_int(watch.get("entry_price_at_detect", watch.get("entry_price_orig", watch.get("entry_price", 0))), 0)
    cur_entry = safe_int(watch.get("entry_price", 0), 0)
    if base_entry > 0 and cur_entry > 0 and base_entry != cur_entry:
        pct = ((cur_entry - base_entry) / base_entry) * 100.0
        lines.append(f"- 진입가 조정: {base_entry:,}원 → {cur_entry:,}원 ({pct:+.1f}%)")
    if not lines:
        return ""
    return "🔄 <b>NXT 반영 변화</b>\n" + "\n".join(lines) + "\n\n"
def _append_entry_watch_expired(expired: list, log_key: str, watch: dict, reason: str, final_status: str = "") -> None:
    expired.append((log_key, reason, final_status or _entry_watch_final_status(watch, final_status or reason)))
def _handle_entry_watch_expiry(log_key: str, watch: dict, expired: list) -> bool:
    if time.time() <= watch.get("expire_ts", watch["registered_ts"] + 86400):
        return False
    _record_entry_miss(watch, "기간만료", watch.get("peak_price", 0))
    miss_count = watch.get("miss_count", 0) + 1
    if miss_count >= 3:
        old_ratio = _dynamic.get("entry_pullback_ratio", ENTRY_PULLBACK_RATIO)
        if old_ratio > 0.15:
            _dynamic["entry_pullback_ratio"] = round(old_ratio - 0.05, 2)
            _save_dynamic_params()
            _log_info_msg(f"  🔧 진입가 비율 완화: {old_ratio:.2f}→{_dynamic['entry_pullback_ratio']:.2f} (미도달 {miss_count}회)")
    expired.append((log_key, "기간만료", _entry_watch_final_status(watch)))
    return True
def _resolve_entry_watch_quote(watch: dict):
    code = watch["code"]
    krx_ok = is_market_open()
    nxt_ok = (not krx_ok) and is_nxt_open() and is_nxt_listed(code)
    nxt_reference_ok = krx_ok and is_nxt_open() and is_nxt_listed(code)
    use_nxt = False
    reference_only = False
    reference_reason = ""
    if krx_ok:
        cur = get_stock_price(code)
        price = cur.get("price", 0)
        if not price:
            return None
        if _is_trading_halt(code, cur):
            _notify_trading_halt_cancel(watch, cur=cur)
            return {"expired": ("거래정지", _entry_watch_final_status(watch, "거래정지"))}
        if nxt_reference_ok and _is_krx_vi_reference_mode(cur, code):
            nxt_cur = get_nxt_stock_price(code)
            nxt_price = nxt_cur.get("price", 0)
            if nxt_price:
                cur = nxt_cur
                price = nxt_price
                reference_only = True
                reference_reason = "krx_vi_reference"
                if not watch.get("nxt_surge_tracked"):
                    _register_nxt_surge_to_krx_watch(watch, nxt_price)
    elif nxt_ok:
        use_nxt = True
        cur = get_nxt_stock_price(code)
        price = cur.get("price", 0)
        if not price:
            return None
        if _is_trading_halt(code, cur):
            _notify_trading_halt_cancel(watch, use_nxt=True, cur=cur)
            return {"expired": ("거래정지", _entry_watch_final_status(watch, "거래정지"))}
    else:
        return None
    return {
        "cur": cur,
        "price": price,
        "use_nxt": use_nxt,
        "reference_only": reference_only,
        "reference_reason": reference_reason,
    }
def _update_entry_watch_intraday_extremes(watch: dict, cur: dict, price: int) -> bool:
    changed = False
    resolved_name = _resolve_stock_name(watch["code"], watch.get("name", ""), cur if isinstance(cur, dict) else None)
    if resolved_name and resolved_name != watch.get("name"):
        watch["name"] = resolved_name
        changed = True
    if price > watch.get("peak_price", 0):
        watch["peak_price"] = price
        changed = True
    low_price = safe_int(watch.get("low_price", 0), 0)
    if low_price <= 0 or price <= low_price:
        watch["low_price"] = int(price or 0)
        watch["low_price_time"] = datetime.now().strftime('%Y-%m-%d %H:%M:%S')
        watch["volume_at_low"] = safe_int(cur.get("today_vol", watch.get("volume_at_low", 0)), safe_int(watch.get("volume_at_low", 0), 0))
        changed = True
    return changed
def _handle_entry_watch_reference_reach(watch: dict, price: int, entry: int, reference_reason: str) -> bool:
    if watch.get("entry_reference_only"):
        return False
    watch["entry_reference_only"] = True
    watch["entry_reference_market"] = "NXT"
    watch["entry_reference_reason"] = reference_reason or "krx_vi_reference"
    watch["entry_reference_time"] = datetime.now().strftime('%Y-%m-%d %H:%M:%S')
    watch["entry_reference_price"] = int(price or 0)
    _record_entry_reference_reach(watch, price, market="NXT", reason=reference_reason or "krx_vi_reference")
    _log_suppressed_alert(
        watch["code"], watch["name"],
        f"NXT 참고 도달 ({reference_reason or 'krx_vi_reference'})",
        watch.get("signal_type", ""),
        {"entry_price": entry, "reference_price": int(price or 0), "market": "NXT"}
    )
    return True
def _get_entry_watch_volume_guard_profile(watch: dict | None = None, use_nxt: bool = False) -> dict:
    watch = watch if isinstance(watch, dict) else {}
    profile = {"min_observe": 2, "grace_sec": 60, "drop_ratio": 0.50}
    if use_nxt:
        profile = {"min_observe": 4, "grace_sec": 180, "drop_ratio": 0.28}
    if watch.get("theme_chain_force_hit") or watch.get("force_external_capture_alert") or watch.get("direct_news_hit"):
        profile["min_observe"] += 1
        profile["grace_sec"] += 120 if use_nxt else 45
        profile["drop_ratio"] *= 0.85
    return profile

def _check_entry_watch_strength_guard(watch: dict, cur: dict, price: int, entry: int, use_nxt: bool) -> tuple[bool, bool, tuple | None]:
    changed = False
    entry_exec_metrics = get_execution_speed_metrics(watch["code"], current_price=price)
    if should_skip_expiration_for_dart_watch(watch):
        return False, changed, None
    strength_now = _classify_signal_strength(watch, entry_exec_metrics)
    vol_now = float(cur.get("volume_ratio", watch.get("volume_ratio", 0)) or 0)
    vol_at_detect = float(watch.get("volume_ratio_at_detect", watch.get("volume_ratio", vol_now)) or vol_now)
    if strength_now == "약한":
        if watch.get("entry_hit"):
            if _notify_entry_guard_followup(watch, "근거약화_신호강도약함", price, entry, use_nxt=use_nxt, detail="1차 도달 이후 신호 강도가 약화되어 신규 진입은 보류가 적절합니다."):
                changed = True
            return True, changed, None
        _notify_entry_watch_terminated(watch, "근거약화_신호강도약함", price, detail="포착 당시 근거가 약해져 지금은 다시 볼 필요가 없습니다.")
        _record_entry_dropped(watch, "근거약화_신호강도약함", price)
        return True, changed, ("근거약화_신호강도약함", "근거탈락")
    guard_profile = _get_entry_watch_volume_guard_profile(watch, use_nxt=use_nxt)
    observe_count = safe_int(watch.get("observe_count", 0), 0)
    since_detect = 0.0
    try:
        detect_dt = _parse_compact_datetime(watch.get("detect_date"), watch.get("detect_time"))
        if detect_dt is not None:
            since_detect = max(0.0, (_now_kst() - detect_dt).total_seconds())
    except Exception as e:
        _swallow_exception(e)
    volume_drop_ratio = max(0.05, safe_float(guard_profile.get("drop_ratio", 0.5), 0.5))
    if vol_at_detect > 0 and vol_now < vol_at_detect * volume_drop_ratio:
        if observe_count < safe_int(guard_profile.get("min_observe", 2), 2) or since_detect < safe_int(guard_profile.get("grace_sec", 60), 60):
            watch["entry_guard_pending_reason"] = "근거약화_거래량폭락_유예"
            return False, changed, None
        if watch.get("entry_hit"):
            ratio = (vol_now / vol_at_detect) if vol_at_detect else 0.0
            if _notify_entry_guard_followup(watch, "근거약화_거래량폭락", price, entry, use_nxt=use_nxt, detail=f"포착 대비 거래량이 {ratio:.2f}배 수준으로 약화되었습니다."):
                changed = True
            return True, changed, None
        _notify_entry_watch_terminated(watch, "근거약화_거래량폭락", price, detail="포착 직후 후속 거래량이 무너져 현재 흐름은 보지 않는 편이 낫습니다.")
        _record_entry_dropped(watch, "근거약화_거래량폭락", price)
        return True, changed, ("근거약화_거래량폭락", "근거탈락")
    return False, changed, None
def _evaluate_entry_watch_sector_guard(watch: dict) -> tuple[bool, float | None]:
    sector_blocked = False
    sector_avg = None
    try:
        s_theme = watch.get("sector_theme", "")
        if s_theme and s_theme != "기타업종":
            for tk, ti in THEME_MAP.items():
                if tk == s_theme or s_theme in ti.get("desc", ""):
                    chg_list = []
                    for sc, sn in ti.get("stocks", [])[:5]:
                        try:
                            sp = get_stock_price(sc)
                            cr = sp.get("change_rate", 0)
                            if cr is not None:
                                chg_list.append(float(cr))
                            time.sleep(0.05)
                        except Exception as e:
                            _swallow_exception(e)
                            continue
                    if chg_list and (sum(chg_list) / len(chg_list)) <= -COMMON_THRESHOLD_3P0:
                        sector_blocked = True
                        sector_avg = round(sum(chg_list) / len(chg_list), 1)
                        _log_suppressed_alert(
                            watch["code"], watch["name"],
                            f"섹터 약세 차단 (섹터 {s_theme} 평균 {sum(chg_list)/len(chg_list):.1f}%)",
                            watch.get("signal_type", ""),
                            {"sector_avg_chg": sector_avg}
                        )
                    break
    except Exception as e:
        _swallow_exception(e)
    return sector_blocked, sector_avg
def _handle_entry_watch_sector_guard(watch: dict, price: int, entry: int, use_nxt: bool, sector_avg: float | None) -> bool:
    if watch.get("entry_hit"):
        return bool(_notify_entry_guard_followup(watch, "섹터약세", price, entry, use_nxt=use_nxt, detail=f"섹터 평균 등락률이 {sector_avg:+.1f}%로 약화되었습니다."))
    return False
def _handle_entry_watch_block_reason(watch: dict, cur: dict, price: int, entry: int, use_nxt: bool) -> tuple[bool, bool]:
    changed = False
    blocked_reason = _detect_entry_block_reason(cur, watch, price, entry)
    if not blocked_reason:
        return False, changed
    # v165.32 [#2]: check_entry_watch 경로 — KRX 개장 10분 A급 no_ask 자동 soft allow
    # 이유: dispatch 통과→entry_watch 등록→1분 후 check_entry_watch에서 재차 no_ask 차단
    # 2026-04-27: 플루토스/리센스메디컬/대원전선 발송 성공 후 09:07 check_entry에서 즉시 차단됨
    if blocked_reason == "no_ask_liquidity" and is_market_open():
        _now_t_ew = datetime.now().time()
        _grade_ew = str(watch.get("execution_grade") or watch.get("grade") or "").upper()
        if dtime(9, 0) <= _now_t_ew < dtime(9, 10) and _grade_ew == "A":
            _log_info_msg(
                f"  ✅ 개장10분 no_ask soft skip: {watch.get('name','')} ({watch.get('code','')}) — 동시호가 잔여 구간"
            )
            return False, False  # 차단 안 함, 다음 사이클 재확인
    if blocked_reason == "no_ask_liquidity" and _should_soft_allow_no_ask_liquidity(cur, watch):
        # v163.14 [#2]: no_ask_liquidity soft allow 5회 초과 → 감시 드롭
        _na_soft_count = safe_int(watch.get("no_ask_soft_count", 0), 0) + 1
        watch["no_ask_soft_count"] = _na_soft_count
        _log_suppressed_alert(
            watch["code"], watch["name"],
            f"진입호가 경고(soft) ({blocked_reason}) {_na_soft_count}회",
            watch.get("signal_type", ""),
            {"entry_price": entry, "blocked_price": int(price or 0), "change_rate": cur.get("change_rate", 0), "ask_qty": cur.get("ask_qty", 0), "bid_qty": cur.get("bid_qty", 0)}
        )
        if _na_soft_count >= 5:
            _log_info_msg(
                f"  ⏭ no_ask_liquidity {_na_soft_count}회 → 진입가 감시 드롭: "
                f"{watch.get('name','')} ({watch.get('code','')})"
            )
            watch["_drop_no_ask_overflow"] = True
            return True, True  # expired 처리는 _process_entry_watch_item에서
        if watch.get("entry_hit") and _notify_entry_guard_followup(watch, blocked_reason, price, entry, use_nxt=use_nxt, detail="매도호가가 얇아 실제 체결 품질을 다시 확인해야 합니다."):
            changed = True
        return True, changed
    watch["entry_blocked"] = True
    watch["entry_blocked_reason"] = blocked_reason
    watch["entry_blocked_time"] = datetime.now().strftime('%Y-%m-%d %H:%M:%S')
    watch["entry_blocked_price"] = int(price or 0)
    changed = True
    _record_entry_blocked(watch, blocked_reason, price)
    _log_suppressed_alert(
        watch["code"], watch["name"],
        f"진입불가 차단 ({blocked_reason})",
        watch.get("signal_type", ""),
        {"entry_price": entry, "blocked_price": int(price or 0), "change_rate": cur.get("change_rate", 0), "ask_qty": cur.get("ask_qty", 0), "bid_qty": cur.get("bid_qty", 0)}
    )
    detail_msg = "이미 1차 도달 후라도 현재 체결 여건은 진입 보류가 적절합니다."
    if blocked_reason == "fake_breakout_risk":
        detail_msg = "돌파 거래량 기준이 약하고 윗꼬리 부담이 커 가짜 돌파 가능성이 높습니다. 재눌림/재돌파 확인 전 신규 진입은 보류합니다."
    if watch.get("entry_hit") and _notify_entry_guard_followup(watch, blocked_reason, price, entry, use_nxt=use_nxt, detail=detail_msg):
        changed = True
    return True, changed
def _handle_entry_watch_reach_state(log_key: str, watch: dict, cur: dict, price: int, entry: int, use_nxt: bool, reference_only: bool, reference_reason: str, reach_via_recovery: bool, expired: list) -> bool:
    changed = False
    if reference_only:
        return _handle_entry_watch_reference_reach(watch, price, entry, reference_reason)
    notify_count = watch.get("notify_count", 0)
    if notify_count >= 2 and not (watch.get("entry_hit") or watch.get("entry_hit_locked")):
        expired.append((log_key, "알림횟수만료", _entry_watch_final_status(watch, "진입미달")))
        return changed
    guarded, guard_changed, expiry = _check_entry_watch_strength_guard(watch, cur, price, entry, use_nxt)
    changed = changed or guard_changed
    if guarded:
        if expiry:
            expired.append((log_key, expiry[0], expiry[1]))
        return changed
    sector_blocked, sector_avg = _evaluate_entry_watch_sector_guard(watch)
    if sector_blocked:
        return changed or _handle_entry_watch_sector_guard(watch, price, entry, use_nxt, sector_avg)
    blocked, block_changed = _handle_entry_watch_block_reason(watch, cur, price, entry, use_nxt)
    changed = changed or block_changed
    if blocked:
        return changed
    if _send_entry_phase_alert(watch, cur, price, entry, use_nxt=use_nxt, reach_via_recovery=reach_via_recovery):
        changed = True
    return changed
def _process_entry_watch_item(log_key: str, watch: dict, expired: list) -> bool:
    if _handle_entry_watch_expiry(log_key, watch, expired):
        return False
    changed = False
    try:
        snapshot = _resolve_entry_watch_quote(watch)
        if not snapshot:
            return changed
        if snapshot.get("expired"):
            reason, final_status = snapshot["expired"]
            expired.append((log_key, reason, final_status))
            return changed
        cur = snapshot["cur"]
        price = snapshot["price"]
        use_nxt = snapshot["use_nxt"]
        reference_only = snapshot["reference_only"]
        reference_reason = snapshot["reference_reason"]
        changed |= _update_entry_watch_intraday_extremes(watch, cur, price)
        watch["observe_count"] = safe_int(watch.get("observe_count", 0), 0) + 1
        if watch.get("entry_hit_locked"):
            return changed
        # v165.11 [#2]: entry_watch 상한가급 자동 만료
        # 기존: 이미 포착된 entry_watch 종목이 상한가급이 돼도 no_ask_liquidity 차단 무한반복
        # 수정: 현재가 기준 change_rate >= 29% OR price >= upper_price → 감시 자동 만료
        _ew_chg = safe_float(cur.get("change_rate", 0), 0.0)
        _ew_upper = safe_int(cur.get("upper_price", 0), 0)
        _ew_prdy_sign = str(cur.get("prdy_vrss_sign", "") or "")
        _is_upper_now = (
            _ew_chg >= 29.0
            or (_ew_upper > 0 and price >= _ew_upper)
            or _ew_prdy_sign == "1"
        )
        if _is_upper_now and not watch.get("entry_hit"):
            # entry_hit 없는 상태에서 상한가급 → 진입 기회 없이 상한가 도달 → 만료
            _log_info_msg(
                f"  🔝 entry_watch 상한가급 자동 만료: {watch.get('name','')}({watch.get('code','')}) "
                f"+{_ew_chg:.1f}% — 진입 기회 없이 상한가"
            )
            _record_entry_miss(watch, "상한가도달만료", price)
            expired.append((log_key, "상한가도달만료", _entry_watch_final_status(watch, "상한가도달")))
            return True
        # v163.14 [#2]: no_ask_liquidity 5회 초과 드롭 플래그
        if watch.get("_drop_no_ask_overflow"):
            expired.append((log_key, "no_ask_overflow_drop", _entry_watch_final_status(watch, "진입불가드롭")))
            return True
        entry = watch["entry_price"]
        diff_pct = (price - entry) / entry * 100
        reach_slack_pct = _get_dynamic_entry_reach_slack_pct(watch)
        reach_via_recovery = bool(reach_slack_pct > 0 and price > entry and price <= int(round(entry * (1.0 + reach_slack_pct))))
        escape_pct = calc_surge_escape_pct(watch["code"], entry)
        if diff_pct >= escape_pct:
            _record_entry_miss(watch, "상승이탈", price)
            send_with_chart_buttons(
                f"📈 <b>[진입가 이탈]</b>\n"
                f"━━━━━━━━━━━━━━━\n"
                f"<b>{watch['name']}</b>  <b><code>{watch['code']}</code></b>\n"
                f"진입가 {entry:,}원에서 +{diff_pct:.1f}% 상승 이탈\n"
                f"진입 기회 없이 상승 → 감시 종료",
                watch["code"], watch["name"]
            )
            expired.append((log_key, "상승이탈", _entry_watch_final_status(watch, "진입미달")))
            return True
        if price <= entry or reach_via_recovery:
            changed |= _handle_entry_watch_reach_state(
                log_key, watch, cur, price, entry, use_nxt, reference_only, reference_reason, reach_via_recovery, expired
            )
        return changed
    except Exception as e:
        _swallow_exception(e)
        return changed
def _finalize_entry_watch_expired_items(expired: list) -> bool:
    changed_active = False
    for item in expired:
        if isinstance(item, tuple):
            k, consume_reason, final_status = item
        else:
            k, consume_reason, final_status = item, "", ""
        watch = _entry_watch.pop(k, None)
        if watch:
            _archive_entry_watch_record(k, watch, consume_reason=consume_reason, final_status=final_status or _entry_watch_final_status(watch))
            changed_active = True
    return changed_active
def check_entry_watch():
    if not _entry_watch:
        return
    expired: list[tuple[str, str, str]] = []
    changed_active = False
    _nxt_only_now = is_nxt_open() and not is_market_open()
    for log_key, watch in list(_entry_watch.items()):
        # v165.15: NXT 전용 시간대에 KRX 전용 종목 watch 처리 스킵
        # market="NXT" 없으면 KRX 전용으로 판단 — _is_nxt_eligible 불안정 대신 필드 기준 사용
        if _nxt_only_now:
            _w_market = str(watch.get("market") or "").upper()
            if _w_market != "NXT":
                continue  # KRX 전용 종목 스킵
        changed_active |= _process_entry_watch_item(log_key, watch, expired)
    changed_active |= _finalize_entry_watch_expired_items(expired)
    if changed_active:
        _save_entry_watch_active()
# ============================================================
# 🛡 장마감 전/후 손익 방어 가이드 (entry_hit 감시 종목)
#   - '진입가 도달' 후 모니터링 중인 종목에
#     지정학/뉴스/DART/지표 리스크가 생기면 손익 방어 안내를 자동 발송
# ============================================================
DEFENSE_KRX_CLOSE_WINDOW_MIN = int(os.getenv("DEFENSE_KRX_CLOSE_WINDOW_MIN", "25") or "25")  # 15:05~15:30
DEFENSE_NXT_CLOSE_WINDOW_MIN = int(os.getenv("DEFENSE_NXT_CLOSE_WINDOW_MIN", "25") or "25")  # 19:35~20:00
DEFENSE_ALERT_COOLDOWN_SEC   = int(os.getenv("DEFENSE_ALERT_COOLDOWN_SEC", "1800") or "1800")  # 30분
DEFENSE_LOSS_WARN_PCT        = float(os.getenv("DEFENSE_LOSS_WARN_PCT", "1.2") or "1.2")  # -1.2% 이하면 경고 강화
DEFENSE_PROFIT_LOCK_PCT      = float(os.getenv("DEFENSE_PROFIT_LOCK_PCT", "2.0") or "2.0")  # +2% 이상이면 익절 방어 권고
_NEG_NEWS_KWS = [
    "급락","하락","쇼크","우려","불확실","리스크","제재","관세","전쟁","공습","미사일","충돌","봉쇄",
    "압수수색","검찰","조사","횡령","배임","파산","회생","워크아웃","상장폐지","거래정지","관리종목",
    "하향","경고","부정","적자전환","실적부진","리콜","사고","해킹",
]
def _is_close_defense_window(now: datetime | None = None) -> bool:
    now = now or _now_kst()
    t = now.time()
    # KRX: 15:30 마감 기준
    krx_start = (datetime.combine(now.date(), dtime(15,30), tzinfo=_KST) - timedelta(minutes=DEFENSE_KRX_CLOSE_WINDOW_MIN)).time()
    krx_end   = dtime(15,30)
    # NXT: 20:00 마감 기준 (NXT만 열릴 수도 있음)
    nxt_start = (datetime.combine(now.date(), dtime(20,0), tzinfo=_KST) - timedelta(minutes=DEFENSE_NXT_CLOSE_WINDOW_MIN)).time()
    nxt_end   = dtime(20,0)
    in_krx = (t >= krx_start and t <= krx_end)
    in_nxt = (t >= nxt_start and t <= nxt_end)
    return in_krx or in_nxt
def _detect_defense_issues(code: str, name: str, entry: int, stop_loss: int) -> tuple[int, list[str]]:
    """리스크 점수(0~100)와 사유 리스트 반환."""
    score = 0
    reasons = []
    try:
        # 1) DART 리스크
        try:
            dr = check_dart_risk(code)
            if isinstance(dr, dict) and dr.get("is_risk"):
                score += 60
                reasons.append(f"⚠️ DART 리스크: {dr.get('title','')}".strip())
        except Exception as e:
            _swallow_exception(e)
        # 2) 지정학/거시 리스크(시장)
        try:
            geo = _geo_event_state or {}
            if geo.get("active") and time.time() - float(geo.get("ts",0) or 0) < 3600*12:
                unc = str(geo.get("uncertainty","mid"))
                adj = int(geo.get("score_adj",0) or 0)
                if unc == "high" and adj <= -5:
                    score += 20
                    reasons.append("🌍 지정학 불확실성(HIGH) — 시장 리스크오프 가능")
                elif adj <= -8:
                    score += 15
                    reasons.append("🌍 지정학 이벤트 — 변동성 확대 가능")
        except Exception as e:
            _swallow_exception(e)
        # 3) 최근 뉴스(타이틀 기반 간단 필터)
        try:
            news = fetch_news_for_stock(code, name) or []
            hits = []
            for n in news[:10]:
                for kw in _NEG_NEWS_KWS:
                    if kw in n and kw not in hits:
                        hits.append(kw)
            if hits:
                score += 15
                reasons.append(f"📰 부정 키워드 감지: {', '.join(hits[:4])}")
        except Exception as e:
            _swallow_exception(e)
        # 4) 가격/손익 상태
        try:
            cur = get_stock_price(code) or {}
            price = int(cur.get("price") or 0)
            if price and entry:
                pnl = (price - entry) / entry * 100
                if pnl <= -DEFENSE_LOSS_WARN_PCT:
                    score += 20
                    reasons.append(f"📉 진입가 대비 {pnl:.1f}% (방어 필요)")
                elif pnl >= DEFENSE_PROFIT_LOCK_PCT:
                    score += 10
                    reasons.append(f"📈 진입가 대비 +{pnl:.1f}% (익절 방어 권장)")
                # 손절선 근접
                if stop_loss and price <= stop_loss * 1.01:
                    score += 20
                    reasons.append("🛡 손절선 근접(1% 이내)")
        except Exception as e:
            _swallow_exception(e)
    except Exception as e:
        _swallow_exception(e)
    score = max(0, min(score, 100))
    return score, reasons
def run_entry_defense_monitor():
    """run_scan 루프에서 호출: 마감 구간에 entry_hit 종목의 리스크를 감지해 손익 방어 가이드 발송."""
    try:
        if not _entry_watch:
            return
        changed_active = False
        # 마감 구간이 아니면 불필요한 API 호출 줄이기
        if not _is_close_defense_window():
            return
        now_ts = time.time()
        use_nxt = (not is_market_open()) and is_nxt_open()
        for _k, w in list(_entry_watch.items()):
            if not isinstance(w, dict):
                continue
            if not w.get("entry_hit"):
                continue
            # 쿨다운(종목별)
            last = float(w.get("defense_last_ts", 0) or 0)
            if now_ts - last < DEFENSE_ALERT_COOLDOWN_SEC:
                continue
            code = w.get("code")
            name = w.get("name") or code
            entry = int(w.get("entry_price") or 0)
            stop  = int(w.get("stop_loss") or 0)
            if not code or not entry:
                continue
            # 현재가
            cur = get_nxt_stock_price(code) if use_nxt else get_stock_price(code)
            price = int((cur or {}).get("price") or 0)
            if not price:
                continue
            risk_score, reasons = _detect_defense_issues(code, name, entry, stop)
            if risk_score < 35 or not reasons:
                continue
            pnl = (price - entry) / entry * 100 if entry else 0.0
            # 가이드 구성(실전 수익 방어 중심)
            guide = []
            if pnl >= DEFENSE_PROFIT_LOCK_PCT:
                guide.append("✅ <b>수익 방어</b>: 1차 분할익절(예: 30~50%) + 잔량은 <b>진입가/단기저점 이탈 시 정리</b>")
                guide.append("✅ <b>트레일링</b>: 전일저가 또는 5분 저점 기준으로 손절선을 끌어올리기")
            else:
                guide.append("🛡 <b>손실 방어</b>: 손절선 엄수(이탈 시 기계적으로 정리) + 무리한 물타기 금지")
                guide.append("🛡 <b>리스크 발생</b>: 변동성 확대 구간이므로 진입/추가매수는 보수적으로")
            # 마감 임박 추가 코멘트
            if is_nxt_open() and not is_market_open():
                guide.append("📡 <b>NXT 단독 시간</b>: 유동성 얇음 → 슬리피지/급변 가능, 보수적 대응 권장")
            else:
                guide.append("⏳ <b>장마감 임박</b>: 뉴스/공시 충격은 익일 갭으로 이어질 수 있어 방어 우선")
            parts = [
                f"🛡 <b>[손익 방어 알림]</b> (리스크 {risk_score}/100)",
                "━━━━━━━━━━━━━━━",
                f"<b>{name}</b>  <code>{code}</code>",
                f"현재가 <b>{price:,}</b> / 진입 {entry:,}  ({pnl:+.1f}%)",
                (f"손절 {stop:,}" if stop else ""),
                "━━━━━━━━━━━━━━━",
                *reasons[:4],
                "━━━━━━━━━━━━━━━",
                *guide[:4],
            ]
            msg = "\n".join([p for p in parts if p])
            send_with_chart_buttons(msg, code, name)
            # 기록
            w["defense_last_ts"] = now_ts
            changed_active = True
        if changed_active:
            _save_entry_watch_active()
    except Exception as e:
        _log_error("run_entry_defense_monitor", e)
def _sanitize_telegram_text(text: str | None) -> str | None:
    """텔레그램 발송 전 표시상 어색한 문자를 정리한다."""
    if text is None:
        return None
    try:
        return str(text).replace(chr(0x2B1C), "").replace(chr(0x26AA), "")
    except Exception as e:
        _swallow_exception(e)  # v105 structured silent-exception log
        return text
_TG_CONNECT_TIMEOUT = float(os.getenv("TG_CONNECT_TIMEOUT", "3.5") or "3.5")
_TG_READ_TIMEOUT = float(os.getenv("TG_READ_TIMEOUT", "25") or "25")
_TG_LONGPOLL_READ_TIMEOUT = float(os.getenv("TG_LONGPOLL_READ_TIMEOUT", "8") or "8")
_TG_FILE_READ_TIMEOUT = float(os.getenv("TG_FILE_READ_TIMEOUT", "45") or "45")
_TG_ERROR_LOG_COOLDOWN_SEC = int(os.getenv("TG_ERROR_LOG_COOLDOWN_SEC", "120") or "120")
_tg_error_last_ts: dict[str, float] = {}
def _tg_log_once(key: str, message: str) -> None:
    now_ts = time.time()
    last_ts = float(_tg_error_last_ts.get(key, 0.0) or 0.0)
    if now_ts - last_ts >= _TG_ERROR_LOG_COOLDOWN_SEC:
        _log_info_msg(message)
        _tg_error_last_ts[key] = now_ts
def _tg_timeout_tuple(read_timeout: float | int | None = None) -> tuple[float, float]:
    rt = float(read_timeout if read_timeout is not None else _TG_READ_TIMEOUT)
    return (float(_TG_CONNECT_TIMEOUT), max(1.0, rt))
def _tg_http_request(
    http_method: str,
    api_method: str,
    *,
    json_payload: dict | None = None,
    data_payload: dict | None = None,
    files: dict | None = None,
    params: dict | None = None,
    read_timeout: float | int | None = None,
    attempts: int = 1,
    quiet: bool = False,
):
    if not TELEGRAM_BOT_TOKEN:
        return None
    url = f"https://api.telegram.org/bot{TELEGRAM_BOT_TOKEN}/{api_method}"
    timeout = _tg_timeout_tuple(read_timeout)
    tries = max(1, int(attempts or 1))
    for attempt in range(1, tries + 1):
        try:
            if http_method.lower() == "get":
                return requests.get(url, params=params, timeout=timeout)
            return requests.post(url, json=json_payload, data=data_payload, files=files, params=params, timeout=timeout)
        except requests.exceptions.ReadTimeout as e:
            if attempt < tries:
                time.sleep(0.6 * attempt)
                continue
            if not quiet:
                _tg_log_once(f"{api_method}:read_timeout", f"⚠️ 텔레그램 {api_method} 읽기 지연: {e}")
            return None
        except requests.exceptions.ConnectTimeout as e:
            if not quiet:
                _tg_log_once(f"{api_method}:connect_timeout", f"⚠️ 텔레그램 {api_method} 연결 지연: {e}")
            return None
        except requests.exceptions.RequestException as e:
            if not quiet:
                _tg_log_once(f"{api_method}:request_error", f"⚠️ 텔레그램 {api_method} 오류: {e}")
            return None
        except Exception as e:
            if not quiet:
                _tg_log_once(f"{api_method}:exception", f"⚠️ 텔레그램 {api_method} 오류: {e}")
            return None
    return None
def _tg_request(method: str, payload: dict, timeout: int | float = 10) -> dict | None:
    """Telegram Bot API 요청. 성공 시 response json 반환, 실패 시 None."""
    try:
        if isinstance(payload, dict):
            if isinstance(payload.get('text'), str):
                payload['text'] = _decorate_ui_score_text(payload['text'])
            if isinstance(payload.get('caption'), str):
                payload['caption'] = _decorate_ui_score_text(payload['caption'])
    except Exception as e:
        _swallow_exception(e)
    r = _tg_http_request("post", method, json_payload=payload, read_timeout=timeout, attempts=1)
    if r is None:
        return None
    try:
        return r.json()
    except Exception as e:
        _swallow_exception(e)  # v105 structured silent-exception log
        return None
def send_with_chart_buttons(text: str, code: str, name: str):
    """
    텍스트 메시지 + 인라인 키보드 버튼(네이버 차트 링크) 전송
    버튼은 기기 기본 브라우저(외부)로 열림
    """
    safe_name = _resolve_stock_name(code, name)
    # v163.15 [#3]: 모바일 지원 URL로 수정 (SKILL.md 명시 정상 URL)
    naver = f"https://m.stock.naver.com/domestic/stock/{code}/total"
    keyboard = {
        "inline_keyboard": [[
            {"text": f"📈 {safe_name} 차트 보기 (네이버)", "url": naver},
        ]]
    }
    send(text, reply_markup=keyboard)
def send(text: str, *, reply_markup: dict | None = None) -> int | None:
    """메시지 전송. 성공 시 message_id 반환."""
    decorated_text = _decorate_ui_score_text(text)
    payload = {"chat_id": TELEGRAM_CHAT_ID, "text": _sanitize_telegram_text(decorated_text), "parse_mode": "HTML"}
    if reply_markup:
        payload["reply_markup"] = reply_markup
    res = _tg_request("sendMessage", payload)
    msg_id = None
    try:
        if res and res.get("ok") and "result" in res:
            msg_id = res["result"].get("message_id")
    except Exception as e:
        _swallow_exception(e)
    # v169.9: 모든 send() 호출을 대시보드 알람 피드에 반영 (v169.15: 안전한 전역변수 접근)
    try:
        _alerts = globals().get("_WEB_DASHBOARD_ALERTS")
        _lock   = globals().get("_WEB_DASHBOARD_LOCK")
        if _alerts is None or _lock is None:
            return msg_id
        clean = decorated_text.replace("<b>","").replace("</b>","").replace("<i>","").replace("</i>","")
        lines = [l.strip() for l in clean.split("\n") if l.strip() and not l.strip().startswith("━")]
        title = lines[0][:60] if lines else "알람"
        body  = "\n".join(lines[1:4])
        lvl   = "red" if any(k in clean for k in ["급등","SURGE","포착","돌파","상한"]) else \
                "blue" if any(k in clean for k in ["시작","배포","완료","연결","✅","📌"]) else "yellow"
        alert_entry = {
            "lvl":   lvl,
            "time":  datetime.now().strftime("%H:%M"),
            "title": title,
            "body":  body,
        }
        with _lock:
            _alerts.insert(0, alert_entry)
            if len(_alerts) > 50:
                _alerts.pop()
        _save_dashboard_alerts()
        threading.Thread(target=_push_dashboard_json, daemon=True).start()
    except Exception as _de:
        _swallow_exception(_de)
    return msg_id
# =======================================================
# Crash guard (Step 1): unhandled exception hook
# =======================================================
_CRASH_NOTIFY_COOLDOWN_SEC = int(os.getenv("CRASH_NOTIFY_COOLDOWN_SEC", "1800") or "1800")
_last_crash_sig: str | None = None
_last_crash_ts: float = 0.0
def install_excepthook() -> None:
    """Unhandled 예외를 파일로 저장하고(영구저장), 텔레그램 알림을 쿨다운(기본 30분)으로 제한."""
    import sys, time, traceback as _tb
    from pathlib import Path
    def _handler(exc_type, exc, tb):
        global _last_crash_sig, _last_crash_ts
        try:
            data_dir = DATA_DIR
            crash_dir = Path(data_dir) / "crash_logs"
            crash_dir.mkdir(parents=True, exist_ok=True)
            ts = datetime.now().strftime("%Y%m%d_%H%M%S")
            fname = f"crash_{ts}.txt"
            fpath = crash_dir / fname
            with open(fpath, "w", encoding="utf-8") as f:
                f.write("".join(_tb.format_exception(exc_type, exc, tb)))
            _log_warn_msg(f"🚨 Unhandled exception saved: {fpath}")
            sig = f"{exc_type.__name__}:{str(exc)[:200]}"
            now = time.time()
            if (_last_crash_sig != sig) or (now - _last_crash_ts > _CRASH_NOTIFY_COOLDOWN_SEC):
                _last_crash_sig, _last_crash_ts = sig, now
                try:
                    send(
                        f"🚨 봇 오류 감지\n"
                        f"- type: <b>{exc_type.__name__}</b>\n"
                        f"- msg: <code>{str(exc)[:250]}</code>\n"
                        f"- crash log: <code>{fname}</code>\n"
                        f"(같은 오류는 {_CRASH_NOTIFY_COOLDOWN_SEC//60}분에 1회만 알림)"
                    )
                except Exception as e:
                    _swallow_exception(e)
        except Exception as e:
            _swallow_exception(e)
        try:
            sys.__excepthook__(exc_type, exc, tb)
        except Exception as e:
            _swallow_exception(e)
    sys.excepthook = _handler
def edit_message(message_id: int, text: str, *, reply_markup: dict | None = None) -> bool:
    decorated_text = _decorate_ui_score_text(text)
    payload = {"chat_id": TELEGRAM_CHAT_ID, "message_id": message_id, "text": decorated_text, "parse_mode": "HTML"}
    if reply_markup:
        payload["reply_markup"] = reply_markup
    res = _tg_request("editMessageText", payload)
    return bool(res and res.get("ok"))
def _load_dashboard_state() -> dict:
    try:
        state = _runtime_state_get("dashboard_state", {}, legacy_path=DASHBOARD_STATE_FILE)
        return state if isinstance(state, dict) else {}
    except Exception as e:
        _swallow_exception(e)
        return {}
def get_today_performance_summary() -> str:
    """signal_log 기준 당일 완료 성과를 한 줄로 요약."""
    try:
        today = datetime.now().strftime("%Y%m%d")
        data = _read_json_locked(SIGNAL_LOG_FILE)
        if not isinstance(data, dict):
            return ""
        done_today = [
            v for v in data.values()
            if (v.get("exit_date") or v.get("detect_date")) == today
            and v.get("status") in ["수익", "손실", "본전"]
        ]
        if not done_today:
            return ""
        wins = sum(1 for v in done_today if float(v.get("pnl_pct", 0) or 0) > 0)
        total = len(done_today)
        win_rate = round(wins / total * 100) if total else 0
        avg_pnl = sum(float(v.get("pnl_pct", 0) or 0) for v in done_today) / total if total else 0.0
        return f"{total}건 · 승률 {win_rate}% · 평균 {avg_pnl:+.1f}%"
    except Exception as e:
        _swallow_exception(e)  # v105 structured silent-exception log
        return ""
def _save_dashboard_state(state: dict) -> None:
    try:
        _runtime_state_set("dashboard_state", state if isinstance(state, dict) else {}, legacy_path=DASHBOARD_STATE_FILE)
    except Exception as e:
        _swallow_exception(e)
def update_dashboard(force: bool = False) -> None:
    # 장 운영 시간에만 텔레그램 대시보드 갱신
    if not is_any_market_open():
        # v169.17: 장 마감/휴장 시에도 대시보드 JSON push (updated_at 타임스탬프 갱신)
        threading.Thread(target=_push_dashboard_json, daemon=True).start()
        return
    # ensure MARKET_REGIME is populated; fall back to US signals if needed
    try:
        us = get_us_market_signals()
        if isinstance(us, dict) and us.get('us_regime'):
            MARKET_REGIME['label'] = us.get('us_regime') or MARKET_REGIME.get('label','neutral')
    except Exception as e:
        _swallow_exception(e)
    """대시보드 메시지(1개)를 편집 업데이트 — v39.4: 변동사항 있을 때만."""
    global _LAST_DASHBOARD_TS, _LAST_DASHBOARD_HASH
    now = time.time()
    if (not force) and (now - _LAST_DASHBOARD_TS) < DASHBOARD_UPDATE_EVERY_SEC:
        return
    _LAST_DASHBOARD_TS = now
    tracked_n = 0
    try:
        tracked_n = len(_entry_watch.get("watch", {})) if isinstance(_entry_watch, dict) else 0
    except Exception as e:
        _swallow_exception(e)  # v105 structured silent-exception log
        tracked_n = 0
    raw_regime = (MARKET_REGIME.get("label") or "neutral")
    regime = regime_label_ko(raw_regime)
    det = market_regime_details() or {}
    det_txt = ""
    try:
        fut = det.get("nasdaq_fut_pct")
        vix = det.get("vix")
        dxy = det.get("dxy")
        if fut is not None:
            det_txt = f" (FUT {float(fut):+.1f}% / VIX {vix} / DXY {dxy})"
    except Exception as e:
        _swallow_exception(e)  # v105 structured silent-exception log
        det_txt = ""
    perf = ""
    try:
        perf = get_today_performance_summary()  # 있으면 사용
    except Exception as e:
        _swallow_exception(e)  # v105 structured silent-exception log
        perf = ""
    text = (
        "📌 <b>운영 대시보드</b>\n"
        f"• 레짐: <b>{regime}</b>{det_txt}\n"
        f"• 진입 감시: <b>{tracked_n}</b> 종목\n"
    )
    if perf:
        text += f"• 오늘 성과: {perf}\n"
    # v162: WebSocket 상태 표시
    if WEBSOCKET_ENABLED:
        ws_conn = "🟢연결" if _ws_connected else "🔴미연결"
        with _ws_lock:
            ws_sub = len(_ws_subscribed_codes)
        text += f"• WebSocket: {ws_conn} | 구독 {ws_sub}/{WS_MAX_SUBSCRIPTIONS}\n"
    text += f"• 업데이트: {datetime.now().strftime('%m-%d %H:%M')}\n"
    # v39.4-#6: 내용 해시 비교 → 변동 없으면 스킵 (메시지량 감소)
    content_hash = hashlib.md5(f"{regime}{tracked_n}{perf}".encode()).hexdigest()[:8]
    if not force and hasattr(update_dashboard, '_last_hash') and update_dashboard._last_hash == content_hash:
        return  # 변동 없음 → 업데이트 불필요
    update_dashboard._last_hash = content_hash
    state = _load_dashboard_state()
    mid = state.get("message_id")
    if isinstance(mid, int):
        ok = edit_message(mid, text)
        if not ok:
            mid2 = send(text)
            if mid2:
                state["message_id"] = mid2
                _save_dashboard_state(state)
    else:
        mid2 = send(text)
        if mid2:
            state["message_id"] = mid2
            _save_dashboard_state(state)
    # v169.9: 웹 대시보드 섹터/랭킹/포착 데이터 갱신 (10분마다)
    # v169.14: 장 마감/휴장 시 장전 섹터도 갱신
    if not is_any_market_open():
        threading.Thread(target=_refresh_premarket_sectors, daemon=True).start()
    threading.Thread(target=_push_dashboard_json, daemon=True).start()
