_WEB_DASHBOARD_JSON          = _state_path("web_dashboard.json")
_WEB_DASHBOARD_ALERTS_JSON   = _state_path("web_dashboard_alerts.json")
_WEB_DASHBOARD_PREMARKET_JSON= _state_path("web_dashboard_premarket.json")  # v169.14: 장전 섹터 캐시
_WEB_DASHBOARD_ALERTS: list  = []
_WEB_DASHBOARD_LOCK          = threading.Lock()
_WEB_DASHBOARD_LAST_PUSH: float = 0.0
_WEB_DASHBOARD_THROTTLE_SEC  = 3.0
_WEB_DASHBOARD_PREMARKET_SECTORS: list = []  # v169.14: 장전/장마감 섹터 캐시
_INFO_AUTO_PUSH_HASHES: dict = {}  # v169.17: 정보성 자동 알람 변경 감지 해시

def _load_premarket_sectors() -> None:
    """재시작 후 장전 섹터 캐시 복원"""
    global _WEB_DASHBOARD_PREMARKET_SECTORS
    try:
        if os.path.exists(_WEB_DASHBOARD_PREMARKET_JSON):
            with open(_WEB_DASHBOARD_PREMARKET_JSON, "r", encoding="utf-8") as f:
                data = json.load(f)
                if isinstance(data, list):
                    _WEB_DASHBOARD_PREMARKET_SECTORS = data
    except Exception:
        pass

def _save_premarket_sectors() -> None:
    """장전 섹터 파일 저장"""
    try:
        tmp = _WEB_DASHBOARD_PREMARKET_JSON + ".tmp"
        with open(tmp, "w", encoding="utf-8") as f:
            json.dump(_WEB_DASHBOARD_PREMARKET_SECTORS, f, ensure_ascii=False)
        os.replace(tmp, _WEB_DASHBOARD_PREMARKET_JSON)
    except Exception:
        pass

def _refresh_premarket_sectors() -> None:
    """장전/장마감 섹터를 _build_premarket_sector_snapshot()으로 갱신.
    API 결과가 없으면 _load_today_sector_results() 기반 fallback 사용."""
    global _WEB_DASHBOARD_PREMARKET_SECTORS
    try:
        snapshot = _build_premarket_sector_snapshot()
        top = snapshot.get("top_sectors") or []

        # fallback: 오늘 섹터 결과 파일 사용
        if not top:
            today_results = _load_today_sector_results() or {}
            if today_results:
                for sector_name, v in sorted(today_results.items(), key=lambda x: -float(x[1].get("avg_chg",0) or 0))[:12]:
                    avg_chg = float(v.get("avg_chg",0) or 0)
                    codes   = list(v.get("codes",[]) or [])[:4]
                    names   = list(v.get("names",[]) or [])[:4]
                    stocks  = []
                    for i, code in enumerate(codes):
                        snap = _get_snap(code)
                        stocks.append({
                            "name": names[i] if i < len(names) else _resolve_stock_name(code,""),
                            "code": code,
                            "chg":  float(snap.get("change_rate") or avg_chg or 0),
                            "vol":  _fmt_vol(safe_int(snap.get("today_vol") or 0)),
                            "amt":  _fmt_amt(safe_int(snap.get("acml_tr_pbmn") or 0)),
                        })
                    top.append({
                        "sector":  sector_name,
                        "score":   int(avg_chg * 2),
                        "grade":   "강함" if avg_chg >= 4 else "보통" if avg_chg >= 2 else "약함",
                        "reasons": [f"전일 {avg_chg:+.1f}%"],
                        "codes":   codes,
                        "names":   names,
                    })

        if not top:
            return

        sectors_out = []
        etc_stocks = []  # 섹터 미확인 종목 → 기타로
        for item in top:
            codes   = item.get("codes") or []
            names   = item.get("names") or []
            score   = item.get("score", 0)
            grade   = item.get("grade", "")
            reasons = item.get("reasons") or []
            sector_name = item.get("sector","")
            stocks  = []
            for i, code in enumerate(codes):
                snap = _get_snap(code)
                sname = names[i] if i < len(names) else _resolve_stock_name(code,"")
                stk = {
                    "name": sname, "code": code,
                    "chg":  float(snap.get("change_rate") or 0),
                    "vol":  _fmt_vol(safe_int(snap.get("today_vol") or 0)),
                    "amt":  _fmt_amt(safe_int(snap.get("acml_tr_pbmn") or 0)),
                }
                # 섹터명이 종목명과 동일 = 섹터 미확인 → 기타
                if sector_name and sector_name.strip() == sname.strip():
                    etc_stocks.append(stk)
                else:
                    stocks.append(stk)
            if sector_name and stocks:
                sectors_out.append({
                    "name": sector_name, "chg": float(score)*0.5,
                    "score": score, "grade": grade, "reasons": reasons,
                    "stocks": stocks, "premarket": True,
                })
            elif stocks:
                etc_stocks.extend(stocks)
        if etc_stocks:
            sectors_out.append({
                "name": "기타", "chg": 0.0, "score": 0,
                "grade": "확인중", "reasons": ["섹터 확인 중"],
                "stocks": etc_stocks[:8], "premarket": True,
            })
        _WEB_DASHBOARD_PREMARKET_SECTORS = sectors_out
        _save_premarket_sectors()
        # JSON 즉시 갱신
        threading.Thread(target=_push_dashboard_json, daemon=True).start()
    except Exception as e:
        _swallow_exception(e)

def _load_dashboard_alerts() -> None:
    """봇 시작 시 이전 알람 목록 로드"""
    global _WEB_DASHBOARD_ALERTS
    try:
        if os.path.exists(_WEB_DASHBOARD_ALERTS_JSON):
            with open(_WEB_DASHBOARD_ALERTS_JSON, "r", encoding="utf-8") as f:
                data = json.load(f)
                if isinstance(data, list):
                    _WEB_DASHBOARD_ALERTS = data[:50]
    except Exception:
        pass

def _save_dashboard_alerts() -> None:
    """알람 목록을 파일에 저장 (재시작 후에도 유지)"""
    try:
        tmp = _WEB_DASHBOARD_ALERTS_JSON + ".tmp"
        with open(tmp, "w", encoding="utf-8") as f:
            json.dump(_WEB_DASHBOARD_ALERTS[:50], f, ensure_ascii=False)
        os.replace(tmp, _WEB_DASHBOARD_ALERTS_JSON)
    except Exception:
        pass

def _next_biz_day_str() -> str:
    DAYS = ["일","월","화","수","목","금","토"]
    KR_HOL = {
        "2026-01-01","2026-01-28","2026-01-29","2026-01-30",
        "2026-03-01","2026-05-01","2026-05-05","2026-05-25",
        "2026-06-06","2026-08-15",
        "2026-09-24","2026-09-25","2026-09-26",
        "2026-10-03","2026-10-09","2026-12-25",
    }
    from datetime import timedelta as _td
    d = datetime.now().replace(hour=0,minute=0,second=0,microsecond=0) + _td(days=1)
    for _ in range(14):
        ymd = d.strftime("%Y-%m-%d")
        dow = d.weekday()
        if dow < 5 and ymd not in KR_HOL:
            kr = (dow+1)%7
            return f"{d.month}월 {d.day}일 ({DAYS[kr]})"
        d += _td(days=1)
    return "--"

def _fmt_vol(v: int) -> str:
    if v >= 100_000_000: return f"{v/100_000_000:.1f}억주"
    if v >= 10_000:      return f"{v//10_000}만주"
    return f"{v:,}주"

def _fmt_amt(v: int) -> str:
    if v >= 1_000_000_000_000: return f"{v/1_000_000_000_000:.1f}조"
    if v >= 100_000_000:       return f"{v//100_000_000}억"
    if v >= 10_000:            return f"{v//10_000}만"
    return f"{v:,}"

def _get_snap(code: str) -> dict:
    """웹소켓 _execution_snapshots 에서 최신 틱 반환 — KIS API 추가호출 없음"""
    buf = _execution_snapshots.get(code)
    return buf[-1] if buf else {}

def _push_dashboard_json() -> None:
    """웹 대시보드 JSON 원자적 갱신 — 웹소켓 스냅샷 직접 사용"""
    global _WEB_DASHBOARD_LAST_PUSH
    now_ts = time.time()
    if now_ts - _WEB_DASHBOARD_LAST_PUSH < _WEB_DASHBOARD_THROTTLE_SEC:
        return
    _WEB_DASHBOARD_LAST_PUSH = now_ts
    try:
        # ── 섹터 (장중=실시간, 장마감/휴장=장전 시나리오) ──
        sectors_raw = []
        market_open = is_any_market_open()
        try:
            if market_open:
                # 장중: get_all_sector_index + _sector_cache 실시간 가격
                sector_list = get_all_sector_index() or []
                for sec in sector_list[:12]:
                    name = sec.get("bstp_name","")
                    chg  = float(sec.get("change_rate") or 0)
                    stocks_raw = []
                    try:
                        for code, cdata in list(_sector_cache.items())[:300]:
                            if not isinstance(cdata, dict): continue
                            if cdata.get("sector","") != name: continue
                            snap = _get_snap(code)
                            stocks_raw.append({
                                "name": _resolve_stock_name(code,""),
                                "code": code,
                                "chg":  float(snap.get("change_rate") or 0),
                                "vol":  _fmt_vol(safe_int(snap.get("today_vol") or 0)),
                                "amt":  _fmt_amt(safe_int(snap.get("acml_tr_pbmn") or 0)),
                            })
                        stocks_raw.sort(key=lambda x:-x["chg"])
                        stocks_raw = stocks_raw[:8]
                    except Exception:
                        pass
                    if name:
                        sectors_raw.append({"name":name,"chg":chg,"stocks":stocks_raw})
                sectors_raw.sort(key=lambda x:-x["chg"])
            else:
                # 장마감/휴장: 캐시된 장전 섹터 사용
                sectors_raw = list(_WEB_DASHBOARD_PREMARKET_SECTORS)
        except Exception:
            pass

        # ── 포착 목록 (_entry_watch 기반 — 텔레그램 /list 동일 소스) v170.0 ──
        captured_raw = []
        _ETF_MARKERS = ("KODEX","TIGER","KOSEF","KBSTAR","ARIRANG","HANARO","ACE","SOL","ETF","ETN","선물","옵션","레버리지","인버스")
        try:
            seen_cap: set = set()
            # ① _entry_watch: 진입가 감시 중 + 진입 도달 후 목표가 추적 중
            for _, watch in list((_entry_watch or {}).items()):
                if not isinstance(watch, dict): continue
                code = normalize_stock_code(watch.get("code",""))
                name = watch.get("name","") or _resolve_stock_name(code,"")
                if not code or len(code) != 6: continue
                if any(m in name for m in _ETF_MARKERS): continue
                if code in seen_cap: continue
                seen_cap.add(code)
                snap    = _get_snap(code)
                # v169.19: 장마감 후 snap 비어도 peak_price 폴백
                cur_price = safe_int(snap.get("price") or watch.get("peak_price") or 0)
                e_price   = safe_int(watch.get("entry_price") or 0)
                hit = bool(watch.get("entry_hit")) or (
                    cur_price > 0 and e_price > 0 and cur_price >= e_price)
                captured_raw.append({
                    "name":       name,
                    "code":       code,
                    "price":      cur_price,
                    "entry":      e_price,
                    "target":     safe_int(watch.get("target_price") or 0),
                    "stop":       safe_int(watch.get("stop_loss") or 0),
                    "hit":        hit,
                    "chg":        float(snap.get("change_rate") or watch.get("change_at_detect") or 0),
                    "miss_count": int(watch.get("miss_count") or 0),
                })
            # ② _detected_stocks: 이월 종목 (entry_price 있으면 포함)
            for code, rec in list((_detected_stocks or {}).items()):
                code = normalize_stock_code(str(code or ""))
                if not code or len(code) != 6 or code in seen_cap: continue
                name = rec.get("name","") or _resolve_stock_name(code,"")
                if any(m in name for m in _ETF_MARKERS): continue
                seen_cap.add(code)
                snap = _get_snap(code)
                # v169.19: 장마감 후 snap 비어도 high_price 폴백
                d_price = safe_int(snap.get("price") or rec.get("high_price") or 0)
                captured_raw.append({
                    "name":       name,
                    "code":       code,
                    "price":      d_price,
                    "entry":      safe_int(rec.get("entry_price") or 0),
                    "target":     safe_int(rec.get("target_price") or 0),
                    "stop":       safe_int(rec.get("stop_loss") or 0),
                    "hit":        False,
                    "chg":        float(snap.get("change_rate") or 0),
                    "miss_count": 0,
                })
            # hit 종목 상단 우선, 동순위는 등락률 내림차순
            captured_raw.sort(key=lambda x: (not x["hit"], -x["chg"]))
            captured_raw = captured_raw[:30]
        except Exception:
            pass

        # ── 랭킹 (웹소켓 구독 종목 기반) ─────────────────
        rank_base = []
        try:
            for code, buf in list(_execution_snapshots.items()):
                if not buf: continue
                snap = buf[-1]
                if time.time() - float(snap.get("ts",0)) > 300: continue
                rank_base.append({
                    "name":    _resolve_stock_name(code,""),
                    "code":    code,
                    "chg":     float(snap.get("change_rate") or 0),
                    "vol_raw": safe_int(snap.get("today_vol") or 0),
                    "amt_raw": safe_int(snap.get("acml_tr_pbmn") or 0),
                    "vol":     _fmt_vol(safe_int(snap.get("today_vol") or 0)),
                    "amt":     _fmt_amt(safe_int(snap.get("acml_tr_pbmn") or 0)),
                })
        except Exception:
            pass

        with _WEB_DASHBOARD_LOCK:
            alerts_snapshot = list(_WEB_DASHBOARD_ALERTS)

        payload = {
            "updated_at":   datetime.now().strftime("%H:%M:%S"),
            "data_date":    datetime.now().strftime("%m-%d"),
            "next_biz_day": _next_biz_day_str(),
            "market_open":  is_any_market_open(),
            "sectors":      sectors_raw,
            "captured":     captured_raw,
            "alerts":       alerts_snapshot,
            "rank_chg":     sorted(rank_base, key=lambda x:-x["chg"])[:12],
            "rank_vol":     sorted(rank_base, key=lambda x:-x["vol_raw"])[:12],
            "rank_view":    sorted(rank_base, key=lambda x:-x["amt_raw"])[:12],
        }
        tmp = _WEB_DASHBOARD_JSON + ".tmp"
        with open(tmp,"w",encoding="utf-8") as f:
            json.dump(payload, f, ensure_ascii=False)
        os.replace(tmp, _WEB_DASHBOARD_JSON)
    except Exception as e:
        _swallow_exception(e)


# ── Flask 앱 ──────────────────────────────────────────────────
_flask_app = _Flask(__name__)

