def check_pullback_signals() -> list:
    signals = []
    for code, info in list(_detected_stocks.items()):
        detected_at = info.get("detected_at")
        if not detected_at or minutes_since(detected_at) < 30: continue
        if time.time() - _pullback_history.get(code,0) < 1800: continue
        try:
            cur = get_stock_price(code)
            high = info.get("high_price",0); price = cur.get("price",0)
            if not price or not high: continue
            if price > high: _detected_stocks[code]["high_price"]=price; continue
            pullback = (high-price)/high*100
            carry    = info.get("carry_day",0)
            if 25.0 <= pullback <= 55.0:
                entry = price
                stop, target, stop_pct, target_pct, atr_used = calc_stop_target(code, entry, signal_type="ENTRY_POINT")
                carry_text = f" (이월 {carry}일차)" if carry>0 else ""
                entry_score = 95
                entry_reasons = [f"🎯 눌림목{carry_text}",
                                            f"📌 고점 {high:,}원 → 현재 {price:,}원 (-{pullback:.1f}%)",
                                            f"⏱ 급등 후 {minutes_since(detected_at)}분 경과"]
                entry_score, entry_reasons, similar_pattern_stats = _apply_similar_pattern_score(
                    entry_score, entry_reasons, code, "ENTRY_POINT", cur.get("change_rate",0), 0, weight_mode="confirm"
                )
                _entry_tf_block = _should_block_multi_tf_downtrend_capture(code, "ENTRY_POINT", signal_meta={"score": entry_score, "change_rate": cur.get("change_rate", 0), "vol_ratio": cur.get("volume_ratio", 0), "reasons": entry_reasons})
                if _entry_tf_block.get("block"):
                    _ctx = _entry_tf_block.get("context", {}) or {}
                    _log_suppressed_alert(
                        code, cur.get("name", code),
                        _entry_tf_block.get("reason", "주봉·일봉 동반 하락 추세 차단"),
                        "ENTRY_POINT",
                        {
                            "daily_ret20": _ctx.get("daily_ret20", 0.0),
                            "weekly_ret8": _ctx.get("weekly_ret8", 0.0),
                            "daily_flags": _ctx.get("daily_flags", 0),
                            "weekly_flags": _ctx.get("weekly_flags", 0),
                            "change_rate": cur.get("change_rate", 0),
                            "score": entry_score,
                        },
                    )
                    continue
                entry_grade = _derive_general_signal_grade(
                    "ENTRY_POINT",
                    entry_score,
                    change_rate=cur.get("change_rate", 0),
                    vol_ratio=cur.get("volume_ratio", 0),
                    sector_info=info.get("sector_info") if isinstance(info.get("sector_info"), dict) else {},
                    direct_news_hit=bool(info.get("direct_news_hit")),
                    market=cur.get("market", ""),
                    reasons=entry_reasons,
                )
                signals.append({"code":code,"name":cur.get("name",code),"price":price,
                                 "change_rate":cur.get("change_rate",0),"volume_ratio":cur.get("volume_ratio",0),
                                 "signal_type":"ENTRY_POINT","score":entry_score,
                                 "grade":entry_grade,"execution_grade":entry_grade,"pattern_grade":entry_grade,
                                 "similar_pattern_stats":similar_pattern_stats,
                                 "entry_price":entry,"stop_loss":stop,"target_price":target,
                                 "stop_pct":stop_pct,"target_pct":target_pct,"atr_used":atr_used,
                                 "prev_upper":False,
                                 "reasons":entry_reasons,
                                 "detected_at":detected_at})
                _pullback_history[code] = time.time()
        except Exception as e:
            _swallow_exception(e)  # v105 structured silent-exception log
            continue
    return signals
