# 뉴스 (3개 소스 병렬)
# ============================================================
def fetch_news_for_stock(code: str, name: str) -> list:
    """
    급등 종목 → 관련 뉴스 역추적
    네이버 금융 종목 뉴스 페이지 스크래핑
    returns: [{"title": str, "time": str}, ...]  최대 3건
    """
    cached = _news_reverse_cache.get(code)
    if cached and time.time() - cached.get("ts", 0) < 1800:
        return cached.get("news", [])
    news = []
    try:
        url  = f"https://finance.naver.com/item/news_news.naver?code={code}&page=1&sm=title_entity_id.basic"
        resp = requests.get(url, headers=_random_ua(), timeout=8)
        soup = BeautifulSoup(resp.text, "html.parser")
        rows = soup.select("table.type5 tr")
        for row in rows[:5]:
            title_el = row.select_one("td.title a")
            time_el  = row.select_one("td.date")
            if not title_el: continue
            title    = title_el.get_text(strip=True)
            t        = time_el.get_text(strip=True) if time_el else ""
            href     = title_el.get("href", "")
            # 절대 URL 변환
            if href and href.startswith("/"):
                href = "https://finance.naver.com" + href
            if len(title) > 5:
                news.append({"title": title, "time": t, "url": href})
            if len(news) >= 3: break
    except Exception as e:
        _swallow_exception(e)
    _news_reverse_cache[code] = {"news": news, "ts": time.time()}
    return news
_news_alert_sent: dict = {}   # code → ts (뉴스 알림 쿨다운, 30분)
def _infer_direct_news_theme(code: str, name: str, articles: list | None = None) -> dict:
    """종목 개별 뉴스 헤드라인에서 직접 이슈 테마를 추론."""
    try:
        items = list(articles or fetch_news_for_stock(code, name) or [])[:3]
        if not items:
            return {"theme": "", "bonus": 0, "reason": "", "headline": "", "matched": []}
        normalized = []
        for item in items:
            title = str(item.get("title", "") or "").strip()
            if title:
                normalized.append(_normalize_news_headline(title))
        if not normalized:
            return {"theme": "", "bonus": 0, "reason": "", "headline": "", "matched": []}
        joined = " ".join(normalized)
        scored = []
        for theme_name, rule in DIRECT_NEWS_THEME_RULES.items():
            hits = []
            for kw in rule.get("keywords", []):
                nkw = _normalize_news_headline(str(kw))
                if nkw and nkw in joined:
                    hits.append(kw)
            uniq_hits = list(dict.fromkeys(hits))
            if uniq_hits:
                scored.append((len(uniq_hits), theme_name, uniq_hits, rule))
        if not scored:
            return {"theme": "", "bonus": 0, "reason": "", "headline": items[0].get("title", ""), "matched": []}
        scored.sort(key=lambda x: (x[0], x[3].get("bonus", 0)), reverse=True)
        _, theme_name, hits, rule = scored[0]
        bonus = int(rule.get("bonus", 0) or 0)
        if len(hits) >= 3:
            bonus += 2
        elif len(hits) >= 2:
            bonus += 1
        return {
            "theme": theme_name,
            "bonus": bonus,
            "reason": str(rule.get("reason", "") or ""),
            "headline": str(items[0].get("title", "") or ""),
            "matched": hits[:4],
        }
    except Exception as e:
        _swallow_exception(e)  # v105 structured silent-exception log
        return {"theme": "", "bonus": 0, "reason": "", "headline": "", "matched": []}
def _normalize_emergent_issue_label(label: str) -> str:
    try:
        t = html.unescape(str(label or "").strip())
        t = t.replace("—", " ").replace("–", " ").replace("|", " ")
        t = _re.sub(r"\s+", " ", t).strip(" -_/,:;[](){}")
        return t
    except Exception as e:
        _swallow_exception(e)  # v105 structured silent-exception log
        return str(label or "").strip()
def _normalize_emergent_issue_key(label: str) -> str:
    txt = _normalize_news_headline(str(label or ""))
    txt = _re.sub(r"[^0-9a-z가-힣]+", "", txt)
    return txt[:24]
def _extract_emergent_issue_candidates(headlines: list, stock_name: str = "") -> list:
    stop_keys = {_normalize_emergent_issue_key(w) for w in EMERGENT_THEME_STOPWORDS}
    stock_key = _normalize_emergent_issue_key(stock_name)
    counter = {}
    for raw in headlines or []:
        title = _normalize_emergent_issue_label(raw)
        if not title:
            continue
        local = {}
        for phrase in _re.findall(r"\[([^\]]{2,18})\]", title):
            label = _normalize_emergent_issue_label(phrase)
            key = _normalize_emergent_issue_key(label)
            if not key or key == stock_key or key in stop_keys or key.isdigit() or len(key) < 2:
                continue
            local[key] = (label, 3)
        norm = _normalize_news_headline(title)
        pieces = [p.strip(".,/%+-") for p in _re.split(r"\s+", norm) if p.strip(".,/%+-")]
        for tok in pieces:
            key = _normalize_emergent_issue_key(tok)
            if not key or key == stock_key or key in stop_keys or key.isdigit() or len(key) < 2:
                continue
            if len(key) <= 3 and not _re.search(r"[a-z]", key):
                continue
            local.setdefault(key, (_normalize_emergent_issue_label(tok), 1))
        for a, b in zip(pieces, pieces[1:]):
            phrase = f"{a} {b}".strip()
            key = _normalize_emergent_issue_key(phrase)
            if not key or key == stock_key or key in stop_keys or key.isdigit() or len(key) < 4:
                continue
            if any(sw in phrase for sw in ("관련", "기대", "상승", "급등", "강세", "주가", "증시", "종목")):
                continue
            local.setdefault(key, (_normalize_emergent_issue_label(phrase), 2))
        for key, (label, weight) in local.items():
            info = counter.setdefault(key, {"label": label, "score": 0, "hits": 0})
            if len(label) > len(info["label"]):
                info["label"] = label
            info["score"] += int(weight)
            info["hits"] += 1
    ranked = sorted(
        [(v["label"], int(v["score"]), int(v["hits"])) for v in counter.values()],
        key=lambda x: (x[1], x[2], len(x[0])),
        reverse=True,
    )
    return ranked[:5]
def _infer_emergent_issue_theme(code: str, name: str, articles: list | None = None) -> dict:
    try:
        items = list(articles or fetch_news_for_stock(code, name) or [])[:3]
        titles = [str((item or {}).get("title", "") or "").strip() for item in items if str((item or {}).get("title", "") or "").strip()]
        if not titles:
            return {"theme": "", "theme_key": "", "bonus": 0, "reason": "", "headline": "", "matched": [], "raw_term": ""}
        ranked = _extract_emergent_issue_candidates(titles, name)
        if not ranked:
            return {"theme": "", "theme_key": "", "bonus": 0, "reason": "", "headline": titles[0], "matched": [], "raw_term": ""}
        label, score, hits = ranked[0]
        if hits < 2 and score < 4:
            return {"theme": "", "theme_key": "", "bonus": 0, "reason": "", "headline": titles[0], "matched": [], "raw_term": ""}
        raw_term = _normalize_emergent_issue_label(label)
        theme_key = _normalize_emergent_issue_key(raw_term)
        if not theme_key:
            return {"theme": "", "theme_key": "", "bonus": 0, "reason": "", "headline": titles[0], "matched": [], "raw_term": ""}
        bonus = 4
        if hits >= 2:
            bonus += 1
        if score >= 6:
            bonus += 1
        theme_label = f"신규이슈·{raw_term[:14]}"
        return {
            "theme": theme_label,
            "theme_key": theme_key,
            "bonus": int(min(bonus, 8)),
            "reason": "반복 헤드라인 기반 신규 이슈 자동감지",
            "headline": titles[0],
            "matched": [term for term, _, _ in ranked[:3]],
            "raw_term": raw_term,
        }
    except Exception as e:
        _swallow_exception(e)  # v105 structured silent-exception log
        return {"theme": "", "theme_key": "", "bonus": 0, "reason": "", "headline": "", "matched": [], "raw_term": ""}
def _register_emergent_issue_theme(code: str, name: str, issue: dict | None, trigger: str = "") -> None:
    issue = issue if isinstance(issue, dict) else {}
    theme = str(issue.get("theme", "") or "").strip()
    theme_key_raw = str(issue.get("theme_key", "") or "").strip()
    if not theme or not theme_key_raw:
        return
    try:
        today = datetime.now().strftime("%m%d")
        dyn_key = f"issue_{theme_key_raw}_{today}"
        existing = _dynamic_theme_map.get(dyn_key)
        if existing and any(c == code for c, _ in existing.get("stocks", [])):
            existing["ts"] = time.time()
            return
        peers = []
        seen = {code}
        if existing:
            for c, n in existing.get("stocks", []):
                if c not in seen:
                    seen.add(c)
                    peers.append((c, n))
        for c, n in build_correlation_theme(code, name):
            if c not in seen:
                seen.add(c)
                peers.append((c, n))
        for c, n, _cnt in get_news_cooccur_peers(code):
            if c not in seen:
                seen.add(c)
                peers.append((c, n))
        for c, n in get_sector_stocks_from_kis(code):
            if c not in seen:
                seen.add(c)
                peers.append((c, n))
        stocks = [(code, name)] + peers[:8]
        payload = {
            "desc": theme,
            "reason": f"{issue.get('reason', '')} [{issue.get('raw_term', '')}]" + (f" ({trigger})" if trigger else ""),
            "stocks": stocks,
            "ts": time.time(),
            "source": "emergent_auto",
            "matched": list(issue.get("matched", [])[:3]),
            "score_adj": int(issue.get("bonus", 0) or 0),
        }
        if existing:
            existing.update(payload)
            existing["stocks"] = stocks
        else:
            _dynamic_theme_map[dyn_key] = payload
            _log_info_msg(f"  🧠 신규 이슈 테마 생성: [{dyn_key}] {theme} | {issue.get('raw_term', '')}")
        try:
            _write_json_atomic(DYNAMIC_THEME_FILE, {k: {**v, "stocks": v["stocks"]} for k, v in _dynamic_theme_map.items()}, indent=2)
        except Exception as e:
            _swallow_exception(e)
    except Exception as e:
        _log_warn_msg(f"⚠️ _register_emergent_issue_theme: {e}")
def _should_soft_allow_no_ask_liquidity_general(cur: dict, signal: dict | None = None) -> bool:
    signal = signal if isinstance(signal, dict) else {}
    sig_type = str(signal.get("signal_type") or "")
    if sig_type not in ("SURGE", "STRONG_BUY", "EARLY_DETECT"):
        return False
    # v161.17: NXT전용 시간대엔 market=="NXT"인 종목만 soft allow — market 오판 방지
    if not is_market_open() and is_nxt_open() and str(signal.get("market") or "") != "NXT":
        return False
    if not is_market_open() and not is_nxt_open():
        return False
    ask_qty = safe_int(cur.get("ask_qty", 0), 0)
    bid_qty = safe_int(cur.get("bid_qty", 0), 0)
    # v169.6: ask_qty > 0이어도 A급 85점↑ +10%↑ SURGE는 통과
    # 이유: 급등 중 호가 얇지만 완전 0이 아닌 경우 이후 조건 전체 차단됨
    #       KBI메탈+22%/해성옵틱스+18.7%/제룡산업+15% 등 A급 고점수 종목 전부 차단 발생
    if ask_qty > 0:
        _grade_q = str(signal.get("execution_grade") or signal.get("grade") or "").upper()
        _cr_q = max(float(cur.get("change_rate", 0) or 0), float(signal.get("change_rate", 0) or 0))
        _sc_q = int(signal.get("score", 0) or 0)
        if not (_grade_q == "A" and _sc_q >= 85 and _cr_q >= 10.0):
            return False  # 조건 미충족 시만 차단, 충족 시 아래로 계속
    # v165.32 [#1]: KRX 개장 직후 10분(09:00~09:10) A급 자동 soft allow
    # 이유: 동시호가 처리 완료 전 ask_qty=0 false positive 집단 발생
    # 2026-04-27 로그: 09:07에 동국제강/서울반도체/플루토스 등 전종목 집단 차단 → 진입 기회 전손
    _grade_now = str(signal.get("execution_grade") or signal.get("grade") or "").upper()
    if is_market_open():
        _now_t = datetime.now().time()
        if dtime(9, 0) <= _now_t < dtime(9, 10) and _grade_now == "A":
            return True  # 개장 10분 A급 → 동시호가 잔여 구간 soft allow
    try:
        change_rate = max(float(cur.get("change_rate", 0.0) or 0.0), float(signal.get("change_rate", 0.0) or 0.0))
    except Exception as e:
        _swallow_exception(e)  # v105 structured silent-exception log
        change_rate = float(signal.get("change_rate", 0.0) or 0.0)
    if bid_qty > 0 and change_rate >= 29.0:
        return False
    # v165.18 [#1]: +15% 이상 급등 종목은 grade 무관 즉시 soft allow
    # 이유: KRX 갭업 구간 09:06 no_ask 차단 30건+ — 15% 이상 급등 중 ask=0은 강한 매수 신호
    if change_rate >= 15.0:
        return True
    try:
        vol_ratio = max(float(cur.get("volume_ratio", 0.0) or 0.0), float(signal.get("volume_ratio", 0.0) or 0.0))
    except Exception as e:
        _swallow_exception(e)  # v105 structured silent-exception log
        vol_ratio = float(signal.get("volume_ratio", 0.0) or 0.0)
    score = int(signal.get("score", 0) or 0)
    direct_news = bool(signal.get("direct_news_hit") or signal.get("direct_news_theme"))
    sector_bonus = int(((signal.get("sector_info") or {}).get("bonus", 0)) or 0)
    sector_live = _extract_alert_sector_theme(signal) != "기타"
    nxt_order_flow = any("NXT 외인+기관 동시매수" in str(r or "") for r in (signal.get("reasons") or []))
    adaptive_priority = bool(_get_adaptive_feedback_code_entry(signal.get("code", "")))
    miss_theme_leader = bool(signal.get("miss_theme_leader_hit"))
    nxt_post_leader = bool(signal.get("nxt_post_leader_hit"))
    leader_priority = bool(signal.get("leader_priority_hit")) or _is_leader_priority_signal(signal) or miss_theme_leader or nxt_post_leader
    # v71: A급 85점↑ NXT 종목은 호가 얇아도 soft allow 통과
    grade = str(signal.get("execution_grade") or signal.get("grade") or "").upper()
    if str(signal.get("market") or "") == "NXT" and grade == "A" and score >= 85 and change_rate >= 5.0:
        return True
    # v165.2: +10% 이상 A급 급등 종목은 체결속도 체크 없이 soft allow
    if grade == "A" and change_rate >= 10.0:
        return True
    # v161.47: 체결속도 soft allow — A급 + score≥72 + change_rate≥5% + exec_speed 보통 이상 + 흐름 비둔화
    # no_ask_liquidity(매도호가 없음)는 급등 중 매수세가 매도물량을 소화한 상태 → 실제로는 강한 매수 신호
    # 이미 수집 중인 _execution_snapshots 활용 (추가 API 호출 없음)
    if grade == "A" and score >= 72 and change_rate >= 5.0:
        _exec_code = str(signal.get("code") or "")
        if _exec_code:
            try:
                _exec_metrics = get_execution_speed_metrics(_exec_code)
                if _exec_metrics.get("ready"):
                    _exec_score = int(_exec_metrics.get("execution_speed_score", 0) or 0)
                    _flow_state = str(_exec_metrics.get("flow_state", "") or "")
                    if _exec_score >= 45 and _flow_state not in ("둔화", "정체"):
                        return True
            except Exception as _e:
                _swallow_exception(_e)
    strong_combo = score >= GENERAL_SOFT_ALLOW_MIN_SCORE and change_rate >= GENERAL_SOFT_ALLOW_MIN_CHANGE and (
        vol_ratio >= GENERAL_SOFT_ALLOW_MIN_VOLUME or sector_bonus >= 10 or sector_live or nxt_order_flow
    )
    if direct_news and change_rate >= max(2.0, GENERAL_SOFT_ALLOW_MIN_CHANGE - 2.0):
        return True
    if str(signal.get("market") or "") == "NXT" and score >= GENERAL_SOFT_ALLOW_MIN_SCORE - 5 and change_rate >= GENERAL_SOFT_ALLOW_MIN_CHANGE and vol_ratio >= 2.0:
        return True
    if adaptive_priority and change_rate >= max(4.0, GENERAL_SOFT_ALLOW_MIN_CHANGE - 1.5) and vol_ratio >= max(1.8, GENERAL_SOFT_ALLOW_MIN_VOLUME - 0.7):
        return True
    if miss_theme_leader and change_rate >= max(5.0, GENERAL_SOFT_ALLOW_MIN_CHANGE - 0.8) and (vol_ratio >= max(1.8, GENERAL_SOFT_ALLOW_MIN_VOLUME - 0.6) or sector_live):
        return True
    if nxt_post_leader and change_rate >= max(4.2, GENERAL_SOFT_ALLOW_MIN_CHANGE - 1.2) and (vol_ratio >= max(1.5, GENERAL_SOFT_ALLOW_MIN_VOLUME - 1.2) or sector_live):
        return True
    if leader_priority and change_rate >= max(4.5, GENERAL_SOFT_ALLOW_MIN_CHANGE - 1.0) and (vol_ratio >= max(1.7, GENERAL_SOFT_ALLOW_MIN_VOLUME - 0.8) or sector_live):
        return True
    return strong_combo
def _has_pending_capture_watch(code: str) -> bool:
    code = normalize_stock_code(code)
    if not code:
        return False
    try:
        if _latest_entry_watch_by_code(code):
            return True
    except Exception as e:
        _swallow_exception(e)
    try:
        for watch in list((_execution_setup_watch or {}).values()):
            if normalize_stock_code((watch or {}).get("code")) == code:
                return True
    except Exception as e:
        _swallow_exception(e)
    return False
def _has_recent_actionable_tracking_state(code: str, max_age_minutes: int = 240) -> bool:
    code = normalize_stock_code(code)
    if not code:
        return False
    try:
        if _has_pending_capture_watch(code):
            return True
    except Exception as e:
        _swallow_exception(e)
    try:
        sig_data = _read_json_locked(SIGNAL_LOG_FILE) if os.path.exists(SIGNAL_LOG_FILE) else {}
    except Exception as e:
        _swallow_exception(e)  # v105 structured silent-exception log
        sig_data = {}
    if not isinstance(sig_data, dict):
        return False
    now_dt = _now_kst()
    active_statuses = {"추적중", "진입준비", "NXT참고도달"}
    newest_dt = None
    for rec in sig_data.values():
        if not isinstance(rec, dict):
            continue
        if normalize_stock_code(rec.get("code")) != code:
            continue
        status = str(rec.get("status", "") or "")
        if status not in active_statuses:
            continue
        cand_dt = None
        for d_key, t_key in (("last_detect_date", "last_detect_time"), ("detect_date", "detect_time"), ("first_detect_date", "first_detect_time")):
            cand_dt = _parse_compact_datetime(rec.get(d_key), rec.get(t_key))
            if cand_dt:
                break
        if not cand_dt:
            continue
        if newest_dt is None or cand_dt > newest_dt:
            newest_dt = cand_dt
    if not newest_dt:
        return False
    return (now_dt - newest_dt).total_seconds() <= max(900, int(max_age_minutes) * 60)
def _should_promote_internal_capture_watch(signal: dict, source_label: str = "") -> bool:
    if not isinstance(signal, dict):
        return False
    code = normalize_stock_code(signal.get("code"))
    if not code or _has_pending_capture_watch(code):
        return False
    entry_price = safe_int(signal.get("entry_price", 0), 0)
    if entry_price <= 0:
        return False
    sig_type = str(signal.get("signal_type", "") or "").upper()
    if sig_type not in ("SURGE", "EARLY_DETECT", "MID_PULLBACK", "ENTRY_POINT", "NEAR_UPPER", "STRONG_BUY"):
        return False
    score = safe_int(signal.get("score", 0), 0)
    grade = str(signal.get("execution_grade") or signal.get("grade") or "C").upper()
    exec_m = signal.get("execution_metrics") or {}
    exec_score = safe_int(exec_m.get("execution_speed_score", 0), 0)
    dip_score = safe_int(exec_m.get("dip_resilience_score", 0), 0)
    theme_live = not _is_generic_sector_theme(_extract_alert_sector_theme(signal))
    direct_like = bool(
        signal.get("direct_news_hit")
        or signal.get("theme_drive_hit")
        or signal.get("adaptive_feedback_hit")
        or signal.get("miss_theme_leader_hit")
        or signal.get("leader_priority_hit")
        or signal.get("emergent_theme_hit")
    )
    change_rate = safe_float(signal.get("change_rate", 0), 0.0)
    vol_ratio = safe_float(signal.get("volume_ratio", 0), 0.0)
    intraday_mode = _intraday_capture_mode_active(_get_intraday_capture_mode())
    if grade == "A":
        return True
    if grade == "B" and (theme_live or direct_like or intraday_mode or exec_score >= 58 or dip_score >= 54 or (change_rate >= 4.0 and vol_ratio >= 2.0)):
        return True
    if score >= max(74, GENERAL_A_RELAXED_SCORE - 2) and (theme_live or direct_like or intraday_mode or exec_score >= 65 or dip_score >= 60):
        return True
    return False
def _promote_internal_capture_watch(signal: dict, hist_key: str = "", source_label: str = "", reason: str = "") -> bool:
    if not _should_promote_internal_capture_watch(signal, source_label=source_label):
        return False
    code = normalize_stock_code(signal.get("code"))
    if not code:
        return False
    snap = dict(signal)
    snap.setdefault("reasons", list(signal.get("reasons") or []))
    snap["internal_watch_promoted"] = True
    snap["internal_watch_reason"] = reason or source_label or "internal_watch_promoted"
    snap["force_register_entry_watch"] = bool(snap.get("force_register_entry_watch"))
    snap.setdefault("reasons", []).append(f"🧭 {source_label or '일반 포착'} 내부감시 자동승격 — {reason or 'near-A 선행 후보 유지'}")
    try:
        save_signal_log(snap)
        if snap.get("signal_type") == "EARLY_DETECT":
            save_early_detect(snap)
        register_entry_watch(snap)
        register_top_signal(snap)
        _log_suppressed_alert(
            snap.get("code", ""), snap.get("name", snap.get("code", "")),
            f"{source_label or '일반 포착'} 내부감시 자동승격 ({reason or 'near-A'})",
            snap.get("signal_type", ""),
            {
                "score": snap.get("score", 0),
                "grade": str(snap.get("execution_grade") or snap.get("grade") or "C"),
                "entry_price": snap.get("entry_price", 0),
                "market": snap.get("market", ""),
            }
        )
        _record_shadow_capture(
            snap.get("code", ""), snap.get("name", snap.get("code", "")), "internal_watch_promoted", snap.get("signal_type", ""),
            stage=source_label or "internal_watch_promoted",
            extra={
                "score": snap.get("score", 0),
                "grade": str(snap.get("execution_grade") or snap.get("grade") or "C"),
                "change_rate": snap.get("change_rate", 0),
                "entry_price": snap.get("entry_price", 0),
                "reason": reason or "near-A",
            },
        )
        return True
    except Exception as e:
        _log_warn_msg(f"⚠️ 내부감시 자동승격 오류 [{code}]: {e}")
        return False
def _is_signal_nxt_premarket_hint(signal: dict | None = None) -> bool:
    signal = signal if isinstance(signal, dict) else {}
    if str(signal.get("market") or "").upper() != "NXT":
        return False
    if _is_nxt_premarket_window():
        return True
    detect_time = str(signal.get("detect_time", "") or "").strip()
    if detect_time.startswith("08:"):
        return True
    detected_at = signal.get("detected_at")
    try:
        if isinstance(detected_at, datetime) and detected_at.hour == 8:
            return True
    except Exception as e:
        _swallow_exception(e)
    return False
def _signal_bid_ask_ratio_hint(signal: dict | None = None) -> float:
    signal = signal if isinstance(signal, dict) else {}
    exec_m = signal.get("execution_metrics") or {}
    candidates = [
        safe_float(signal.get("bid_ask_ratio", 0.0), 0.0),
        safe_float(signal.get("market_flow_bid_ask_ratio", 0.0), 0.0),
        safe_float(exec_m.get("avg_bid_ask_ratio", 0.0), 0.0),
    ]
    return round(max(candidates + [0.0]), 3)
def _should_delay_external_general_capture(signal: dict) -> str:
    if not isinstance(signal, dict):
        return ""
    if signal.get("force_external_capture_alert"):
        return ""
    sig_type = str(signal.get("signal_type") or "").upper()
    entry_price = safe_int(signal.get("entry_price", 0), 0)
    if sig_type == "EARLY_DETECT":
        guard_delay_reason = str(signal.get("early_guard_external_delay_reason") or "").strip()
        if guard_delay_reason:
            return guard_delay_reason
        grade = str(signal.get("execution_grade") or signal.get("grade") or "C").upper()
        score = safe_int(signal.get("score", 0), 0)
        market = str(signal.get("market") or "").upper()
        is_nxt_premarket = market == "NXT" and _is_signal_nxt_premarket_hint(signal)
        if is_nxt_premarket and score >= 70 and grade in ("A", "B"):
            return ""
        # v163.5: KRX EARLY_DETECT 외부알림 조건 완화
        # 기존: exec_score >= 52 OR bid_ask_ratio >= 1.2 필수 → WebSocket 스냅샷 실패 시 전량 차단
        # 변경: A급 + score >= 74이면 exec_score/bid_ask_ratio 무관하게 통과
        #       단, early_guard_external_delay_reason이 있으면 여전히 차단
        if (
            grade == "A"
            and score >= EARLY_EXTERNAL_KRX_SCORE_MIN
            and entry_price > 0
        ):
            return ""
        # B급도 점수 85 이상이면 통과 (고점수 B급 손실 방지)
        if grade == "B" and score >= 85 and entry_price > 0:
            return ""
        return "조기포착 행동단계 전 외부알림 지연"
    if bool(signal.get("execution_setup_required")):
        return "체결확인 전 외부알림 지연"
    if entry_price <= 0:
        price = safe_int(signal.get("price", 0), 0)
        if price > 0:
            signal["entry_price"] = price
            signal.setdefault("reasons", []).append("⚠️ 진입가 미산출 — 현재가 기준 발송")
        else:
            return "진입가 미확정 외부알림 지연"
    return ""
def _persist_general_capture_without_external(s: dict, hist_key: str, source_label: str, delay_reason: str) -> bool:
    code = normalize_stock_code(s.get("code"))
    grade_upper = str(s.get("execution_grade") or s.get("grade") or "C").upper()
    _logged = _record_internal_only_alert(hist_key, s, f"{source_label} {delay_reason}")
    save_signal_log(s)
    if s.get("signal_type") == "EARLY_DETECT":
        save_early_detect(s)
    if code and safe_int(s.get("entry_price", 0), 0) > 0 and (_logged or not _has_pending_capture_watch(code)):
        register_entry_watch(s)
        register_top_signal(s)
    _record_shadow_capture(
        s.get("code", ""), s.get("name", s.get("code", "")), "external_action_delayed", s.get("signal_type", ""),
        stage=source_label,
        extra={
            "score": s.get("score", 0),
            "grade": grade_upper,
            "change_rate": s.get("change_rate", 0),
            "market": s.get("market", ""),
            "delay_reason": delay_reason,
            "entry_price": s.get("entry_price", 0),
        },
    )
    _log_info_msg(f"  ⏭ {s['name']}{' 🟡NXT' if str(s.get('market') or '') == 'NXT' else ''} {s.get('change_rate',0):+.1f}% [{s.get('signal_type','')}] {s.get('score',0)}점 [{grade_upper}] — 외부알림 지연/내부감시 유지 ({delay_reason})")
    return False
def _should_keep_internal_watch_on_no_ask_liquidity(cur: dict, signal: dict | None = None) -> bool:
    signal = signal if isinstance(signal, dict) else {}
    entry_price = safe_int(signal.get("entry_price", 0), 0)
    if entry_price <= 0:
        return False
    if _should_promote_internal_capture_watch(signal, source_label="호가차단내부유지"):
        return True
    score = safe_int(signal.get("score", 0), 0)
    grade = str(signal.get("execution_grade") or signal.get("grade") or "").upper()
    exec_m = signal.get("execution_metrics") or {}
    exec_score = safe_int(exec_m.get("execution_speed_score", 0), 0)
    change_rate = safe_float(signal.get("change_rate", 0), 0.0)
    vol_ratio = safe_float(signal.get("volume_ratio", 0), 0.0)
    if signal.get("theme_chain_force_hit") or signal.get("force_external_capture_alert"):
        return True
    if grade == "A" or score >= 82:
        return True
    if grade == "B" and (exec_score >= 58 or (change_rate >= 4.0 and vol_ratio >= 2.0)):
        return True
    return False
def _persist_blocked_capture_watch(signal: dict, source_label: str = "", blocked_reason: str = "") -> bool:
    snap = dict(signal if isinstance(signal, dict) else {})
    code = normalize_stock_code(snap.get("code"))
    if not code:
        return False
    if _has_pending_capture_watch(code):
        return True
    snap["force_register_entry_watch"] = True
    snap["internal_watch_promoted"] = True
    snap["internal_watch_reason"] = f"{source_label or '포착'} {blocked_reason or '차단'} 내부감시 유지"
    snap.setdefault("reasons", []).append(f"🧭 {source_label or '포착'} 호가 차단 상태에서도 내부감시 유지 ({blocked_reason or 'no_ask_liquidity'})")
    try:
        save_signal_log(snap)
        register_entry_watch(snap)
        register_top_signal(snap)
        _log_suppressed_alert(
            snap.get("code", ""), snap.get("name", snap.get("code", "")),
            f"{source_label or '포착'} 내부감시 유지 ({blocked_reason or 'no_ask_liquidity'})",
            snap.get("signal_type", ""),
            {"entry_price": snap.get("entry_price", 0), "score": snap.get("score", 0), "grade": str(snap.get("execution_grade") or snap.get("grade") or "")}
        )
        _record_shadow_capture(
            snap.get("code", ""), snap.get("name", snap.get("code", "")), "internal_watch_kept", snap.get("signal_type", ""),
            stage=source_label or "internal_watch_kept",
            extra={"blocked_reason": blocked_reason or "no_ask_liquidity", "entry_price": snap.get("entry_price", 0), "score": snap.get("score", 0), "grade": str(snap.get("execution_grade") or snap.get("grade") or "")}
        )
        return True
    except Exception as e:
        _log_warn_msg(f"⚠️ 호가 차단 내부감시 유지 오류 [{code}]: {e}")
        return False
def _build_general_alert_dispatch_context(s: dict, hist_key: str | None) -> dict | None:
    if not isinstance(s, dict) or not s.get("code"):
        return None
    s = _coerce_run_scan_signal_defaults(s, fallback_code=s.get("code"))
    if is_scoring_only_instrument(s.get("code", ""), s.get("name", "")):
        _log_info_msg(f"  ⏭ 점수전용 종목 제외: {s.get('name', s.get('code',''))}")
        return None
    is_nxt = str(s.get("market") or "") == "NXT"
    # v161.17: KRX 장마감 후 NXT 종목만 허용 — market 필드 오판 방지 위해 is_nxt_open()+not is_market_open() 기준 사용
    # is_nxt_listed()가 _nxt_unavailable 기준이라 KRX 종목도 NXT로 오판 가능 → market!="NXT"이면 모두 차단
    if not is_market_open() and is_nxt_open() and not is_nxt:
        _log_info_msg(f"  ⏭ NXT전용 시간대 비NXT 종목 차단: {s.get('name', s.get('code',''))} (market={s.get('market','')})")
        return None
    # KRX·NXT 모두 닫힌 시간대도 차단
    if not is_market_open() and not is_nxt_open():
        _log_info_msg(f"  ⏭ 전 시장 마감 후 차단: {s.get('name', s.get('code',''))}")
        return None
    resolved_hist_key = hist_key or (f"NXT_{s['code']}" if is_nxt else s["code"])
    mkt_tag = " 🟡NXT" if is_nxt else ""
    s = _apply_execution_speed_to_signal(s)
    s = _coerce_run_scan_signal_defaults(s, fallback_code=s.get("code"))
    live = _get_live_quote_for_signal(s)
    live_price = safe_int((live or {}).get("price", s.get("price", 0)), 0)
    # v161.22: live_price 확정 즉시 s["price"] 갱신 — 이후 모든 하위 로직이 실시간 가격 기준으로 동작
    # (entry_block 판단, soft_allow, save_signal_log, send_alert 등 전부 live_price 기반)
    if live_price > 0:
        s["price"] = live_price
        live_change_rate = safe_float((live or {}).get("change_rate", 0), 0.0)
        if live_change_rate != 0.0:
            s["change_rate"] = live_change_rate
    # v161.29: change_rate>=29% 또는 price>=upper_price 종목이 SURGE로 알람 나가는 문제 차단
    # ask_qty>0이어도 상한가급은 NEAR_UPPER로 강제 변환 → 이후 entry_block에서 차단됨
    _live_cr = safe_float(s.get("change_rate", 0), 0.0)
    _live_upper = safe_int((live or {}).get("upper_price", 0), 0)
    _live_sign  = str((live or {}).get("prdy_vrss_sign", "") or "")
    _is_upper_hit = (_live_upper > 0 and live_price >= _live_upper) or _live_sign == "1" or _live_cr >= 29.0
    if _is_upper_hit and s.get("signal_type") not in ("UPPER_LIMIT", "NEAR_UPPER"):
        s["signal_type"] = "NEAR_UPPER"
        _log_info_msg(f"  ⏭ {s.get('name', s.get('code',''))} 상한가급({_live_cr:.1f}%) → NEAR_UPPER 강제 변환")
    entry = safe_int(s.get("entry_price", 0), 0)
    blocked_reason = ""
    if entry and live_price and live_price >= entry:
        try:
            blocked_reason = _detect_entry_block_reason(live or {}, s, live_price, entry)
            if blocked_reason == "fake_breakout_risk":
                # v165.33 [#4]: fake_breakout_risk 차단을 Telegram 발송 이전으로 이동
                # 이유: 기존 blocked_reason=""로 초기화 → 알람 발송 → 15초 후 entry_watch에서 뒤늦게 차단
                # 2026-04-27 이렘/동원수산: "✓ ... [A]" 알람 수신 후 즉시 "🚫 fake_breakout_risk 차단"
                # 개선점: blocked_reason 유지 → _handle_general_alert_entry_block이 발송 전 차단
                # 주의점: cautions/reasons 주석은 entry_watch 경로 차단 메시지에서 계속 사용됨
                s.setdefault("cautions", []).append("⚠️ 가짜 돌파 주의 — 거래량 기준 미달 + 윗꼬리 부담, 신규 진입은 재눌림/재돌파 확인 우선")
                s.setdefault("reasons", []).append("⚠️ 돌파형은 재눌림 또는 재돌파 확인 후 접근")
                # blocked_reason = ""  ← 제거: 이 라인이 차단을 해제하여 발송 → entry_watch 뒤늦게 차단
        except Exception as e:
            _swallow_exception(e)
            blocked_reason = ""
    grade_upper = str(s.get("execution_grade") or s.get("grade") or "C").upper()
    return {
        "signal": s,
        "hist_key": resolved_hist_key,
        "mkt_tag": mkt_tag,
        "live": live or {},
        "live_price": live_price,
        "entry": entry,
        "blocked_reason": blocked_reason,
        "grade_upper": grade_upper,
    }
def _handle_general_alert_entry_block(ctx: dict, source_label: str) -> bool:
    blocked_reason = ctx["blocked_reason"]
    if not blocked_reason:
        # v165.25 [#1]: 선진입 발송 종목 당일 SURGE/NEAR_UPPER 중복 차단
        _code = (ctx.get("signal") or {}).get("code", "")
        _today = _now_kst().strftime("%Y%m%d")
        if _code and _preclose_gap_sent_today.get(_code) == _today:
            _sig_type = str((ctx.get("signal") or {}).get("signal_type", "")).upper()
            if _sig_type in ("SURGE", "NEAR_UPPER"):
                _log_info_msg(f"  🚫 선진입 발송 종목 SURGE 중복 차단: {(ctx.get('signal') or {}).get('name', _code)}({_code})")
                return False
        return True
    s = ctx["signal"]
    live = ctx["live"]
    entry = ctx["entry"]
    live_price = ctx["live_price"]
    if blocked_reason == "no_ask_liquidity" and _should_soft_allow_no_ask_liquidity_general(live, s):
        s["entry_soft_block_allowed"] = True
        s.setdefault("reasons", []).append("⚠️ 현재 호가 매도잔량이 얇아 즉시 체결은 불리할 수 있음 — 직접뉴스/수급/거래대금 근거로 관찰 우선 통과")
        _log_suppressed_alert(
            s["code"],
            s["name"],
            f"{source_label} 호가경고(soft) ({blocked_reason})",
            s.get("signal_type", ""),
            {
                "entry_price": entry,
                "blocked_price": live_price,
                "change_rate": live.get("change_rate", 0),
                "ask_qty": live.get("ask_qty", 0),
                "bid_qty": live.get("bid_qty", 0),
            },
        )
        return True
    kept_internal = False
    if blocked_reason == "no_ask_liquidity" and _should_keep_internal_watch_on_no_ask_liquidity(live, s):
        kept_internal = _persist_blocked_capture_watch(s, source_label=source_label, blocked_reason=blocked_reason)
    # v161.12: upper_limit_reached 시 당일 코드 기준으로 재알람 차단 기록
    # v163.9 [#2]: 등록 전 실시간 등락률 재확인 — 오판된 upper_limit_reached 영구차단 방지
    if blocked_reason == "upper_limit_reached":
        code = s.get("code", "")
        today = _now_kst().strftime("%Y%m%d")
        _live_chg = safe_float((live or {}).get("change_rate", 0), 0.0)
        _live_upper = safe_int((live or {}).get("upper_price", 0), 0)
        _live_price = safe_int((live or {}).get("price", 0), 0)
        _real_upper = (_live_upper > 0 and _live_price >= _live_upper) or _live_chg >= 28.0
        if _real_upper:
            _upper_limit_alerted_today[code] = today
            _save_upper_limit_alerted_today()
        else:
            # 실제 상한가 미도달 — 등록 skip, 다음 사이클에 재시도 가능
            _log_info_msg(f"  ⚠️ upper_limit_reached 오판 방지: {s.get('name', code)}({code}) 등락률 {_live_chg:.1f}% < 28% — 차단 등록 skip")
    _log_suppressed_alert(
        s["code"],
        s["name"],
        f"{source_label} 신호 차단 ({blocked_reason})",
        s.get("signal_type", ""),
        {
            "entry_price": entry,
            "blocked_price": live_price,
            "change_rate": live.get("change_rate", 0),
            "ask_qty": live.get("ask_qty", 0),
            "bid_qty": live.get("bid_qty", 0),
            "internal_watch_kept": bool(kept_internal),
        },
    )
    _record_shadow_capture(
        s.get("code", ""),
        s.get("name", s.get("code", "")),
        blocked_reason,
        s.get("signal_type", ""),
        stage=source_label,
        extra={
            "score": s.get("score", 0),
            "grade": s.get("grade", ""),
            "entry_price": entry,
            "blocked_price": live_price,
            "change_rate": live.get("change_rate", 0),
            "market": s.get("market", ""),
            "internal_watch_kept": bool(kept_internal),
        },
    )
    return False
def _handle_general_alert_external_policy(ctx: dict, source_label: str) -> bool:
    s = ctx["signal"]
    hist_key = ctx["hist_key"]
    grade_upper = ctx["grade_upper"]
    delay_reason = _should_delay_external_general_capture(s)
    if delay_reason:
        return _persist_general_capture_without_external(s, hist_key, source_label, delay_reason)
    if _should_send_external_grade_alert(s):
        _internal_only_alert_history.pop(hist_key, None)
        return True
    logged = _record_internal_only_alert(hist_key, s, f"{source_label} {grade_upper}등급 외부알림 억제(A전용)")
    promoted = _promote_internal_capture_watch(s, hist_key=hist_key, source_label=source_label, reason=f"{grade_upper}등급 near-A/테마/체결 확증")
    if logged and not promoted:
        save_signal_log(s)
        if s.get("signal_type") == "EARLY_DETECT":
            save_early_detect(s)
    _record_shadow_capture(
        s.get("code", ""),
        s.get("name", s.get("code", "")),
        "external_grade_suppressed",
        s.get("signal_type", ""),
        stage=source_label,
        extra={
            "score": s.get("score", 0),
            "grade": grade_upper,
            "change_rate": s.get("change_rate", 0),
            "market": s.get("market", ""),
            "internal_watch_promoted": bool(promoted),
        },
    )
    if promoted:
        _log_info_msg(
            f"  ⏭ {s.get('name', s.get('code',''))}{ctx['mkt_tag']} {safe_float(s.get('change_rate', 0.0), 0.0):+.1f}% [{s.get('signal_type', '')}] {safe_int(s.get('score', 0), 0)}점 [{grade_upper}] — 외부억제/내부감시 자동승격"
        )
    else:
        _log_info_msg(
            f"  ⏭ {s.get('name', s.get('code',''))}{ctx['mkt_tag']} {safe_float(s.get('change_rate', 0.0), 0.0):+.1f}% [{s.get('signal_type', '')}] {safe_int(s.get('score', 0), 0)}점 [{grade_upper}] — 내부기록만 유지"
        )
    return False
def _trigger_general_alert_phase2_upgrade(s: dict, existing_hit_watch: dict, old_sig_type: str, new_sig_type: str) -> bool:
    _log_info_msg(f"  🔀 신호 강화({old_sig_type}→{new_sig_type}): {s.get('name','')} — 포착 알림 차단, phase2 트리거")
    save_signal_log(s)
    try:
        p2_cur = get_nxt_stock_price(s["code"]) if (str(s.get("market") or "") == "NXT") else get_stock_price(s["code"])
        p2_price = safe_int((p2_cur or {}).get("price", s.get("price", 0)), 0) or safe_int(s.get("price", 0), 0)
        p2_entry = safe_int(existing_hit_watch.get("entry_price", 0), 0)
        p2_exec = get_execution_speed_metrics(s["code"], current_price=p2_price)
        p2_judgement = _judge_phase2_entry(existing_hit_watch, p2_cur or {}, p2_price, p2_exec)
        p2_detail = p2_judgement.get("detail", "")
        p2_reasons = p2_judgement.get("reasons", [])
        p2_decision = p2_judgement.get("decision", "보류")
        p2_emoji = {"가능": "✅", "보류": "🟡", "금지": "🔴"}.get(p2_decision, "🟡")
        p2_diff_pct = round((p2_price - p2_entry) / p2_entry * 100, 1) if p2_entry else 0.0
        p2_diff_str = f"+{p2_diff_pct:.1f}%" if p2_diff_pct >= 0 else f"{p2_diff_pct:.1f}%"
        split_rule = _get_entry_split_rule(existing_hit_watch.get("regime_mode", "normal"))
        p2_pct = split_rule.get("phase2_pct", 20)
        p1_pct = split_rule.get("phase1_pct", 30)
        total_pct = p1_pct + p2_pct
        avg_price = _calc_avg_entry_price(p2_entry, p2_price, p1_pct, p2_pct)
        nxt_notice = "\n📡 <b>NXT 기준 가격</b>" if (str(s.get("market") or "") == "NXT") else ""
        sig_labels = {
            "UPPER_LIMIT": "상한가",
            "NEAR_UPPER": "상한가근접",
            "SURGE": "급등",
            "EARLY_DETECT": "조기포착",
            "MID_PULLBACK": "눌림목",
            "ENTRY_POINT": "눌림목",
        }
        old_sig_label = sig_labels.get(old_sig_type, old_sig_type)
        new_sig_label = sig_labels.get(new_sig_type, new_sig_type)
        entry_hit_ts = str(existing_hit_watch.get("entry_hit_time") or datetime.now().strftime('%Y-%m-%d %H:%M:%S'))
        reasons_str = "\n".join([f"│ {r}" for r in p2_reasons])
        if not _should_send_phase2_upgrade_alert(existing_hit_watch, new_sig_type, p2_decision):
            _log_info_msg(f"  ⏭ phase2 중복억제({old_sig_type}→{new_sig_type}/{p2_decision}): {s.get('name','')} — 외부알림 생략")
            return False
        if not _should_send_entry_followup_alert(existing_hit_watch, "phase2", p2_decision):
            _log_info_msg(f"  ⏭ 후속알림 통합억제(phase2/{p2_decision}): {s.get('name','')} — 외부알림 생략")
            return False
        send_with_chart_buttons(
            f"🔔🔔 <b>[2차 진입 판단]</b>{nxt_notice}\n"
            f"━━━━━━━━━━━━━━━\n"
            f"🔴 <b>{existing_hit_watch.get('name', s.get('name', ''))}</b>  "
            f"<code>{existing_hit_watch.get('code', s.get('code', ''))}</code>\n"
            f"원신호: {old_sig_label} → 신규: <b>{new_sig_label}</b> (모멘텀 강화)\n"
            f"1차 도달: {entry_hit_ts}  |  감지: {datetime.now().strftime('%Y-%m-%d %H:%M:%S')}\n\n"
            f"━━━━━━━━━━━━━━━\n"
            f"┌─────────────────────\n"
            f"│ {p2_emoji} <b>{p2_decision}</b>\n"
            f"│ 📍 현재가  <b>{p2_price:,}원</b>  ({p2_diff_str})\n"
            f"│ 💰 권장 추가비중: <b>{p2_pct}%</b>\n"
            f"│ 📊 총 누적 권장비중: <b>{total_pct}%</b>\n"
            f"│ 📐 평균단가 예상: <b>{avg_price:,}원</b>\n"
            f"│ 🛡 손절가: <b>{int(existing_hit_watch.get('stop_loss', 0)):,}원</b>\n"
            f"├─────────────────────\n"
            f"│ <b>판단 근거</b>\n"
            f"{reasons_str}\n"
            f"│ → {p2_detail}\n"
            f"└─────────────────────",
            existing_hit_watch.get("code", s.get("code", "")),
            existing_hit_watch.get("name", s.get("name", "")),
        )
        _mark_phase2_upgrade_alert_sent(existing_hit_watch, new_sig_type, p2_decision, p2_price)
        _mark_entry_followup_alert_sent(existing_hit_watch, "phase2", p2_decision, p2_price)
        # v165.46 [1][2]: 2차 진입 "가능" 확정 시 watch 완전 업데이트
        if p2_decision == "가능" and avg_price > 0:
            orig_entry_p1 = existing_hit_watch.get("entry_price", avg_price)
            orig_stop_pct = abs((orig_entry_p1 - existing_hit_watch.get("stop_loss", 0)) / orig_entry_p1) if orig_entry_p1 > 0 else 0.07
            new_stop_final = int(avg_price * (1 - orig_stop_pct) / 10) * 10
            # [1] target_price 재계산: avg 높아진 경우 목표 상향, 낮아진 경우 원래 목표 유지
            orig_target = existing_hit_watch.get("target_price", 0)
            if orig_target > 0 and orig_entry_p1 > 0:
                orig_target_pct = (orig_target - orig_entry_p1) / orig_entry_p1
                new_target_from_avg = int(avg_price * (1 + orig_target_pct) / 10) * 10
                final_target = max(orig_target, new_target_from_avg)
            else:
                final_target = orig_target
            # [2] 분할 목표가 설정
            target_phase1 = final_target
            target_phase2 = int((final_target + (final_target - avg_price) * 0.5) / 10) * 10 if final_target > avg_price else final_target
            existing_hit_watch["phase2_confirmed"] = True
            existing_hit_watch["phase2_entry_price"] = p2_price
            existing_hit_watch["phase2_pct"] = p2_pct
            existing_hit_watch["phase2_ts"] = datetime.now().strftime('%Y-%m-%d %H:%M:%S')
            existing_hit_watch["entry_price_phase1"] = orig_entry_p1
            existing_hit_watch["entry_price"] = avg_price
            existing_hit_watch["stop_loss"] = new_stop_final
            existing_hit_watch["target_price_phase1"] = target_phase1
            existing_hit_watch["target_price"] = target_phase1
            existing_hit_watch["target_price_phase2"] = target_phase2
            try:
                _mark_entry_hit_in_signal_log(
                    existing_hit_watch.get("code", ""),
                    existing_hit_watch.get("signal_type", ""),
                    hit_price=avg_price,
                    hit_time=datetime.now().strftime('%Y-%m-%d %H:%M:%S'),
                    log_key=existing_hit_watch.get("signal_log_key"),
                    extra={
                        "phase2_confirmed": True, "phase2_avg_entry": avg_price,
                        "phase2_stop": new_stop_final, "target_price_phase1": target_phase1,
                        "target_price_phase2": target_phase2,
                    },
                )
            except Exception as _e2:
                _swallow_exception(_e2)
            _log_info_msg(f"  ✅ 2차진입 확정 — {existing_hit_watch.get('name','')} avg={avg_price:,} stop={new_stop_final:,} target1={target_phase1:,} target2={target_phase2:,}")
        _save_entry_watch_active()
    except Exception as e:
        _log_warn_msg(f"  ⚠️ phase2 트리거 오류: {e}")
    return True
def _handle_general_alert_existing_entry_hit(ctx: dict) -> bool | None:
    s = ctx["signal"]
    live_for_halt = ctx["live"] if isinstance(ctx["live"], dict) else {}
    code = normalize_stock_code(s.get("code", ""))
    if _is_trading_halt(code, live_for_halt or None):
        _mark_trading_halt_state(code, title=_get_trading_halt_reason_label(s.get("code", "")), name=s.get("name", ""), source="dispatch_block")
        _log_warn_msg(f"  🚫 거래정지 차단: {s.get('name','')} [{s.get('signal_type','')}] — 포착 알림 억제")
        save_signal_log(s)
        return False
    signal_strength_rank = {
        "MID_PULLBACK": 1,
        "ENTRY_POINT": 1,
        "EARLY_DETECT": 2,
        "SURGE": 3,
        "NEAR_UPPER": 4,
        "UPPER_LIMIT": 5,
        "STRONG_BUY": 5,
    }
    new_sig_type = str(s.get("signal_type") or "").upper()
    _, existing_hit_watch = _find_existing_entry_hit_watch(s.get("code", ""))
    if existing_hit_watch is None:
        return None
    old_sig_type = str(existing_hit_watch.get("signal_type") or "").upper()
    new_rank = signal_strength_rank.get(new_sig_type, 0)
    old_rank = signal_strength_rank.get(old_sig_type, 0)
    if new_rank > old_rank:
        return _trigger_general_alert_phase2_upgrade(s, existing_hit_watch, old_sig_type, new_sig_type)
    _log_info_msg(f"  ⏭ 신호 약화/유지({old_sig_type}→{new_sig_type}): {s.get('name','')} — 기존 entry_hit 보호, 내부 기록만")
    save_signal_log(s)
    return False
def _finalize_general_alert_dispatch(ctx: dict) -> bool:
    s = _coerce_run_scan_signal_defaults(ctx.get("signal"), fallback_code=(ctx.get("signal") or {}).get("code"))
    ctx["signal"] = s
    name = s.get("name", s.get("code", ""))
    code = s.get("code", "")
    signal_type = s.get("signal_type", "")
    grade_upper = str(ctx.get("grade_upper") or s.get("execution_grade") or s.get("grade") or "C").upper()
    # v161.3 #7: 쿨다운 내 동일 score·change_rate면 재발송 억제
    hist_key = ctx.get("hist_key", code)
    prev = _alert_history.get(hist_key)
    if isinstance(prev, dict):
        if (prev.get("score") == safe_int(s.get("score", 0), 0)
                and abs(prev.get("change_rate", 0) - safe_float(s.get("change_rate", 0), 0.0)) < 0.1):
            _log_info_msg(f"  ⏭ {name} — 동일 신호 재발송 억제 (score={prev.get('score')} change_rate={prev.get('change_rate'):+.1f}%)")
            return False
    # v161.12: upper_limit_reached 당일 차단 확인
    today = _now_kst().strftime("%Y%m%d")
    if _upper_limit_alerted_today.get(code) == today:
        _log_info_msg(f"  ⏭ {name} — upper_limit_reached 당일 재알람 차단")
        save_signal_log(s)
        return False
    _log_info_msg(f"  ✓ {name}{ctx.get('mkt_tag','')} {safe_float(s.get('change_rate',0),0.0):+.1f}% [{signal_type}] {safe_int(s.get('score',0),0)}점 [{grade_upper}]")
    # v163.6: NXT SURGE 동일 종목 2시간 텔레그램 쿨다운 — 에스투더블유류 7회 중복 발송 방지
    # 진입가 도달 알람은 예외(쿨다운 미적용)
    # v163.14 [#3]: ✓ 로그는 쿨다운 통과 후에만 의미 있으므로 쿨다운 차단 시 ✓ 대신 ⏭ 로 교체
    if (signal_type == "SURGE"
            and str(s.get("market") or s.get("_market") or "").upper() == "NXT"
            and not s.get("_entry_hit_alert")):
        nxt_surge_cooldown_key = f"nxt_surge_cd:{code}"
        prev_nxt = _alert_history.get(nxt_surge_cooldown_key)
        if isinstance(prev_nxt, dict):
            elapsed = time.time() - float(prev_nxt.get("ts", 0) or 0)
            if elapsed < 7200:  # 2시간
                # v163.14 [#3]: ✓ 로그 취소 (이미 출력됨) → 덮어쓰기용 ⏭ 로그
                _log_info_msg(f"  ⏭ {name} — NXT SURGE 2시간 쿨다운 ({int(elapsed//60)}분 경과, 대표갱신만)")
                save_signal_log(s)
                register_entry_watch(s)  # 진입가 갱신은 유지
                return False
    # v161.43: 기존 entry_hit watch 존재 시 헤더에 "+ 1차 진입가 도달" 반영 허용
    # v162.6: notify_count>=1 조건 추가 — 사용자가 실제 1차 알람 받은 경우에만 헤더 반영
    #         1차 알람 미수령(notify_count=0) 상태에서 NEAR_UPPER에 '1차 진입가 도달' 표시 시 혼란
    # v165.44 [1][3]: entry_hit 상태에 따른 분기
    # entry_hit=False → 기존대로 _allow_existing_entry_hit_header (1차 도달 헤더 허용)
    # entry_hit=True  → _is_second_entry_reopen 마킹 (1차 헤더 재사용 금지, signal_log 새 레코드 강제)
    _, _existing_watch_nc = _find_existing_entry_hit_watch(code)
    if _existing_watch_nc is not None and safe_int(_existing_watch_nc.get("notify_count", 0), 0) >= 1:
        if _existing_watch_nc.get("entry_hit"):
            # 이미 1차 진입 완료된 종목 재포착 → 2차 진입 검토 경로
            s["_is_second_entry_reopen"] = True
            s["_allow_existing_entry_hit_header"] = False
            # signal_log: 1차 데이터 보존 위해 대표 레코드 갱신 금지 (신규 독립 레코드 저장)
            s["_force_new_signal_log_record"] = True
            _log_info_msg(f"  ♻️ {name} — entry_hit 재포착 → 2차진입 경로 (1차 데이터 보존)")
        else:
            s["_allow_existing_entry_hit_header"] = True
    # v163.1: send_alert 전 게이트 선차단 확인 — 차단 시 register_entry_watch도 스킵
    _gate_block = _pre_send_upper_block(s)
    if _gate_block:
        _log_info_msg(f"  🚫 [게이트 선차단] {name} — {_gate_block} (진입감시 등록 스킵)")
        save_signal_log(s)
        return False
    send_alert(s)
    _alert_history[ctx["hist_key"]] = {
        "ts": time.time(),
        "score": safe_int(s.get("score", 0), 0),
        "change_rate": safe_float(s.get("change_rate", 0), 0.0),
    }
    # v163.6: NXT SURGE 발송 성공 시 쿨다운 키 기록
    if signal_type == "SURGE" and str(s.get("market") or s.get("_market") or "").upper() == "NXT":
        _alert_history[f"nxt_surge_cd:{code}"] = {"ts": time.time()}
    _save_alert_history()   # v161.15: 발송 즉시 상태파일 저장 → 재시작 후 쿨다운 유지
    # v161.23: NEAR_UPPER/UPPER_LIMIT 발송 즉시 당일 차단 등록 — 오전 상한가 종목이 봇 미포착 상태면
    # _upper_limit_alerted_today에 기록이 없어 나중에 재포착 시 알람이 나가는 문제 방지
    if signal_type in ("UPPER_LIMIT", "NEAR_UPPER") or safe_float(s.get("change_rate", 0), 0.0) >= 29.0:
        today = _now_kst().strftime("%Y%m%d")
        _upper_limit_alerted_today[code] = today
        _save_upper_limit_alerted_today()
        _log_info_msg(f"  🔒 {name} — 상한가류 발송 완료, 당일 재알람 차단 등록")
    save_signal_log(s)
    if signal_type == "EARLY_DETECT":
        save_early_detect(s)
    # v161.43: 상한가류(NEAR_UPPER/UPPER_LIMIT/29%↑)는 entry_watch 신규 등록 차단
    if signal_type in ("UPPER_LIMIT", "NEAR_UPPER") or safe_float(s.get("change_rate", 0), 0.0) >= 29.0:
        _expire_entry_watch_for_upper_limit(code, name)
        watch_key = None
    else:
        watch_key = register_entry_watch(s)
    _maybe_send_immediate_entry_hit_from_signal(s, watch_key=watch_key, merge_capture_phase1=False)
    # v165.9: "1차 진입가 도달" 헤더가 실제로 발송됐는데 entry_hit 미기록된 경우 동기화
    # 원인: _maybe_send_immediate_entry_hit_from_signal에서 no_ask_liquidity 등으로 차단되면
    #       entry_hit=True 기록 없이 return → 2시간 후 재포착 시 신규 포착으로 오인 → 동일 알람 재발송
    # 수정: 알람 발송 시점에 price <= entry_price 조건이 성립했으면 entry_hit 기록 (알람 발송이 곧 hit 인정)
    if watch_key and watch_key in _entry_watch:
        _w = _entry_watch.get(watch_key)
        if (isinstance(_w, dict)
                and not _w.get("entry_hit")
                and not _w.get("entry_hit_locked")
                and _is_general_capture_first_entry_reached(s, live_price=safe_int(s.get("price", 0), 0))):
            _w["entry_hit"] = True
            _w.setdefault("entry_hit_time", datetime.now().strftime('%Y-%m-%d %H:%M:%S'))
            _w.setdefault("entry_hit_price", safe_int(s.get("price", 0), 0))
            _log_info_msg(f"  📌 {name}({code}) entry_hit 동기화 — 알람 발송 시점 진입가 도달 기록")
            try:
                _save_entry_watch_active()
            except Exception as _e:
                _swallow_exception(_e)
    register_top_signal(s)
    if len(_sector_monitor) < 8 and _needs_sector_resend_for_alert(s):
        sector_retry_snap = _clone_alert_snapshot_for_sector_retry(s)
        sector_retry_snap["_alert_sender"] = "send_alert"
        # v165.44 [2]: from_alert=False → 섹터 모니터링·모멘텀 추적은 유지, 재안내 알람 발송 금지
        # 이유: "섹터 미반영 재안내" 알람이 사용자에게 혼선 유발 (같은 종목 두 번 전송 인상)
        #       섹터 모멘텀은 내부 스코어링·진입 판단에 계속 활용됨 (_process_sector_monitor_iteration)
        start_sector_monitor(code, name, signal_type, s.get("detect_time", ""), False, alert_snapshot=sector_retry_snap)
    try:
        threading.Thread(target=auto_update_theme, args=(code, name, signal_type), daemon=True).start()
    except Exception as e:
        _swallow_exception(e)
    # v169.0: 포착 즉시 자동 섹터 등록 — SECTOR_SEED_STOCKS 하드코딩 불필요
    # 5%↑ 포착 종목의 bstp_code 기반으로 동업종 중소형주를 _dynamic_theme_map에 자동 등록
    try:
        if safe_float(s.get("change_rate", 0), 0.0) >= 5.0 and signal_type in ("SURGE", "NEAR_UPPER", "STRONG_BUY", "UPPER_LIMIT", "EARLY_DETECT"):
            threading.Thread(
                target=_auto_register_sector_from_signal,
                args=(code, name, safe_float(s.get("change_rate", 0), 0.0)),
                daemon=True,
            ).start()
    except Exception as e:
        _swallow_exception(e)
    try:
        if safe_float(s.get("change_rate", 0), 0.0) >= 5.0:
            news_titles = [r for r in s.get("reasons", []) if isinstance(r, str)]
            threading.Thread(target=_discover_new_theme_from_surge, args=(code, name, news_titles, safe_float(s.get("change_rate", 0), 0.0)), daemon=True).start()
    except Exception as e:
        _swallow_exception(e)
    if signal_type != "ENTRY_POINT" and code:
        if code not in _detected_stocks:
            _detected_stocks[code] = {
                "name": name,
                "high_price": safe_int(s.get("price", 0), 0),
                "entry_price": safe_int(s.get("entry_price", 0), 0),
                "stop_loss": safe_int(s.get("stop_loss", 0), 0),
                "target_price": safe_int(s.get("target_price", 0), 0),
                "detected_at": s.get("detected_at", datetime.now()),
                "carry_day": 0,
            }
        elif safe_int(s.get("price", 0), 0) > safe_int(_detected_stocks[code].get("high_price", 0), 0):
            _detected_stocks[code]["high_price"] = safe_int(s.get("price", 0), 0)
    return True
def _expire_entry_watch_for_upper_limit(code: str, name: str) -> None:
    """NEAR_UPPER/UPPER_LIMIT 발송 즉시 해당 종목 entry_watch 전부 만료 처리.
    이후 check_entry_watch 사이클에서 upper_limit_reached 진입불가 반복 차단.
    """
    norm = normalize_stock_code(code)
    if not norm:
        return
    to_expire = [k for k, w in list(_entry_watch.items())
                 if isinstance(w, dict) and normalize_stock_code(w.get("code", "")) == norm]
    for k in to_expire:
        w = _entry_watch.pop(k, None)
        if w:
            _archive_entry_watch_record(k, w, consume_reason="상한가류발송만료",
                                        final_status=_entry_watch_final_status(w, "상한가차단"))
            _log_info_msg(f"  🔒 {name} — entry_watch 상한가류 발송 즉시 만료 ({k})")
    if to_expire:
        _save_entry_watch_active()


def _dispatch_general_alert_signal(s: dict, hist_key: str | None = None, source_label: str = "일반 포착") -> bool:
    ctx = _build_general_alert_dispatch_context(s, hist_key)
    if ctx is None:
        return False
    if not _handle_general_alert_entry_block(ctx, source_label):
        return False
    if not _handle_general_alert_external_policy(ctx, source_label):
        return False
    existing_hit_result = _handle_general_alert_existing_entry_hit(ctx)
    if existing_hit_result is not None:
        return existing_hit_result
    return _finalize_general_alert_dispatch(ctx)
def _hydrate_alert_sector_theme(alert: dict, *, force_lookup: bool = False) -> str:
    try:
        if not isinstance(alert, dict):
            return "기타"
        sector_info = alert.get("sector_info") if isinstance(alert.get("sector_info"), dict) else {}
        public_meta = _get_public_stock_meta(alert.get("code", "")) if alert.get("code") else {}
        public_sector = _normalize_public_sector_name((public_meta or {}).get("sector", ""))
        for candidate in (
            alert.get("sector_theme"),
            sector_info.get("theme"),
            public_sector,  # v161.3: public_meta sector를 bstp_name보다 우선 적용 (#5 섹터 오분류 수정)
            alert.get("bstp_name"),
            sector_info.get("bstp_name"),
            alert.get("adaptive_feedback_theme"),
            alert.get("theme_desc"),
        ):
            sec = _normalize_public_sector_name(candidate)
            if sec and not _is_generic_sector_theme(sec):
                sector_info["theme"] = sec
                if public_sector:
                    sector_info["public_sector"] = public_sector
                alert["sector_info"] = sector_info
                alert["sector_theme"] = sec
                return sec
        code = normalize_stock_code(alert.get("code", ""))
        if code and force_lookup:
            theme_name, _, _ = get_theme_sector_stocks(code)
            theme_name = _normalize_public_sector_name(theme_name)
            if theme_name and not _is_generic_sector_theme(theme_name):
                sector_info["theme"] = theme_name
                alert["sector_info"] = sector_info
                alert["sector_theme"] = theme_name
                return theme_name
        return "기타"
    except Exception as e:
        _swallow_exception(e)
        return "기타"
def _extract_alert_sector_theme(alert: dict) -> str:
    try:
        return _hydrate_alert_sector_theme(alert, force_lookup=False)
    except Exception as e:
        _swallow_exception(e)  # v105 structured silent-exception log
        return "기타"
def _is_generic_sector_theme(theme_name: str) -> bool:
    try:
        theme = str(theme_name or "").strip()
        return theme in ("", "기타", "기타업종", "동일업종", "업종미상", "unknown", "미분류")
    except Exception as e:
        _swallow_exception(e)  # v105 structured silent-exception log
        return True
def _get_theme_drive_hint(code: str, name: str = "", change_rate: float = 0.0,
                          vol_ratio: float = 0.0, market: str = "", max_members: int = 6) -> dict:
    code = str(code or "").strip()
    if not code:
        return {}
    theme_name, peers, _ = get_theme_sector_stocks(code)
    if _is_generic_sector_theme(theme_name):
        return {}
    market_basis = "NXT" if str(market or "").upper() == "NXT" else "KRX"
    cache_key = f"{market_basis}:{theme_name}"
    now_ts = time.time()
    cached = _theme_drive_cache.get(cache_key)
    if isinstance(cached, dict) and now_ts - float(cached.get("ts", 0) or 0) < THEME_DRIVE_CACHE_TTL:
        return dict(cached)
    members = [(code, name)]
    seen = {code}
    for peer_code, peer_name in list(peers or [])[:max(0, max_members - 1)]:
        peer_code = str(peer_code or "").strip()
        if not peer_code or peer_code in seen:
            continue
        seen.add(peer_code)
        members.append((peer_code, peer_name))
    quotes = []
    for member_code, member_name in members[:max_members]:
        try:
            q = _get_live_quote_for_signal({
                "code": member_code,
                "name": member_name,
                "market": market_basis if market_basis == "NXT" else "",
            })
        except Exception as e:
            _swallow_exception(e)  # v105 structured silent-exception log
            q = {}
        if not isinstance(q, dict) or not q.get("price"):
            continue
        quotes.append({
            "code": member_code,
            "name": _resolve_stock_name(member_code, member_name, q),
            "change_rate": safe_float(q.get("change_rate", 0)),
            "volume_ratio": safe_float(q.get("volume_ratio", 0)),
            "market": q.get("market", market_basis),
        })
        time.sleep(0.03)
    if len(quotes) < 2:
        return {}
    quotes.sort(key=lambda x: (safe_float(x.get("change_rate", 0)), safe_float(x.get("volume_ratio", 0))), reverse=True)
    leader = quotes[0]
    risers = [q for q in quotes if safe_float(q.get("change_rate", 0)) >= THEME_DRIVE_PEER_CHANGE]
    flow_avg = sum(max(0.0, safe_float(q.get("volume_ratio", 0))) for q in quotes) / max(1, len(quotes))
    avg_change = sum(safe_float(q.get("change_rate", 0)) for q in risers) / max(1, len(risers)) if risers else 0.0
    if safe_float(leader.get("change_rate", 0)) < THEME_DRIVE_LEADER_CHANGE or len(risers) < 2:
        return {}
    bonus = 4
    if len(risers) >= 3:
        bonus += 1
    if avg_change >= 6.0:
        bonus += 1
    if flow_avg >= 4.0:
        bonus += 1
    hint = {
        "theme": theme_name,
        "theme_key": theme_name,
        "leader_name": leader.get("name", ""),
        "leader_change": round(safe_float(leader.get("change_rate", 0)), 1),
        "riser_cnt": len(risers),
        "member_cnt": len(quotes),
        "avg_change": round(avg_change, 1),
        "flow_avg": round(flow_avg, 1),
        "bonus": int(min(bonus, 8)),
        "reason": "실시간 테마 주도/동조 강세",
        "ts": now_ts,
    }
    _theme_drive_cache[cache_key] = dict(hint)
    return hint
def _get_theme_breadth_hint(code: str, name: str = "", theme: str = "", market: str = "", max_members: int = 6) -> dict:
    code = str(code or "").strip()
    theme_name = str(theme or "").strip()
    market_basis = "NXT" if str(market or "").upper() == "NXT" else "KRX"
    if not theme_name and code:
        try:
            theme_name, _, _ = get_theme_sector_stocks(code)
        except Exception as e:
            _swallow_exception(e)  # v105 structured silent-exception log
            theme_name = ""
    if _is_generic_sector_theme(theme_name):
        return {}
    cache_key = f"{market_basis}:{theme_name}:breadth"
    now_ts = time.time()
    cached = _theme_breadth_cache.get(cache_key)
    if isinstance(cached, dict) and now_ts - float(cached.get("ts", 0) or 0) < THEME_DRIVE_CACHE_TTL:
        return dict(cached)
    members = []
    seen = set()
    if code:
        members.append((code, name))
        seen.add(code)
    try:
        seed = code
        if not seed and isinstance(_adaptive_capture_feedback, dict):
            row = (_adaptive_capture_feedback.get("theme_bias") or {}).get(_safe_feedback_theme_key(theme_name)) or {}
            for c in row.get("codes", []) or []:
                seed = normalize_stock_code(c)
                if seed:
                    break
        if seed:
            _theme_name, peers, _ = get_theme_sector_stocks(seed)
            if not theme_name and _theme_name:
                theme_name = _theme_name
            for peer_code, peer_name in list(peers or [])[:max(0, max_members - len(members))]:
                peer_code = str(peer_code or "").strip()
                if not peer_code or peer_code in seen:
                    continue
                seen.add(peer_code)
                members.append((peer_code, peer_name))
    except Exception as e:
        _swallow_exception(e)
    quotes = []
    for member_code, member_name in members[:max_members]:
        try:
            q = _get_live_quote_for_signal({
                "code": member_code,
                "name": member_name,
                "market": market_basis if market_basis == "NXT" else "",
            })
        except Exception as e:
            _swallow_exception(e)  # v105 structured silent-exception log
            q = {}
        if not isinstance(q, dict) or not q.get("price"):
            continue
        quotes.append({
            "code": member_code,
            "name": _resolve_stock_name(member_code, member_name, q),
            "change_rate": safe_float(q.get("change_rate", 0)),
            "volume_ratio": safe_float(q.get("volume_ratio", 0)),
            "market": q.get("market", market_basis),
        })
        time.sleep(0.02)
    if len(quotes) < 2:
        return {}
    quotes.sort(key=lambda x: (safe_float(x.get("change_rate", 0)), safe_float(x.get("volume_ratio", 0))), reverse=True)
    leader = quotes[0]
    risers = [q for q in quotes if safe_float(q.get("change_rate", 0)) >= THEME_DRIVE_PEER_CHANGE]
    breadth_ratio = len(risers) / max(1, len(quotes))
    avg_change = sum(safe_float(q.get("change_rate", 0)) for q in risers) / max(1, len(risers)) if risers else 0.0
    hint = {
        "theme": theme_name,
        "leader_code": leader.get("code", ""),
        "leader_name": leader.get("name", ""),
        "leader_change": round(safe_float(leader.get("change_rate", 0)), 1),
        "riser_cnt": len(risers),
        "member_cnt": len(quotes),
        "breadth_ratio": round(breadth_ratio, 3),
        "avg_change": round(avg_change, 1),
        "weak_breadth": bool(breadth_ratio < STALE_THEME_WEAK_BREADTH_RATIO or len(risers) <= 1 or avg_change < STALE_THEME_WEAK_AVG_CHANGE),
        "strong_breadth": bool(breadth_ratio >= MISSED_THEME_STRONG_BREADTH_RATIO and len(risers) >= 2 and safe_float(leader.get("change_rate", 0)) >= MISSED_THEME_STRONG_LEADER_CHANGE),
        "ts": now_ts,
    }
    _theme_breadth_cache[cache_key] = dict(hint)
    return hint
def _collect_theme_feedback_candidates(existing_codes=None, limit_total: int | None = None) -> list:
    existing = {normalize_stock_code(c) for c in (existing_codes or []) if c}
    rows = []
    if not isinstance(_adaptive_capture_feedback, dict):
        return rows
    theme_bias = _adaptive_capture_feedback.get("theme_bias") or {}
    if not isinstance(theme_bias, dict) or not theme_bias:
        return rows
    limit_total = max(0, int(limit_total or MISSED_THEME_CANDIDATE_LIMIT or 0))
    if limit_total <= 0:
        return rows
    nxt_open = is_nxt_open()
    krx_open = is_market_open()
    for theme_key, meta in list(sorted(theme_bias.items(), key=lambda kv: float((kv[1] or {}).get("weight", 0.0) or 0.0), reverse=True)):
        if len(rows) >= limit_total:
            break
        weight = float((meta or {}).get("weight", 0.0) or 0.0)
        if weight < MISSED_THEME_LEADER_MIN_WEIGHT:
            continue
        seed_codes = list((meta or {}).get("codes") or [])
        seed = ""
        for cand in seed_codes:
            cand = normalize_stock_code(cand)
            if cand:
                seed = cand
                break
        if not seed:
            continue
        try:
            theme_name, peers, _ = get_theme_sector_stocks(seed)
        except Exception as e:
            _swallow_exception(e)  # v105 structured silent-exception log
            continue
        if _is_generic_sector_theme(theme_name):
            continue
        market = "NXT" if (nxt_open and is_nxt_listed(seed)) else ("KRX" if (krx_open or nxt_open) else "")
        member_list = [(seed, "")] + list(peers or [])[:6]
        seen_local = set()
        for peer_code, peer_name in member_list:
            peer_code = normalize_stock_code(peer_code)
            if not peer_code or peer_code in existing or peer_code in seen_local:
                continue
            seen_local.add(peer_code)
            try:
                q = _get_live_quote_for_signal({
                    "code": peer_code,
                    "name": peer_name,
                    "market": market if market == "NXT" else "",
                })
            except Exception as e:
                _swallow_exception(e)  # v105 structured silent-exception log
                q = {}
            if not isinstance(q, dict) or not q.get("price"):
                continue
            chg = safe_float(q.get("change_rate", 0))
            vol = safe_float(q.get("volume_ratio", 0))
            if chg < 4.5 and vol < 2.0:
                continue
            rows.append({
                "code": peer_code,
                "name": _resolve_stock_name(peer_code, peer_name, q),
                "price": safe_int(q.get("price", 0), 0),
                "change_rate": chg,
                "volume_ratio": vol,
                "today_vol": safe_int(q.get("today_vol", 0), 0),
                "market": market or ("NXT" if is_nxt_listed(peer_code) and nxt_open else "KRX"),
                "desc": f"theme_feedback[{theme_name}]",
                "theme_feedback": True,
                "theme_feedback_weight": weight,
                "adaptive_feedback_theme": theme_name,
            })
            existing.add(peer_code)
            time.sleep(0.02)
            if len(rows) >= limit_total:
                break
    return rows
def _calc_miss_theme_leader_bonus(code: str, name: str = "", theme: str = "", signal_type: str = "", change_rate: float = 0.0, vol_ratio: float = 0.0, market: str = "") -> tuple[int, list[str], dict]:
    theme_row = _get_adaptive_feedback_theme_entry(theme)
    if not theme_row:
        return 0, [], {}
    sig = str(signal_type or "").upper()
    if sig not in ("SURGE", "EARLY_DETECT", "NEAR_UPPER", "STRONG_BUY", "UPPER_LIMIT"):
        return 0, [], {}
    weight = float(theme_row.get("weight", 0.0) or 0.0)
    if weight < MISSED_THEME_LEADER_MIN_WEIGHT:
        return 0, [], {}
    breadth = _get_theme_breadth_hint(code, name, theme=theme, market=market)
    leader_code = normalize_stock_code(breadth.get("leader_code", "")) if breadth else ""
    leader_change = safe_float((breadth or {}).get("leader_change", 0.0), 0.0)
    breadth_ratio = safe_float((breadth or {}).get("breadth_ratio", 0.0), 0.0)
    riser_cnt = safe_int((breadth or {}).get("riser_cnt", 0), 0)
    leader_like = bool(code and code == leader_code) or change_rate >= max(MISSED_THEME_STRONG_LEADER_CHANGE, leader_change - 0.4)
    breadth_ok = bool((breadth or {}).get("strong_breadth")) or breadth_ratio >= MISSED_THEME_STRONG_BREADTH_RATIO or riser_cnt >= 3
    if not leader_like and not (change_rate >= MISSED_THEME_STRONG_LEADER_CHANGE and vol_ratio >= 2.0):
        return 0, [], breadth or {}
    if not breadth_ok and vol_ratio < 2.2:
        return 0, [], breadth or {}
    bonus = min(MISSED_THEME_LEADER_MAX_BONUS, max(2, int(round(weight * 0.35)) + (1 if breadth_ok else 0)))
    notes = [f"🚀 반복 miss 테마 신규 리더 보정 [{theme}] +{bonus}점"]
    if breadth:
        notes.append(f"🏭 breadth {safe_int(breadth.get('riser_cnt',0),0)}/{safe_int(breadth.get('member_cnt',0),0)} · 리더 {breadth.get('leader_name','')} {safe_float(breadth.get('leader_change',0.0),0.0):+.1f}%")
    return bonus, notes, breadth or {}
def _collect_theme_peer_follow_candidates(existing_codes: set | None = None, limit_total: int = 8) -> list:
    existing_codes = set(existing_codes or set())
    candidates = []
    seen = set(existing_codes)
    seeds = []
    try:
        if is_market_open():
            seeds.extend(get_upper_limit_stocks()[:6])
            seeds.extend(get_volume_surge_stocks()[:12])
        if is_nxt_open():
            seeds.extend(get_nxt_surge_stocks()[:8])
    except Exception as e:
        _swallow_exception(e)  # v105 structured silent-exception log
        seeds = list(seeds)
    seed_seen = set()
    merged_seeds = []
    for item in seeds:
        if not isinstance(item, dict):
            continue
        seed_code = str(item.get("code", "") or "").strip()
        if not seed_code or seed_code in seed_seen:
            continue
        seed_seen.add(seed_code)
        merged_seeds.append(item)
    for seed in merged_seeds[:16]:
        try:
            seed_code = str(seed.get("code", "") or "").strip()
            seed_name = str(seed.get("name", "") or "").strip()
            if not seed_code:
                continue
            seed_chg = safe_float(seed.get("change_rate", 0))
            seed_vol = safe_float(seed.get("volume_ratio", 0))
            if seed_chg < 8.0 and seed_vol < 5.0:
                continue
            theme_name, peers, _ = get_theme_sector_stocks(seed_code)
            if _is_generic_sector_theme(theme_name):
                continue
            market = str(seed.get("market", "") or "")
            for peer_code, peer_name in list(peers or [])[:6]:
                peer_code = str(peer_code or "").strip()
                if not peer_code or peer_code in seen or peer_code == seed_code:
                    continue
                q = _get_live_quote_for_signal({
                    "code": peer_code,
                    "name": peer_name,
                    "market": market if market == "NXT" else "",
                })
                if not isinstance(q, dict) or not q.get("price"):
                    continue
                peer_chg = safe_float(q.get("change_rate", 0))
                peer_vol = safe_float(q.get("volume_ratio", 0))
                if peer_chg < 4.0 and peer_vol < 2.0:
                    continue
                cand = dict(q)
                cand["code"] = peer_code
                cand["name"] = _resolve_stock_name(peer_code, peer_name, q)
                if market == "NXT":
                    cand["market"] = "NXT"
                cand["_theme_peer_seed"] = seed_name or seed_code
                cand["_theme_peer_theme"] = theme_name
                candidates.append(cand)
                seen.add(peer_code)
                time.sleep(0.03)
                if len(candidates) >= limit_total:
                    return candidates
        except Exception as e:
            _swallow_exception(e)  # v105 structured silent-exception log
            continue
    return candidates
def _build_general_a_support_profile(change_rate: float = 0.0, vol_ratio: float = 0.0,
                                    sector_info: dict | None = None, direct_news_hit: bool = False,
                                    nxt_delta: int = 0, market: str = "", reasons: list | None = None,
                                    signal_type: str = "") -> dict:
    joined_reasons = " ".join(str(r or "") for r in (reasons or []))
    try:
        _cr = float(change_rate or 0.0)
    except Exception as e:
        _swallow_exception(e)
        _cr = 0.0
    try:
        _vr = float(vol_ratio or 0.0)
    except Exception as e:
        _swallow_exception(e)
        _vr = 0.0
    sig_type = str(signal_type or "").upper()
    if sig_type == "NEAR_UPPER":
        strong_price = _cr >= 18.0
    elif sig_type == "UPPER_LIMIT":
        strong_price = _cr >= 25.0
    else:
        strong_price = _cr >= 5.5
    strong_flow = _vr >= 2.0 or int(nxt_delta or 0) >= 5
    premium_flow = _vr >= COMMON_THRESHOLD_3P0 or int(nxt_delta or 0) >= 8
    theme = _extract_alert_sector_theme({"sector_info": sector_info or {}, "sector_theme": (sector_info or {}).get("theme", "")})
    meaningful_theme = theme != "기타"
    direct_like = bool(direct_news_hit) or any(token in joined_reasons for token in ("직접뉴스 테마", "신규이슈 자동감지", "테마 동조강세", "섹터 확산", "반복 miss 테마 신규 리더", "섹터 대장 후속 강제감시", "LNG", "플랜트", "열교환기", "암모니아", "수소", "수주", "탈 플라스틱", "친환경", "생분해"))
    intraday_support = any(token in joined_reasons for token in ("거래량 이상 급증", "거래대금 급증", "고가 유지", "코스피 상대강도", "코스닥 상대강도", "장초반 ORB", "전고 돌파", "장중 돌파", "장중돌파", "재상승", "거래량 회복", "20일선 회복", "외국인 음→양 전환", "상한가 근접", "상한가 도달", "전일 포함 연속 패턴", "cross-day", "연속 패턴", "섹터 확산", "follow-up 감시"))
    flow_support = strong_flow or premium_flow
    support_count = sum(1 for flag in (direct_like, meaningful_theme, flow_support, intraday_support) if flag)
    market_flag = str(market or "").upper() == "NXT"
    return {
        "strong_price": bool(strong_price),
        "strong_flow": bool(strong_flow),
        "premium_flow": bool(premium_flow),
        "flow_support": bool(flow_support),
        "meaningful_theme": bool(meaningful_theme),
        "direct_like": bool(direct_like),
        "intraday_support": bool(intraday_support),
        "support_count": int(support_count),
        "market_flag": bool(market_flag),
    }
def _resolve_general_a_cut(signal_type: str, score: int, change_rate: float = 0.0,
                           vol_ratio: float = 0.0, sector_info: dict | None = None,
                           direct_news_hit: bool = False, nxt_delta: int = 0,
                           market: str = "", reasons: list | None = None) -> int:
    sig_type = str(signal_type or "").upper()
    dynamic_relax_types = _get_dynamic_general_a_relax_signal_types()
    extendable_types = set(dynamic_relax_types) | set(GENERAL_A_EXTENDED_SIGNAL_TYPES)
    if sig_type not in extendable_types:
        return GENERAL_GRADE_A_CUT
    support = _build_general_a_support_profile(
        change_rate=change_rate, vol_ratio=vol_ratio, sector_info=sector_info,
        direct_news_hit=direct_news_hit, nxt_delta=nxt_delta, market=market,
        reasons=reasons, signal_type=sig_type,
    )
    _session_profile = _get_full_session_capture_profile(datetime.now().strftime("%H:%M:%S"), market)
    _session_bonus = int(_session_profile.get("a_relax_bonus", 0) or 0)
    a_cut = GENERAL_GRADE_A_CUT
    if sig_type in GENERAL_A_RELAX_SIGNAL_TYPES:
        near_a_score = int(score or 0) >= max(72, GENERAL_A_RELAXED_SCORE - 2 - _session_bonus)
        support_ok = support["support_count"] >= 1
        if near_a_score and support_ok and (support["strong_price"] or support["intraday_support"] or (support["market_flag"] and support["flow_support"])):
            a_cut = min(a_cut, GENERAL_A_RELAXED_SCORE)
    extended_score_ok = int(score or 0) >= max(74, GENERAL_A_EXTENDED_SCORE - _session_bonus)
    extended_core = (support["direct_like"] or support["meaningful_theme"]) and support["flow_support"]
    extended_price = support["strong_price"] or support["intraday_support"] or (support["market_flag"] and support["flow_support"])
    if extended_score_ok and support["support_count"] >= GENERAL_A_EXTENDED_SUPPORT_MIN and extended_core and extended_price:
        a_cut = min(a_cut, GENERAL_A_EXTENDED_SCORE)
    st = _get_intraday_capture_mode()
    if _intraday_capture_mode_active(st):
        proactive_support = any(token in " ".join(str(r or "") for r in (reasons or [])) for token in ("코스피 상대강도", "거래량 회복", "20일선 회복", "외국인 음→양 전환", "장중 돌파", "장중돌파", "재상승", "거래량 이상 급증", "거래량3배", "당일양봉"))
        try:
            soft_price = float(change_rate or 0.0) >= 2.5
        except Exception as e:
            _swallow_exception(e)
            soft_price = False
        if int(score or 0) >= INTRADAY_CAPTURE_RELAX_SCORE and soft_price and (support["direct_like"] or support["meaningful_theme"] or support["flow_support"] or proactive_support):
            a_cut = min(a_cut, INTRADAY_CAPTURE_RELAX_SCORE)
    return a_cut
def _should_relax_general_a_threshold(signal_type: str, score: int, change_rate: float = 0.0,
                                     vol_ratio: float = 0.0, sector_info: dict | None = None,
                                     direct_news_hit: bool = False, nxt_delta: int = 0,
                                     market: str = "", reasons: list | None = None) -> bool:
    return _resolve_general_a_cut(
        signal_type, score, change_rate=change_rate, vol_ratio=vol_ratio,
        sector_info=sector_info, direct_news_hit=direct_news_hit, nxt_delta=nxt_delta,
        market=market, reasons=reasons,
    ) < GENERAL_GRADE_A_CUT
def _derive_general_signal_grade(signal_type: str, score: int, change_rate: float = 0.0,
                                 vol_ratio: float = 0.0, sector_info: dict | None = None,
                                 direct_news_hit: bool = False, nxt_delta: int = 0,
                                 market: str = "", reasons: list | None = None) -> str:
    a_cut = _resolve_general_a_cut(
        signal_type, score, change_rate=change_rate, vol_ratio=vol_ratio,
        sector_info=sector_info, direct_news_hit=direct_news_hit, nxt_delta=nxt_delta,
        market=market, reasons=reasons,
    )
    if score >= a_cut:
        return "A"
    if score >= 60:
        return "B"
    return "C"
def _should_send_external_grade_alert(signal: dict | None) -> bool:
    grade = str((signal or {}).get("execution_grade") or (signal or {}).get("grade") or "").upper()
    return grade == "A"
def _record_internal_only_alert(hist_key: str, signal: dict, reason: str) -> bool:
    if not hist_key or not isinstance(signal, dict):
        return False
    grade = str(signal.get("execution_grade") or signal.get("grade") or "C").upper()
    prev = _internal_only_alert_history.get(hist_key) or {}
    prev_ts = float(prev.get("ts", 0) or 0)
    prev_grade = str(prev.get("grade", "C") or "C").upper()
    should_log = (time.time() - prev_ts) >= INTERNAL_ONLY_ALERT_COOLDOWN or _grade_rank(grade) > _grade_rank(prev_grade)
    _internal_only_alert_history[hist_key] = {"ts": time.time(), "grade": grade}
    if should_log:
        _log_suppressed_alert(
            signal.get("code", ""), signal.get("name", signal.get("code", "")), reason,
            signal.get("signal_type", ""),
            {"score": signal.get("score", 0), "grade": grade, "entry_price": signal.get("entry_price", 0), "market": signal.get("market", "")}
        )
    return should_log
def _sector_gate_sort_key(alert: dict) -> tuple:
    alert = _annotate_signal_priority(alert)
    sec = _extract_alert_sector_theme(alert)
    signal_rank = {
        "UPPER_LIMIT": 6,
        "NEAR_UPPER": 5,
        "STRONG_BUY": 4,
        "SURGE": 3,
        "EARLY_DETECT": 2,
        "ENTRY_POINT": 1,
    }.get(str(alert.get("signal_type", "") or ""), 0)
    return (
        1 if alert.get("leader_priority_hit") else 0,
        1 if alert.get("nxt_post_leader_hit") else 0,
        1 if alert.get("sector_leader_follow_hit") else 0,
        1 if alert.get("material_first_priority_hit") else 0,
        1 if alert.get("direct_news_hit") else 0,
        1 if alert.get("theme_drive_hit") else 0,
        1 if alert.get("adaptive_feedback_hit") else 0,
        1 if alert.get("miss_theme_leader_hit") else 0,
        0 if alert.get("stale_pullback_hit") else 1,
        0 if alert.get("stale_replay_penalty_hit") else 1,
        0 if sec == "기타" else 1,
        signal_rank,
        int(alert.get("score", 0) or 0),
        float(alert.get("change_rate", 0) or 0),
        float(alert.get("volume_ratio", 0) or 0),
    )
# ============================================================
# 🚨 DART 리스크 차단 + 보유 종목 뉴스 감시 (v33.0)
# ============================================================
_dart_risk_cache: dict = {}   # code → {is_risk, title, ts}  (10분 캐시)
_carry_news_watch: dict = {}  # code → last_check_ts          (30분 쿨다운)
_trading_halt_state: dict = {"active": {}}
def _default_trading_halt_state() -> dict:
    return {"active": {}}
def _prune_trading_halt_state(state: dict | None) -> dict:
    active = {}
    if isinstance(state, dict):
        active = state.get("active") if isinstance(state.get("active"), dict) else {}
    keep_sec = max(1, int(TRADING_HALT_KEEP_DAYS or 1)) * 86400
    now_ts = time.time()
    pruned = {}
    for raw_code, rec in active.items():
        if not isinstance(rec, dict):
            continue
        code = normalize_stock_code(raw_code or rec.get("code"))
        if not code:
            continue
        try:
            last_seen_ts = float(rec.get("last_seen_ts", rec.get("ts", 0)) or 0)
        except Exception as e:
            _swallow_exception(e)  # v105 structured silent-exception log
            last_seen_ts = 0.0
        if last_seen_ts and now_ts - last_seen_ts > keep_sec:
            continue
        title = str(rec.get("title", "") or "").strip()
        if any(kw in title for kw in ("거래재개", "매매재개", "거래정지해제", "매매정지해제")):
            continue
        item = dict(rec)
        item["code"] = code
        item["status"] = "halted"
        item["title"] = title or "주권매매거래정지"
        item["first_seen_ts"] = float(item.get("first_seen_ts", last_seen_ts or now_ts) or (last_seen_ts or now_ts))
        item["last_seen_ts"] = float(item.get("last_seen_ts", last_seen_ts or now_ts) or (last_seen_ts or now_ts))
        pruned[code] = item
    return {"active": pruned}
def _save_trading_halt_state() -> None:
    try:
        _write_state_json(TRADING_HALT_STATE_FILE, _prune_trading_halt_state(_trading_halt_state))
    except Exception as e:
        _swallow_exception(e)
def _load_trading_halt_state() -> None:
    global _trading_halt_state
    try:
        raw = _read_state_json(TRADING_HALT_STATE_FILE, _default_trading_halt_state())
        _trading_halt_state = _prune_trading_halt_state(raw)
        if raw != _trading_halt_state:
            _save_trading_halt_state()
        active_cnt = len((_trading_halt_state.get("active") or {})) if isinstance(_trading_halt_state, dict) else 0
        if active_cnt:
            _log_info_msg(f"📂 거래정지 영속 상태 {active_cnt}개 복원")
            # v165.8: 복원 직후 실시간 검증 — 정상 거래 중인 종목은 즉시 제거
            _verify_and_clean_restored_halt_state()
    except Exception as e:
        _swallow_exception(e)
        _trading_halt_state = _default_trading_halt_state()


def _verify_and_clean_restored_halt_state() -> None:
    """봇 재시작 후 trading_halt_state.json 복원 시 실시간 조회로 오래된 상태 제거.
    v165.10 [#2]: ThreadPoolExecutor 병렬 조회 — 직렬 12초→2초 이내로 단축"""
    if not isinstance(_trading_halt_state, dict):
        return
    active = _trading_halt_state.get("active") or {}
    codes = list(active.keys())
    if not codes:
        return

    def _check_one(code: str) -> tuple[str, bool]:
        try:
            cur = get_stock_price(code)
            if cur and _is_live_trading_normal(cur):
                return code, True  # 정상 → 제거 대상
        except Exception as e:
            _swallow_exception(e)
        return code, False  # 제거 안 함

    to_remove = []
    try:
        from concurrent.futures import ThreadPoolExecutor, as_completed
        with ThreadPoolExecutor(max_workers=min(8, len(codes))) as ex:
            futures = {ex.submit(_check_one, c): c for c in codes}
            for fut in as_completed(futures, timeout=10):
                try:
                    code, should_remove = fut.result()
                    if should_remove:
                        to_remove.append(code)
                        _log_info_msg(f"  🗑 거래정지 상태 제거: {code} — 실시간 정상 거래 확인")
                except Exception as e:
                    _swallow_exception(e)
    except Exception as e:
        _swallow_exception(e)

    for code in to_remove:
        active.pop(code, None)
    if to_remove:
        _save_trading_halt_state()
        _log_info_msg(f"  ✅ 거래정지 상태 {len(to_remove)}개 정리 완료 (실시간 검증)")
def _get_persisted_trading_halt(code: str) -> dict:
    code = normalize_stock_code(code)
    if not code:
        return {}
    active = (_trading_halt_state.get("active") or {}) if isinstance(_trading_halt_state, dict) else {}
    rec = active.get(code)
    return rec if isinstance(rec, dict) else {}
def _mark_trading_halt_state(code: str, title: str = "", name: str = "", source: str = "") -> None:
    code = normalize_stock_code(code)
    if not code:
        return
    if not isinstance(_trading_halt_state, dict):
        return
    active = _trading_halt_state.setdefault("active", {})
    prev = active.get(code) if isinstance(active.get(code), dict) else {}
    now_ts = time.time()
    item = dict(prev) if isinstance(prev, dict) else {}
    item["code"] = code
    item["name"] = str(name or item.get("name", "") or "")
    item["title"] = str(title or item.get("title", "") or "주권매매거래정지")
    item["status"] = "halted"
    item["source"] = str(source or item.get("source", "") or "")
    item["first_seen_ts"] = float(item.get("first_seen_ts", now_ts) or now_ts)
    item["last_seen_ts"] = now_ts
    active[code] = item
    _save_trading_halt_state()
def _clear_trading_halt_state(code: str, resume_title: str = "", source: str = "") -> None:
    code = normalize_stock_code(code)
    if not code or not isinstance(_trading_halt_state, dict):
        return
    active = _trading_halt_state.setdefault("active", {})
    if code in active:
        active.pop(code, None)
        _save_trading_halt_state()
        title_part = f" — {resume_title}" if resume_title else ""
        _log_info_msg(f"  ✅ 거래정지 영속 해제: {code}{title_part}")
def check_dart_risk(code: str) -> dict:
    """
    종목별 최근 5일 DART 공시 → 리스크 키워드 있으면 True 반환
    analyze() 내 매수 신호 최종 차단 판단에 사용
    returns: {"is_risk": bool, "title": str}
    """
    if not DART_API_KEY:
        return {"is_risk": False, "title": ""}
    now = time.time()
    cached = _dart_risk_cache.get(code)
    if cached and now - cached.get("ts", 0) < 600:   # 10분 캐시
        return cached
    result = {"is_risk": False, "title": "", "ts": now}
    try:
        today = datetime.now().strftime("%Y%m%d")
        bgn   = (datetime.now() - timedelta(days=5)).strftime("%Y%m%d")
        resp  = requests.get(
            "https://opendart.fss.or.kr/api/list.json",
            params={
                "crtfc_key":  DART_API_KEY,
                "bgn_de":     bgn,
                "end_de":     today,
                "stock_code": code,
                "page_count": 20,
            },
            timeout=8
        )
        dart_rows = []
        result.update({"scenario_id": "", "scenario_label": "", "matched_keywords": [], "source": "", "official": False, "titles": []})
        for item in resp.json().get("list", []):
            title = item.get("report_nm", "")
            rcept_dt = str(item.get("rcept_dt", "") or "")
            if title:
                dart_rows.append({"title": title, "source": "DART", "rcept_dt": rcept_dt})
            # v80/v92: 거래재개/정지해제 공시는 즉시 halt 해제
            if _is_trade_resume_title(title):
                result["is_risk"] = False
                result["title"]   = ""
                _clear_trading_halt_state(code, resume_title=title, source="DART")
                _clear_dart_halt_cache(code)
                break
            # v92: halt 제목은 same-day 직접 거래정지 제목만 리스크/영속 halt로 인정
            if _is_trade_halt_title(title):
                if _should_persist_trade_halt_title(title, rcept_dt=rcept_dt):
                    result.update({
                        "is_risk": True,
                        "title": title,
                        "ts": 0,
                        "scenario_id": "listing_risk",
                        "scenario_label": "관리/상폐/거래정지 리스크",
                        "matched_keywords": ["거래정지"],
                        "source": "DART",
                        "official": True,
                    })
                    _mark_trading_halt_state(code, title=title, source="DART")
                    break
                # 기간변경/복합 제목/과거 이력은 내부 조회만 하고 위험 차단/영속 저장은 하지 않음
                continue
            _scenario_meta = _match_material_downside_scenario_rows([{"title": title, "source": "DART"}])
            if _scenario_meta:
                result.update({
                    "is_risk": True,
                    "title": title,
                    "scenario_id": _scenario_meta.get("scenario_id", ""),
                    "scenario_label": _scenario_meta.get("label", "DART 리스크"),
                    "matched_keywords": list(_scenario_meta.get("hits", []) or [])[:5],
                    "source": "DART",
                    "official": True,
                })
                break
            if any(kw in title for kw in DART_RISK_KEYWORDS):
                result.update({
                    "is_risk": True,
                    "title": title,
                    "scenario_id": "dart_risk",
                    "scenario_label": "DART 리스크",
                    "matched_keywords": [kw for kw in DART_RISK_KEYWORDS if kw in title][:5],
                    "source": "DART",
                    "official": True,
                })
                break
        result["titles"] = [str(row.get("title", "") or "") for row in dart_rows[:10]]
    except Exception as e:
        _log_warn_msg(f"  ⚠️ DART리스크체크오류 [{code}]: {e}")
    _dart_risk_cache[code] = result
    return result
def _normalize_news_headline(title: str) -> str:
    try:
        t = html.unescape((title or '').strip())
        # RSS description 결합부 정리
        t = t.replace('—', ' ').replace('–', ' ').replace('|', ' ')
        t = _re.sub(r"\[[^\]]+\]", ' ', t)
        t = _re.sub(r"\([^\)]*사진[^\)]*\)", ' ', t)
        t = _re.sub(r"[\"'`]+", '', t)
        t = _re.sub(r"\s+", ' ', t).strip().lower()
        return t
    except Exception as e:
        _swallow_exception(e)  # v105 structured silent-exception log
        return (title or '').strip().lower()
