def _dispatch_telegram_command(raw: str, text: str):
    global _bot_paused
    exact_handlers = {
        "/status": _send_telegram_status_summary,
        "/list": _handle_telegram_list_command,
        "/watch": _handle_telegram_watch_command,
        "/포착감시": _handle_telegram_watch_command,
        "/재료": _handle_telegram_material_command,
        "/material": _handle_telegram_material_command,
        "/top": _handle_telegram_top_command,
        "/nxt": _handle_telegram_nxt_command,
        "/week": _handle_telegram_week_command,
        "/daily": _handle_telegram_daily_command,
        "/오늘": _handle_telegram_daily_command,
        "/stats": _send_stats,
        "/reset_stats": lambda: _handle_reset_stats_command("/reset_stats"),
        "/승률초기화": lambda: _handle_reset_stats_command("/reset_stats"),
        "/menu": _send_menu,
        "/도움": _send_menu,
        "/help": _send_menu,
        "/설정": _send_telegram_setup_guide,
        "/setup": _send_telegram_setup_guide,
        "/geo": _handle_telegram_geo_command,
        "/us": _handle_telegram_us_command,
        "/overnight": _handle_telegram_overnight_command,
    }
    if text == "/stop":
        _bot_paused = True
        send("⏸ <b>봇 일시정지</b>  /resume 으로 재개")
        return
    if text == "/resume":
        _bot_paused = False
        send("▶️ <b>봇 재개</b>")
        return
    if text in ("/compact", "/컴팩트"):
        _handle_telegram_compact_toggle()
        return
    if text in ("/백업", "/backup"):
        _handle_telegram_backup_command()
        return
    if text.startswith("/result"):
        _handle_result_command(raw)
        return
    if text.startswith("/진입"):
        _handle_entry_confirm_command(raw)
        return
    if text.startswith("/skip"):
        _handle_skip_command(raw)
        return
    if text.startswith("/reset_stats") or text.startswith("/승률초기화"):
        _handle_reset_stats_command(raw)
        return
    if text.startswith("/yt_exclude"):
        _handle_telegram_yt_exclude_command(raw)
        return
    if text.startswith("/test"):
        _handle_telegram_test_command()
        return
    handler = exact_handlers.get(text)
    if handler:
        handler()
        return
    _send_menu(f"❓ <b>'{raw}'</b> 는 알 수 없는 명령어예요\n아래 버튼으로 실행해보세요")
def poll_telegram_commands():
    global _tg_offset
    try:
        updates = _poll_telegram_fetch_updates()
        for update in updates:
            _tg_offset = update["update_id"] + 1
            raw, text = _extract_telegram_command_payload(update)
            if not raw:
                continue
            _dispatch_telegram_command(raw, text)
    except Exception as e:
        _log_error_msg(f"⚠️ TG 명령어 오류: {e}")
def _telegram_poll_loop():
    """스캔과 분리된 텔레그램 명령/버튼 전용 루프 (지수 백오프 적용)."""
    _consecutive_fails = 0
    _TG_POLL_BACKOFF_MAX = 60  # 최대 백오프 60초
    while True:
        try:
            poll_telegram_commands()
            _consecutive_fails = 0  # 성공 시 즉시 정상 간격 복귀
        except Exception as e:
            _consecutive_fails += 1
            if _consecutive_fails <= 3 or _consecutive_fails == 5:
                _log_warn_msg(f"⚠️ 텔레그램 폴링 루프 오류 ({_consecutive_fails}회 연속): {e}")
            elif _consecutive_fails == 10:
                _log_warn_msg(f"⚠️ 텔레그램 폴링 연속 실패 {_consecutive_fails}회 — 백오프 {min(TELEGRAM_POLL_INTERVAL * (2 ** min(_consecutive_fails, 5)), _TG_POLL_BACKOFF_MAX)}초")
            backoff = min(TELEGRAM_POLL_INTERVAL * (2 ** min(_consecutive_fails, 5)), _TG_POLL_BACKOFF_MAX)
            time.sleep(max(1, backoff))
            continue
        time.sleep(max(1, TELEGRAM_POLL_INTERVAL))
def _request_actual_entry_confirm(rec: dict):
    """
    이론 추적 완료 시 → 실제 진입 여부 확인 요청 알림.
    사용자가 /result 또는 /skip으로 응답.
    """
    name    = rec.get("name", "")
    code    = rec.get("code", "")
    pnl     = rec.get("pnl_pct", 0)
    sig     = rec.get("signal_type", "")
    pnl_str = f"+{pnl:.1f}%" if pnl >= 0 else f"{pnl:.1f}%"
    emoji   = "✅" if pnl > 0 else "🔵"
    msg = (
        f"❓ <b>[진입 여부 확인]</b>\n"
        f"━━━━━━━━━━━━━━━\n"
        f"{emoji} <b>{name}</b>  <code>{code}</code>\n"
        f"이론 결과: <b>{pnl_str}</b>  [{sig}]\n"
        f"━━━━━━━━━━━━━━━\n"
        f"실제 진입하셨다면:\n"
        f"<code>/result {name} 실제수익률</code>\n"
        f"예) /result {name} +8.5\n\n"
        f"💡 미응답 시 미진입으로 자동 처리됩니다"
    )
    send(msg)
def _handle_entry_confirm_command(raw: str):
    """
    /진입 종목명 [실제진입가]  처리
    예) /진입 대주산업          ← 봇이 계산한 진입가로 확정
    예) /진입 대주산업 15300    ← 실제 진입가 직접 입력
    목적: 내가 실제 진입한 종목을 기록해서 /stats의 "내 실제 수익" 에 반영.
    봇의 이론 추적(signal_log)은 계속 병행 → 봇 조건 학습에 활용됨.
    즉, 진입 여부와 무관하게 이론 데이터는 항상 쌓임.
    """
    try:
        parts      = raw.strip().split(maxsplit=2)
        name_input = parts[1] if len(parts) > 1 else ""
        price_input = parts[2] if len(parts) > 2 else ""
        if not name_input:
            send("⚠️ 형식: /진입 종목명 [실제진입가]\n"
                 "예) /진입 대주산업\n"
                 "예) /진입 대주산업 15300"); return
        data = {}
        try:
            data = _read_json_locked(SIGNAL_LOG_FILE)
        except Exception as e:
            _swallow_exception(e)
        matched = []
        for log_key, rec in data.items():
            if name_input in rec.get("name", "") and rec.get("actual_entry") is None:
                matched.append((log_key, rec))
        if not matched:
            send(f"❓ '{name_input}' 종목을 찾을 수 없어요.\n"
                 f"추적 중인 종목명을 확인해주세요."); return
        # 가장 최근 신호 선택
        matched.sort(key=lambda x: x[1].get("detect_date",""), reverse=True)
        log_key, rec = matched[0]
        # 실제 진입가 처리
        try:
            actual_price = int(price_input) if price_input else rec.get("entry_price", 0)
        except Exception as e:
            _swallow_exception(e)  # v105 structured silent-exception log
            actual_price = rec.get("entry_price", 0)
        rec["actual_entry"]       = True
        rec["actual_entry_price"] = actual_price
        # 실제 진입가로 손절/목표 재계산
        if actual_price and actual_price != rec.get("entry_price", 0):
            diff_ratio = actual_price / rec["entry_price"] if rec.get("entry_price") else 1
            rec["stop_price"]    = int(rec.get("stop_price",  0) * diff_ratio / 10) * 10
            rec["target_price"]  = int(rec.get("target_price", 0) * diff_ratio / 10) * 10
        _write_json_atomic(SIGNAL_LOG_FILE, data, indent=2)
        entry_p  = actual_price or rec.get("entry_price", 0)
        stop_p   = rec.get("stop_price", 0)
        target_p = rec.get("target_price", 0)
        stop_pct  = round((stop_p   - entry_p) / entry_p * 100, 1) if entry_p else 0
        tgt_pct   = round((target_p - entry_p) / entry_p * 100, 1) if entry_p else 0
        send(f"✅ <b>[진입 확정]</b>\n"
             f"━━━━━━━━━━━━━━━\n"
             f"🔴 <b>{rec['name']}</b>  <b><code>{rec['code']}</code></b>\n"
             f"━━━━━━━━━━━━━━━\n"
             f"📍 실제 진입가: <b>{entry_p:,}원</b>\n"
             f"🛡 손절가:  <b>{stop_p:,}원</b>  ({stop_pct:+.1f}%)\n"
             f"🏆 목표가:  <b>{target_p:,}원</b>  ({tgt_pct:+.1f}%)\n"
             f"━━━━━━━━━━━━━━━\n"
             f"이 기준으로 자동 추적을 시작합니다.\n"
             f"결과는 /result 로 직접 입력하거나\n"
             f"목표가/손절가 도달 시 자동 확정됩니다.")
        _log_info_msg(f"  ✅ 진입 확정: {rec['name']} {entry_p:,}원")
    except Exception as e:
        _log_error("_handle_entry_confirm_command", e)
        send(f"⚠️ /진입 처리 오류: {e}")
def _handle_skip_command(raw: str):
    """
    /skip 종목명 이유  처리
    예) /skip 대주산업 시간없음
    → actual_entry=False, skip_reason 기록
    → 봇 학습: 어떤 상황에서 진입 기회를 놓치는지 패턴 분석
    """
    try:
        parts      = raw.strip().split(maxsplit=2)
        name_input = parts[1] if len(parts) > 1 else ""
        reason     = parts[2] if len(parts) > 2 else "미입력"
        if not name_input:
            send("⚠️ 형식: /skip 종목명 이유\n예) /skip 대주산업 시간없음\n\n"
                 "이유 예시: 시간없음 / 조건불일치 / 이미상승 / 분산투자 / 기타"); return
        data = {}
        try:
            data = _read_json_locked(SIGNAL_LOG_FILE)
        except Exception as e:
            _swallow_exception(e)
        matched_key  = None
        matched_name = None
        # 가장 최근 해당 종목 찾기
        for key in sorted(data.keys(), reverse=True):
            rec = data[key]
            if name_input in rec.get("name", ""):
                matched_key  = key
                matched_name = rec["name"]
                break
        if not matched_key:
            send(f"⚠️ '{name_input}' 종목을 찾을 수 없어요.\n/list 로 감시 중인 종목 확인"); return
        data[matched_key]["actual_entry"]  = False
        data[matched_key]["skip_reason"]   = reason
        data[matched_key]["actual_pnl"]    = None
        _write_json_atomic(SIGNAL_LOG_FILE, data, indent=2)
        theo_pnl = data[matched_key].get("pnl_pct", 0)
        theo_str = f"+{theo_pnl:.1f}%" if theo_pnl >= 0 else f"{theo_pnl:.1f}%"
        send(
            f"⏭ <b>진입 스킵 기록 완료</b>\n"
            f"종목: <b>{matched_name}</b>\n"
            f"이유: {reason}\n"
            f"이론 수익률: {theo_str} (봇 학습에 반영됩니다)\n\n"
            f"💡 스킵 패턴도 쌓이면 봇이 진입 타이밍을 개선해요."
        )
        _log_info_msg(f"  ⏭ 스킵 기록: {matched_name} / {reason}")
    except Exception as e:
        send(f"⚠️ 스킵 기록 오류: {e}")
def _parse_result_command_payload(raw: str) -> tuple[str, float]:
    parts = raw.strip().split()
    if len(parts) < 3:
        raise ValueError('format')
    return parts[1], float(parts[2].replace('%', ''))
def _build_result_status_bundle(pnl: float) -> dict:
    return {
        "result_emoji": "✅" if pnl > 0 else ("🔵" if pnl < 0 else "➖"),
        "status": "수익" if pnl > 0 else ("손실" if pnl < 0 else "본전"),
        "today": datetime.now().strftime("%Y%m%d"),
        "exit_time": datetime.now().strftime("%H:%M:%S"),
    }
def _load_result_signal_data() -> dict:
    try:
        data = _read_json_locked(SIGNAL_LOG_FILE)
        return data if isinstance(data, dict) else {}
    except Exception as e:
        _swallow_exception(e)
        return {}
def _find_result_signal_match(sig_data: dict, name_input: str) -> tuple[str | None, str | None, str]:
    for key, rec in sig_data.items():
        if name_input in rec.get("name", "") and rec.get("status") == "추적중":
            return key, rec.get("name"), rec.get("signal_type", "MANUAL")
    return None, None, "MANUAL"
def _maybe_warn_result_pnl_gap(rec: dict, pnl: float) -> None:
    try:
        cur_p = get_stock_price(rec["code"]).get("price", 0)
        entry = rec.get("entry_price", 0)
        if cur_p and entry:
            auto_pnl = round((cur_p - entry) / entry * 100, 1)
            if abs(pnl - auto_pnl) > 5:
                send(
                    f"⚠️ 입력 수익률({pnl:+.1f}%)과 현재가 기준({auto_pnl:+.1f}%) 차이가 큽니다.\n"
                    f"현재가: {cur_p:,}원  |  입력값 그대로 기록합니다."
                )
    except Exception as e:
        _swallow_exception(e)
def _apply_result_signal_update(sig_data: dict, sig_matched_key: str, pnl: float, status_bundle: dict) -> None:
    rec = sig_data[sig_matched_key]
    _ensure_record_stats_meta(rec)
    if not rec.get("pnl_pct"):
        rec["gross_pnl_pct"] = pnl
        rec["net_pnl_pct"] = pnl
        rec["round_trip_cost_pct"] = 0.0
        rec["pnl_pct"] = pnl
        rec["status"] = status_bundle["status"]
        rec["exit_date"] = status_bundle["today"]
        rec["exit_time"] = status_bundle["exit_time"]
        rec["exit_reason"] = "수동입력"
    rec["actual_entry"] = True
    rec["actual_pnl"] = pnl
    rec["actual_exit_date"] = status_bundle["today"]
    rec["skip_reason"] = ""
    _write_json_atomic(SIGNAL_LOG_FILE, sig_data, indent=2)
def _load_result_early_data() -> dict:
    try:
        data = _read_json_safe(EARLY_LOG_FILE, {}) or {}
        return data if isinstance(data, dict) else {}
    except Exception as e:
        _swallow_exception(e)
        return {}
def _find_result_early_match(early_data: dict, name_input: str) -> str | None:
    for code, info in early_data.items():
        if name_input in info.get("name", ""):
            return code
    return None
def _build_manual_result_record(name_input: str, pnl: float, status_bundle: dict) -> tuple[str, dict]:
    new_key = f"manual_{datetime.now().strftime('%m%d%H%M')}"
    return new_key, {
        "log_key": new_key,
        "code": new_key,
        "name": name_input,
        "signal_type": "MANUAL",
        "bot_version": BOT_VERSION,
        "stats_cohort": BOT_STATS_COHORT,
        "structure_cohort": BOT_STATS_COHORT,
        "detect_date": status_bundle["today"],
        "detect_time": status_bundle["exit_time"],
        "detect_price": 0,
        "entry_price": 0,
        "stop_price": 0,
        "target_price": 0,
        "status": status_bundle["status"],
        "gross_pnl_pct": pnl,
        "net_pnl_pct": pnl,
        "round_trip_cost_pct": 0.0,
        "pnl_pct": pnl,
        "exit_date": status_bundle["today"],
        "exit_time": status_bundle["exit_time"],
        "exit_reason": "수동입력",
        "score": 0,
        "sector_bonus": 0,
        "sector_theme": "",
    }
def _send_result_record_message(display_name: str, pnl: float, signal_type: str, status_bundle: dict) -> None:
    send(
        f"{status_bundle['result_emoji']} <b>결과 기록 완료</b>\n"
        f"종목: <b>{display_name}</b>\n"
        f"수익률: <b>{pnl:+.1f}%</b>  ({status_bundle['status']})\n"
        f"신호: {signal_type}\n\n"
        f"/stats 로 전체 통계 확인"
    )
def _handle_result_command(raw: str):
    """
    /result 종목명 수익률  처리
    예) /result 대주산업 +12.5
    → signal_log.json (메인) + early_detect_log.json (하위호환) 동시 업데이트
    → 자동 튜닝 즉시 반영
    """
    try:
        name_input, pnl = _parse_result_command_payload(raw)
        status_bundle = _build_result_status_bundle(pnl)
        sig_data = _load_result_signal_data()
        sig_matched_key, matched_name, signal_type = _find_result_signal_match(sig_data, name_input)
        if sig_matched_key:
            _maybe_warn_result_pnl_gap(sig_data[sig_matched_key], pnl)
            _apply_result_signal_update(sig_data, sig_matched_key, pnl, status_bundle)
        early_data = _load_result_early_data()
        early_matched = _find_result_early_match(early_data, name_input)
        if early_matched:
            early_data[early_matched].update({
                "status": status_bundle["status"],
                "gross_pnl_pct": pnl,
                "net_pnl_pct": pnl,
                "round_trip_cost_pct": 0.0,
                "pnl_pct": pnl,
                "exit_date": status_bundle["today"],
            })
            _write_json_atomic(EARLY_LOG_FILE, early_data, indent=2)
        elif not sig_matched_key:
            new_key, new_record = _build_manual_result_record(name_input, pnl, status_bundle)
            sig_data[new_key] = new_record
            _write_json_atomic(SIGNAL_LOG_FILE, sig_data, indent=2)
            matched_name = name_input
        display_name = matched_name or name_input
        _send_result_record_message(display_name, pnl, signal_type, status_bundle)
        load_tracker_feedback()
    except ValueError:
        send("⚠️ 형식: /result 종목명 수익률\n예) /result 대주산업 +12.5")
    except Exception as e:
        send(f"⚠️ 결과 기록 오류: {e}")
# ============================================================
# 🌙 오버나이트 위험도 계산
# ============================================================
def calc_overnight_risk(code: str, name: str, entry: int, current_pnl: float) -> dict:
    """
    장 마감 후 보유 위험도 계산.
    v40.0-#5: 리스크 원인별 분류 (유동성/에너지·지정학/국내추세)
    반환: {level: "high"/"mid"/"low", score: int, reason: str, causes: list}
    """
    try:
        now        = _now_kst()
        us         = get_us_market_signals()
        short_r    = get_short_sell_ratio(code)
        vix        = us.get("vix", 20)
        us_regime  = us.get("us_regime", "neutral")
        gap_signal = us.get("gap_signal", "flat")
        risk_score = 0
        reasons    = []
        # NXT 시간대 → 거래량 얇아서 변동성 추가
        nxt_only = is_nxt_open() and not is_market_open()
        if nxt_only:
            risk_score += 10; reasons.append("📡 NXT 단독 시간대 (유동성 낮음)")
        if us_regime == "panic":
            risk_score += 40; reasons.append("🔵 미국 급락장")
        elif us_regime == "risk_off":
            risk_score += 20; reasons.append("🔵 미국 약세장")
        if vix >= 30:
            risk_score += 20; reasons.append(f"🔵 VIX {vix:.0f} (공포)")
        elif vix >= 25:
            risk_score += 10; reasons.append(f"🟡 VIX {vix:.0f} (불안)")
        if short_r >= 10:
            risk_score += 15; reasons.append(f"📉 공매도 {short_r:.1f}%")
        elif short_r >= 5:
            risk_score += 7; reasons.append(f"⚠️ 공매도 {short_r:.1f}%")
        if gap_signal == "gap_down":
            risk_score += 15; reasons.append("⬇️ 갭하락 가능성")
        if current_pnl > 5:
            risk_score -= 10; reasons.append(f"✅ 현재 +{current_pnl:.1f}% 수익 중")
        # v40.0-#6: 금요일 마감 시 주말 리스크 가중
        if datetime.now().weekday() == 4 and _get_time_risk_profile() == "friday_close":
            risk_score += 10; reasons.append("📅 금요일 오버나이트 (주말 리스크)")
        # v41.61 #6: 한국 시장 레짐 기반 오버나이트 위험 가중
        _on_regime_add = get_regime_overnight_add()
        if _on_regime_add > 0:
            risk_score += _on_regime_add
            _on_regime_mode = _dynamic.get("regime_mode", "normal")
            _on_labels = {"bear": "🔵 하락장", "crash": "🔵 급락장"}
            reasons.append(f"{_on_labels.get(_on_regime_mode, '')} 레짐 가중 +{_on_regime_add}점")
        if   risk_score >= 50: level = "high"
        elif risk_score >= 25: level = "mid"
        else:                  level = "low"
        # v40.0-#5: 원인별 분류
        kospi_5d = 0.0
        try:
            items = get_daily_data("0001", 10)
            closes = [i["close"] for i in items if i.get("close")]
            if len(closes) >= 5:
                kospi_5d = (closes[-1] - closes[-5]) / closes[-5] * 100
        except Exception as e:
            _swallow_exception(e)
        geo_state = _get_effective_geo_state(now)
        overnight_lines = _get_effective_overnight_lines(now)
        causes = _classify_risk_causes(us, geo_state, kospi_5d)
        level_emoji = {"high": "🔵 위험", "mid": "🟡 경계", "low": "🔴 안전"}
        return {
            "level":  level,
            "score":  risk_score,
            "reason": f"{level_emoji[level]}  {'  '.join(reasons)}",
            "causes": causes,
        }
    except Exception as e:
        _swallow_exception(e)  # v105 structured silent-exception log
        return {"level": "low", "score": 0, "reason": "", "causes": []}
# ============================================================
# 🔄 테마 로테이션 감지
# ============================================================
_theme_rotation_cache: dict = {"ts": 0, "themes": {}}
def detect_theme_rotation() -> dict:
    """
    THEME_MAP 기반 테마별 평균 등락률 계산 → 강세/약세 테마 감지.
    1시간 캐시. 반환: {강한테마: [], 약한테마: [], ts}
    """
    if time.time() - float(_theme_rotation_cache.get("ts", 0) or 0) < 3600:
        return _theme_rotation_cache
    theme_scores = {}
    try:
        for theme_key, theme_info in list(THEME_MAP.items())[:10]:  # 상위 10개 테마
            stocks   = theme_info.get("stocks", [])[:5]  # 테마당 5개만
            chg_list = []
            for code, name in stocks:
                try:
                    cur = get_stock_price(code)
                    if cur and cur.get("change_rate") is not None:
                        chg_list.append(cur["change_rate"])
                    time.sleep(0.1)
                except Exception as e:
                    _swallow_exception(e)  # v105 structured silent-exception log
                    continue
            if chg_list:
                theme_scores[theme_key] = round(sum(chg_list) / len(chg_list), 2)
        sorted_themes = sorted(theme_scores.items(), key=lambda x: -x[1])
        strong = [(k, v) for k, v in sorted_themes if v >= 2.0][:3]
        weak   = [(k, v) for k, v in sorted_themes if v <= -1.5][:3]
        _theme_rotation_cache.update({
            "ts":      time.time(),
            "themes":  theme_scores,
            "strong":  strong,
            "weak":    weak,
        })
    except Exception as e:
        _log_error("detect_theme_rotation", e)
    return _theme_rotation_cache
# ============================================================
# 💸 놓친 수익 추적
# ============================================================
def get_missed_profit_summary() -> dict:
    """
    signal_log에서 미진입(actual_entry=False 또는 None) 건의
    이론 수익률 집계 → "놓친 수익" 통계.
    반환: {count, avg_pnl, total_pnl, best: dict}
    """
    try:
        data = {}
        try:
            data = _read_json_locked(SIGNAL_LOG_FILE)
        except Exception as e:
            _swallow_exception(e)
        missed = [v for v in data.values()
                  if _record_matches_stats_scope(v)
                  and v.get("actual_entry") in (False, None)
                  and v.get("status") in ("수익", "손실", "본전")
                  and v.get("pnl_pct") is not None]
        if not missed:
            return {"count": 0, "avg_pnl": 0.0, "total_pnl": 0.0, "best": None}
        pnls     = [v["pnl_pct"] for v in missed]
        avg_pnl  = round(sum(pnls) / len(pnls), 1)
        best_rec = max(missed, key=lambda x: x.get("pnl_pct", 0))
        return {
            "count":     len(missed),
            "avg_pnl":   avg_pnl,
            "total_pnl": round(sum(pnls), 1),
            "best":      best_rec,
        }
    except Exception as e:
        _swallow_exception(e)  # v105 structured silent-exception log
        return {"count": 0, "avg_pnl": 0.0, "total_pnl": 0.0, "best": None}
def _build_signal_stats_context(data: dict) -> dict:
    scoped = _filter_records_by_stats_scope(list(data.values()), cohort=BOT_STATS_COHORT)
    completed = [v for v in scoped if v.get("status") in ["수익", "손실", "본전"]]
    tracking = _filter_records_by_stats_scope(_get_valid_tracking(data), cohort=BOT_STATS_COHORT)
    actual_entered = [v for v in scoped if v.get("actual_entry") is True and v.get("actual_pnl") is not None]
    skipped = [v for v in scoped if v.get("actual_entry") is False]
    unconfirmed = [v for v in completed if v.get("actual_entry") is None]
    return {
        "scoped": scoped,
        "completed": completed,
        "tracking": tracking,
        "actual_entered": actual_entered,
        "skipped": skipped,
        "unconfirmed": unconfirmed,
        "stats_cohort": BOT_STATS_COHORT,
        "version_label": BOT_VERSION,
        "type_labels": {
            "UPPER_LIMIT": "🚨 상한가",
            "NEAR_UPPER": "🔥 상한가근접",
            "STRONG_BUY": "💎 강력매수",
            "SURGE": "📈 급등",
            "EARLY_DETECT": "🔍 조기포착",
            "ENTRY_POINT": "🎯 눌림목",
            "MID_PULLBACK": "🏆 눌림목",
            "MANUAL": "✏️ 수동",
        },
    }
def _build_signal_stats_header(data: dict, ctx: dict) -> str:
    completed = ctx["completed"]
    tracking = ctx["tracking"]
    actual_entered = ctx["actual_entered"]
    skipped = ctx["skipped"]
    unconfirmed = ctx["unconfirmed"]
    total_pnl = [v["pnl_pct"] for v in completed]
    total_win = sum(1 for p in total_pnl if p > 0)
    avg_pnl = sum(total_pnl) / len(total_pnl)
    total_rate = total_win / len(total_pnl) * 100
    actual_msg = ""
    if actual_entered:
        a_pnls = [v["actual_pnl"] for v in actual_entered]
        a_win = sum(1 for p in a_pnls if p > 0)
        a_avg = sum(a_pnls) / len(a_pnls)
        a_rate = a_win / len(a_pnls) * 100
        actual_msg = f"💰 <b>내 실제 수익</b>  {len(actual_entered)}건\n  승률 <b>{a_rate:.0f}%</b>  평균 <b>{a_avg:+.1f}%</b>\n"
    elif unconfirmed:
        actual_msg = f"❓ 확인 대기 {len(unconfirmed)}건  (/result 또는 /skip 로 기록)\n"
    skip_msg = ""
    if skipped:
        skip_reasons = {}
        for v in skipped:
            reason = v.get("skip_reason", "미입력")
            skip_reasons[reason] = skip_reasons.get(reason, 0) + 1
        skip_top = sorted(skip_reasons.items(), key=lambda x: -x[1])[:3]
        skip_str = "  /  ".join([f"{r}:{n}건" for r, n in skip_top])
        skip_pnls = [v.get("pnl_pct", 0) for v in skipped if v.get("pnl_pct")]
        opp_cost = sum(skip_pnls) / len(skip_pnls) if skip_pnls else 0
        skip_msg = f"⏭ <b>스킵</b>  {len(skipped)}건  (이론 평균 {opp_cost:+.1f}%)\n  이유: {skip_str}\n"
    miss_all = [v for v in data.values() if _record_matches_stats_scope(v) and v.get("status") in ["진입미달", "진입가변경"]]
    miss_surge = sum(1 for v in miss_all if "상승이탈" in str(v.get("exit_reason", "")))
    miss_expire = sum(1 for v in miss_all if "기간만료" in str(v.get("exit_reason", "")))
    miss_reentry = sum(1 for v in miss_all if "진입가변경" in str(v.get("exit_reason", "")))
    cur_ratio = _dynamic.get("entry_pullback_ratio", ENTRY_PULLBACK_RATIO)
    miss_msg = ""
    if miss_all:
        miss_msg = f"⚠️ <b>진입 미달</b>  {len(miss_all)}건\n  상승이탈 {miss_surge}건  기간만료 {miss_expire}건  재포착 {miss_reentry}건\n  현재 진입가 비율: <b>{cur_ratio:.2f}</b>  (0.2=보수적 ↔ 0.7=공격적)\n"
    return (
        f"📊 <b>신호 성과 통계</b>\n"
        f"━━━━━━━━━━━━━━━\n"
        f"🧬 <b>현재 구조 cohort</b>  {ctx['stats_cohort']}  (실행 버전 {ctx['version_label']})\n"
        f"🤖 <b>이론 수익률</b> (현재 구조 기준)  {len(completed)}건\n"
        f"  승률 <b>{total_rate:.0f}%</b>  평균 <b>{avg_pnl:+.1f}%</b>  추적중 {len(tracking)}건\n"
        f"━━━━━━━━━━━━━━━\n"
        f"{actual_msg}{skip_msg}{miss_msg}━━━━━━━━━━━━━━━\n"
    )
def _append_signal_stats_missed_profit_block(msg: str) -> str:
    try:
        missed = get_missed_profit_summary()
        if missed["count"] >= 3:
            best = missed.get("best") or {}
            best_str = f"  최고: {best.get('name','')} {best.get('pnl_pct',0):+.1f}%" if best else ""
            msg += (
                f"💸 <b>놓친 수익</b>  {missed['count']}건  평균 {missed['avg_pnl']:+.1f}%  합계 {missed['total_pnl']:+.1f}%\n"
                f"{best_str}\n"
                f"━━━━━━━━━━━━━━━\n"
            )
    except Exception as e:
        _swallow_exception(e)
    return msg
def _append_signal_stats_by_type_block(msg: str, completed: list, type_labels: dict) -> str:
    by_type = {}
    for rec in completed:
        sig_type = rec.get("signal_type", "기타")
        by_type.setdefault(sig_type, []).append(rec)
    for sig_type, recs in sorted(by_type.items(), key=lambda x: -len(x[1])):
        pnls = [r["pnl_pct"] for r in recs]
        win = sum(1 for p in pnls if p > 0)
        rate = win / len(pnls) * 100
        avg = sum(pnls) / len(pnls)
        best = max(pnls)
        worst = min(pnls)
        label = type_labels.get(sig_type, sig_type)
        bar = "🔴" * int(rate / 20)
        reasons = {}
        for rec in recs:
            exit_reason = rec.get("exit_reason", "?")
            reasons[exit_reason] = reasons.get(exit_reason, 0) + 1
        reason_str = "  ".join([f"{k}:{v}건" for k, v in reasons.items()])
        msg += f"\n{label}  ({len(recs)}건)\n  {bar}  승률 {rate:.0f}%  평균 {avg:+.1f}%\n  최고 {best:+.1f}%  최저 {worst:+.1f}%\n  {reason_str}\n"
    return msg
def _append_signal_stats_theme_and_timeslot_blocks(msg: str, completed: list) -> str:
    solo = [v for v in completed if not v.get("sector_bonus", 0)]
    themed = [v for v in completed if v.get("sector_bonus", 0)]
    if solo and themed:
        solo_avg = sum(v["pnl_pct"] for v in solo) / len(solo)
        themed_avg = sum(v["pnl_pct"] for v in themed) / len(themed)
        solo_win = sum(1 for v in solo if v["pnl_pct"] > 0) / len(solo) * 100
        themed_win = sum(1 for v in themed if v["pnl_pct"] > 0) / len(themed) * 100
        msg += f"\n━━━━━━━━━━━━━━━\n🔍 단독 상승:  승률 {solo_win:.0f}%  평균 {solo_avg:+.1f}% ({len(solo)}건)\n🏭 테마 동반:  승률 {themed_win:.0f}%  평균 {themed_avg:+.1f}% ({len(themed)}건)\n"
    slot_stats = analyze_timeslot_winrate(completed)
    if slot_stats:
        msg += "\n━━━━━━━━━━━━━━━\n🕐 <b>시간대별 승률</b>\n"
        for slot in ["장초반", "오전", "오후", "장후반", "기타"]:
            if slot not in slot_stats:
                continue
            st = slot_stats[slot]
            adj = _dynamic["timeslot_score_adj"].get(slot, 0)
            adj_str = f"  [+{adj}점 보정 중]" if adj > 0 else ""
            bar = "🔴" * int(st["rate"] / 20)
            msg += f"  {slot}: {bar}  승률 {st['rate']:.0f}%  평균 {st['avg']:+.1f}%  ({st['total']}건){adj_str}\n"
    loss_pattern = analyze_loss_pattern(completed)
    if loss_pattern:
        msg += f"\n━━━━━━━━━━━━━━━\n{loss_pattern}\n"
    return msg
def _append_signal_stats_kpi_block(msg: str, completed: list, actual_entered: list) -> str:
    try:
        kpi = compute_signal_kpi(completed)
        ov = kpi.get("overall", {})
        if ov.get("n", 0) >= KPI_MIN_SAMPLES:
            exp_emoji = "🔴" if ov["expectancy"] > 0.5 else "🟡" if ov["expectancy"] >= 0 else "🔵"
            pf_emoji = "🔴" if ov["profit_factor"] > 1.5 else "🟡" if ov["profit_factor"] >= 1.0 else "🔵"
            msg += f"\n━━━━━━━━━━━━━━━\n📐 <b>KPI 요약</b> ({ov['n']}건 기준)\n  승률: <b>{ov['win_rate']:.0f}%</b>  손익비: {pf_emoji} <b>{ov['payoff_ratio']:.2f}</b>  기대수익: {exp_emoji} <b>{ov['expectancy']:+.2f}%</b>\n  Profit Factor: {ov['profit_factor']:.2f}\n"
            by_t = kpi.get("by_type", {})
            type_labels_kpi = {"UPPER_LIMIT": "상한가", "NEAR_UPPER": "상한가근접", "STRONG_BUY": "강력매수", "SURGE": "급등", "EARLY_DETECT": "조기포착", "ENTRY_POINT": "눌림목", "MID_PULLBACK": "눌림목", "MANUAL": "수동"}
            good = [(t, k) for t, k in by_t.items() if k.get("n", 0) >= 5 and k["win_rate"] >= 60 and k.get("payoff_ratio", 0) >= 1.2]
            bad = [(t, k) for t, k in by_t.items() if k.get("n", 0) >= 5 and (k["win_rate"] < 35 or k.get("payoff_ratio", 0) < 0.8)]
            if good:
                g_str = ', '.join([f"{type_labels_kpi.get(t, t)}({k['win_rate']:.0f}%)" for t, k in good[:3]])
                msg += f"  🌟 고성과: {g_str}\n"
            if bad:
                b_str = ', '.join([f"{type_labels_kpi.get(t, t)}({k['win_rate']:.0f}%)" for t, k in bad[:3]])
                msg += f"  ⚠️ 저성과: {b_str}\n"
            if kpi.get("consecutive_loss", 0) >= 3:
                msg += f"  🚨 연속 손절: {kpi['consecutive_loss']}회\n"
        else:
            msg += f"\n━━━━━━━━━━━━━━━\n📐 <b>KPI</b>: 데이터 부족 ({ov.get('n', 0)}/{KPI_MIN_SAMPLES}건)\n"
        bucket_kpi = kpi.get("by_mid_pullback_bucket", {})
        if bucket_kpi:
            msg += "\n━━━━━━━━━━━━━━━\n🧪 <b>눌림목 bucket 진단</b>\n"
            msg += _build_signal_stats_bucket_lines(bucket_kpi, actual=False)
        actual_bucket_recs = [v for v in actual_entered if v.get("mid_pullback_bucket")]
        if actual_bucket_recs:
            actual_kpi = compute_signal_kpi(actual_bucket_recs, pnl_field="actual_pnl")
            actual_bucket_kpi = actual_kpi.get("by_mid_pullback_bucket", {})
            if actual_bucket_kpi:
                msg += "\n━━━━━━━━━━━━━━━\n🪙 <b>실진입 눌림목 bucket</b>\n"
                msg += _build_signal_stats_bucket_lines(actual_bucket_kpi, actual=True)
    except Exception as e:
        _swallow_exception(e)
    return msg
def _build_signal_stats_bucket_lines(bucket_kpi: dict, actual: bool = False) -> str:
    lines = []
    high = []
    low = []
    for bucket in ["weekly_monthly_trend", "daily_trend", "gap_first_pullback", "intraday_reclaim"]:
        bk = bucket_kpi.get(bucket)
        if not bk:
            continue
        label = MID_PULLBACK_BUCKET_LABELS.get(bucket, bucket)
        n = bk.get("n", 0)
        if n < 2:
            lines.append(f"  {label}: 표본 부족 ({n}건)")
            continue
        grade_dist = bk.get("execution_grade_dist", {}) or {}
        grade_str = " ".join(f"{g}{grade_dist.get(g,0)}" for g in ("A", "B", "C") if grade_dist.get(g, 0)) or "-"
        emoji = "🔴" if bk.get("expectancy", 0) > 0.5 else "🟡" if bk.get("expectancy", 0) >= 0 else "🔵"
        lines.append(f"  {emoji} {label}: 승률 {bk['win_rate']:.0f}%  평균 {bk['avg_pnl']:+.1f}%  손익비 {bk['payoff_ratio']:.2f}  기대 {bk['expectancy']:+.2f}%  ({n}건) [{grade_str}]")
        if n >= 3 and bk.get("win_rate", 0) >= 60 and bk.get("expectancy", 0) > 0:
            high.append(label)
        if n >= 3 and (bk.get("win_rate", 0) < 35 or bk.get("expectancy", 0) < 0):
            low.append(label)
    if high:
        prefix = "실진입 고성과" if actual else "고성과 bucket"
        lines.append(f"  🌟 {prefix}: {', '.join(high[:3])}")
    if low:
        prefix = "실진입 저성과" if actual else "저성과 bucket"
        lines.append(f"  ⚠️ {prefix}: {', '.join(low[:3])}")
    return "\n".join(lines) + ("\n" if lines else "")
def _append_signal_stats_regime_and_dynamic_blocks(msg: str, completed: list) -> str:
    regime = get_market_regime()
    rmode = regime.get("mode", "normal")
    rlabels = {"bull": "🔴 상승장", "normal": "🟡 보통장", "bear": "🔵 하락장", "crash": "🔵 급락장"}
    mult_map = {"bull": "기준 완화 (×1.15)", "normal": "표준", "bear": "기준 강화 (×0.75)", "crash": "급락장 — 상한가만 허용"}
    msg += f"\n━━━━━━━━━━━━━━━\n🌐 <b>현재 시장 국면</b>: {rlabels.get(rmode,'보통장')}\n  코스피 당일 {regime.get('chg_1d',0):+.1f}%  |  5일 {regime.get('chg_5d',0):+.1f}%\n  신호 기준: {mult_map.get(rmode,'표준')}\n"
    if completed:
        a_recs = [v for v in completed if v.get("grade", "B") == "A"]
        b_recs = [v for v in completed if v.get("grade", "B") == "B"]
        if a_recs:
            a_avg = sum(v["pnl_pct"] for v in a_recs) / len(a_recs)
            a_win = sum(1 for v in a_recs if v["pnl_pct"] > 0) / len(a_recs) * 100
            msg += f"\n━━━━━━━━━━━━━━━\n💰 <b>등급별 성과</b>\n  A등급: {len(a_recs)}건  승률 {a_win:.0f}%  평균 {a_avg:+.1f}%\n"
        if b_recs:
            b_avg = sum(v["pnl_pct"] for v in b_recs) / len(b_recs)
            b_win = sum(1 for v in b_recs if v["pnl_pct"] > 0) / len(b_recs) * 100
            msg += f"  B등급: {len(b_recs)}건  승률 {b_win:.0f}%  평균 {b_avg:+.1f}%\n"
    msg += f"\n━━━━━━━━━━━━━━━\n⚙️ <b>현재 자동 조정 파라미터</b>\n  최소점수: {_dynamic['min_score_normal']}점 (엄격: {_dynamic['min_score_strict']}점)\n  RSI 과매수 기준: {_dynamic['rsi_overbuy']:.0f}\n  ATR 손절:{_dynamic['atr_stop_mult']} / 목표:{_dynamic.get('atr_target_mult', ATR_TARGET_MULT)}\n  포지션 기본비중: {_dynamic.get('position_base_pct',8.0)}%\n"
    feat_labels = {
        "feat_w_rsi": "RSI 필터",
        "feat_w_ma": "이동평균",
        "feat_w_bb": "볼린저밴드",
        "feat_w_sector": "섹터모멘텀",
        "feat_w_nxt": "NXT 보정",
        "feat_w_geo": "지정학 보정",
    }
    msg += "\n━━━━━━━━━━━━━━━\n🔧 <b>기능별 가중치</b> (auto_tune 자동 조정)\n"
    for fk, flabel in feat_labels.items():
        w = _dynamic.get(fk, 1.0)
        if w >= 1.2:
            status = "🔺 강화"
        elif w >= 0.8:
            status = "✅ 정상"
        elif w >= 0.4:
            status = "🔻 약화"
        else:
            status = "⛔ 거의 비활성"
        bar = "█" * int(w * 5) + "░" * max(0, 5 - int(w * 5))
        msg += f"  {flabel}: {bar} {w:.1f}  {status}\n"
    return msg
def _send_stats():
    """신호 유형별 승률·평균 수익률 통계 전송 (signal_log.json 기반)"""
    try:
        data = _load_signal_log_data()
        ctx = _build_signal_stats_context(data)
        if len(ctx["completed"]) < 3:
            send(f"📊 아직 이론 결과가 {len(ctx['completed'])}건뿐이에요. (추적 중: {len(ctx['tracking'])}건)\n결과가 쌓이면 자동으로 통계가 갱신돼요.")
            return
        msg = _build_signal_stats_header(data, ctx)
        msg = _append_signal_stats_missed_profit_block(msg)
        msg = _append_signal_stats_by_type_block(msg, ctx["completed"], ctx["type_labels"])
        msg = _append_signal_stats_theme_and_timeslot_blocks(msg, ctx["completed"])
        msg = _append_signal_stats_kpi_block(msg, ctx["completed"], ctx["actual_entered"])
        msg = _append_signal_stats_regime_and_dynamic_blocks(msg, ctx["completed"])
        send(msg)
    except Exception as e:
        send(f"⚠️ 통계 오류: {e}")
# ============================================================
# 장 마감
