# v165.30 [#2]: 섹터 시드 자동 등록 래퍼 (09:05, 당일 1회)
_sector_seed_registered_date: str = ""
_nxt_sector_seed_registered_date: str = ""  # v169.3: 누락된 전역 선언 추가 (NameError → 메인루프 크래시 수정)

def _register_sector_seed_from_yesterday_once():
    """07:28 장전 브리핑 직전: 어제 강세 섹터 기반 섹터 시드 1차 등록.
    이유: 09:10 등록은 NXT 오픈(08:00) 후 1시간 이상 섹터 풀 미준비 상태.
    장중 포착 즉시 _auto_register_sector_from_signal()이 실시간 갱신하므로
    이 함수는 "최소 보장 준비" 역할.
    """
    global _nxt_sector_seed_registered_date, _dynamic_theme_map
    if is_holiday():
        return
    today = _now_kst().strftime("%Y-%m-%d")
    if _nxt_sector_seed_registered_date == today:
        return
    _nxt_sector_seed_registered_date = today
    try:
        yesterday_results = _load_today_sector_results()
        if not yesterday_results:
            _log_info_msg("  ℹ️ [07:28 섹터시드] 전일 결과 없음 — 기본 시드로 대체")
            _register_sector_seed_stocks()
            return
        registered = 0
        today_mmdd = _now_kst().strftime("%m%d")
        for sector_name, v in list(yesterday_results.items())[:8]:
            codes = v.get("codes") or []
            if not codes:
                continue
            seed_code = normalize_stock_code(codes[0])
            if not seed_code:
                continue
            bstp_key = f"auto_sector_bstp_pre_{seed_code[:4]}_{today_mmdd}"
            if bstp_key in _dynamic_theme_map:
                continue
            all_stocks = [(normalize_stock_code(c), n)
                          for c, n in zip(v.get("codes", []), v.get("names", []))
                          if c]
            if not all_stocks:
                continue
            _dynamic_theme_map[bstp_key] = {
                "desc":        f"[전일강세] {sector_name}",
                "sectors":     [sector_name],
                "events":      [sector_name],
                "stocks":      all_stocks[:8],
                "ts":          time.time(),
                "direction":   "up",
                "source":      "yesterday_result",
                "seed_code":   seed_code,
                "trigger_chg": float(v.get("avg_chg", 0)),
                "win_count":   0,
                "loss_count":  0,
            }
            registered += 1
        if registered:
            _log_info_msg(f"  🌅 [07:28 섹터시드] 전일 강세 {registered}개 섹터 등록 완료")
        threading.Thread(target=_register_sector_seed_stocks, daemon=True).start()
    except Exception as e:
        _log_warn_msg(f"⚠️ _register_sector_seed_from_yesterday_once: {e}")

def _register_sector_seed_stocks_once():
    global _sector_seed_registered_date
    if is_holiday():
        return
    today = _now_kst().strftime("%Y-%m-%d")
    if _sector_seed_registered_date == today:
        return
    _sector_seed_registered_date = today
    try:
        _register_sector_seed_stocks()
    except Exception as e:
        _log_warn_msg(f"⚠️ 섹터시드 자동 등록 오류: {e}")
def _market_leader_profile(now_dt: datetime | None = None) -> dict:
    now_dt = now_dt or _now_kst()
    hhmm = now_dt.strftime("%H:%M")
    is_morning_open = "09:00" <= hhmm < "09:30"
    is_morning = "09:30" <= hhmm < "10:30"
    # 오전/이슈장엔 더 빨리 잡히게, 일반장도 지나치게 높지 않게 조정
    leader_min = 4.0 if is_morning_open else 5.5 if is_morning else 6.5
    score_min = 54 if is_morning_open else 60 if is_morning else 64
    follow_min = 0.8 if is_morning_open else 1.2 if is_morning else 1.6
    max_sections = 4 if is_morning_open or is_morning else 3
    return {
        "leader_min": leader_min,
        "score_min": score_min,
        "follow_min": follow_min,
        "max_sections": max_sections,
        "is_morning_open": is_morning_open,
        "is_morning": is_morning,
    }
def _read_market_leader_state() -> dict:
    state = _read_json_safe(MARKET_LEADER_STATE_FILE, {})
    return state if isinstance(state, dict) else {}
def _save_market_leader_state(state: dict):
    try:
        _write_json_atomic(MARKET_LEADER_STATE_FILE, state if isinstance(state, dict) else {}, indent=2)
    except Exception as e:
        _log_warn_msg(f"⚠️ 시장 주도 섹터 상태 저장 실패: {e}")
def _collect_market_leader_seed_stocks(market_open: bool | None = None, nxt_open: bool | None = None) -> list:
    market_open = is_market_open() if market_open is None else bool(market_open)
    nxt_open = is_nxt_open() if nxt_open is None else bool(nxt_open)
    seeds = []
    try:
        if market_open:
            seeds.extend(get_upper_limit_stocks()[:8])
            seeds.extend(get_volume_surge_stocks()[:16])
        if nxt_open:
            seeds.extend(get_nxt_surge_stocks()[:10])
        for item in list(_dynamic_candidates or [])[:24]:
            if isinstance(item, dict):
                seeds.append(item)
        try:
            for item in list(get_all_scan_candidates() or [])[:24]:
                if isinstance(item, dict):
                    seeds.append(item)
        except Exception as e:
            _swallow_exception(e)
    except Exception as e:
        _log_warn_msg(f"⚠️ 시장 주도 섹터 seed 수집 오류: {e}")
    seen = set()
    merged = []
    for item in seeds:
        if not isinstance(item, dict):
            continue
        code = str(item.get("code", "") or "").strip()
        if not code or code in seen:
            continue
        seen.add(code)
        merged.append(item)
    return merged
def _get_market_leader_live_quote(code: str, name: str = "", market_open: bool | None = None, nxt_open: bool | None = None) -> dict:
    market_open = is_market_open() if market_open is None else bool(market_open)
    nxt_open = is_nxt_open() if nxt_open is None else bool(nxt_open)
    market = ""
    try:
        if nxt_open and not market_open and is_nxt_listed(code):
            market = "NXT"
    except Exception as e:
        _swallow_exception(e)  # v105 structured silent-exception log
        market = ""
    q = _get_live_quote_for_signal({"code": code, "name": name, "market": market})
    if not q:
        return {}
    q = dict(q)
    q["market"] = market or str(q.get("market", "") or "")
    return q
def _collect_actionable_market_leader_quotes(quotes: list) -> tuple[list, dict]:
    actionable = []
    shadow_codes = []
    for q in list(quotes or []):
        code = normalize_stock_code((q or {}).get("code"))
        if not code:
            continue
        if _has_recent_actionable_tracking_state(code):
            actionable.append(dict(q))
        else:
            shadow_codes.append(code)
    meta = {
        "actionable_count": len(actionable),
        "missing_codes": shadow_codes[:6],
    }
    return actionable, meta
def _calc_market_leader_sector_score(quotes: list, leader: dict, follow_min: float, market_chg: float) -> tuple[float, int, float, float]:
    risers = [q for q in quotes if safe_float(q.get("change_rate", 0)) >= follow_min]
    breadth_ratio = len(risers) / max(1, len(quotes))
    breadth_score = 35.0 * breadth_ratio
    leader_score = min(25.0, max(0.0, safe_float(leader.get("change_rate", 0))))
    follow_rates = [safe_float(q.get("change_rate", 0)) for q in risers if str(q.get("code", "")) != str(leader.get("code", ""))]
    follow_avg = sum(follow_rates) / len(follow_rates) if follow_rates else 0.0
    follow_score = min(20.0, max(0.0, follow_avg * 2.5))
    flow_avg = sum(max(0.0, safe_float(q.get("volume_ratio", 0))) for q in quotes) / max(1, len(quotes))
    flow_score = min(10.0, max(0.0, flow_avg * 2.0))
    avg_change = sum(safe_float(q.get("change_rate", 0)) for q in risers) / max(1, len(risers)) if risers else 0.0
    relative_score = min(10.0, max(0.0, (avg_change - market_chg) * 2.0))
    total = breadth_score + leader_score + follow_score + flow_score + relative_score
    return round(total, 1), len(risers), round(avg_change, 1), round(flow_avg, 1)
def _build_market_leader_candidate_themes(seeds: list) -> tuple[dict, int, int, bool]:
    candidate_themes = {}
    strong_seed_cnt = 0
    upper_seed_cnt = 0
    for item in seeds[:24]:
        code = str(item.get("code", "") or "").strip()
        if not code:
            continue
        chg = safe_float(item.get("change_rate", 0))
        vr = safe_float(item.get("volume_ratio", 0))
        if chg >= 8.0 and vr >= 5.0:
            strong_seed_cnt += 1
        if chg >= 29.0:
            upper_seed_cnt += 1
        theme_name, peers, _ = get_theme_sector_stocks(code)
        if not theme_name or theme_name == "기타업종":
            continue
        bucket = candidate_themes.setdefault(theme_name, {"members": {}, "seed_codes": set()})
        name = _resolve_stock_name(code, item.get("name", ""))
        if is_trade_candidate_name(name):
            bucket["members"][code] = name
            bucket["seed_codes"].add(code)
        for peer_code, peer_name in peers[:5]:
            if peer_code == code:
                continue
            bucket["members"].setdefault(peer_code, peer_name)
    event_mode = upper_seed_cnt >= 1 or strong_seed_cnt >= 2
    return candidate_themes, strong_seed_cnt, upper_seed_cnt, event_mode
def _collect_market_leader_theme_quotes(bucket: dict, quote_market_basis: str, market_open: bool, nxt_open: bool, quote_cache: dict) -> list[dict]:
    members = list(bucket.get("members", {}).items())[:6]
    quotes = []
    for code, name in members:
        cache_key = (str(code), quote_market_basis)
        quote = quote_cache.get(cache_key)
        if quote is None:
            quote = _get_market_leader_live_quote(code, name, market_open=market_open, nxt_open=nxt_open)
            quote_cache[cache_key] = dict(quote) if isinstance(quote, dict) else {}
        else:
            quote = dict(quote) if isinstance(quote, dict) else {}
        if not quote or not quote.get("price"):
            continue
        nm = _resolve_stock_name(code, name, quote)
        if not is_trade_candidate_name(nm):
            continue
        quotes.append({
            "code": code,
            "name": nm,
            "change_rate": safe_float(quote.get("change_rate", 0)),
            "volume_ratio": safe_float(quote.get("volume_ratio", 0)),
            "market": quote.get("market", ""),
        })
        time.sleep(0.05)
    return quotes
def _maybe_build_market_leader_sector(theme_name: str, bucket: dict, market_chg: float, follow_min: float, leader_min: float, score_min: float, market_open: bool, nxt_open: bool, quote_market_basis: str, quote_cache: dict) -> dict:
    quotes = _collect_market_leader_theme_quotes(bucket, quote_market_basis, market_open, nxt_open, quote_cache)
    if len(quotes) < 2:
        return {}
    quotes.sort(key=lambda x: (safe_float(x.get("change_rate", 0)), safe_float(x.get("volume_ratio", 0))), reverse=True)
    leader = quotes[0]
    score, riser_cnt, avg_change, flow_avg = _calc_market_leader_sector_score(quotes, leader, follow_min, market_chg)
    followers = [q for q in quotes if q["code"] != leader["code"] and safe_float(q.get("change_rate", 0)) >= follow_min][:4]
    if safe_float(leader.get("change_rate", 0)) < leader_min or riser_cnt < 2 or not followers or score < score_min:
        return {}
    actionable_quotes, actionable_meta = _collect_actionable_market_leader_quotes([leader] + followers)
    if not actionable_quotes:
        _record_shadow_capture(
            leader.get("code", ""), leader.get("name", leader.get("code", "")),
            "sector_actionable_missing", "MARKET_LEADER", stage="market_leader_sector",
            extra={
                "theme": theme_name,
                "score": int(round(score)),
                "leader_change_rate": leader.get("change_rate", 0),
                "missing_codes": actionable_meta.get("missing_codes", []),
            },
        )
        return {}
    actionable_quotes.sort(key=lambda x: (safe_float(x.get("change_rate", 0)), safe_float(x.get("volume_ratio", 0))), reverse=True)
    display_leader = actionable_quotes[0]
    display_followers = [q for q in actionable_quotes[1:] if safe_float(q.get("change_rate", 0)) >= follow_min][:4]
    return {
        "theme": theme_name,
        "score": int(round(score)),
        "leader": display_leader,
        "followers": display_followers,
        "riser_cnt": riser_cnt,
        "member_cnt": len(quotes),
        "avg_change": avg_change,
        "flow_avg": flow_avg,
        "actionable_count": actionable_meta.get("actionable_count", 0),
        "actionable_missing_codes": actionable_meta.get("missing_codes", []),
    }
def _render_market_leading_sector_payload(top: list, now_dt, market_heat: int, interval_min: int, event_mode: bool, profile: dict) -> tuple[str, str]:
    title_icon = "🔥" if max(s.get("score", 0) for s in top) >= 75 else "📈"
    mode_line = "🟡 NXT (넥스트레이드) 주도" if is_nxt_open() and not is_market_open() else "🟡 오전 반응형" if profile["is_morning_open"] or profile["is_morning"] else "🔴 장중 주도"
    lines = [
        f"{title_icon} <b>[시장 주도 섹터]</b>",
        f"🕐 {now_dt.strftime('%Y-%m-%d %H:%M:%S')}  |  {mode_line}",
        "━━━━━━━━━━━━━━━",
    ]
    digest_parts = []
    for sec in top:
        leader = sec["leader"]
        linked = int(sec.get("actionable_count", 0) or 0)
        lines.append(f"🏭 <b>{sec['theme']}</b>  <b>{sec['score']}점</b>" + (f"  🔗종목연동 {linked}건" if linked > 0 else ""))
        lines.append(f"👑 {leader['name']} {leader['change_rate']:+.1f}%")
        followers = "  ".join(f"{q['name']} {q['change_rate']:+.1f}%" for q in sec.get("followers", [])[:4])
        if followers:
            lines.append(f"📈 {followers}")
        lines.append("")
        digest_parts.append(sec["theme"])
        digest_parts.append(leader['code'])  # v161.39: 등락률 제외 → 섹터 구성 변화 시에만 재발송
        digest_parts.extend(q['code'] for q in sec.get("followers", [])[:4])
    lines.append("━━━━━━━━━━━━━━━")
    lines.append(f"💥 시장 활력 {market_heat}점  |  다음 재평가 {interval_min}분")
    return "\n".join(lines).strip(), hashlib.sha256("|".join(digest_parts).encode("utf-8")).hexdigest()
def _build_market_leading_sector_payload(force: bool = False) -> dict:
    market_open = is_market_open()
    nxt_open = is_nxt_open()
    if not (market_open or nxt_open):
        return {}
    now_dt = _now_kst()
    profile = _market_leader_profile(now_dt)
    seeds = _collect_market_leader_seed_stocks(market_open=market_open, nxt_open=nxt_open)
    if not seeds:
        _log_info_msg("ℹ️ 시장 주도 섹터 생략 — seed 0건")
        return {}
    market_chg = get_kospi_change()
    candidate_themes, strong_seed_cnt, upper_seed_cnt, event_mode = _build_market_leader_candidate_themes(seeds)
    if not candidate_themes:
        _log_info_msg("ℹ️ 시장 주도 섹터 생략 — 유효 테마 0개")
        return {}
    leader_min = max(3.8, profile["leader_min"] - (1.0 if event_mode else 0.0))
    score_min = max(52, profile["score_min"] - (5 if event_mode else 0))
    follow_min = max(1.0, profile["follow_min"] - (0.3 if event_mode else 0.0))
    sectors = []
    quote_cache: dict[tuple[str, str], dict] = {}
    quote_market_basis = "NXT" if nxt_open and not market_open else "KRX"
    for theme_name, bucket in list(candidate_themes.items())[:10]:
        sector = _maybe_build_market_leader_sector(theme_name, bucket, market_chg, follow_min, leader_min, score_min, market_open, nxt_open, quote_market_basis, quote_cache)
        if sector:
            sectors.append(sector)
    if not sectors:
        return {}
    sectors.sort(key=lambda s: (s.get("score", 0), safe_float(s.get("leader", {}).get("change_rate", 0))), reverse=True)
    top = sectors[:profile["max_sections"]]
    market_heat = min(100, int(len(sectors) * 12 + strong_seed_cnt * 10 + upper_seed_cnt * 15 + max(s.get("score", 0) for s in top) * 0.2))
    interval_min = 10 if market_heat >= 70 or event_mode else 15 if market_heat >= 45 else 20
    msg, digest = _render_market_leading_sector_payload(top, now_dt, market_heat, interval_min, event_mode, profile)
    return {
        "msg": msg,
        "digest": digest,
        "interval_min": interval_min,
        "market_heat": market_heat,
        "event_mode": event_mode,
        "sectors": top,
        "ts": now_dt.strftime("%Y-%m-%d %H:%M:%S"),
    }
def send_market_leading_sector_update(force: bool = False):
    if is_holiday() or not is_any_market_open():
        return
    try:
        payload = _build_market_leading_sector_payload(force=force)
        if not payload:
            _log_info_msg("ℹ️ 시장 주도 섹터 생략 — 조건 충족 섹터 없음")
            return
        now_ts = time.time()
        state = _read_market_leader_state()
        last_ts = float(state.get("last_ts", 0) or 0)
        last_digest = str(state.get("last_digest", "") or "")
        interval_sec = int(max(600, safe_float(payload.get("interval_min", 15)) * 60))
        if not force and last_ts and now_ts - last_ts < interval_sec:
            _log_info_msg(f"ℹ️ 시장 주도 섹터 생략 — 최근 발송 {int(now_ts-last_ts)}초 전")
            return
        if not force and last_digest == payload.get("digest") and last_ts and now_ts - last_ts < max(interval_sec, 1800):
            _log_info_msg("ℹ️ 시장 주도 섹터 생략 — 구성 변화 없음")
            return
        send(payload.get("msg", ""))
        _save_market_leader_state({
            "last_ts": now_ts,
            "last_digest": payload.get("digest", ""),
            "interval_min": payload.get("interval_min", 15),
            "market_heat": payload.get("market_heat", 0),
            "sent_at": payload.get("ts", ""),
            "themes": [sec.get("theme", "") for sec in payload.get("sectors", [])],
            "sectors": payload.get("sectors", []),  # v161.44: 선진입 풀 직결용
        })
        _log_info_msg(f"✅ 시장 주도 섹터 발송 완료 ({len(payload.get('sectors', []))}개 섹터, heat={payload.get('market_heat', 0)})")
    except Exception as e:
        _log_error("send_market_leading_sector_update", e)
def _detect_and_send_sector_breadth_alert() -> None:
    """v165.40 [B]: 섹터 breadth 특보 — 동일 섹터 N개 이상 급등 시 섹터 특보 알람 발송.
    개별 알람이 섹터 제한에 걸려도 섹터 전체 상승 자체를 사용자에게 알려줌.
    금속 섹터 14종목 동시 상승 같은 경우 개별 포착이 어려워도 섹터 브레이크아웃 인지 가능.
    쿨다운: 섹터당 30분 (같은 섹터 반복 발송 방지)
    발동 조건: 동일 섹터 종목 3개 이상이 change_rate >= 8% 동시 달성
    """
    if not is_market_open():
        return
    global _sector_breadth_alert_cache
    now = time.time()
    try:
        # 네이버 rise에서 상위 종목 수집
        rising = _fetch_naver_rank("rise", top_n=80)
        if not rising:
            return
        # 섹터별 급등 종목 집계
        sector_rising: dict[str, list] = {}
        for r in rising:
            code = normalize_stock_code(r.get("code", "") or "")
            name = str(r.get("name", code) or code)
            cr = float(r.get("change_rate", 0) or 0)
            if cr < 8.0:
                continue
            try:
                theme, _, _ = get_theme_sector_stocks(code)
            except Exception:
                theme = ""
            sec = str(theme or "").strip()
            if not sec or sec in ("기타업종", "기타", ""):
                continue
            sector_rising.setdefault(sec, []).append({"code": code, "name": name, "change_rate": cr})
        # 조건: 3개 이상 동시 급등 섹터 감지
        BREADTH_MIN = 3
        BREADTH_MIN_RATE = 8.0
        for sec, stocks in sector_rising.items():
            if len(stocks) < BREADTH_MIN:
                continue
            # 쿨다운 체크 (섹터당 30분)
            last_sent = (_sector_breadth_alert_cache or {}).get(sec, 0)
            if now - last_sent < 1800:
                continue
            # 특보 메시지 작성
            avg_rate = sum(s["change_rate"] for s in stocks) / len(stocks)
            top_stocks = sorted(stocks, key=lambda x: x["change_rate"], reverse=True)[:6]
            stock_lines = "\n".join(
                f"  • {s['name']} <b>{s['change_rate']:+.1f}%</b>"
                for s in top_stocks
            )
            msg = (
                f"📢 <b>[섹터 브레이크아웃]</b> {sec}\n"
                f"━━━━━━━━━━━━━━━\n"
                f"📊 동시 급등: <b>{len(stocks)}종목</b> (평균 {avg_rate:+.1f}%)\n"
                f"\n"
                f"{stock_lines}\n"
                f"\n"
                f"⚠️ 섹터 전체 상승 중 — 개별 알람 외 섹터 흐름 직접 확인 권장"
            )
            send(msg)
            if _sector_breadth_alert_cache is None:
                _sector_breadth_alert_cache = {}
            _sector_breadth_alert_cache[sec] = now
            _log_info_msg(f"  📢 섹터 브레이크아웃 특보: {sec} {len(stocks)}종목 avg={avg_rate:+.1f}%")
    except Exception as e:
        _swallow_exception(e)

