def _fetch_kis_overseas_price(symbol: str, excd: str = "NAS") -> float | None:
    """v162.1: KIS HHDFS00000300 TR로 해외주식 현재가 조회.
    symbol: 종목코드 (예: NVDA, TSM, QQQ)
    excd: 거래소코드 (NAS=나스닥, NYS=NYSE, TSE=도쿄, SHS=상해)
    반환: 현재가(float) 또는 None(실패 시)
    """
    try:
        url = f"{KIS_BASE_URL}/uapi/overseas-price/v1/quotations/price"
        params = {
            "AUTH": "",
            "EXCD": excd,
            "SYMB": symbol,
        }
        data = _safe_get(url, "HHDFS00000300", params)
        if not isinstance(data, dict):
            return None
        output = data.get("output") or {}
        last_str = str(output.get("last", "") or "")
        if last_str:
            return float(last_str)
        return None
    except Exception as e:
        _warn_throttled_once(
            f"kis_overseas:{symbol}",
            f"🌐 KIS 해외주식 {symbol} 조회 실패 ({type(e).__name__})",
            cooldown_sec=1800.0,
        )
        return None


def _fetch_stooq_quote(stooq_sym: str) -> float | None:
    """v166.0: Stooq에서 단순 현재가 조회 (Yahoo 실패 시 fallback).
    Stooq는 crumb 없이 CSV 조회 가능. 15분 지연 가능.
    stooq_sym 예시: ^ndq (나스닥), ^spx (S&P500), gc.f (금선물), cl.f (WTI선물)
    """
    try:
        url = f"https://stooq.com/q/l/?s={stooq_sym}&f=sd2t2ohlcv&h&e=csv"
        resp = requests.get(url, timeout=6, headers={"User-Agent": random.choice(_UA_POOL)})
        if resp.status_code != 200:
            return None
        lines = resp.text.strip().split("\n")
        if len(lines) < 2:
            return None
        parts = lines[1].split(",")
        # CSV 컬럼: Symbol,Date,Time,Open,High,Low,Close,Volume
        if len(parts) >= 7:
            close_str = parts[6].strip()
            val = float(close_str)
            return val if val > 0 else None
    except Exception as e:
        _swallow_exception(e)
    return None


def _fetch_btc_coingecko() -> float | None:
    """v166.0: CoinGecko 무료 API로 BTC/USD 현재가 조회.
    분당 30회 제한. 봇 1시간 캐시이므로 충분히 여유 있음.
    """
    try:
        url = "https://api.coingecko.com/api/v3/simple/price?ids=bitcoin&vs_currencies=usd"
        resp = requests.get(url, timeout=6, headers={"User-Agent": random.choice(_UA_POOL)})
        if resp.status_code != 200:
            return None
        data = resp.json()
        price = data.get("bitcoin", {}).get("usd")
        return float(price) if price else None
    except Exception as e:
        _swallow_exception(e)
    return None


def _fetch_yahoo_finance_crumb() -> tuple[str, dict]:
    """v165.36: Yahoo Finance crumb 취득 — 세션 쿠키 기반.
    Yahoo Finance 2024+는 crumb 없이 v8 chart API 호출 시 HTML 반환(비JSON).
    """
    try:
        s = requests.Session()
        s.headers.update({
            "User-Agent": random.choice(_UA_POOL),
            "Accept": "text/html,application/xhtml+xml,application/xml;q=0.9,*/*;q=0.8",
            "Accept-Language": "en-US,en;q=0.9",
        })
        s.get("https://finance.yahoo.com/", timeout=8, allow_redirects=True)
        resp = s.get("https://query2.finance.yahoo.com/v1/test/getcrumb", timeout=8)
        crumb = (resp.text or "").strip()
        if crumb and len(crumb) < 50 and "<" not in crumb and " " not in crumb:
            return crumb, dict(s.cookies)
    except Exception as e:
        _swallow_exception(e)
    return "", {}

def _get_yf_crumb() -> tuple[str, dict]:
    """v165.36: crumb 캐시 반환 (TTL 6시간). 실패 시 빈 값 허용."""
    global _yf_crumb_cache
    if time.time() - float(_yf_crumb_cache.get("ts", 0) or 0) < 21600 and _yf_crumb_cache.get("crumb"):
        return _yf_crumb_cache["crumb"], _yf_crumb_cache.get("cookies", {})
    crumb, cookies = _fetch_yahoo_finance_crumb()
    if crumb:
        _yf_crumb_cache.update({"crumb": crumb, "cookies": cookies, "ts": time.time()})
    return crumb, cookies

def _fetch_us_market_signal_values(symbols: dict) -> dict:
    values = {}
    crumb, cookies = _get_yf_crumb()
    for sym, key in symbols.items():
        fetched = False
        # v165.36: query1 → query2 fallback, crumb 파라미터 추가, 재시도 1회
        base_urls = [
            f"https://query1.finance.yahoo.com/v8/finance/chart/{sym}?interval=1d&range=2d",
            f"https://query2.finance.yahoo.com/v8/finance/chart/{sym}?interval=1d&range=2d",
        ]
        if crumb:
            base_urls = [u + f"&crumb={crumb}" for u in base_urls]
        _headers = {
            "User-Agent": random.choice(_UA_POOL),
            "Accept": "application/json",
            "Accept-Language": "en-US,en;q=0.9",
            "Referer": "https://finance.yahoo.com/",
            "Origin": "https://finance.yahoo.com",
        }
        for attempt_url in base_urls:
            try:
                resp = requests.get(attempt_url, timeout=8, headers=_headers,
                                    cookies=cookies if cookies else None)
                data = safe_json_response(resp)
                chart = data.get("chart", {}) if isinstance(data, dict) else {}
                results = chart.get("result") or []
                if not results:
                    continue  # 다음 URL 시도
                result0 = results[0] if isinstance(results[0], dict) else {}
                meta = result0.get("meta", {}) if isinstance(result0, dict) else {}
                indicators = result0.get("indicators", {}) if isinstance(result0, dict) else {}
                quotes = indicators.get("quote") if isinstance(indicators, dict) else []
                quote0 = quotes[0] if isinstance(quotes, list) and quotes else {}
                prev = quote0.get("close") if isinstance(quote0, dict) else []
                prev_close = [c for c in (prev or []) if c is not None]
                cur_price = meta.get("regularMarketPrice", 0)
                if key == "vix":
                    values["vix"] = round(float(cur_price), 1)
                elif key == "dxy":
                    values["dxy"] = round(float(cur_price), 2)
                elif key == "tnx":
                    values["tnx"] = round(float(cur_price), 3)
                elif key == "krw":
                    values["krw_usd"] = round(float(cur_price), 1)
                    if prev_close and cur_price:
                        values["krw_usd_chg"] = round((float(cur_price) - prev_close[-1]) / prev_close[-1] * 100, 2)
                elif prev_close and cur_price:
                    values[f"{key}_chg"] = round((float(cur_price) - prev_close[-1]) / prev_close[-1] * 100, 2)
                fetched = True
                break  # 성공 → 다음 심볼로
            except Exception as e:
                _swallow_exception(e)
        # v166.0: Yahoo 완전 실패 시 Stooq fallback (주요 지수/선물만)
        if not fetched:
            _stooq_map = {
                "NQ=F": ("^ndq", "nasdaq"),
                "ES=F": ("^spx", "sp500"),
                "GC=F": ("gc.f", "gold"),
                "CL=F": ("cl.f", "oil"),
            }
            if sym in _stooq_map:
                stooq_sym, stooq_key = _stooq_map[sym]
                stooq_price = _fetch_stooq_quote(stooq_sym)
                if stooq_price and stooq_price > 0:
                    # Stooq는 전일 종가 대비 변화율을 별도 제공 안 함 → 이전 캐시값 활용
                    prev_cached = _us_cache.get(f"{stooq_key}_prev_close", 0.0)
                    if prev_cached and prev_cached > 0:
                        values[f"{stooq_key}_chg"] = round(
                            (stooq_price - prev_cached) / prev_cached * 100, 2
                        )
                    values[f"{stooq_key}_prev_close"] = stooq_price
                    fetched = True
            if not fetched:
                _warn_throttled_once("us_market_invalid_json",
                                     "🌐 미국시장 응답 비정상/비JSON → flat fallback 유지",
                                     cooldown_sec=1800.0)
        time.sleep(0.2)
    return values
def _evaluate_us_market_signal_result(values: dict) -> dict:
    nasdaq_chg = values.get("nasdaq_chg", 0.0)
    vix = values.get("vix", 20.0)
    dxy = values.get("dxy", 104.0)
    score_adj = 0
    if vix >= 35 or nasdaq_chg <= -COMMON_THRESHOLD_3P0:
        us_regime = "panic"; score_adj = -15; gap_signal = "gap_down"
    elif vix >= 25 or nasdaq_chg <= -1.5:
        us_regime = "risk_off"; score_adj = -8; gap_signal = "gap_down" if nasdaq_chg <= -2.0 else "flat"
    elif vix <= 15 and nasdaq_chg >= 1.0:
        us_regime = "risk_on"; score_adj = +8; gap_signal = "gap_up"
    elif nasdaq_chg >= 0.5:
        us_regime = "risk_on"; score_adj = +4; gap_signal = "flat"
    else:
        us_regime = "neutral"; gap_signal = "flat"
    krw_usd = values.get("krw_usd", 0.0)
    krw_usd_chg = values.get("krw_usd_chg", 0.0)
    gold_chg = values.get("gold_chg", 0.0)
    oil_chg = values.get("oil_chg", 0.0)
    tnx = values.get("tnx", 0.0)
    if dxy >= 107:
        score_adj -= 5
    if krw_usd >= 1400:
        score_adj -= 5
    elif krw_usd_chg >= 0.8:
        score_adj -= 3
    elif krw_usd_chg <= -0.8:
        score_adj += 2
    if gold_chg >= 2.0:
        score_adj -= 3
    if oil_chg >= 4.0:
        score_adj -= 2
    elif oil_chg <= -4.0:
        score_adj += 1
    if tnx >= 5.0:
        score_adj -= 3
    elif tnx >= 4.5:
        score_adj -= 1
    # v162.2: SOX 반도체지수 score_adj 반영
    sox_chg = values.get("sox_chg", 0.0)
    nvda_chg = values.get("nvda_chg", 0.0)
    tsm_chg  = values.get("tsm_chg",  0.0)
    nikkei_chg   = values.get("nikkei_chg",   0.0)
    shanghai_chg = values.get("shanghai_chg", 0.0)
    if sox_chg >= 2.5:
        score_adj += 4   # SOX 급등 → 반도체 섹터 강세 가중
    elif sox_chg >= 1.2:
        score_adj += 2
    elif sox_chg <= -2.5:
        score_adj -= 4   # SOX 급락 → 반도체 섹터 약세 차감
    elif sox_chg <= -1.2:
        score_adj -= 2
    # v166.0: 신규 symbols 값 추출
    soxl_chg  = values.get("soxl_chg",  0.0)
    tsla_chg  = values.get("tsla_chg",  0.0)
    googl_chg = values.get("googl_chg", 0.0)
    mu_chg    = values.get("mu_chg",    0.0)
    avgo_chg  = values.get("avgo_chg",  0.0)
    sndk_chg  = values.get("sndk_chg",  0.0)
    oklo_chg  = values.get("oklo_chg",  0.0)
    smr_chg   = values.get("smr_nuc_chg", 0.0)  # SMR은 smr_nuc key
    btc_chg   = values.get("btc_chg",   0.0)
    # SOXL(3x 반도체 ETF) 급등 → 반도체 섹터 추가 가중 (SOX와 중복 시 경감)
    if soxl_chg >= 5.0:
        score_adj += 3
    elif soxl_chg >= 2.5:
        score_adj += 1
    elif soxl_chg <= -5.0:
        score_adj -= 3
    elif soxl_chg <= -2.5:
        score_adj -= 1
    # BTC 급등 → 글로벌 위험선호 +1 (미약하지만 보조 지표)
    if btc_chg >= 5.0:
        score_adj += 1
    elif btc_chg <= -8.0:
        score_adj -= 1
    return {
        "nasdaq_chg": nasdaq_chg,
        "vix": vix,
        "dxy": dxy,
        "us_regime": us_regime,
        "gap_signal": gap_signal,
        "score_adj": score_adj,
        "sp500_chg": values.get("sp500_chg", 0.0),
        "gold_chg": gold_chg,
        "oil_chg": oil_chg,
        "tnx": tnx,
        "krw_usd": krw_usd,
        "krw_usd_chg": krw_usd_chg,
        "sox_chg": sox_chg,
        "nvda_chg": nvda_chg,
        "tsm_chg": tsm_chg,
        "nikkei_chg": nikkei_chg,
        "shanghai_chg": shanghai_chg,
        # v166.0 신규
        "soxl_chg": soxl_chg,
        "tsla_chg": tsla_chg,
        "googl_chg": googl_chg,
        "mu_chg": mu_chg,
        "avgo_chg": avgo_chg,
        "sndk_chg": sndk_chg,
        "oklo_chg": oklo_chg,
        "smr_chg": smr_chg,
        "btc_chg": btc_chg,
    }
def _compose_us_market_signal_summary(result: dict) -> str:
    regime_emoji = {"panic": "🔵", "risk_off": "🟡", "neutral": "🟡", "risk_on": "🔴"}
    gap_emoji = {"gap_up": "⬆️", "flat": "➡️", "gap_down": "⬇️"}
    extra_parts = []
    if result.get("sox_chg"):
        extra_parts.append(f"SOX{result['sox_chg']:+.1f}%")
    if result.get("soxl_chg"):   # v166.0
        extra_parts.append(f"SOXL{result['soxl_chg']:+.1f}%")
    if result.get("nvda_chg"):
        extra_parts.append(f"NVDA{result['nvda_chg']:+.1f}%")
    if result.get("tsla_chg"):   # v166.0
        extra_parts.append(f"TSLA{result['tsla_chg']:+.1f}%")
    if result.get("nikkei_chg"):
        extra_parts.append(f"닛케이{result['nikkei_chg']:+.1f}%")
    if result.get("krw_usd"):
        extra_parts.append(f"원/달러{result['krw_usd']:.0f}원({result.get('krw_usd_chg', 0):+.1f}%)")
    if result.get("gold_chg"):
        extra_parts.append(f"금{result['gold_chg']:+.1f}%")
    if result.get("oil_chg"):
        extra_parts.append(f"유가{result['oil_chg']:+.1f}%")
    if result.get("tnx"):
        extra_parts.append(f"10Y{result['tnx']:.2f}%")
    if result.get("sp500_chg"):
        extra_parts.append(f"S&P{result['sp500_chg']:+.1f}%")
    if result.get("btc_chg"):    # v166.0
        extra_parts.append(f"BTC{result['btc_chg']:+.1f}%")
    summary = (
        f"{regime_emoji.get(result.get('us_regime'), '🟡')} 나스닥선물 {result.get('nasdaq_chg', 0):+.1f}%  "
        f"VIX {result.get('vix', 20):.0f}  DXY {result.get('dxy', 104):.1f}  "
        f"갭예측 {gap_emoji.get(result.get('gap_signal'), '➡️')} {result.get('gap_signal', 'flat')}"
    )
    if extra_parts:
        summary += f"\n  📊 {'  '.join(extra_parts)}"
    return summary
def get_us_market_signals() -> dict:
    """
    나스닥 선물(NQ=F), VIX(^VIX), 달러인덱스(DX-Y.NYB) 조회.
    Yahoo Finance JSON API 사용 (무료, pip 설치 불필요).
    v162.1: SOX(^SOX)·NVDA·TSM·닛케이(^N225)·상하이(000001.SS) 추가.
            NVDA·TSM은 KIS HHDFS00000300 TR 우선, 실패 시 Yahoo 보조.
    v166.0: SOXL/TSLA/GOOGL/MU/AVGO/SNDK/OKLO/SMR 추가 (사진 종목 반영).
            BTC는 CoinGecko fallback. cache TTL 1800초로 단축.
    """
    if time.time() - _us_cache.get("ts", 0) < 1800:   # v166.0: 3600→1800 (빠른 재시도)
        return _us_cache
    result = _build_us_market_signal_default()
    try:
        symbols = {
            "NQ=F": "nasdaq", "^VIX": "vix", "DX-Y.NYB": "dxy",
            "ES=F": "sp500", "GC=F": "gold", "CL=F": "oil",
            "^TNX": "tnx", "KRW=X": "krw",
            "^SOX": "sox", "NVDA": "nvda", "TSM": "tsm",
            "^N225": "nikkei", "000001.SS": "shanghai",
            # v166.0: 신규 symbols (사진 종목 반영)
            "SOXL": "soxl",    # Direxion 3x Semi ETF
            "TSLA": "tsla",    # Tesla
            "GOOGL": "googl",  # Alphabet
            "MU": "mu",        # Micron
            "AVGO": "avgo",    # Broadcom
            "SNDK": "sndk",    # SanDisk (WDC 스핀오프)
            "OKLO": "oklo",    # 소형 핵분열로
            "SMR": "smr_nuc",  # NuScale Power (원전 테마 SMR과 key 충돌 회피)
            # v169.0: 국내 섹터 선행지표 US 종목 (NXT 선진입 개별 종목 가점용)
            "BE":   "be",      # Bloom Energy — 연료전지/수소
            "PLUG": "plug",    # Plug Power — 연료전지
            "FCEL": "fcel",    # FuelCell Energy
            "CEG":  "ceg",     # Constellation Energy — 원전/청정에너지
            "ETN":  "etn_pw",  # Eaton Corp — 전력기기 (key충돌 회피: etn)
            "LMT":  "lmt",     # Lockheed Martin — 방산
            "ALB":  "alb",     # Albemarle — 리튬/2차전지
        }
        values = _fetch_us_market_signal_values(symbols)
        # v162.1: NVDA·TSM KIS 우선 조회 (Yahoo 실패 시 보완)
        for sym, key, excd in [("NVDA", "nvda", "NAS"), ("TSM", "tsm", "NAS")]:
            if not values.get(f"{key}_chg"):
                kis_price = _fetch_kis_overseas_price(sym, excd)
                if kis_price and kis_price > 0:
                    values[f"{key}_last"] = kis_price
        # v167.0: KIS 해외선물 현재가 → Yahoo 실패 시 NQ/ES/GC/CL 보완
        # 거래소 코드: NQ=CME 나스닥선물, ES=CME S&P500선물, GC=COMEX 금선물, CL=NYMEX WTI선물
        _kis_fut_map = [
            ("NQ", "CME", "nasdaq", "nasdaq_prev_close"),
            ("ES", "CME", "sp500",  "sp500_prev_close"),
            ("GC", "COMEX", "gold", "gold_prev_close"),
            ("CL", "NYMEX", "oil",  "oil_prev_close"),
        ]
        for _fsym, _excd, _key, _prev_key in _kis_fut_map:
            if values.get(f"{_key}_chg", 0.0) == 0.0:  # Yahoo 0.0% → KIS 시도
                _fp = _fetch_kis_futures_price(_fsym, _excd)
                if _fp and _fp > 0:
                    _prev = _us_cache.get(_prev_key, 0.0)
                    if _prev and _prev > 0:
                        values[f"{_key}_chg"] = round((_fp - _prev) / _prev * 100, 2)
                    _us_cache[_prev_key] = _fp
        # v166.0: BTC CoinGecko fallback
        if not values.get("btc_chg"):
            btc_price = _fetch_btc_coingecko()
            if btc_price and btc_price > 0:
                btc_prev = _us_cache.get("btc_prev_close", 0.0)
                if btc_prev and btc_prev > 0:
                    values["btc_chg"] = round((btc_price - btc_prev) / btc_prev * 100, 2)
                _us_cache["btc_prev_close"] = btc_price
        result.update(_evaluate_us_market_signal_result(values))
        result["ts"] = time.time()
        result["summary"] = _compose_us_market_signal_summary(result)
        result["macro_drivers"] = [item.get("event_name", "") for item in _build_macro_signal_scenarios(result)[:4]]
        MARKET_REGIME.update(compute_market_regime(result["nasdaq_chg"], result["vix"], result["dxy"]))
        _us_cache.update(result)
        _log_info_msg(f"  🌐 미국 시장: {result['summary']}")
    except Exception as e:
        _log_error("get_us_market_signals", e)
    return result
def calc_position_size(signal_type: str, score: int, grade: str) -> dict:
    """
    v41.66: 1종목 집중 + 분할진입 비중 계산.
    투자금 10만원 기준, 1종목 집중 전략.
    켈리 공식: f = (p*b - q) / b  (p=승률, q=1-p, b=손익비)
    반환: {"pct": float, "phase1_pct": int, "phase2_pct": int, "strength": str,
           "kelly": float, "guide": str, "win_rate": float|None, "samples": int}
    """
    try:
        # 과거 신호 유형별 승률 조회
        data = {}
        try:
            data = _read_json_locked(SIGNAL_LOG_FILE)
        except Exception as e:
            _swallow_exception(e)
        same_type = [v for v in data.values()
                     if v.get("signal_type") == signal_type
                     and v.get("status") in ["수익","손실","본전"]]
        if len(same_type) >= 5:
            wins  = sum(1 for v in same_type if v["pnl_pct"] > 0)
            p     = wins / len(same_type)
            avg_w = sum(v["pnl_pct"] for v in same_type if v["pnl_pct"] > 0) / max(wins, 1)
            avg_l = abs(sum(v["pnl_pct"] for v in same_type if v["pnl_pct"] < 0) / max(len(same_type)-wins, 1))
            b     = avg_w / avg_l if avg_l else 2.0
            if b <= 0:
                b = 2.0
            kelly = max(0, (p * b - (1-p)) / b)
            kelly = min(kelly * 0.5, 0.25)  # 하프 켈리, 1종목 집중이므로 최대 25%
        else:
            p     = 0.55  # 기본값
            kelly = 0.10
        # 등급별 보정 → 신호 강도 결정
        grade_upper = str(grade or "B").upper()
        if grade_upper == "A" and score >= 75:
            strength = "강한"
        elif grade_upper == "C" or score < 50:
            strength = "약한"
        else:
            strength = "보통"
        # 분할진입 비중 규칙
        split_rule = _get_entry_split_rule(strength)
        # 시장 국면 보정 (감축 전용, 1종목이므로 확대는 제한적)
        regime_info  = get_market_regime()
        regime       = regime_info.get("mode", "normal")
        nxt_only     = regime_info.get("nxt_only", False)
        regime_mult  = {"bull": 1.0, "normal": 1.0, "bear": 0.7, "crash": 0.4}.get(regime, 1.0)
        # v41.64: NXT 시간대별 포지션 비중 세분화
        if nxt_only:
            _nxt_p = get_nxt_params()
            if _nxt_p:
                regime_mult = max(regime_mult * _nxt_p.get("position_mult", 0.8), 0.3)
            else:
                regime_mult = max(regime_mult * 0.8, 0.3)
        # 1종목 집중 기본: 총 비중 = phase1 + phase2 (비상여유 제외)
        total_base = split_rule["phase1_pct"] + split_rule["phase2_pct"]
        final_pct = round(min(total_base * regime_mult, 100.0), 1)
        phase1_pct = int(split_rule["phase1_pct"] * regime_mult)
        phase2_pct = int(split_rule["phase2_pct"] * regime_mult) if split_rule["phase2_allowed"] else 0
        if regime in ("bear", "crash"):
            guide = f"⚠️ {regime_label()} — 비중 축소, 1종목 집중"
        elif strength == "강한" and p >= 0.6:
            guide = f"💪 고확률 신호 — 1종목 적극 진입"
        elif strength == "약한":
            guide = f"⚠️ 약한 신호 — 관찰 전용, 실진입 제외"
        else:
            guide = f"📊 표준 비중 — 1종목 분할 진입"
        return {
            "pct":       final_pct,
            "phase1_pct": phase1_pct,
            "phase2_pct": phase2_pct,
            "strength":  strength,
            "kelly":     round(kelly * 100, 1),
            "guide":     guide,
            "win_rate":  round(p * 100, 1) if len(same_type) >= 5 else None,
            "samples":   len(same_type),
        }
    except Exception as e:
        _swallow_exception(e)  # v105 structured silent-exception log
        return {"pct": 35.0, "phase1_pct": 35, "phase2_pct": 0, "strength": "보통",
                "kelly": 10.0, "guide": "📊 표준 비중", "win_rate": None, "samples": 0}
# ============================================================
# 📐 ③ 손익비 동적 최적화
# ============================================================
def calc_dynamic_stop_target(code: str, entry: int, signal_type: str | None = None) -> tuple:
    """
    시장 변동성 + 국면 + 신호유형에 따라 손절/목표가 배수 동적 조정.
    v41.61: 신호유형별 SIGNAL_STOP_PARAMS 적용 + 종목 ATR 변동성 구간 보정.
    반환: (stop, target, stop_pct, target_pct, atr_used)
    """
    atr = get_atr(code)
    if not atr:
        _rm   = get_atr_regime_mult()
        _stop_pct   = max(0.05, 0.07 * _rm)
        _target_pct = max(0.08, 0.15 / _rm)
        # v161.28: entry=0 방어 — entry가 0이면 stop/target 모두 0이 되므로 즉시 (0,0) 반환 방지
        if entry <= 0:
            return 0, 0, 7.0, 10.0, False
        stop   = int(entry * (1 - _stop_pct)   / 10) * 10
        target = int(entry * (1 + _target_pct) / 10) * 10
        # v161.28: atr=0 fallback에도 클램핑 적용 (v161.25는 atr>0 분기에만 있었음)
        min_stop   = int(entry * 0.93 / 10) * 10
        min_target = int(entry * 1.10 / 10) * 10
        if stop <= 0 or stop >= entry:
            stop = min_stop
        if target <= entry:
            target = min_target
        return stop, target, round(_stop_pct*100,1), round(_target_pct*100,1), False
    regime_info = get_market_regime()
    regime  = regime_info.get("mode", "normal")
    nxt_only = regime_info.get("nxt_only", False)
    # ── v41.61 #8: 신호유형별 기본 배수 선택 ──
    sig_params = SIGNAL_STOP_PARAMS.get(signal_type or "", {})
    stop_m  = _dynamic.get("atr_stop_mult",   sig_params.get("stop_mult", ATR_STOP_MULT))
    tgt_m   = _dynamic.get("atr_target_mult", sig_params.get("target_mult", ATR_TARGET_MULT))
    # signal_type이 명시된 경우 해당 유형 배수를 우선 적용
    if signal_type and signal_type in SIGNAL_STOP_PARAMS:
        stop_m = sig_params["stop_mult"]
        tgt_m  = sig_params["target_mult"]
    # ── v41.61 #8: 종목별 ATR 변동성 구간 보정 ──
    # 저변동(ATR<1.5%) → 손절 타이트, 목표 보수적
    # 고변동(ATR>4.0%) → 손절 여유, 목표 확대
    atr_pct = atr / entry * 100 if entry > 0 else 2.0
    if atr_pct < 1.5:
        stop_m  = max(stop_m * 0.85, 0.8)    # 저변동: 타이트
        tgt_m   = max(tgt_m * 0.85, 1.5)
    elif atr_pct > 4.0:
        stop_m  = min(stop_m * 1.25, 3.5)    # 고변동: 여유
        tgt_m   = min(tgt_m * 1.20, 6.0)
    # 시장 국면 보정
    if regime == "crash":
        stop_m  = max(stop_m  * 0.8, 1.0)
        tgt_m   = max(tgt_m   * 0.7, 2.0)
    elif regime == "bear":
        stop_m  = max(stop_m  * 0.9, 1.0)
        tgt_m   = max(tgt_m   * 0.8, 2.0)
    elif regime == "bull":
        tgt_m   = min(tgt_m   * 1.2, 5.0)
    # NXT 단독 시간대 보정: v41.64 시간대별 세분화
    if nxt_only:
        _nxt_p = get_nxt_params()
        if _nxt_p:
            stop_m  = max(stop_m  * _nxt_p.get("stop_mult", 1.0),   1.0)
            tgt_m   = max(tgt_m   * _nxt_p.get("target_mult", 1.0), 1.5)
        else:
            stop_m  = max(stop_m  * 0.85, 1.0)
            tgt_m   = max(tgt_m   * 0.80, 1.5)
    stop      = int((entry - atr * stop_m)  / 10) * 10
    target    = int((entry + atr * tgt_m)   / 10) * 10
    # v161.25: ATR 과대 시 음수/0 결과 방지 — entry 기반 고정비율 하한 보장
    min_stop   = int(entry * 0.93 / 10) * 10   # 최대 -7% 손절
    min_target = int(entry * 1.10 / 10) * 10   # 최소 +10% 목표
    if stop <= 0 or stop >= entry:
        stop = min_stop
    if target <= entry:
        target = min_target
    stop_pct  = round((entry - stop)   / entry * 100, 1) if entry > 0 else 7.0
    tgt_pct   = round((target - entry) / entry * 100, 1) if entry > 0 else 10.0
    return stop, target, stop_pct, tgt_pct, True
# ============================================================
# 📅 ④ 실적 발표 전후 필터
# ============================================================
_earnings_cache: dict = {}   # {code: {"date": "YYYYMMDD", "ts": float}}
def check_earnings_risk(code: str, name: str) -> dict:
    """
    DART에서 최근 실적 발표 일정 확인.
    발표 3일 전이면 경고, 당일/다음날이면 강경고.
    반환: {"risk": "none"/"warn"/"high", "desc": str}
    """
    if not DART_API_KEY:
        return {"risk": "none", "desc": ""}
    cached = _earnings_cache.get(code)
    if cached and time.time() - cached["ts"] < 3600:
        return cached["result"]
    try:
        today   = datetime.now()
        bgn_de  = today.strftime("%Y%m%d")
        end_de  = (today + timedelta(days=7)).strftime("%Y%m%d")
        url    = "https://opendart.fss.or.kr/api/list.json"
        params = {
            "crtfc_key": DART_API_KEY,
            "bgn_de":    bgn_de,
            "end_de":    end_de,
            "pblntf_ty": "A",           # 정기공시 (실적)
            "corp_name": name[:4],      # 종목명 앞 4글자로 검색
            "page_count": 10,
        }
        resp = _session.get(url, params=params, timeout=10)
        items = (safe_json_response(resp) or {}).get("list", []) if resp.status_code == 200 else []
        result = {"risk": "none", "desc": ""}
        for item in items:
            rpt_nm = item.get("report_nm", "")
            rcept_dt = item.get("rcept_dt", "")
            if any(kw in rpt_nm for kw in ["사업보고서","분기보고서","반기보고서"]):
                try:
                    rpt_date = datetime.strptime(rcept_dt, "%Y%m%d")
                    diff = (rpt_date - today).days
                    if diff <= 1:
                        result = {"risk": "high",
                                  "desc": f"⚠️ 실적발표 임박! ({rcept_dt}) — 변동성 주의"}
                    elif diff <= 3:
                        result = {"risk": "warn",
                                  "desc": f"📅 실적발표 {diff}일 전 ({rcept_dt}) — 관망 고려"}
                    break
                except Exception as e:
                    _swallow_exception(e)
        _earnings_cache[code] = {"result": result, "ts": time.time()}
        return result
    except Exception as e:
        _swallow_exception(e)  # v105 structured silent-exception log
        return {"risk": "none", "desc": ""}
# ============================================================
# 🗂️ ⑤ 동시 신호 포트폴리오 관리
# ============================================================
def _get_carry_position_context() -> tuple[int, set[str]]:
    # v66: _collect_actionable_position_limit_codes()가 빈 set을 반환하면
    #       "보유 0건"으로 즉시 반환. 이전 코드는 빈 set(falsy)일 때
    #       _detected_stocks fallback으로 빠져 stale 23~24개가 보유로 오카운트되어
    #       모든 신규 포착이 position_limit에 막히는 치명적 병목이었음.
    try:
        siglog_data = _read_json_safe(SIGNAL_LOG_FILE, {})
    except Exception as e:
        _swallow_exception(e)  # v105 structured silent-exception log
        siglog_data = {}
    today = datetime.now().strftime("%Y%m%d")
    try:
        actionable_codes = _collect_actionable_position_limit_codes(siglog_data=siglog_data, today=today)
        # v66 핵심: 빈 set = 0 보유 (정상). fallback 없이 즉시 반환.
        return len(actionable_codes), actionable_codes
    except Exception as _e:
        _log_warn_msg(f"  ⚠️ actionable 수집 오류 → carry fallback: {_e}")
    # fallback: actionable 수집 자체가 예외 발생한 경우만
    try:
        raw_carry = _read_json_safe(CARRY_FILE, {})
        if isinstance(raw_carry, dict):
            latest_by_code = _build_latest_tracking_by_code(siglog_data)
            carry_codes = set()
            for raw_code, info in raw_carry.items():
                if not isinstance(info, dict):
                    continue
                code = normalize_stock_code(raw_code)
                if not code:
                    continue
                rec = latest_by_code.get(code)
                if isinstance(rec, dict) and rec.get("entry_hit") and rec.get("status") in TRACK_ACTIVE_STATUSES:
                    carry_codes.add(code)
            return len(carry_codes), carry_codes
    except Exception as e:
        _swallow_exception(e)
    return 0, set()
def _extract_tracking_sector_theme(rec: dict | None = None) -> str:
    rec = rec if isinstance(rec, dict) else {}
    theme = _extract_alert_sector_theme(rec)
    if not _is_generic_sector_theme(theme):
        return theme
    feature_snapshot = rec.get("feature_snapshot") if isinstance(rec.get("feature_snapshot"), dict) else {}
    feature_theme = str(feature_snapshot.get("sector_theme", "") or rec.get("sector_theme", "") or "").strip()
    return "기타" if _is_generic_sector_theme(feature_theme) else feature_theme
def _should_allow_conditional_second_position(alert: dict | None = None, carry_codes: set[str] | None = None,
                                             latest_by_code: dict | None = None) -> bool:
    alert = alert if isinstance(alert, dict) else {}
    carry_codes = set(carry_codes or set())
    latest_by_code = latest_by_code if isinstance(latest_by_code, dict) else {}
    if len(carry_codes) != 1:
        return False
    if not is_market_open() or _is_nxt_premarket_window() or _is_nxt_postmarket_only_window():
        return False
    market = str(alert.get("market") or "KRX").upper()
    if market == "NXT":
        return False
    grade = str(alert.get("execution_grade") or alert.get("grade") or "").upper()
    score = safe_int(alert.get("score", 0), 0)
    entry_price = safe_int(alert.get("entry_price", alert.get("planned_entry_price", alert.get("execution_hint_entry_price", 0))), 0)
    candidate_theme = _extract_alert_sector_theme(alert)
    if grade != "A" or score < CONDITIONAL_SECOND_POSITION_MIN_SCORE or entry_price <= 0:
        return False
    if _is_generic_sector_theme(candidate_theme):
        return False
    active_themes = set()
    for code in carry_codes:
        rec = latest_by_code.get(code) if isinstance(latest_by_code, dict) else None
        active_theme = _extract_tracking_sector_theme(rec)
        if _is_generic_sector_theme(active_theme):
            return False
        active_themes.add(active_theme)
    return candidate_theme not in active_themes
def _apply_position_limit_after_priority(sorted_alerts: list, carry_codes: set[str], carry_count: int, max_positions: int, stage: str = "") -> list:
    # v82: 동시보유 제한 완전 제거 — v62~v80 9회 수정에도 오카운트 반복, 실진입은 사용자 수동 결정이므로 봇 단계에서 차단 불필요.
    return sorted_alerts if sorted_alerts else []
def filter_portfolio_signals(alerts: list) -> list:
    """
    동시 다발 신호에서 실질 섹터 스코어 기반 중복 제거.
    - 두 신호 간 real_sector_score >= 50 이면 같은 실질섹터로 판단
    - 점수 높은 것 1개만 통과 (나머지 제외)
    - 국면별 총 신호 수 제한
    - v53: 신규/기존 신호를 먼저 평가한 뒤 동시 보유 제한을 마지막 행동 단계에 적용
    """
    if not alerts:
        return alerts
    regime_info = get_market_regime()
    regime    = regime_info.get("mode", "normal")
    rp        = REGIME_PARAMS.get(regime, REGIME_PARAMS["normal"])
    max_positions = rp.get("max_positions", 1)
    max_total = {"bull": 8, "normal": 6, "bear": 3, "crash": 1}.get(regime, 6)
    carry_count, carry_codes = _get_carry_position_context()
    alerts = _apply_stale_pullback_quota(alerts, stage="filter_portfolio_signals")
    # 신규 리더 우선 + stale 눌림목 후순위 정렬
    sorted_alerts = sorted(
        alerts,
        key=lambda x: (
            1 if x.get("leader_priority_hit") else 0,
            0 if x.get("stale_pullback_hit") else 1,
            0 if x.get("stale_replay_penalty_hit") else 1,
            int(x.get("score", 0) or 0),
            float(x.get("change_rate", 0) or 0),
            float(x.get("volume_ratio", 0) or 0),
        ),
        reverse=True,
    )
    sorted_alerts = _apply_position_limit_after_priority(
        sorted_alerts,
        carry_codes=carry_codes,
        carry_count=carry_count,
        max_positions=max_positions,
        stage="filter_portfolio_signals",
    )
    if not sorted_alerts:
        return []
    passed   = []
    excluded = set()
    for i, s in enumerate(sorted_alerts):
        if len(passed) >= max_total:
            break
        if s["code"] in excluded:
            continue
        passed.append(s)
        # 아직 통과 안 된 뒤 신호들과 실질 섹터 비교
        for j in range(i + 1, len(sorted_alerts)):
            peer = sorted_alerts[j]
            if peer["code"] in excluded:
                continue
            # v162.7: 섹터대장 강제감시 종목(_sector_leader_follow)은 실질섹터 중복 카운트에서 면제
            # — 대장 종목이 상한가에 가기 전 후속 종목 조기포착 경로 확보
            if peer.get("_sector_leader_follow") or peer.get("_force_news_recheck"):
                continue
            # v165.33 [#2-C]: 뉴스+주가연동 직접 상승 종목은 섹터 한도 +1 추가 허용
            # 이유: 2026-04-27 SK증권 +15.2% — 뉴스 수혜 직접 상승 중인데 섹터 3/3 한도로 차단
            # 뉴스테마 rising 경로로 A급 판정된 종목은 섹터 편향이 아닌 뉴스 팩트 기반 포착
            if peer.get("_news_theme_rising"):
                _max_news_same = _dynamic.get("max_same_sector", 2) + 1  # 뉴스 직접 상승 +1 여유
                same_sector_passed_news = sum(
                    1 for p in passed
                    if calc_real_sector_score(s["code"], p["code"], s["name"], p["name"]).get("score", 0) >= 50
                )
                if same_sector_passed_news < _max_news_same:
                    continue  # 섹터 한도 초과 안 했으면 통과
            try:
                rs = calc_real_sector_score(s["code"], peer["code"],
                                            s["name"], peer["name"])
                # v165.41: 실질섹터 중복 제한 완전 제거
                # 이유: _apply_scan_sector_gate(1차) + max_total=6(2차)이 이미 충분히 제한
                #       섹터 전체 상승 장에서 max_same_sector=3(또는 5)은 역효과
                #       → 가장 좋은 종목 선택은 사용자 판단에 맡김
                # (rs 계산은 향후 참고용으로 유지)
                _ = rs  # 사용 안 함 (제거하면 calc_real_sector_score 호출 제거도 가능하나 이후 활용 여지)
            except Exception as e:
                _swallow_exception(e)
    if len(passed) < len(sorted_alerts):
        skipped = len(sorted_alerts) - len(passed)
        _log_info_msg(f"  🗂️ 포트폴리오 필터: {skipped}개 제외 ({regime}장, 최대 {max_total}개)")
    return passed
# v37.0: schedule lambda → 명명 함수 (에러 추적 가능)
def _on_market_open():
    """장 시작 시 초기화 — schedule에서 호출"""
    if is_holiday(): return
    _clear_all_cache()
    _overnight_state.update({"last_us_regime":"neutral","last_vix":20.0,
                              "alerted_regime":"","summary_lines":[]})
    try:
        _save_overnight_active_state(_default_overnight_active_state())
        _save_geo_active_state(_default_geo_active_state())
    except Exception as e:
        _swallow_exception(e)
    _upper_limit_day_alerted.clear()  # v40.0-#10: 상한가 당일 추적 초기화
    reset_top_signals_daily()
    refresh_dynamic_candidates()
    # v162: 장 시작 시 WebSocket 스레드 (재)시작
    try:
        _ws_start()
    except Exception as e:
        _swallow_exception(e)
    send(f"🌅 <b>장 시작!</b>  {datetime.now().strftime('%Y-%m-%d')}\n"
         f"📂 이월: {len(_detected_stocks)}개  |  📡 전체 스캔 시작")
def _build_scan_runtime_context() -> dict:
    krx_open = is_market_open()
    nxt_open = is_nxt_open()
    if not krx_open and not nxt_open:
        return {}
    if _bot_paused:
        return {}
    strict_tag = " [엄격]" if is_strict_time() else ""
    mkt_tag = "KRX+NXT" if krx_open and nxt_open else ("NXT전용" if nxt_open else "KRX")
    return {"krx_open": krx_open, "nxt_open": nxt_open, "strict_tag": strict_tag, "mkt_tag": mkt_tag}
def _normalize_scan_signal_code(payload: dict | None = None, fallback_code: str | None = None) -> str:
    code = normalize_stock_code((payload or {}).get("code", ""))
    if code:
        return code
    return normalize_stock_code(fallback_code or "")

def _needs_run_scan_payload_repair(payload: dict | None = None) -> bool:
    item = payload if isinstance(payload, dict) else {}
    code = _normalize_scan_signal_code(item)
    if not code:
        return False
    signal_type = str(item.get("signal_type") or "").strip().upper()
    score = safe_int(item.get("score", 0), 0)
    change_rate = safe_float(item.get("change_rate", 0.0), 0.0)
    volume_ratio = safe_float(item.get("volume_ratio", 0.0), 0.0)
    return signal_type in ("", "UNKNOWN") or score <= 0 or (abs(change_rate) < 0.01 and volume_ratio <= 0.0)

def _build_fallback_scan_signal_type(item: dict) -> str:
    signal_type = str(item.get("signal_type") or "").strip().upper()
    if signal_type not in ("", "UNKNOWN"):
        return signal_type
    change_rate = safe_float(item.get("change_rate", 0.0), 0.0)
    volume_ratio = safe_float(item.get("volume_ratio", 0.0), 0.0)
    joined = " ".join([str(item.get("desc") or ""), str(item.get("theme_desc") or ""), " ".join(map(str, item.get("reasons") or []))]).upper()
    has_live = safe_int(item.get("price", 0), 0) > 0 and bool(str(item.get("name", "") or "").strip())
    if change_rate >= UPPER_LIMIT_THRESHOLD:
        return "NEAR_UPPER"
    # v165.33 [#1]: change_rate 음수인 종목이 volume_ratio OR 조건으로 SURGE 판정되는 버그 수정
    # 이유: 2026-04-28 이렘(009730) — change_rate=-29.4%인데 vol_ratio 폭발로 SURGE 91점 [A] 발송
    # _build_fallback_scan_signal_type의 OR 조건이 부호 검증 없이 거래량만으로 SURGE 반환 가능
    if change_rate >= max(PRICE_SURGE_MIN, 4.0):
        return "SURGE"
    if change_rate > 0 and volume_ratio >= max(3.0, COMMON_THRESHOLD_3P0):
        return "SURGE"  # 거래량 폭발 단독 SURGE는 반드시 양수 등락률 종목만 허용
    if change_rate >= max(0.8, _early_price_min_dynamic) and volume_ratio >= max(1.2, _early_volume_min_dynamic * 0.7):
        return "EARLY_DETECT"
    if any(token in joined for token in ("MID_PULLBACK", "재상승", "시가회복", "박스돌파", "박스지지")):
        return "MID_PULLBACK"
    if has_live and any(token in joined for token in ("랭킹후보", "자동편입", "NXT장후리더", "THEME_FEEDBACK", "ADAPTIVE_FEEDBACK", "PREWATCH", "리더")):
        return "EARLY_DETECT"
    if has_live and (bool(item.get("direct_news_hit")) or bool(item.get("theme_chain_force_hit")) or bool(item.get("material_first_priority_hit"))):
        return "EARLY_DETECT"
    return ""

def _build_fallback_scan_score(item: dict, signal_type: str = "") -> int:
    score = safe_int(item.get("score", 0), 0)
    if score > 0:
        return score
    change_rate = safe_float(item.get("change_rate", 0.0), 0.0)
    volume_ratio = safe_float(item.get("volume_ratio", 0.0), 0.0)
    sig = str(signal_type or item.get("signal_type") or "").upper()
    has_live = safe_int(item.get("price", 0), 0) > 0 and bool(str(item.get("name", "") or "").strip())
    meaningful_theme = not _is_generic_sector_theme(str(item.get("sector_theme") or (item.get("sector_info") or {}).get("theme") or ""))
    base = 0
    if sig == "UPPER_LIMIT":
        base = 90
    elif sig == "NEAR_UPPER":
        base = 82
    elif sig == "SURGE":
        base = 62
    elif sig == "MID_PULLBACK":
        base = 58
    elif sig == "EARLY_DETECT":
        base = 54
    elif has_live and (meaningful_theme or bool(item.get("direct_news_hit")) or bool(item.get("material_first_priority_hit"))):
        base = 46
    base += min(18, max(0, int(abs(change_rate) * 1.4)))
    base += min(14, max(0, int(volume_ratio * 2.5)))
    if has_live and str(item.get("market", "") or "").upper() == "NXT":
        base += 2
    return max(0, min(99, base))

def _build_run_scan_missing_reasons(item: dict) -> list[str]:
    reasons = []
    if not str(item.get("name") or "").strip():
        reasons.append("missing_name")
    if safe_int(item.get("price", 0), 0) <= 0:
        reasons.append("missing_price")
    if not str(item.get("signal_type") or "").strip():
        reasons.append("missing_signal_type")
    if safe_int(item.get("score", 0), 0) <= 0:
        reasons.append("missing_score")
    return reasons

def _queue_run_scan_repair(item: dict, stage: str = "") -> None:
    code = _normalize_scan_signal_code(item)
    if not code:
        return
    if is_scoring_only_instrument(code, str(item.get("name") or "")):
        return
    # v163.6: missing_signal_type 단독 결측은 큐 등록 자체 차단 (장중 포함) — 1,519건 루프 방지
    reasons = _build_run_scan_missing_reasons(item)
    if reasons == ["missing_signal_type"]:
        return
    # v163.6: 큐 크기 제한 — 최대 80개 초과 시 오래된 항목 제거
    if len(_run_scan_repair_queue) >= 80:
        oldest = sorted(_run_scan_repair_queue.keys(),
                        key=lambda c: float(_run_scan_repair_queue[c].get("next_ts", 0) or 0))
        for c in oldest[:20]:
            _run_scan_repair_queue.pop(c, None)
    # v161.19: NXT 전용 시간대에 KRX 종목은 repair 큐 등록 자체 차단 — 무한 재시도 방지
    if not is_market_open() and is_nxt_open() and str(item.get("market") or "") != "NXT":
        return
    row = dict(_run_scan_repair_queue.get(code) or {})
    row["payload"] = dict(item)
    row["stage"] = str(stage or row.get("stage", ""))
    row["attempts"] = int(row.get("attempts", 0) or 0)
    row["next_ts"] = min(float(row.get("next_ts", time.time()) or time.time()), time.time() + RUN_SCAN_REPAIR_RETRY_SEC)
    _run_scan_repair_queue[code] = row


def _emit_run_scan_code_change_request(item: dict) -> None:
    code = _normalize_scan_signal_code(item)
    if not code:
        return
    if is_scoring_only_instrument(code, str(item.get("name") or "")):
        return
    reasons = list(item.get("_scan_payload_missing_reasons") or [])
    # missing_signal_type 단독이면 analyze() 정상 차단 — 사용자 알람 불필요
    if reasons == ["missing_signal_type"] or (len(reasons) == 1 and "missing_signal_type" in reasons):
        _log_info_msg(f"  ⏭ run_scan 결측(signal_type) 조용히 폐기: {item.get('name', code) or code}")
        return
    reasons = list(item.get("_scan_payload_missing_reasons") or [])
    lines = [f"종목: {str(item.get('name', '') or code)} ({code})", f"market: {str(item.get('market','') or '')}"]
    for r in reasons:
        lines.append(f"- {r}")
    _send_code_change_request_alert(f"run_scan_payload:{code}", lines, cooldown_min=120)


def _drain_run_scan_repair_queue(alerts: list, seen: set) -> None:
    if not _repair_drain_lock.acquire(blocking=False):
        return
    try:
        now = time.time()
        remove_codes = []
        for code, row in list(_run_scan_repair_queue.items()):
            if now < float(row.get("next_ts", 0.0) or 0.0):
                continue
            item = dict(row.get("payload") or {})
            item["code"] = code
            # v161.19: NXT 전용 시간대에 KRX 종목은 재시도 없이 즉시 폐기 — missing_signal_type 무한반복 방지
            if not is_market_open() and is_nxt_open() and str(item.get("market") or "") != "NXT":
                remove_codes.append(code)
                continue
            # v165.29 [#1]: NXT 전용 시간대 + 복합결측(price+signal_type+score 모두) → NXT 종목도 조용히 폐기
            # KRX 마감 후 NXT 상장 종목도 KRX 분석 데이터 복구 불가 → 재시도 무의미, 경고 반복 방지
            if not is_market_open() and is_nxt_open():
                _pre_reasons = _build_run_scan_missing_reasons(item)
                if all(r in _pre_reasons for r in ("missing_price", "missing_signal_type", "missing_score")):
                    remove_codes.append(code)
                    continue
            repaired = _coerce_run_scan_signal_defaults(item, fallback_code=code)
            if bool(repaired.get("_scan_payload_incomplete")):
                _drain_reasons = list(repaired.get("_scan_payload_missing_reasons") or [])
                # v163.8 [#2]: missing_signal_type 단독이면 재시도 없이 즉시 큐에서 제거
                if _drain_reasons == ["missing_signal_type"]:
                    remove_codes.append(code)
                    continue
                attempts = int(row.get("attempts", 0) or 0) + 1
                if attempts >= RUN_SCAN_REPAIR_MAX_ATTEMPTS:
                    _emit_run_scan_code_change_request(repaired)
                    remove_codes.append(code)
                else:
                    row["payload"] = dict(repaired)
                    row["attempts"] = attempts
                    row["next_ts"] = now + RUN_SCAN_REPAIR_RETRY_SEC
                    _run_scan_repair_queue[code] = row
                continue
            remove_codes.append(code)
            # v165.17: repair 완료 후에도 NXT 전용 시간대 체크 — analyze()가 market="NXT" 마킹해도 최종 차단
            # 이유: _scan_rank_and_theme_candidates()가 nxt_only_window 통과 종목에 market="NXT" 마킹 후
            #       repair queue 등록 → drain 시 analyze()가 get_nxt_delta() 경유 market="NXT" 재마킹
            #       → 37543 NXT 체크 통과 → 삼기에너지솔루션즈/대우건설/수산세보틱스 오발송
            if not is_market_open() and is_nxt_open():
                _rc = normalize_stock_code(repaired.get("code", "") or code)
                if _rc in _nxt_unavailable:
                    continue  # 확인된 KRX 전용 → 폐기
                if _rc not in _nxt_cache:
                    # NXT 캐시에 없음 → 실제 NXT 거래량 확인
                    try:
                        _nxt_q = get_nxt_stock_price(_rc)
                        _nxt_vol = safe_int((_nxt_q or {}).get("today_vol", 0), 0)
                        if not _nxt_q or _nxt_vol == 0:
                            _nxt_unavailable.add(_rc)
                            continue  # NXT 거래량 없음 → KRX 전용
                    except Exception as _ne:
                        _swallow_exception(_ne)
                        continue  # 조회 실패 → 보수적으로 폐기
            _append_scan_alert(alerts, seen, repaired, hist_key=code, seen_code=code)
        for code in remove_codes:
            _run_scan_repair_queue.pop(code, None)
    finally:
        _repair_drain_lock.release()

def _repair_run_scan_payload(payload: dict | None = None, fallback_code: str | None = None) -> dict:
    item = dict(payload or {})
    code = _normalize_scan_signal_code(item, fallback_code=fallback_code)
    if not code:
        return item
    item["code"] = code
    market = "NXT" if str(item.get("market", "") or "").upper() == "NXT" else "KRX"
    if _needs_run_scan_payload_repair(item):
        try:
            quote = get_nxt_stock_price(code) if market == "NXT" else get_stock_price(code)
        except Exception as e:
            _swallow_exception(e)
            quote = {}
        if isinstance(quote, dict) and quote.get("price"):
            for key in ("name", "price", "change_rate", "volume_ratio", "today_vol", "market", "open", "prev_close", "ask_qty", "bid_qty", "ask_price", "bid_price", "bstp_code", "bstp_name"):
                if quote.get(key) not in (None, "", 0):
                    item[key] = quote.get(key)
        item["change_rate"] = _get_effective_change_rate(item, safe_int(item.get("price", 0), 0))
        try:
            analyzed = analyze(item)
        except Exception as e:
            _swallow_exception(e)
            analyzed = {}
        if isinstance(analyzed, dict) and _normalize_scan_signal_code(analyzed, fallback_code=code) == code:
            merged = dict(item)
            _orig_market = str(item.get("market") or "")  # v165.17: repair 전 market 보존
            merged.update(analyzed)
            # v165.17: analyze() 내 get_nxt_delta()가 market="NXT"로 덮어쓰는 것 방지
            # repair queue 항목은 원래 market 값을 유지 — NXT 판별은 drain 단계에서 실시
            if _orig_market:
                merged["market"] = _orig_market
            elif item.get("market") and not merged.get("market"):
                merged["market"] = item.get("market")
            merged_reasons = list(item.get("reasons") or []) + list(analyzed.get("reasons") or [])
            if merged_reasons:
                uniq = []
                seen_reason = set()
                for reason in merged_reasons:
                    key = str(reason)
                    if key in seen_reason:
                        continue
                    seen_reason.add(key)
                    uniq.append(reason)
                merged["reasons"] = uniq
            item = merged
    if not str(item.get("name") or "").strip():
        item["name"] = _resolve_stock_name(code, item.get("name", ""), cur=item)
    if safe_int(item.get("price", 0), 0) <= 0:
        for key in ("ask_price", "bid_price", "entry_price", "planned_entry_price", "execution_hint_entry_price", "open", "prev_close"):
            val = safe_int(item.get(key, 0), 0)
            if val > 0:
                item["price"] = val
                break
    bstp_name = str(item.get("bstp_name") or (item.get("sector_info") or {}).get("bstp_name") or "").strip()
    public_meta = _get_public_stock_meta(code)
    public_sector = _normalize_public_sector_name((public_meta or {}).get("sector", ""))
    if (bstp_name and not _is_generic_sector_theme(bstp_name)) or public_sector not in ("", "기타업종", "기타"):
        sector_info = item.get("sector_info") if isinstance(item.get("sector_info"), dict) else {}
        resolved_sector = bstp_name if bstp_name and not _is_generic_sector_theme(bstp_name) else public_sector
        sector_info["theme"] = str(sector_info.get("theme") or resolved_sector) if _is_generic_sector_theme(str(sector_info.get("theme") or "")) else str(sector_info.get("theme") or "")
        sector_info["bstp_name"] = bstp_name or resolved_sector
        if public_sector not in ("", "기타업종", "기타"):
            sector_info["public_sector"] = public_sector
        item["sector_info"] = sector_info
        if _is_generic_sector_theme(str(item.get("sector_theme") or "")):
            item["sector_theme"] = sector_info.get("theme", resolved_sector)
    signal_type = _build_fallback_scan_signal_type(item)
    if signal_type and str(item.get("signal_type") or "").strip().upper() in ("", "UNKNOWN"):
        item["signal_type"] = signal_type
    if safe_int(item.get("score", 0), 0) <= 0:
        item["score"] = _build_fallback_scan_score(item, signal_type=str(item.get("signal_type") or signal_type or ""))
    if not str(item.get("grade") or item.get("execution_grade") or "").strip():
        score = safe_int(item.get("score", 0), 0)
        grade = "A" if score >= GENERAL_GRADE_A_CUT else "B" if score >= GENERAL_GRADE_B_CUT else "C"
        item["grade"] = grade
        item["execution_grade"] = grade
    missing_reasons = _build_run_scan_missing_reasons(item)
    incomplete = bool(missing_reasons)
    item["_scan_payload_incomplete"] = bool(incomplete)
    item["_scan_payload_missing_reasons"] = list(missing_reasons)
    if incomplete:
        item.setdefault("reasons", []).append("⚠️ 시세/신호 결측 — 일반 포착 재복구 대기")
    return item

def _coerce_run_scan_signal_defaults(payload: dict | None = None, fallback_code: str | None = None) -> dict:
    item = _repair_run_scan_payload(payload, fallback_code=fallback_code)
    code = _normalize_scan_signal_code(item, fallback_code=fallback_code)
    if code:
        item["code"] = code
    # v161.3 #8: name이 비어있거나 코드와 동일하면 재시도
    if code and (not str(item.get("name") or "").strip() or str(item.get("name") or "").strip() == code):
        resolved = _resolve_stock_name(code, "")
        if resolved and resolved != code:
            item["name"] = resolved
    item["change_rate"] = safe_float(item.get("change_rate", 0.0), 0.0)
    item["volume_ratio"] = safe_float(item.get("volume_ratio", 0.0), 0.0)
    item["score"] = safe_int(item.get("score", 0), 0)
    item["price"] = safe_int(item.get("price", 0), 0)
    item["today_vol"] = safe_int(item.get("today_vol", 0), 0)
    item["entry_price"] = safe_int(item.get("entry_price", 0), 0)
    item["planned_entry_price"] = safe_int(item.get("planned_entry_price", item.get("entry_price", 0)), 0)
    item["execution_hint_entry_price"] = safe_int(item.get("execution_hint_entry_price", 0), 0)
    item["stop_loss"] = safe_int(item.get("stop_loss", 0), 0)
    item["target_price"] = safe_int(item.get("target_price", 0), 0)
    item["market"] = str(item.get("market", "") or "")
    item["grade"] = str(item.get("execution_grade") or item.get("grade") or "C").upper()
    item["execution_grade"] = str(item.get("execution_grade") or item.get("grade") or item["grade"] or "C").upper()
    if "signal_type" not in item or item.get("signal_type") is None:
        item["signal_type"] = ""
    if "name" not in item or item.get("name") is None:
        item["name"] = ""
    if "reasons" not in item or not isinstance(item.get("reasons"), list):
        item["reasons"] = list(item.get("reasons") or []) if item.get("reasons") else []
    if "detected_at" not in item or item.get("detected_at") in (None, ""):
        item["detected_at"] = _now_kst()
    return item
def _sanitize_run_scan_alerts(alerts: list, stage: str = "") -> list:
    cleaned = []
    dropped = 0
    dropped_names = []  # v165.1: 제거 종목 추적
    # v165.14: NXT 전용 시간대에 비NXT 거래가능 종목 pre_sector_gate 단계에서 제거
    # analyze() 전 단계가 아닌 여기서 걸러내는 이유:
    # build_stock_universe 수정 시 영향 범위 크고, 이 단계가 dispatch 직전 최종 정리 포인트
    # _is_nxt_eligible() 캐시로 반복 API 호출 없음
    _nxt_only_now = is_nxt_open() and not is_market_open()
    for item in list(alerts or []):
        if not isinstance(item, dict):
            dropped += 1
            continue
        code = _normalize_scan_signal_code(item)
        if not code:
            dropped += 1
            _nm = item.get('name', '') or item.get('signal_type', '') or 'unknown'
            dropped_names.append(_nm)
            _log_warn_msg(f"⚠️ run_scan code 누락 제거{(' [' + stage + ']') if stage else ''}: {_nm}")
            continue
        # v163.11 [#2]: ETN/레버리지/인버스 복합결측 종목 큐 등록 차단
        _item_name = str(item.get("name") or "")
        if is_scoring_only_instrument(code, _item_name):
            dropped += 1
            continue
        item = _coerce_run_scan_signal_defaults(item, fallback_code=code)
        # v165.21 [#1]: NXT 전용 시간대 — market="NXT" 필드 단일 기준으로 차단
        # v165.27 [#2]: _nxt_confirmed_codes 화이트리스트가 있으면 더 정확하게 판별
        if _nxt_only_now:
            _item_market = str(item.get("market") or "").upper()
            _item_code = code
            # 화이트리스트가 충분히 쌓였으면(50개 이상) → 화이트리스트 기준 판별
            if len(_nxt_confirmed_codes) >= 50:
                if _item_code not in _nxt_confirmed_codes:
                    dropped += 1
                    dropped_names.append(f"{item.get('name', code)}(KRX전용확정)")
                    continue
            else:
                # 화이트리스트 미형성 시 기존 market 필드 기준 유지
                if _item_market != "NXT":
                    dropped += 1
                    dropped_names.append(f"{item.get('name', code)}(KRX전용)")
                    continue
        if bool(item.get("_scan_payload_incomplete")):
            dropped += 1
            _missing_r = list(item.get("_scan_payload_missing_reasons") or [])
            # v163.8 [#1]: missing_signal_type 단독이면 경고 로그 없이 조용히 drop
            if _missing_r == ["missing_signal_type"]:
                _queue_run_scan_repair(item, stage=stage)
                continue
            _queue_run_scan_repair(item, stage=stage)
            _nm2 = item.get('name', code) or code
            dropped_names.append(f"{_nm2}({','.join(_missing_r)})")
            _log_warn_msg(f"⚠️ run_scan 결측 재복구 큐 등록{(' [' + stage + ']') if stage else ''}: {_nm2} / {','.join(_missing_r)}")
            continue
        cleaned.append(item)
    if dropped > 0:
        # v165.21 [#1]: KRX전용 제거는 INFO, 실제 malformed(code 결측/payload 불완전)는 WARNING 구분
        krx_only = [n for n in dropped_names if "(KRX전용)" in n]
        real_malformed = [n for n in dropped_names if "(KRX전용)" not in n]
        if real_malformed:
            suffix = f" → {', '.join(real_malformed[:5])}" if real_malformed else ""
            _log_warn_msg(f"⚠️ run_scan malformed alert {len(real_malformed)}건 제거{(' [' + stage + ']') if stage else ''}{suffix}")
        if krx_only:
            _log_info_msg(f"  ↪ NXT시간 KRX전용 {len(krx_only)}건 제외{(' [' + stage + ']') if stage else ''}")
    return cleaned

def _append_scan_alert(alerts: list, seen: set, result: dict, *, hist_key: str | None = None, seen_code: str | None = None) -> None:
    if not isinstance(result, dict):
        return
    normalized_seen_code = normalize_stock_code(seen_code or "")
    result_code = _normalize_scan_signal_code(result, fallback_code=normalized_seen_code)
    if not result_code:
        _log_warn_msg(f"⚠️ run_scan alert code 누락 스킵: {result.get('name', '') or result.get('signal_type', '') or 'unknown'}")
        return
    result = _coerce_run_scan_signal_defaults(result, fallback_code=result_code)
    if bool(result.get("_scan_payload_incomplete")):
        _reasons = list(result.get("_scan_payload_missing_reasons") or [])
        # v163.7 [#1]: missing_signal_type 단독이면 경고 로그 없이 조용히 drop
        if _reasons == ["missing_signal_type"]:
            return
        # v163.15 [#2]: ETN/레버리지/인버스 복합결측 종목은 WARNING 없이 조용히 드롭
        _res_name = str(result.get("name") or "")
        if is_scoring_only_instrument(result_code, _res_name):
            return
        # v165.25 [#3]: NXT 전용 시간대 복합결측(price+signal_type+score 모두 결측) → 조용히 폐기
        # 이유: KEC처럼 KRX 데이터가 NXT 시간대에 price/signal_type/score 모두 결측 → 복구 불가, 경고만 반복
        _nxt_time = not is_market_open() and is_nxt_open()
        _all_core_missing = all(r in _reasons for r in ("missing_price", "missing_signal_type", "missing_score"))
        if _nxt_time and _all_core_missing:
            return  # WARNING 없이 조용히 폐기
        _queue_run_scan_repair(result, stage="append")
        _log_warn_msg(f"⚠️ run_scan alert 결측 재복구 대기: {result.get('name', result_code) or result_code} / {','.join(_reasons)}")
        return
    resolved_hist_key = hist_key or (f"NXT_{result_code}" if result.get("market") == "NXT" else result_code)
    prev_hist = _alert_history.get(resolved_hist_key, 0)
    prev_ts = prev_hist.get("ts", 0) if isinstance(prev_hist, dict) else float(prev_hist or 0)
    if time.time() - prev_ts <= get_regime_cooldown():
        return
    alerts.append(result)
    seen.add(normalized_seen_code or result_code)
def _scan_overnight_watchlist_candidates(alerts: list, seen: set, krx_open: bool) -> None:
    try:
        if not (_overnight_watchlist and krx_open):
            return
        for wl_code, wl_info in list(_overnight_watchlist.items())[:10]:
            if wl_code in seen:
                continue
            try:
                cur = get_stock_price(wl_code)
                if cur and cur.get("price", 0) > 0:
                    wl_stock = {
                        "code": wl_code,
                        "name": wl_info.get("name", ""),
                        "price": cur["price"],
                        "change_rate": cur.get("change_rate", 0),
                        "volume_ratio": cur.get("volume_ratio", 0),
                        "today_vol": cur.get("today_vol", 0),
                        "_overnight_event": wl_info.get("event", ""),
                    }
                    _append_scan_alert(alerts, seen, analyze(wl_stock), hist_key=wl_code, seen_code=wl_code)
                time.sleep(0.1)
            except Exception as e:
                _swallow_exception(e)
                continue
    except Exception as _e:
        _log_warn_msg(f"  ⚠️ 야간 워치리스트 우선 스캔 오류: {_e}")
def _scan_scenario_action_board_candidates(alerts: list, seen: set, krx_open: bool) -> None:
    try:
        # v162.2: NXT 전용 시간대(KRX 마감 후)에도 시나리오 액션보드 스캔 허용
        nxt_open = is_nxt_open()
        if not krx_open and not nxt_open:
            return
        board = _load_premarket_action_board()
        if not board.get("items"):
            return
        nxt_only_window = nxt_open and not krx_open
        scanned = 0
        for item in list(board.get("items", []) or []):
            if str(item.get("direction", "")) != "up":
                continue
            for cand in list(item.get("kr_stock_candidates_long", []) or [])[:3]:
                code = normalize_stock_code(cand.get("code"))
                if not code or code in seen:
                    continue
                # v162.2: NXT 전용 시간대에는 KRX 전용 종목 skip
                if nxt_only_window and not is_nxt_listed(code):
                    continue
                cur = get_stock_price(code)
                if not cur or not cur.get("price", 0):
                    continue
                stock = {
                    "code": code,
                    "name": _resolve_stock_name(code, cand.get("name", "")),
                    "price": cur.get("price", 0),
                    "change_rate": cur.get("change_rate", 0),
                    "volume_ratio": cur.get("volume_ratio", 0),
                    "today_vol": cur.get("today_vol", 0),
                    "scenario_event": item.get("event_name", ""),
                }
                result = analyze(stock)
                if isinstance(result, dict):
                    result = dict(result)
                    result.setdefault("reasons", []).append(f"🧭 24H 시나리오 후보: {str(item.get('event_name','') or '')[:24]}")
                _append_scan_alert(alerts, seen, result, hist_key=code, seen_code=code)
                scanned += 1
                if scanned >= SCENARIO_SCAN_LIMIT:
                    return
                time.sleep(0.1)
    except Exception as e:
        _log_warn_msg(f"  ⚠️ 시나리오 액션보드 우선 스캔 오류: {e}")


def _scan_issue_prewatch_candidates(alerts: list, seen: set) -> None:
    if not _news_issue_prewatch or not is_any_market_open():
        return
    now = time.time()
    expired_keys = []
    for theme_key, pw in list(_news_issue_prewatch.items())[:MATERIAL_PREWATCH_SCAN_LIMIT]:
        if _should_expire_issue_prewatch(theme_key, pw, now):
            expired_keys.append(theme_key)
            continue
        try:
            pw = dict(pw)
            pw.setdefault("theme_key", theme_key)
            reacted = _collect_issue_prewatch_reacted(pw.get("stocks", []), pw)
            if not reacted:
                continue
            summary = _summarize_material_reaction(reacted, pw)
            if not summary.get("passes"):
                continue
            reacted_sorted = sorted(reacted, key=lambda item: _material_reacted_priority_score(item, pw, summary), reverse=True)
            dispatched_codes = set()
            for item in reacted_sorted[:ISSUE_PREWATCH_REACT_LIMIT]:
                code = normalize_stock_code(item.get("code", ""))
                if not code or code in seen or _is_material_first_stock_cooldown(code, theme_key):
                    continue
                result = analyze(item)
                if not isinstance(result, dict):
                    continue
                if result.get("grade") != "A" or int(result.get("entry_price", 0) or 0) <= 0:
                    continue
                result = dict(result)
                result.setdefault("reasons", []).append(f"👁 재료-first prewatch: {str(pw.get('theme_desc', '') or '')[:30]}")
                result["material_first_hint"] = True
                result["material_first_priority_hit"] = bool(summary.get("strong"))
                result["material_first_theme"] = theme_key
                result["material_first_seed_score"] = summary.get("seed_score", 0)
                result["material_first_reacted_cnt"] = summary.get("reacted_cnt", 0)
                _append_scan_alert(alerts, seen, result, hist_key=code, seen_code=code)
                _mark_material_first_stock_alerted(code, theme_key)
                dispatched_codes.add(code)
            if dispatched_codes:
                _news_prewatch_fired[theme_key] = now
                expired_keys.append(theme_key)
                _log_info_msg(f"  👁 재료-first prewatch→본스캔 합류: [{theme_key}] {len(dispatched_codes)}종목")
        except Exception as e:
            _log_error("_scan_issue_prewatch_candidates", e)
    for key in expired_keys:
        _news_issue_prewatch.pop(key, None)


def _scan_krx_market_candidates(alerts: list, seen: set) -> None:
    today_date = datetime.now().strftime("%Y%m%d")
    # v167.0: 상한가 포착 API → _upper_limit_alerted_today 자동 갱신 (장중에만)
    try:
        get_capture_uplowprice(prc_cls="0")
    except Exception as _cue:
        _swallow_exception(_cue)
    for stock in get_upper_limit_stocks():
        code = normalize_stock_code(stock.get("code", ""))
        if not code:
            _log_warn_msg("⚠️ run_scan upper_limit 후보 code 누락 스킵")
            continue
        stock = dict(stock)
        stock["code"] = code
        _register_sector_leader_follow_seed(stock)
        if code in seen:
            continue
        _ul_rec = _upper_limit_day_alerted.get(code)
        if _ul_rec and _ul_rec.get("date") == today_date:
            cr = stock.get("change_rate", 0)
            if cr >= 29.0:
                continue
            _upper_limit_day_alerted.pop(code, None)
        r = analyze(stock)
        result_code = _normalize_scan_signal_code(r, fallback_code=code) if isinstance(r, dict) else ""
        if isinstance(r, dict) and r.get("signal_type") in ("UPPER_LIMIT", "NEAR_UPPER") and result_code:
            _upper_limit_day_alerted[result_code] = {"date": today_date, "alerted": True}
        _append_scan_alert(alerts, seen, r, seen_code=code)
    for stock in get_volume_surge_stocks():
        code = normalize_stock_code(stock.get("code", ""))
        if not code:
            _log_warn_msg("⚠️ run_scan volume_surge 후보 code 누락 스킵")
            continue
        stock = dict(stock)
        stock["code"] = code
        _register_sector_leader_follow_seed(stock)
        if code in seen:
            continue
        _ul_today = _upper_limit_alerted_today.get(code)
        if _ul_today and _ul_today == today_date:
            continue
        # v167.0: VI 발동 종목 진입 차단
        if _vi_blocked_codes.get(code, 0) > time.time():
            _log_info_msg(f"  🚦 VI 차단 스킵 (KRX): {stock.get('name', code)}")
            continue
        _append_scan_alert(alerts, seen, analyze(stock), seen_code=code)
    # v167.0: 체결강도 상위 소스 추가 — 거래량 기준 누락 급등 종목 보완
    try:
        for stock in get_volume_power_rank("J"):
            code = normalize_stock_code(stock.get("code", ""))
            if not code or code in seen:
                continue
            if _upper_limit_alerted_today.get(code) == today_date:
                continue
            if _vi_blocked_codes.get(code, 0) > time.time():
                continue
            cr = float(stock.get("change_rate", 0) or 0)
            if cr < 2.0:
                continue
            _register_sector_leader_follow_seed(stock)
            _append_scan_alert(alerts, seen, analyze(stock), seen_code=code)
    except Exception as _vpe:
        _swallow_exception(_vpe)
    # v167.0: 신고가 근접 소스 추가 — 52주 신고가 5% 이내 돌파 후보
    try:
        for stock in get_near_new_highlow_rank(high=True):
            code = normalize_stock_code(stock.get("code", ""))
            if not code or code in seen:
                continue
            if _upper_limit_alerted_today.get(code) == today_date:
                continue
            cr = float(stock.get("change_rate", 0) or 0)
            if cr < 1.0:
                continue
            _register_sector_leader_follow_seed(stock)
            _append_scan_alert(alerts, seen, analyze(stock), seen_code=code)
    except Exception as _nhe:
        _swallow_exception(_nhe)
    # v167.0: 등락률 순위 소스 추가 — 거래량 기준 미포착 등락률 상위 보완
    try:
        for stock in get_fluctuation_rank("J", "0"):
            code = normalize_stock_code(stock.get("code", ""))
            if not code or code in seen:
                continue
            if _upper_limit_alerted_today.get(code) == today_date:
                continue
            if _vi_blocked_codes.get(code, 0) > time.time():
                continue
            cr = float(stock.get("change_rate", 0) or 0)
            if cr < 3.0:    # KRX 등락률 3% 이상만 (중복 방지)
                continue
            _register_sector_leader_follow_seed(stock)
            _append_scan_alert(alerts, seen, analyze(stock), seen_code=code)
    except Exception as _fre:
        _swallow_exception(_fre)
def _scan_nxt_market_candidates(alerts: list, seen: set) -> None:
    # v167.0: NXT 시간외 구간(KRX 닫힘+NXT 열림)에는 overtime 전용 소스 우선 사용
    nxt_only_window = not is_market_open() and is_nxt_open()
    # v167.0: overtime 소스 수집 (NXT 전용 등락률/거래량 순위)
    overtime_items: list = []
    if nxt_only_window:
        try:
            ot_fluct = get_overtime_fluctuation_rank()
            ot_vol   = get_overtime_volume_rank()
            # v169.0: NXT 시간대 체결강도·신고가 소스 추가
            ot_power = get_volume_power_rank("Q")   # Q=NXT 시장코드
            ot_high  = get_near_new_highlow_rank(high=True)
            seen_ot  = set()
            for it in ot_fluct + ot_vol + ot_power + ot_high:
                c = normalize_stock_code(it.get("code", ""))
                if c and c not in seen_ot:
                    seen_ot.add(c)
                    it["market"] = "NXT"
                    overtime_items.append(it)
        except Exception as _ote:
            _swallow_exception(_ote)
    for stock in (overtime_items if overtime_items else []) + list(get_nxt_surge_stocks()):
        code = normalize_stock_code(stock.get("code", ""))
        if not code:
            _log_warn_msg("⚠️ run_scan NXT 후보 code 누락 스킵")
            continue
        stock = dict(stock)
        stock["code"] = code
        _register_sector_leader_follow_seed(stock)
        if code in seen:
            continue
        # v167.0: VI 발동 종목 진입 차단
        if _vi_blocked_codes.get(code, 0) > time.time():
            _log_info_msg(f"  🚦 VI 차단 스킵 (NXT): {stock.get('name', code)}")
            continue
        if _is_nxt_premarket_window():
            gate = stock.get("_nxt_premarket_gate") if isinstance(stock.get("_nxt_premarket_gate"), dict) else _get_nxt_premarket_quality_gate(stock)
            if not gate.get("allow"):
                continue
            stock["_nxt_premarket_gate"] = gate
        else:
            _cr = float(stock.get("change_rate", 0) or 0)
            _vr = float(stock.get("volume_ratio", 0) or 0)
            if _cr < 1.0 and _vr < 1.5:
                continue
        r = analyze(stock)
        if isinstance(r, dict):
            r["market"] = "NXT"
        hist_code = _normalize_scan_signal_code(r, fallback_code=code) if isinstance(r, dict) else code
        _append_scan_alert(alerts, seen, r, hist_key=f"NXT_{hist_code}", seen_code=code)
def _collect_quiet_absorption_scan_pool(existing_codes: set | None = None) -> list[dict]:
    scan_limit = max(2, int(MARKET_FLOW_QUIET_SCAN_LIMIT_PER_MARKET or 2))
    pool: list[dict] = []
    seen = set(existing_codes or set())
    for stock in get_market_rank_focus_stocks(scan_limit_per_market=scan_limit):
        code = normalize_stock_code(stock.get("code", ""))
        if not code or code in seen:
            continue
        change_rate = safe_float(stock.get("change_rate", 0.0), 0.0)
        volume_ratio = safe_float(stock.get("volume_ratio", 0.0), 0.0)
        if change_rate < MARKET_FLOW_QUIET_MIN_CHANGE or change_rate > MARKET_FLOW_QUIET_MAX_CHANGE:
            continue
        if volume_ratio <= 0 or volume_ratio > MARKET_FLOW_QUIET_MAX_VOLUME_RATIO:
            continue
        seen.add(code)
        pool.append(stock)
    return pool
def _slice_quiet_absorption_scan_pool(pool: list[dict]) -> list[dict]:
    if not pool:
        return []
    deep_limit = max(1, int(MARKET_FLOW_QUIET_DEEP_FETCH_LIMIT or 1))
    if len(pool) <= deep_limit:
        return pool
    cursor = int(_quiet_scan_cursor.get("all", 0) or 0) % len(pool)
    selected = [pool[(cursor + idx) % len(pool)] for idx in range(deep_limit)]
    _quiet_scan_cursor["all"] = (cursor + deep_limit) % len(pool)
    return selected
def _scan_quiet_absorption_candidates(alerts: list, seen: set) -> None:
    nxt_only_window = not is_market_open() and is_nxt_open()  # v161.45
    pool = _slice_quiet_absorption_scan_pool(_collect_quiet_absorption_scan_pool(existing_codes=seen))
    if not pool:
        return
    _reset_quiet_scan_cycle_state()
    for stock in pool:
        code = normalize_stock_code(stock.get("code", ""))
        if not code:
            continue
        # v161.45: NXT 전용 시간대에 KRX 전용 종목 차단
        if nxt_only_window and stock.get("market", "") != "NXT" and not is_nxt_listed(code):
            _log_info_msg(f"  ⏭ NXT전용 시간대 비NXT 종목 차단(quiet): {stock.get('name', code)}")
            continue
        registered = _register_quiet_absorption_seed(stock, source="quiet_absorption_scan")
        if not registered or code in seen:
            continue
        analyzed = analyze(stock)
        if isinstance(analyzed, dict):
            analyzed.setdefault("reasons", []).append("🪙 뉴스 전 조용한 선매집 초기감지")
        _append_scan_alert(alerts, seen, analyzed, seen_code=code)
    skipped = int(_quiet_scan_cycle_state.get("skipped_budget", 0) or 0)
    if skipped > 0:
        _log_info_msg(f"  ⏭ quiet scan budget 절약: snapshot 생략 {skipped}건")
def _scan_rank_and_theme_candidates(alerts: list, seen: set) -> None:
    _rank_scan_limit = NXT_POSTMARKET_EXTRA_RANK_LIMIT if _is_nxt_postmarket_only_window() else None
    # v161.17: NXT전용 시간대(KRX 닫힘+NXT 열림) 판단 — market 필드 오판 방지 위해 시장 상태 직접 체크
    nxt_only_window = not is_market_open() and is_nxt_open()
    for stock in get_market_rank_focus_stocks(scan_limit_per_market=_rank_scan_limit):
        code = stock.get("code")
        if not code or code in seen:
            continue
        # NXT전용 시간대엔 market=="NXT" 명시된 종목만 스캔
        if nxt_only_window and str(stock.get("market") or "") != "NXT":
            continue
        # v165.37 [C]: analyze() 전 빠른 pre-filter — API 호출 비용 절감
        _cr = float(stock.get("change_rate", 0) or 0)
        _vr = float(stock.get("volume_ratio", 0) or 0)
        _pre_min_cr = 1.0 if nxt_only_window else 2.0  # NXT 장전/장후는 완화
        if _cr < _pre_min_cr and _vr < 2.0:
            continue
        r = analyze(stock)
        # v165.15: NXT전용 시간대 통과 종목에 market="NXT" 명시 마킹 (sanitize 필터 일관성)
        if nxt_only_window and isinstance(r, dict):
            r["market"] = "NXT"
        _append_scan_alert(alerts, seen, r, seen_code=code)
    for stock in _collect_theme_peer_follow_candidates(existing_codes=seen):
        code = stock.get("code")
        if not code or code in seen:
            continue
        # NXT전용 시간대엔 market=="NXT" 명시된 종목만 스캔
        if nxt_only_window and str(stock.get("market") or "") != "NXT":
            continue
        r = analyze(stock)
        # v165.15: NXT전용 시간대 통과 종목에 market="NXT" 명시 마킹
        if nxt_only_window and isinstance(r, dict):
            r["market"] = "NXT"
        _append_scan_alert(alerts, seen, r, seen_code=code)
def _scan_sector_leader_follow_candidates(alerts: list, seen: set) -> None:
    # v165.31 [#1]: NXT 프리마켓(08:00~08:59) + KRX 오픈 초기(09:00~09:03:30) 스킵
    # _collect_sector_leader_follow_candidates()가 183종목 전부 live quote API 순차 호출 →
    # 첫 run_scan()을 9~10분 블로킹 → NXT/KRX 개장 직후 종목이 이미 급등 후 포착됨
    # 이 시간대엔 NXT surge / KRX 상한가·거래량 종목 우선 처리 후 다음 주기에 재개
    if _is_nxt_premarket_window() or _is_krx_open_burst_window():
        _log_info_msg("  ⏭ 섹터팔로우 스킵 [장전/오픈초기] — surge 우선 처리")
        return
    nxt_only_window = not is_market_open() and is_nxt_open()  # v161.45
    # v165.34 [#2]: 섹터 팔로우 루프 사이클당 타임 버짓 5분 제한
    # 이유: 2026-04-27 14:41~15:11 섹터 대장 등록 24종목 × 1.5분 = 35분 run_scan 블로킹
    #       14:45 선진입 스캔이 15:11에 시작 (26분 지연) → 1차/최종 거의 동시 실행 → 중복 발송
    #       공매도 ConnectTimeout 12회 × 30초도 복합 원인
    _sfw_time_budget = 300.0  # 5분 (seconds)
    _sfw_start_ts = time.time()
    for stock in _collect_sector_leader_follow_candidates(existing_codes=seen):
        if time.time() - _sfw_start_ts > _sfw_time_budget:
            _log_info_msg(
                f"  ⏱ 섹터팔로우 타임버짓 {_sfw_time_budget:.0f}초 초과 → 나머지 다음 사이클로 연기"
            )
            break
        code = stock.get("code")
        if not code or code in seen:
            continue
        # v165.15: is_nxt_listed() 불안정 → market="NXT" 필드 단일 기준으로 교체
        # KRX 전용 종목은 _collect_sector_leader_follow_candidates에서 market=""로 들어옴
        if nxt_only_window and str(stock.get("market") or "") != "NXT":
            _log_info_msg(f"  ⏭ NXT전용 시간대 비NXT 종목 차단(섹터팔로우): {stock.get('name', code)}")
            continue
        r = analyze(stock)
        # v165.15: NXT전용 시간대 통과 종목에 market="NXT" 명시 마킹
        if nxt_only_window and isinstance(r, dict):
            r["market"] = "NXT"
        _append_scan_alert(alerts, seen, r, seen_code=code)
# ============================================================
# ⚡ F구간 VWAP 눌림반등 당일 단타 진입 감지 (v162.4)
# 근거: F구간(거래대금 8배↑+등락률 10%↑) 소진 후 VWAP 눌림→반등 패턴
# 진입: 알림 시점 현재가 / 손절: VWAP 이탈 / 목표: 당일 고가 / 만료: 당일
# ============================================================
def _detect_fzone_vwap_bounce(code: str) -> dict | None:
    """F구간 마킹 종목의 VWAP 눌림반등 감지. 감지되면 신호 dict 반환, 아니면 None.
    조건:
      1) 오늘 F구간 마킹됨
      2) WS 스냅샷 최근 틱에서 weighted_avg(VWAP) 존재
      3) 현재가가 VWAP 근처까지 눌림 후 회복 (현재가 >= VWAP, 직전 저점 <= VWAP*1.02)
      4) 눌림 구간 중 exec_vol 감소 (매도세 소진)
      5) 현재 exec_strength 회복 (>= 100)
      6) 당일 고가 > 현재가 (목표가 여유 있음)
      7) 상한가/거래정지 종목 제외
    """
    code = normalize_stock_code(code)
    if not code:
        return None
    # F구간 마킹 확인 (오늘, 재료 없음 → 페널티 대상이어야 의미 있음)
    info = _f_zone_codes.get(code)
    if not info:
        return None
    today_str = _now_kst().strftime("%Y%m%d")
    if info.get("date") != today_str:
        return None
    # 시장 시간 확인 (KRX 또는 NXT 개장 중)
    krx_open = is_market_open()
    nxt_open = is_nxt_open()
    if not krx_open and not nxt_open:
        return None
    # 당일 청산 여유 시간 확인: KRX 15:10 이후, NXT 19:40 이후 신규 진입 금지
    now = _now_kst()
    if krx_open and now.time() >= dtime(15, 10):
        return None
    if not krx_open and nxt_open and now.time() >= dtime(19, 40):
        return None
    # WS 스냅샷 확인 — v165.18 [#3]: buf<5 → buf<2 완화 (F존 12종목 알람 0건 해소)
    buf = list((_execution_snapshots.get(code) or []))
    if len(buf) < 2:
        return None
    recent = buf[-1]
    vwap = safe_int(recent.get("weighted_avg", 0))
    current_price = safe_int(recent.get("price", 0))
    exec_strength = float(recent.get("exec_strength", 0.0) or 0.0)
    high_price = safe_int(recent.get("high", 0))
    change_rate = float(recent.get("change_rate", 0.0) or 0.0)
    if vwap <= 0 or current_price <= 0:
        return None
    # 상한가 근처 제외 (변동 제한 >25%)
    if change_rate >= 25.0:
        return None
    # 조건3: 현재가 VWAP 위 회복 확인 (VWAP 대비 0~3% 내)
    vwap_recovery_ratio = (current_price - vwap) / vwap * 100 if vwap > 0 else 0.0
    _fzone_vwap_tol = float(_dynamic.get("fzone_vwap_tol_pct", 3.0) or 3.0)
    if not (0.0 <= vwap_recovery_ratio <= _fzone_vwap_tol):
        return None
    # 조건3-b: 직전 5~15틱 중 VWAP 아래로 눌렸던 시점 확인
    pullback_buf = buf[-15:-1] if len(buf) >= 15 else buf[:-1]
    had_pullback = any(
        safe_int(s.get("price", 0)) <= vwap * 1.02
        for s in pullback_buf
    )
    if not had_pullback:
        return None
    # 조건4: 눌림 구간 exec_vol 감소 확인
    pull_vols = [safe_int(s.get("exec_vol", 0)) for s in pullback_buf if safe_int(s.get("exec_vol", 0)) > 0]
    if len(pull_vols) >= 3:
        # 눌림 중반 평균 vs 최근 평균 비교 (감소 추세)
        mid_avg = sum(pull_vols[:len(pull_vols)//2]) / max(len(pull_vols)//2, 1)
        late_avg = sum(pull_vols[len(pull_vols)//2:]) / max(len(pull_vols) - len(pull_vols)//2, 1)
        vol_decreasing = late_avg <= mid_avg * 1.2  # 완화 기준 (20% 이내 증가 허용)
    else:
        vol_decreasing = True  # 샘플 부족 시 통과
    if not vol_decreasing:
        return None
    # 조건5: 체결강도 100 이상 (매수세 우위)
    _fzone_min_str = float(_dynamic.get("fzone_min_exec_strength", 100.0) or 100.0)
    if exec_strength < _fzone_min_str:
        return None
    # 조건6: 당일 고가 > 현재가 (목표가 여유)
    if high_price <= current_price:
        return None
    # 목표가: 당일 고가 97% (보수적), 손절: VWAP
    _fzone_tgt_pct = float(_dynamic.get("fzone_target_pct", 100.0) or 100.0) / 100.0
    stop_price = int(vwap * 0.995)  # VWAP 아래 0.5% 여유
    target_price = int(high_price * _fzone_tgt_pct)
    if target_price <= current_price:  # 목표가가 현재가 이하면 원래 고가로
        target_price = int(high_price)
    rr = (target_price - current_price) / max(current_price - stop_price, 1)
    _fzone_min_rr = float(_dynamic.get("fzone_min_rr", 1.2) or 1.2)
    if rr < _fzone_min_rr:  # 손익비 미달이면 패스 (학습으로 조정)
        return None
    stock_name = _resolve_stock_name(code, code)
    market = "NXT" if (not krx_open and nxt_open) else "KRX"
    # 당일 만료 시각: KRX 15:09, NXT 19:39
    expire_clock = dtime(15, 9) if krx_open else dtime(19, 39)
    today = _now_kst().date()
    expire_dt = datetime.combine(today, expire_clock)
    expire_ts = expire_dt.timestamp()
    return {
        "code": code,
        "name": stock_name,
        "signal_type": "FZONE_VWAP_BOUNCE",
        "price": current_price,
        "entry_price": current_price,
        "stop_loss": stop_price,
        "target_price": target_price,
        "vwap": vwap,
        "vwap_recovery_pct": round(vwap_recovery_ratio, 2),
        "exec_strength": round(exec_strength, 1),
        "high_price": high_price,
        "change_rate": round(change_rate, 1),
        "rr": round(rr, 2),
        "market": market,
        "expire_ts": expire_ts,
        "grade": "B",  # 재료 없는 기술적 진입 → B등급
        "sector_theme": "",
        "reasons": [
            f"⚡ F구간 VWAP 눌림반등 +{vwap_recovery_ratio:.1f}%",
            f"📊 체결강도 {exec_strength:.0f} (매수우위)",
            f"🎯 당일고가 {high_price:,}원 재도전",
        ],
        "cautions": [
            "⚠️ 당일 단타 전용 — 장마감 전 청산 필수",
            f"🛑 손절: VWAP({vwap:,}원) 이탈 즉시",
        ],
        "is_fzone_bounce": True,
        "fzone_date": today_str,
    }

def _scan_fzone_vwap_bounce_candidates(alerts: list, seen: set) -> None:
    """F구간 마킹 종목 전체를 순회하며 VWAP 눌림반등 신호 감지."""
    if not _f_zone_codes:
        return
    today_str = _now_kst().strftime("%Y%m%d")
    # 오늘 마킹된 종목만 대상
    target_codes = [
        c for c, info in dict(_f_zone_codes).items()
        if isinstance(info, dict) and info.get("date") == today_str
    ]
    if not target_codes:
        return
    for code in target_codes:
        try:
            if code in seen:
                continue
            # 당일 이미 발송한 종목 쿨다운 (hist_key로 구분)
            hist_key = f"FZONE_BOUNCE_{code}"
            if hist_key in _alert_history:
                continue
            sig = _detect_fzone_vwap_bounce(code)
            if not sig:
                continue
            # 최소 안전장치: 거래정지 확인
            if _trading_halt_state.get(code, {}).get("is_halt"):
                continue
            _append_scan_alert(alerts, seen, sig, hist_key=hist_key, seen_code=code)
        except Exception as e:
            _swallow_exception(e)

def _scan_early_pullback_candidates(alerts: list, seen: set, krx_open: bool, nxt_open: bool) -> None:
    if krx_open:
        for s in check_early_detection():
            code = _normalize_scan_signal_code(s)
            if not code:
                _log_warn_msg("⚠️ run_scan EARLY_DETECT 결과 code 누락 스킵")
                continue
            hist_key = f"NXT_{code}" if s.get("market") == "NXT" else code
            if code not in seen:
                _append_scan_alert(alerts, seen, s, hist_key=hist_key, seen_code=code)
        for s in check_pullback_signals():
            code = _normalize_scan_signal_code(s)
            if not code:
                _log_warn_msg("⚠️ run_scan pullback 결과 code 누락 스킵")
                continue
            if s.get("code") != code:
                s = dict(s)
                s["code"] = code
            if code not in seen and code not in _mid_pullback_alert_history:
                alerts.append(s)
                seen.add(code)
    elif nxt_open:
        for s in check_nxt_intraday_early_detection(existing_codes=seen):
            code = _normalize_scan_signal_code(s)
            if not code:
                _log_warn_msg("⚠️ run_scan NXT intraday EARLY 결과 code 누락 스킵")
                continue
            if code not in seen:
                _append_scan_alert(alerts, seen, s, hist_key=f"NXT_{code}", seen_code=code)
        for s in check_nxt_preopen_detection(existing_codes=seen):
            code = _normalize_scan_signal_code(s)
            if not code:
                _log_warn_msg("⚠️ run_scan NXT preopen 결과 code 누락 스킵")
                continue
            if code not in seen:
                _append_scan_alert(alerts, seen, s, hist_key=f"NXT_{code}", seen_code=code)
        for s in check_nxt_postmarket_detection(existing_codes=seen):
            code = _normalize_scan_signal_code(s)
            if not code:
                _log_warn_msg("⚠️ run_scan NXT postmarket 결과 code 누락 스킵")
                continue
            if code not in seen:
                _append_scan_alert(alerts, seen, s, hist_key=f"NXT_{code}", seen_code=code)
def _apply_scan_sector_gate(alerts: list) -> list:
    alerts = sorted(alerts, key=_sector_gate_sort_key, reverse=True)
    max_signals_per_sector = int(SCAN_SECTOR_LIMIT or 3)
    max_signals_misc = max_signals_per_sector + 1  # 기타 섹터는 1개 더 허용
    exempt_rate = float(SCAN_SECTOR_EXEMPT_RATE or 15.0)
    burst_threshold = int(SCAN_SECTOR_BURST_THRESHOLD or 7)

    # v165.24 [#3]: SNAP heat 기반 오늘 강세 섹터 top3 산출 → base_limit +2
    _heat_top_sectors: set = set()
    try:
        snap_state = _load_intraday_snap_state()
        _sec_appear: dict = {}
        for snap in (snap_state.get("snapshots") or []):
            for _c, _info in (snap.get("stocks") or {}).items():
                _sec = str(_info.get("sector") or _info.get("sector_theme") or "").strip()
                if _sec and _sec != "기타":
                    _sec_appear[_sec] = _sec_appear.get(_sec, 0) + 1
        # 등장 횟수 상위 3개 섹터 → heat_top_sectors
        if _sec_appear:
            _top3 = sorted(_sec_appear.items(), key=lambda x: -x[1])[:3]
            _heat_top_sectors = {s for s, _ in _top3}
            if _heat_top_sectors:
                _log_info_msg(f"  🔥 SNAP 오늘 강세 섹터 (동적 상한 +2): {', '.join(_heat_top_sectors)}")
    except Exception:
        pass

    # 섹터별 후보 수 사전 집계 → 급등장 판단용
    sector_total: dict = {}
    for s in alerts:
        sec = str(s.get("sector_theme") or s.get("sector") or "기타").strip() or "기타"
        sector_total[sec] = sector_total.get(sec, 0) + 1

    sector_counts: dict = {}
    filtered_alerts = []
    for s in alerts:
        sec = _hydrate_alert_sector_theme(s, force_lookup=True)
        if not str(s.get("name") or "").strip() and s.get("code"):
            s["name"] = _resolve_stock_name(s.get("code"), s.get("name", ""))

        change_rate = float(s.get("change_rate") or 0.0)
        # v161.23: 섹터 면제 판단 시 prev_close 기반 실계산 change_rate도 고려 — 스냅샷 지연 보정
        prev_close = safe_int(s.get("prev_close", 0), 0)
        price_now = safe_int(s.get("price", 0), 0)
        if prev_close > 0 and price_now > 0:
            calc_rate = ((price_now - prev_close) / prev_close) * 100.0
            change_rate = max(change_rate, calc_rate)  # 더 높은 값 사용

        # ── 규칙1: 등락률 15% 이상 → 섹터 제한 면제 (카운트도 증가 안 함)
        if change_rate >= exempt_rate:
            if not s.get("sector_theme") and sec != "기타":
                s["sector_theme"] = sec
            filtered_alerts.append(s)
            continue  # sector_counts 증가 없이 통과

        # v165.39: upper_limit_reached 등록 종목 → 섹터 슬롯 소비 차단
        # 이유: 아주스틸/금강철강 등 당일 상한가 차단 종목이 금속 섹터 1~5번 슬롯을 선점
        #       → 넥스틸 같은 유효 종목이 "금속 14번째"로 밀려 섹터 제한 탈락
        #       → 이 종목들은 sector_counts 증가 없이 pass-through (나중에 차단됨)
        _s_code = str(s.get("code") or "")
        _is_upper_blocked = _s_code in _upper_limit_alerted_today if _s_code else False
        if not _is_upper_blocked:
            _sig_type = str(s.get("signal_type") or "").upper()
            # NEAR_UPPER/UPPER_LIMIT + 28% 이상 → 사실상 상한가급 → 슬롯 소비 차단
            if _sig_type in ("NEAR_UPPER", "UPPER_LIMIT") and change_rate >= 28.0:
                _is_upper_blocked = True

        if _is_upper_blocked:
            # 섹터 카운트 없이 pass-through → 나중에 upper_limit 게이트에서 차단됨
            filtered_alerts.append(s)
            continue

        # ── 규칙2: 섹터별 한도 계산
        base_limit = max_signals_misc if sec == "기타" else max_signals_per_sector

        # 테마·재료 우선 종목 +2
        if s.get("theme_chain_force_hit") or s.get("force_external_capture_alert") or s.get("material_first_priority_hit") or s.get("direct_news_hit"):
            base_limit += 2

        # v161.48: A급 종목 한도 +1 — A급이 섹터 제한에 B급보다 먼저 탈락하는 역전 방지
        _gate_grade = str(s.get("execution_grade") or s.get("grade") or "").upper()
        if _gate_grade == "A":
            base_limit += 1

        # 급등장 감지: 이 섹터 전체 후보가 burst_threshold 이상이면 +3
        if sector_total.get(sec, 0) >= burst_threshold:
            base_limit += 3

        # v165.24 [#3]: SNAP 오늘 강세 섹터면 +2 추가
        if sec in _heat_top_sectors:
            base_limit += 2

        sector_counts[sec] = sector_counts.get(sec, 0) + 1
        if sector_counts[sec] <= base_limit:
            if not s.get("sector_theme") and sec != "기타":
                s["sector_theme"] = sec
            filtered_alerts.append(s)
        else:
            _record_shadow_capture(s.get("code", ""), s.get("name", s.get("code", "")), "sector_limit", s.get("signal_type", ""), stage="sector_gate", extra={"sector": sec, "score": s.get("score", 0), "change_rate": change_rate})
            _log_info_msg(f"  ⏭ 섹터 제한({sec} {sector_counts[sec]}번째): {s.get('name','')} 생략")
    return filtered_alerts
def _dispatch_scan_alerts(alerts: list) -> None:
    if not alerts:
        _log_info_msg("  → 조건 충족 없음")
        return
    if not _dispatch_scan_lock.acquire(blocking=False):
        return
    try:
        _log_info_msg(f"  → {len(alerts)}개 감지! [{regime_label()}]")
        for s in alerts:
            if is_scoring_only_instrument(s.get("code", ""), s.get("name", "")):
                _log_info_msg(f"  ⏭ 점수전용 종목 제외: {s.get('name', s.get('code',''))}")
                continue
            is_nxt = s.get("market") == "NXT"
            hist_key = f"NXT_{s['code']}" if is_nxt else s["code"]
            _dispatch_general_alert_signal(s, hist_key=hist_key, source_label="일반 포착")
    finally:
        _dispatch_scan_lock.release()
def _check_upper_limit_release() -> None:
    """v161.24: 당일 상한가 차단 종목의 매도호가 복원(상한가 풀림) 감지 → 즉시 알람.
    _upper_limit_alerted_today에 등록된 종목을 매 스캔 사이클마다 체크.
    ask_qty > 0 복원 확인 시 → 상한가 풀림 알람 발송 + 차단 목록에서 제거.
    """
    if not _upper_limit_alerted_today or not is_any_market_open():
        return
    today = _now_kst().strftime("%Y%m%d")
    released = []
    for code, date_str in list(_upper_limit_alerted_today.items()):
        if date_str != today:
            continue
        try:
            if is_market_open():
                cur = get_stock_price(code)
            elif is_nxt_open() and is_nxt_listed(code):
                cur = get_nxt_stock_price(code) or get_stock_price(code)
            else:
                cur = get_stock_price(code)
            if not cur:
                continue
            ask_qty = safe_int(cur.get("ask_qty", 0), 0)
            price = safe_int(cur.get("price", 0), 0)
            change_rate = safe_float(cur.get("change_rate", 0), 0.0)
            if not price:
                continue
            # 매도호가 복원 + 등락률이 여전히 강함(10% 이상) 확인
            if ask_qty > 0 and change_rate >= 10.0:
                name = _resolve_stock_name(code, cur.get("name", code))
                _log_info_msg(f"  🔓 상한가 풀림 감지: {name} ask={ask_qty:,} price={price:,} ({change_rate:+.1f}%)")
                send_with_chart_buttons(
                    f"🔓 <b>[상한가 풀림 — 매수 가능]</b>\n"
                    f"━━━━━━━━━━━━━━━\n"
                    f"🔴 <b>{name}</b>  <code>{code}</code>\n"
                    f"📍 현재가: <b>{price:,}원</b>  ({change_rate:+.1f}%)\n"
                    f"✅ 매도호가 복원 ({ask_qty:,}주) — 즉시 매수 가능\n"
                    f"━━━━━━━━━━━━━━━\n"
                    f"⚠️ 상한가 풀림 직후 변동성 주의 — 호가·거래량 확인 후 진입",
                    code, name
                )
                released.append(code)
        except Exception as e:
            _swallow_exception(e)
    for code in released:
        _upper_limit_alerted_today.pop(code, None)
    if released:
        _save_upper_limit_alerted_today()
        _log_info_msg(f"  🔓 상한가 풀림 차단 해제: {len(released)}종목")
def _run_scan_followup_hooks() -> None:
    check_execution_setup_watch()
    _tick_exec_speed_prewarm()
    check_entry_watch()
    check_preclose_gap_entry_watch()
    run_entry_defense_monitor()
    check_reentry_watch()
    _check_upper_limit_release()   # v161.24: 상한가 풀림 감지
    track_signal_results()
def run_price_first_scan() -> None:
    run_scan()

# v169.7: 선진입 스케줄용 named wrapper — lambda는 __name__="<lambda>"로 동일해져
#          _leader_job_running fn_key 충돌 → 14:35/15:08/19:10 중 하나만 실행되는 버그 수정
def _job_preclose_krx_initial():
    if not is_holiday():
        send_next_open_gap_alert(stage="krx", phase="initial")

def _job_preclose_krx_final():
    if not is_holiday():
        send_next_open_gap_alert(stage="krx", phase="final")

def _job_preclose_nxt_final():
    if not is_holiday():
        send_next_open_gap_alert(stage="nxt", phase="final")


_run_scan_global_lock = threading.Lock()  # v165.42: 스캔 전체 동시 실행 방지 (재시작 catchup+정규 스캔 중복 문제)
_surge_velocity_lock = threading.Lock()   # v165.43: 경량 급등 감지 스캔 중복 실행 방지
_surge_velocity_seen: dict = {}           # v165.43: {code: last_alerted_ts} — 동일 종목 30분 쿨다운

def _run_surge_velocity_scan() -> None:
    """v165.43 [1]: 경량 급등 감지 스캔 — 거래량 폭증 + 등락률 복합 조건으로 초기 급등 포착.
    기존 run_scan()은 naver_rise 수집→후보군→analyze() 파이프라인으로 수분 소요.
    이 스캔은 30초마다 FHPST01710000(거래량순위)를 직접 호출해 조건 충족 종목을 빠르게 analyze()로 연결.

    포착 조건 (AND):
      ① vol_ratio(거래량비율) >= 3.0x   — 거래량 폭증 (세력 매집 선행 지표)
      ② change_rate >= 3.0%            — 가격 반응 시작 확인
      ③ 우선주·스팩주 제외              — 알람 불가 종목 필터

    KRX 장중 + NXT 운영 시간 모두 동작.
    종목당 쿨다운 30분 (동일 급등 반복 알람 방지).
    """
    if not is_any_market_open() or is_holiday():
        return
    if not _surge_velocity_lock.acquire(blocking=False):
        return
    try:
        krx_open = is_market_open()
        nxt_open = is_nxt_open()
        markets = []
        if krx_open:
            markets.append(("J", "KRX"))
        if nxt_open and not krx_open:
            markets.append(("NX", "NXT"))
        if not markets:
            return

        now = time.time()
        candidates = []
        for mrkt_code, mkt_label in markets:
            try:
                data = _safe_get(
                    f"{KIS_BASE_URL}/uapi/domestic-stock/v1/quotations/volume-rank",
                    "FHPST01710000",
                    {
                        "FID_COND_MRKT_DIV_CODE": mrkt_code,
                        "FID_COND_SCR_DIV_CODE": "20171",
                        "FID_INPUT_ISCD": "0000",
                        "FID_DIV_CLS_CODE": "0",
                        "FID_BLNG_CLS_CODE": "0",
                        "FID_TRGT_CLS_CODE": "111111111",
                        "FID_TRGT_EXLS_CLS_CODE": "000000",
                        "FID_INPUT_PRICE_1": "1000",
                        "FID_INPUT_PRICE_2": "",
                        "FID_VOL_CNT": "30",
                        "FID_INPUT_DATE_1": "",
                    },
                )
                for item in (data.get("output") or []):
                    code = normalize_stock_code(item.get("mksc_shrn_iscd", "") or "")
                    if not code:
                        continue
                    try:
                        cr = float(item.get("prdy_ctrt", 0) or 0)
                        vr = float(item.get("vol_inrt", 0) or 0)
                        name = str(item.get("hts_kor_isnm", code) or code)
                    except Exception:
                        continue
                    # 조건 ①②
                    if vr < 3.0 or cr < 3.0:
                        continue
                    # 조건 ③ 우선주·스팩주 제외
                    nm_c = name.replace(" ", "")
                    if re.search(r'우[B0-9]*$', nm_c) or "스팩" in nm_c or "SPAC" in nm_c.upper():
                        continue
                    # 쿨다운 30분
                    if now - _surge_velocity_seen.get(code, 0) < 1800:
                        continue
                    candidates.append({
                        "code": code, "name": name,
                        "change_rate": cr, "volume_ratio": vr,
                        "price": safe_int(item.get("stck_prpr", 0), 0),
                        "market": mkt_label,
                        "_surge_velocity_hit": True,  # 경량 스캔 출처 마킹
                    })
            except Exception as e:
                _swallow_exception(e)

        if not candidates:
            return

        _log_info_msg(f"  ⚡ [경량급등] {len(candidates)}종목 감지 → analyze() 연결")
        alerts, seen = [], set()
        for stock in candidates:
            code = stock["code"]
            try:
                r = analyze(stock)
                if isinstance(r, dict) and r:
                    _surge_velocity_seen[code] = now  # 쿨다운 등록
                    mkt = stock.get("market", "KRX")
                    if isinstance(r, dict):
                        r["market"] = mkt
                    hist_key = f"VEL_{code}"
                    _append_scan_alert(alerts, seen, r, hist_key=hist_key, seen_code=code)
            except Exception as e:
                _swallow_exception(e)

        if alerts:
            alerts = _sanitize_run_scan_alerts(alerts, stage="pre_sector_gate")
            alerts = _apply_scan_sector_gate(alerts)
            alerts = _sanitize_run_scan_alerts(alerts, stage="pre_portfolio_filter")
            alerts = filter_portfolio_signals(alerts)
            alerts = _sanitize_run_scan_alerts(alerts, stage="pre_dispatch")
            _dispatch_scan_alerts(alerts)
    except Exception as e:
        _log_error("_run_surge_velocity_scan", e)
    finally:
        _surge_velocity_lock.release()

def run_scan():
    # v165.42: 스캔 전체 레벨 락 — catch-up 스캔과 정규 스캔 동시 실행 차단
    # 기존 _dispatch_scan_lock은 dispatch 단계만 보호 → analyze 단계부터 중복 실행 방지 필요
    if not _run_scan_global_lock.acquire(blocking=False):
        _log_info_msg("  ⏭ run_scan 이미 실행 중 — 이번 스캔 스킵 (중복 방지)")
        return
    try:
        _run_scan_body()
    finally:
        _run_scan_global_lock.release()

def _run_scan_body():
    code = ""
    ctx = _build_scan_runtime_context()
    if not ctx:
        return
    _log_info_msg(f"\n[{datetime.now().strftime('%H:%M:%S')}] 스캔{ctx['strict_tag']} [{ctx['mkt_tag']}]...")
    try:
        _ensure_dynamic_candidates_fresh()
        alerts, seen = [], set()
        # v167.0: VI 현황 갱신 (5분 캐시) — 장중에만 의미 있음
        if ctx["krx_open"]:
            try:
                get_vi_status()
            except Exception as _vi_e:
                _swallow_exception(_vi_e)
        # v167.0: 시장별 투자자 수급 방향 → _us_cache score_adj 보완 (장중에만)
        if ctx["krx_open"]:
            try:
                mit_adj = _update_market_investor_score_adj()
                if mit_adj:
                    _log_info_msg(f"  📊 시장수급 adj: {mit_adj:+d}점 (코스피 외인/기관 방향)")
            except Exception as _mit_e:
                _swallow_exception(_mit_e)
        # v167.0: 장전(08:00~08:59) 예상체결 상위 → prewatch 시드 보완
        now_h = _now_kst().hour
        if not ctx["krx_open"] and ctx["nxt_open"] and now_h == 8:
            try:
                exp_stocks = get_exp_trans_updown_rank(before_open=True)
                exp_headlines = []
                for es in exp_stocks[:10]:
                    es_code = normalize_stock_code(es.get("code", ""))
                    cr = es.get("change_rate", 0)
                    if es_code and cr >= 2.0:
                        exp_headlines.append({
                            "code": es_code,
                            "name": es.get("name", es_code),
                            "headline": f"장전예상체결상승{cr:.1f}%",
                            "quality_score": 4,
                        })
                if exp_headlines:
                    _register_material_seed_prewatch(exp_headlines, source_label="exp_trans_updown")
            except Exception as _exp_e:
                _swallow_exception(_exp_e)
        _drain_run_scan_repair_queue(alerts, seen)
        _scan_overnight_watchlist_candidates(alerts, seen, ctx["krx_open"])
        _scan_scenario_action_board_candidates(alerts, seen, ctx["krx_open"])
        _scan_issue_prewatch_candidates(alerts, seen)
        if ctx["krx_open"]:
            _scan_krx_market_candidates(alerts, seen)
        if ctx["nxt_open"]:
            _scan_nxt_market_candidates(alerts, seen)
        _scan_quiet_absorption_candidates(alerts, seen)
        _scan_rank_and_theme_candidates(alerts, seen)
        _scan_sector_leader_follow_candidates(alerts, seen)
        _scan_fzone_vwap_bounce_candidates(alerts, seen)
        _scan_early_pullback_candidates(alerts, seen, ctx["krx_open"], ctx["nxt_open"])
        alerts = _sanitize_run_scan_alerts(alerts, stage="pre_sector_gate")
        alerts = _apply_scan_sector_gate(alerts)
        alerts = _sanitize_run_scan_alerts(alerts, stage="pre_portfolio_filter")
        alerts = filter_portfolio_signals(alerts)
        alerts = _sanitize_run_scan_alerts(alerts, stage="pre_dispatch")
        _dispatch_scan_alerts(alerts)
        try:
            if is_market_open():
                _detect_and_send_sector_breadth_alert()
        except Exception as _sb_e:
            _swallow_exception(_sb_e)
        _run_scan_followup_hooks()
    except Exception as e:
        _log_error("run_scan", e, critical=True)
